const verseHeadersTamil = {
    // ===========================
    // OLD TESTAMENT
    // ===========================

    "Genesis 1:1": ["தேவன் வானத்தையும் பூமியையும் படைத்தல்", "ஆதியிலே தேவன் வானத்தையும் பூமியையும் சிருஷ்டித்தார்."],
    "Genesis 1:2": ["ஒழுங்கற்றிருந்த பூமி", "பூமியானது ஒழுங்கின்மையும் வெறுமையுமாயிருந்தது; ஆழத்தின்மேல் இருள் இருந்தது; தேவ ஆவியானவர் ஜலத்தின்மேல் அசைவாடிக்கொண்டிருந்தார்."],
    "Genesis 1:3": ["வெளிச்சம் உண்டாதல்", "தேவன்: 'வெளிச்சம் உண்டாகக்கடவது' என்றார், அப்பொழுது வெளிச்சம் உண்டாயிற்று."],
    "Genesis 1:6": ["ஆகாய விரிவு", "மேலேயுள்ள ஜலத்தையும் கீழேயுள்ள ஜலத்தையும் பிரிக்க தேவன் ஆகாய விரிவை உண்டாக்கினார்."],
    "Genesis 1:9": ["வெட்டாந்தரை தோன்றுதல்", "தேவன் ஜலத்தைத் தொகுக்கச் செய்ததால் வெட்டாந்தரை தெரிந்தது; அதற்குப் பூமி என்று பெயரிட்டார்."],
    "Genesis 1:11": ["தாவரங்கள் படைக்கப்படுதல்", "பூமி புல்லையும், விதையையும், கனிகளையும் தரும் மரங்களையும் முளைப்பிக்கச் செய்தார்."],
    "Genesis 1:14": ["சூரியன், சந்திரன் மற்றும் நட்சத்திரங்கள்", "பகலுக்கும் இரவுக்கும் வித்தியாசம் உண்டாக்கவும், காலங்களையும் நாட்களையும் குறிக்கவும் வானத்தில் சுடர்களை உண்டாக்கினார்."],
    "Genesis 1:20": ["நீர்வாழ் உயிரினங்கள் மற்றும் பறவைகள்", "ஜலத்திலுள்ள ஜீவஜந்துக்களையும், வானத்தில் பறக்கும் பறவைகளையும் தேவன் சிருஷ்டித்தார்."],
    "Genesis 1:24": ["பூமியின் விலங்குகள்", "பூமியின் காட்டுமிருகங்களையும், ஊரும் பிராணிகளையும், நாட்டுமிருகங்களையும் தேவன் உண்டாக்கினார்."],
    "Genesis 1:26": ["மனிதனைப் படைத்தல்", "தேவன் நம்முடைய சாயலாகவும் நமது ரூபத்தின்படியேயும் மனுஷனை உண்டாக்கி, பூமியை ஆள அவருக்கு அதிகாரம் கொடுத்தார்."],
    "Genesis 1:29": ["உணவு வழங்கப்படுதல்", "மனுஷனுக்கும் விலங்குகளுக்கும் உணவாகப் பூமியின் செடிகளையும் கனிகளையும் தேவன் கொடுத்தார்."],
    "Genesis 1:31": ["படைப்பு மிகவும் நன்றாயிருந்தது", "தேவன் தாம் உண்டாக்கின எல்லாவற்றையும் பார்த்தார், அது மிகவும் நன்றாயிருந்தது."],

    "Genesis 2:1": ["சிருஷ்டிப்பு நிறைவடைதல்", "வானமும் பூமியும் அவைகளின் சேனைகள் யாவும் முடிக்கப்பட்டன."],
    "Genesis 2:2": ["ஏழாம் நாளில் தேவன் ஓய்ந்திருத்தல்", "தேவன் தமது கிரியைகளை முடித்து ஏழாம் நாளில் ஓய்ந்திருந்தார்; அந்த நாளை ஆசீர்வதித்துப் பரிசுத்தமாக்கினார்."],
    "Genesis 2:4": ["மனித வாழ்வின் ஆரம்பம்", "தேவனாகிய கர்த்தர் பூமியையும் வானத்தையும் உண்டாக்கின வரலாறு இதுவே."],
    "Genesis 2:7": ["மனுஷனை உருவாக்குதல்", "தேவனாகிய கர்த்தர் மனுஷனைப் பூமியின் மண்ணினாலே உருவாக்கி, அவன் நாசியிலே ஜீவசுவாசத்தை ஊதினார்."],
    "Genesis 2:8": ["ஏதேன் தோட்டம்", "தேவன் ஏதேனிலே ஒரு தோட்டத்தை உண்டாக்கி, தாம் உருவாக்கின மனுஷனை அங்கே வைத்தார்."],
    "Genesis 2:9": ["தோட்டத்தின் மரங்கள்", "பார்க்கிறதற்கு அழகும் புசிக்கிறதற்கு நலமுமான மரங்களையும், ஜீவவிருட்சத்தையும் நன்மை தீமை அறியத்தக்க விருட்சத்தையும் வளரச் செய்தார்."],
    "Genesis 2:10": ["ஏதேனின் நதி", "தோட்டத்திற்குத் தண்ணீர் பாய்ச்ச ஏதேனிலிருந்து ஒரு நதி ஓடி, அது நான்கு ஆறுகளாகப் பிரிந்தது."],
    "Genesis 2:15": ["தோட்டத்தில் மனுஷனின் பொறுப்பு", "மனுஷனை ஏதேன் தோட்டத்தில் வைத்து, அதைப் பண்படுத்தவும் காக்கவும் கர்த்தர் கட்டளையிட்டார்."],
    "Genesis 2:16": ["விருட்சத்தைப் பற்றிய கட்டளை", "தோட்டத்திலுள்ள சகல விருட்சத்தின் கனியையும் புசிக்கலாம், ஆனால் நன்மை தீமை அறியத்தக்க விருட்சத்தின் கனியை மட்டும் புசிக்கக்கூடாது."],
    "Genesis 2:18": ["துணையின் அவசியம்", "மனுஷன் தனிமையாயிருப்பது நல்லதல்ல, அவனுக்கு ஏற்ற துணையை உண்டாக்குவேன் என்று தேவன் சொன்னார்."],
    "Genesis 2:19": ["விலங்குகளுக்குப் பெயரிடுதல்", "தேவன் சகல மிருகங்களையும் பறவைகளையும் மனுஷனிடத்தில் கொண்டுவந்து, அவன் அவைகளுக்கு என்ன பெயரிடுவான் என்று பார்த்தார்."],
    "Genesis 2:21": ["ஸ்திரீயைப் படைத்தல்", "தேவன் மனுஷனுக்கு அயர்ந்த நித்திரையை வரப்பண்ணி, அவன் விலாவெலும்புகளில் ஒன்றை எடுத்து ஸ்திரீயை உண்டாக்கினார்."],
    "Genesis 2:24": ["திருமணம் ஏற்படுத்தப்படுதல்", "புருஷன் தன் தகப்பனையும் தாயையும் விட்டுத் தன் மனைவியுடன் இசைந்திருப்பான்; அவர்கள் ஒரே மாம்சமாயிருப்பார்கள்."],
    "Genesis 2:25": ["அப்பாவித்தனம்", "மனுஷனும் அவன் மனைவியும் நிர்வாணிகளாயிருந்தும், அவர்கள் வெட்கப்படவில்லை."],

    "Genesis 3:1": ["ஏவாளைப் பாம்பு சோதித்தல்", "பாம்பு தேவனுடைய கட்டளையைச் சந்தேகிக்கும்படி செய்து, விலக்கப்பட்ட கனியைப் புசிக்க ஏவாளைத் தூண்டியது."],
    "Genesis 3:4": ["பாம்பின் வஞ்சகம்", "நீங்கள் சாகவே சாவதில்லை, தேவன் நன்மை தீமைகளை அறிவதுபோல நீங்களும் அறிவீர்கள் என்று பாம்பு சொன்னது."],
    "Genesis 3:6": ["முதல் பாவம்", "ஸ்திரீ அந்தப் பழத்தைப் புசித்து, தன் புருஷனுக்கும் கொடுத்தாள், அவனும் புசித்தான்."],
    "Genesis 3:7": ["நிர்வாணத்தை உணர்தல்", "இருவருடைய கண்களும் திறக்கப்பட்டது; அவர்கள் நிர்வாணிகளென்று அறிந்து, அத்தி இலைகளைத் தைத்துக் கச்சைகளை உண்டாக்கினார்கள்."],
    "Genesis 3:8": ["தேவனிடமிருந்து ஒளிந்துகொள்ளுதல்", "தேவன் தோட்டத்தில் உலாவி வரும் சத்தத்தைக் கேட்டு, ஆதாமும் அவன் மனைவியும் மறைந்துகொண்டார்கள்."],
    "Genesis 3:9": ["ஆதாமை தேவன் கேள்வி கேட்டல்", "தேவனாகிய கர்த்தர் ஆதாமை நோக்கி: 'நீ எங்கே இருக்கிறாய்?' என்று கூப்பிட்டார்."],
    "Genesis 3:11": ["பாவத்திற்கான பழி", "ஆதாம் ஸ்திரீயின் மேலும், ஸ்திரீ பாம்பின் மேலும் பழியைப் போட்டார்கள்."],
    "Genesis 3:14": ["பாம்பின் மேல் சாபம்", "தேவன் பாம்பைச் சபித்து, அது தன் வயிற்றினால் ஊர்ந்து மண்ணைத் தின்னும் என்று சொன்னார்."],
    "Genesis 3:15": ["மீட்பரின் வாக்குத்தத்தம்", "ஸ்திரீயின் வித்து பாம்பின் தலையை நசுக்கும் என்று தேவன் அறிவித்தார்."],
    "Genesis 3:16": ["ஸ்திரீயின் மேல் தீர்ப்பு", "கர்ப்பவேதனையும், உறவுகளில் போராட்டமும் இருக்கும் என்று அறிவிக்கப்பட்டது."],
    "Genesis 3:17": ["புருஷனின் மேல் தீர்ப்பு", "பூமி சபிக்கப்பட்டது; மனுஷன் வருத்தத்தோடே அதின் பலனைப் புசிப்பான் என்று சொல்லப்பட்டது."],
    "Genesis 3:20": ["ஏவாள் என்று பெயரிடுதல்", "ஏவாள் எல்லா ஜீவனுள்ளோருக்கும் தாயானபடியால் ஆதாம் தன் மனைவிக்கு இப்பெயரிட்டான்."],
    "Genesis 3:21": ["தேவன் உடைகளைத் தருதல்", "தேவனாகிய கர்த்தர் ஆதாமுக்கும் அவன் மனைவிக்கும் தோல் உடைகளை உண்டாக்கி உடுத்தினார்."],
    "Genesis 3:23": ["ஏதேனிலிருந்து வெளியேற்றப்படுதல்", "மனுஷன் வந்த மண்ணைப் பண்படுத்த தேவன் அவனை ஏதேன் தோட்டத்திலிருந்து அனுப்பிவிட்டார்."],
    "Genesis 3:24": ["ஜீவவிருட்சத்தைப் பாதுகாத்தல்", "கேருபீன்களையும் சுடர்வீசும் பட்டயத்தையும் வைத்து ஜீவவிருட்சத்திற்குப் போகும் வழியைக் காவல் செய்தார்."],

    "Genesis 4:1": ["காயீன் மற்றும் ஆபேலின் பிறப்பு", "ஆதாம் தன் மனைவி ஏவாளை அறிந்தான்; அவள் கர்ப்பவதியாகி காயீனையும் ஆபேலையும் பெற்றாள்."],
    "Genesis 4:3": ["கர்த்தருக்குக் காணிக்கை", "காயீன் நிலத்தின் கனிகளையும், ஆபேல் தன் மந்தையின் தலையீற்றுகளையும் காணிக்கையாகக் கொண்டு வந்தார்கள்."],
    "Genesis 4:5": ["காயீனின் காணிக்கை நிராகரிக்கப்படுதல்", "கர்த்தர் ஆபேலின் காணிக்கையை அங்கீகரித்தார், ஆனால் காயீனுடையதை அங்கீகரிக்கவில்லை; அதனால் காயீன் கோபமடைந்தான்."],
    "Genesis 4:6": ["காயீனுக்கு எச்சரிக்கை", "பாவம் வாசற்படியில் படுத்திருக்கும், நீ அதை ஆள வேண்டும் என்று தேவன் சொன்னார்."],
    "Genesis 4:8": ["காயீன் ஆபேலைக் கொலை செய்தல்", "காயீன் தன் சகோதரன் ஆபேலைத் தாக்கி அவனைக் கொலை செய்தான்."],
    "Genesis 4:9": ["காயீனிடம் தேவன் கேட்டல்", "உன் சகோதரன் எங்கே என்று தேவன் கேட்டபோது, 'நான் என் சகோதரனுக்குக் காவலாளியோ?' என்று காயீன் பதிலளித்தான்."],
    "Genesis 4:11": ["காயீன் சபிக்கப்படுதல்", "தேவன் காயீனைச் சபித்து, அவனை தேசத்திலிருந்து ஓடித்திரிகிறவனாக அனுப்பினார்."],
    "Genesis 4:15": ["காயீனுக்குப் பாதுகாப்பு", "காயீனை யாரும் கொல்லாதபடி கர்த்தர் அவன் மேல் ஒரு அடையாளத்தைப் போட்டார்."],
    "Genesis 4:17": ["காயீனின் சந்ததியினர்", "காயீனின் குடும்பம் பெருகியது; பட்டணங்களும் கட்டப்பட ஆரம்பித்தன."],
    "Genesis 4:19": ["லாமேக்கும் அவன் குடும்பமும்", "லாமேக் இரண்டு மனைவிகளைத் திருமணஞ் செய்து வன்முறையைப் பற்றிப் பேசினான்."],
    "Genesis 4:25": ["சேத்தின் பிறப்பு", "ஆதாமுக்குச் சேத் என்னும் மற்றொரு குமாரன் பிறந்தான்."],
    "Genesis 4:26": ["தேவனைத் தொழுதுகொள்ளுதல்", "சேத்தின் காலத்தில் மனுஷர்கள் கர்த்தருடைய நாமத்தைத் தொழுதுகொள்ள ஆரம்பித்தார்கள்."],

    "Genesis 5:1": ["ஆதாமின் வம்ச வரலாறு", "தேவன் மனுஷனைத் தமது சாயலாகப் படைத்த நாள் முதல் ஆதாமின் வம்ச வரலாறு இதுவே."],
    "Genesis 5:3": ["சேத்தின் பிறப்பு", "ஆதாம் சேத் என்னும் குமாரனைப் பெற்றுத் தன் வம்சத்தைத் தொடர்ந்தான்."],
    "Genesis 5:6": ["சந்ததி தொடருதல்", "ஏனோஸ், கேனான், மகலாலெயேல் மற்றும் யாரேத் என வம்சம் தொடர்ந்தது."],
    "Genesis 5:18": ["ஏனோக்கின் பிறப்பு", "யாரேத் ஏனோக்கைப் பெற்றான்; ஏனோக்கு தேவனோடு சஞ்சரித்துக் கொண்டிருந்தான்."],
    "Genesis 5:21": ["ஏனோக்கு தேவனோடு சஞ்சரித்தல்", "ஏனோக்கு தேவனோடு சஞ்சரித்தபடியால் மரணத்தைக் காணவில்லை; தேவன் அவனை எடுத்துக்கொண்டார்."],
    "Genesis 5:25": ["மெத்தூசலாவின் பிறப்பு", "மெத்தூசலா பிறந்தான்; இவனே வேதாகமத்தில் அதிக காலம் உயிர்வாழ்ந்த மனிதன்."],
    "Genesis 5:28": ["நோவாவின் பிறப்பு", "லாமேக் நோவாவைப் பெற்று, இவன் நமக்கு ஆறுதல் தருவான் என்று நம்பினான்."],
    "Genesis 5:32": ["நோவாவின் குமாரர்கள்", "நோவாவுக்குச் சேம், காம், யாப்பேத் என்னும் மூன்று குமாரர்கள் பிறந்தார்கள்."],

    "Genesis 6:1": ["பூமியில் மனிதர் பெருகுதல்", "பூமியில் மனுஷர் பெருகத்தொடங்கினபோது, தேவகுமாரர் மனுஷகுமாரத்திகளை நோக்கி, அவர்களைத் தங்களுக்குப் பெண்களாகக் கொண்டார்கள்."],
    "Genesis 6:3": ["மனித ஆயுட்கால எல்லை", "மனுஷர்கள் மாம்சமானபடியால், அவர்கள் உயிரோடிருக்கும் காலம் நூற்றிருபது வருஷமென்று தேவன் தீர்மானித்தார்."],
    "Genesis 6:5": ["மனிதனின் அக்கிரமம்", "மனுஷனுடைய அக்கிரமம் பூமியிலே பெருகினது என்றும், அவன் இருதயத்தின் நினைவுகள் எல்லாம் நித்தமும் பொல்லாததே என்றும் கர்த்தர் கண்டார்."],
    "Genesis 6:6": ["பாவத்தினால் தேவன் மனஸ்தாபப்படுதல்", "தாம் பூமியிலே மனுஷனை உண்டாக்கினதற்காகக் கர்த்தர் மனஸ்தாபப்பட்டார்; அது அவர் இருதயத்திற்கு விசனமாயிருந்தது."],
    "Genesis 6:7": ["பூமியை நியாயந்தீர்க்கத் தீர்மானித்தல்", "மனுஷனையும், மிருகங்களையும், ஊரும் பிராணிகளையும், ஆகாயத்துப் பறவைகளையும் பூமியின்மேல் இராதபடிக்கு நிர்மூலமாக்குவேன் என்று தேவன் சொன்னார்."],
    "Genesis 6:8": ["நோவாவுக்குக் கிடைத்த கிருபை", "நோவாவுக்கோ கர்த்தருடைய கண்களில் கிருபை கிடைத்தது."],
    "Genesis 6:9": ["நோவாவின் நீதிமானான குணம்", "நோவா தன் காலத்தில் இருந்தவர்களுக்குள்ளே நீதிமானும் உத்தமனுமாயிருந்தான்; நோவா தேவனோடே சஞ்சரித்துக்கொண்டிருந்தான்."],
    "Genesis 6:11": ["பூமியின் சீர்கேடு", "பூமியானது தேவனுக்கு முன்பாகச் சீர்கெட்டிருந்தது; பூமி கொடுமையினால் நிறைந்திருந்தது."],
    "Genesis 6:13": ["வெள்ளத்தைக் குறித்து தேவன் அறிவித்தல்", "பூமி கொடுமையினால் நிறைந்திருக்கிறபடியால், மாம்சமான யாவரையும் பூமியோடுங்கூட அழித்துப் போடுவேன் என்று நோவாவிடம் தேவன் சொன்னார்."],
    "Genesis 6:14": ["பேழையைச் செய்யக் கட்டளை", "உயிரைக் காக்கும்படிக்கு ஒரு பேழையைச் செய்யுமாறு நோவாவுக்குத் தேவன் கட்டளையிட்டார்."],
    "Genesis 6:19": ["மிருகங்களைப் பேழைக்குள் கொண்டுவருதல்", "சகலவிதமான ஜீவன்களிலும் ஜோடி ஜோடியாகப் பேழைக்குள் கொண்டு வரும்படி நோவாவுக்குச் சொல்லப்பட்டது."],
    "Genesis 6:22": ["நோவா தேவனுக்குக் கீழ்ப்படிதல்", "தேவன் தனக்குக் கட்டளையிட்டபடியெல்லாம் நோவா செய்து முடித்தான்."],

    "Genesis 7:1": ["நோவா பேழைக்குள் பிரவேசித்தல்", "நோவா நீதிமானாயிருந்தபடியால், அவனையும் அவன் குடும்பத்தையும் பேழைக்குள் பிரவேசிக்கும்படி கர்த்தர் சொன்னார்."],
    "Genesis 7:2": ["மிருகங்கள் சேர்க்கப்படுதல்", "சுத்தமான மிருகங்களில் ஏழேழு ஜோடிகளையும், அசுத்தமானவைகளில் இரண்டிரண்டு ஜோடிகளையும் எடுத்துக்கொள்ளக் கட்டளையிட்டார்."],
    "Genesis 7:4": ["பெருவெள்ளம் அறிவிக்கப்படுதல்", "இன்னும் ஏழு நாள் சென்றபின், நாற்பது நாள் இரவும் பகலும் பூமியின்மேல் மழையைப் பெய்யப்பண்ணி, ஜீவஜந்துக்களை அழிப்பேன் என்று தேவன் சொன்னார்."],
    "Genesis 7:5": ["நோவா கீழ்ப்படிதல்", "கர்த்தர் தனக்குக் கட்டளையிட்டபடியெல்லாம் நோவா செய்தான்."],
    "Genesis 7:7": ["குடும்பம் பேழைக்குள் செல்லுதல்", "நோவாவும், அவன் குமாரரும், அவன் மனைவியும், அவன் குமாரரின் மனைவிகளும் ஜலப்பிரளயத்திற்குத் தப்பும்படி பேழைக்குள் பிரவேசித்தார்கள்."],
    "Genesis 7:11": ["வெள்ளம் தொடங்குதல்", "மகா ஆழத்தின் ஊற்றுக்கண்ணெல்லாம் பிளந்தன; வானத்தின் மதகுகளும் திறக்கப்பட்டன."],
    "Genesis 7:12": ["நாற்பது நாள் மழை", "நாற்பது நாள் இரவும் பகலும் பூமியின்மேல் பெருமழை பெய்தது."],
    "Genesis 7:17": ["தண்ணீர் பூமியை மூடுதல்", "ஜலம் பெருகிப் பேழையை உயர்த்தினது, அது பூமிக்குமேல் எழும்பினது."],
    "Genesis 7:19": ["மலைகள் மூழ்கடிக்கப்படுதல்", "ஜலம் பூமியின்மேல் மிகவும் அதிகமாய்ப் பெருகினதினால், வானத்தின்கீழ் எங்குமுள்ள உயர்ந்த மலைகளெல்லாம் மூடிப் போயின."],
    "Genesis 7:21": ["உயிரினங்களின் அழிவு", "பூமியின்மேல் நடமாடின மாம்சமான யாவரும், பறவைகளும், ஊரும் பிராணிகளும், மனுஷர்களும் அழிந்தார்கள்."],
    "Genesis 7:23": ["நோவா மாத்திரம் தப்புதல்", "பேழைக்கு வெளியே இருந்த யாவும் நிர்மூலமாயின; நோவாவும் அவனோடே பேழையிலிருந்தவர்களும் மாத்திரம் தப்பினார்கள்."],
    "Genesis 7:24": ["தண்ணீர் நிலைத்திருத்தல்", "ஜலம் நூற்றைம்பது நாள் பூமியின்மேல் மிஞ்சியிருந்தது."],

    "Genesis 8:1": ["தேவன் நோவாவை நினைத்தருளுதல்", "தேவன் நோவாவையும் பேழையிலிருந்த சகல ஜீவஜந்துக்களையும் நினைத்தருளினார்; தேவன் பூமியின்மேல் காற்றை வீசப்பண்ணினதினால் ஜலம் குறைந்தது."],
    "Genesis 8:3": ["தண்ணீர் வடிதல்", "ஜலம் பூமியின்மேல் இருந்து வாபசாகிக் குறைந்துகொண்டே வந்தது."],
    "Genesis 8:4": ["ஆரராத் மலையில் பேழை தங்குதல்", "பேழையானது ஆரராத் என்னும் மலைகளின்மேல் தங்கியது."],
    "Genesis 8:6": ["நோவா காகத்தை அனுப்புதல்", "நாற்பது நாள் சென்றபின், நிலத்தின் நிலையை அறிய நோவா ஒரு காகத்தை வெளியே விட்டான்."],
    "Genesis 8:8": ["நோவா புறாவை அனுப்புதல்", "ஜலம் பூமியின்மேல் வடிந்ததோ என்று அறிய நோவா ஒரு புறாவை வெளியே விட்டான்."],
    "Genesis 8:10": ["புறா ஒலிவ இலையோடு திரும்புதல்", "புறா தன் வாயிலே ஒரு ஒலிவ இலைப்பொத்தை நறுக்கிக்கொண்டு திரும்பி வந்தது; அதனால் ஜலம் வடிந்தது என்று நோவா அறிந்தான்."],
    "Genesis 8:13": ["பூமி உலர்தல்", "ஜலம் வற்றிப்போய், நோவா பேழையின் மேல்தட்டை எடுத்துப் பார்த்தபோது, பூமியின் முகம் உலர்ந்திருந்தது."],
    "Genesis 8:15": ["பேழையை விட்டு வெளியே வரக் கட்டளை", "நோவாவையும் அவன் குடும்பத்தையும் சகல மிருகங்களோடும் பேழையை விட்டு வெளியே வரும்படி தேவன் சொன்னார்."],
    "Genesis 8:20": ["நோவா பலிபீடம் கட்டுதல்", "நோவா கர்த்தருக்கு ஒரு பலிபீடம் கட்டி, சர்வாங்க தகனபலிகளைச் செலுத்தினான்."],
    "Genesis 8:21": ["பூமியின் நிலையை தேவன் உறுதிப்படுத்துதல்", "இனி நான் பூமியைச் சபிப்பதில்லை என்றும், பூமியுள்ள நாளளவும் விதைப்பும் அறுப்பும், சீதோஷ்ண காலங்களும் மாறாது என்றும் கர்த்தர் சொன்னார்."],

    "Genesis 9:1": ["நோவாவையும் அவன் குமாரரையும் தேவன் ஆசீர்வதித்தல்", "தேவன் நோவாவையும் அவன் குமாரரையும் ஆசீர்வதித்து: நீங்கள் பலுகிப் பெருகிப் பூமியை நிரப்புங்கள் என்றார்."],
    "Genesis 9:2": ["மிருகங்கள் மீதான அதிகாரம்", "பூமியிலுள்ள சகல மிருகங்களும் பறவைகளும் உங்களைக் குறித்துப் பயப்படும்; அவைகள் உங்கள் கையில் ஒப்புக்கொடுக்கப்பட்டன."],
    "Genesis 9:3": ["மனிதனுக்கு உணவாக விலங்குகள்", "தாவரங்களைப் போலவே சகல பிராணிகளையும் நீங்கள் புசிக்கலாம்."],
    "Genesis 9:4": ["இரத்தத்தைப் புசிக்கக் கூடாது", "மாம்சத்தை அதின் உயிராகிய இரத்தத்தோடே புசிக்கவேண்டாம்."],
    "Genesis 9:5": ["மனித உயிரின் மதிப்பு", "மனுஷனுடைய இரத்தத்தைச் சிந்திக்கிறவனுடைய இரத்தம் மனுஷனாலேயே சிந்திக்கப்படும்; ஏனெனில் தேவன் மனுஷனைத் தமது சாயலாக உண்டாக்கினார்."],
    "Genesis 9:8": ["நோவாவுடன் தேவன் செய்த உடன்படிக்கை", "தேவன் நோவாவுடனும் அவன் சந்ததியாருடனும் சகல ஜீவஜந்துக்களுடனும் ஒரு உடன்படிக்கையை ஏற்படுத்தினார்."],
    "Genesis 9:12": ["வானவில் ஒரு அடையாளமாக", "இனி ஜலப்பிரளயத்தினால் பூமி அழிக்கப்படுவதில்லை என்பதற்கு அடையாளமாக வானவில்லை மேகத்தில் வைத்தார்."],
    "Genesis 9:18": ["நோவாவின் குமாரர்கள்", "நோவாவின் குமாரராகிய சேம், காம், யாப்பேத் என்பவர்களே பூமியெங்கும் பரவின ஜாதிகளுக்கு மூதாதையர்."],
    "Genesis 9:20": ["நோவா திராட்சத்தோட்டம் நடுதல்", "நோவா பயிரிடத் தொடங்கி, ஒரு திராட்சத்தோட்டத்தை நாட்டினான்."],
    "Genesis 9:21": ["நோவா வெறித்தல்", "நோவா திராட்சரசம் குடித்து, வெறித்து, தன் கூடாரத்துக்குள்ளே நிர்வாணமாய்க் கிடந்தான்."],
    "Genesis 9:22": ["காமின் அவமரியாதை", "காம் தன் தகப்பனுடைய நிர்வாணத்தைக் கண்டு, அதைத் தன் சகோதரர்களுக்கு வெளியிலே சொன்னான்."],
    "Genesis 9:23": ["சேமும் யாப்பேத்தும் மரியாதை செய்தல்", "அவர்கள் தங்கள் தகப்பனின் நிர்வாணத்தைப் பாராதபடிக்கு, ஒரு வஸ்திரத்தைத் தங்கள் தோள்மேல் போட்டுக்கொண்டு பின்னிட்டுச் சென்று அவரை மூடினார்கள்."],
    "Genesis 9:24": ["நோவாவின் சாபமும் ஆசீர்வாதமும்", "நோவா விழித்து நடந்ததை அறிந்து, கானானைச் சபித்து, சேமையும் யாப்பேத்தையும் ஆசீர்வதித்தான்."],
    "Genesis 9:28": ["நோவாவின் இறுதி ஆண்டுகள்", "நோவா ஜலப்பிரளயத்திற்குப் பின் பல வருஷங்கள் உயிர்வாழ்ந்து மரித்தான்."],

    "Genesis 10:1": ["நோவாவின் சந்ததியினர்", "ஜலப்பிரளயத்திற்குப் பின் நோவாவின் குமாரராகிய சேம், காம், யாப்பேத் என்பவர்களுக்குப் பிறந்த குமாரர்களின் வம்ச வரலாறு இதுவே."],
    "Genesis 10:2": ["யாப்பேத்தின் சந்ததி", "யாப்பேத்தின் குமாரர் கடல் ஓரங்களிலும் வட திசைகளிலும் உள்ள ஜாதிகளுக்கு மூதாதையர் ஆனார்கள்."],
    "Genesis 10:6": ["காமின் சந்ததி", "காமின் குமாரர் எத்தியோப்பியா, எகிப்து, பூத், கானான் ஆகிய தேசங்களில் பரவினார்கள்."],
    "Genesis 10:8": ["நிம்ரோத் என்னும் பராக்கிரமசாலி", "நிம்ரோத் பூமியிலே பராக்கிரமசாலியான வேட்டைக்காரனும் ஆளுகை செய்கிறவனுமாய் இருந்தான்."],
    "Genesis 10:10": ["நிம்ரோத் ராஜ்யத்தின் ஆரம்பம்", "சீனார் தேசத்திலுள்ள பாபேல், ஏரேக், அக்காத் போன்ற பட்டணங்கள் அவன் ராஜ்யத்திற்கு ஆரம்பமாயிருந்தது."],
    "Genesis 10:15": ["கானானின் சந்ததி", "கானானுடைய சந்ததியினர் இஸ்ரவேலருக்குப் பின்நாளில் வாக்குத்தத்தம் பண்ணப்பட்ட தேசங்களில் பரவினார்கள்."],
    "Genesis 10:21": ["சேமின் சந்ததி", "சேமின் வம்சாவழி செமித்திய ஜாதிகளுக்கு மூதாதையர் ஆனது."],
    "Genesis 10:25": ["பூமி பிரிக்கப்படுதல்", "பேலேகுடைய நாட்களில் பூமி பிரிக்கப்பட்டது."],
    "Genesis 10:31": ["பாஷை மற்றும் தேசங்களின்படி ஜாதிகள்", "சேமின் சந்ததியினர் தங்கள் பாஷைகளின்படியும் தேசங்களின்படியும் ஜாதிகளாகப் பிரிந்தார்கள்."],
    "Genesis 10:32": ["ஜாதிகளின் தோற்றம்", "நோவாவின் வம்சங்களின்படியே ஜலப்பிரளயத்திற்குப் பின் பூமியிலே ஜாதிகள் பிரிந்தன."],

    "Genesis 11:1": ["பூமியெங்கும் ஒரே பாஷை", "பூமியெல்லாம் ஒரே பாஷையும் ஒரே விதமான பேச்சும் உள்ளதாயிருந்தது."],
    "Genesis 11:2": ["சீனார் தேசத்தில் குடியேறுதல்", "மனுஷர்கள் கிழக்கிலிருந்து பிரயாணம் பண்ணி, சீனார் தேசத்திலுள்ள ஒரு சமபூமியைக்கண்டு அங்கே குடியிருந்தார்கள்."],
    "Genesis 11:3": ["செங்கற்களால் கட்டுதல்", "அவர்கள் செங்கல் சுட்டு, சாந்துக்குப் பதிலாகக் கீலையும் உபயோகித்து ஒரு நகரத்தைக் கட்டத் தொடங்கினார்கள்."],
    "Genesis 11:4": ["பாபேல் கோபுரம்", "தாங்கள் சிதறிப்போகாதபடிக்கு வானத்தை எட்டும் சிகரமுள்ள ஒரு கோபுரத்தைக் கட்டி, தங்களுக்கு ஒரு பேரையுண்டாக்க நினைத்தார்கள்."],
    "Genesis 11:5": ["கோபுரத்தைக் கர்த்தர் பார்த்தல்", "மனுபுத்திரர் கட்டுகிற நகரத்தையும் கோபுரத்தையும் பார்க்கும்படிக்குக் கர்த்தர் இறங்கிவந்தார்."],
    "Genesis 11:7": ["பாஷைத் தடுமாற்றம்", "அவர்கள் ஒருவருடைய பேச்சை ஒருவர் அறியாதபடிக்கு, அங்கே அவர்கள் பாஷையைத் தாறுமாறாக்க தேவன் தீர்மானித்தார்."],
    "Genesis 11:8": ["பூமியெங்கும் சிதறடிக்கப்படுதல்", "கர்த்தர் அவர்களை அங்கேயிருந்து பூமியின்மீதெங்கும் சிதறிப்போகப்பண்ணினார்; அப்பொழுது நகரம் கட்டுகிறது நின்றுபோயிற்று."],
    "Genesis 11:9": ["பாபேல் என்னும் பெயர்", "கர்த்தர் பூமியெங்கும் இருந்த பாஷையைத் தாறுமாறாக்கினபடியால், அந்த இடத்திற்குப் பாபேல் என்று பெயரிடப்பட்டது."],
    "Genesis 11:10": ["சேமின் வம்சாவழி", "சேமின் வம்ச வரலாறு பதிவு செய்யப்பட்டு, அது அடுத்த தலைமுறைகளுக்கு வழிவகுத்தது."],
    "Genesis 11:24": ["தேராகின் குடும்பப் பிறப்பு", "வம்சாவழி நாகோர் மற்றும் தேராகு வழியாகத் தொடர்ந்தது."],
    "Genesis 11:27": ["தேராகின் குடும்பம்", "தேராகு ஆபிராம், நாகோர், ஆரான் என்பவர்களைப் பெற்றான்."],
    "Genesis 11:31": ["கானானை நோக்கிய பிரயாணம்", "தேராகு தன் குடும்பத்தை ஊர் என்னும் பட்டணத்திலிருந்து கானானுக்கு அழைத்துச் செல்லப் புறப்பட்டு, ஆரான் வரை வந்து அங்கே தங்கிவிட்டான்."],
    "Genesis 11:32": ["தேராகின் மரணம்", "தேராகு இருநூற்று ஐந்து வருஷம் உயிர்வாழ்ந்து ஆரானிலே மரித்தான்."],

    "Genesis 12:1": ["ஆபிராமை தேவன் அழைத்தல்", "கர்த்தர் ஆபிராமை நோக்கி: 'நீ உன் தேசத்தையும் உன் இனத்தையும் விட்டுப் புறப்பட்டு, நான் உனக்குக் காண்பிக்கும் தேசத்துக்குப் போ' என்றார்."],
    "Genesis 12:2": ["பெரிய ஜாதியாக்குவேன் என்ற வாக்குத்தத்தம்", "நான் உன்னைப் பெரிய ஜாதியாக்கி, உன்னை ஆசீர்வதித்து, உன் பேரைப் பெருமைப்படுத்துவேன்."],
    "Genesis 12:3": ["பூமியின் வம்சங்களுக்கு ஆசீர்வாதம்", "உனக்குள் பூமியிலுள்ள வம்சங்களெல்லாம் ஆசீர்வதிக்கப்படும் என்று தேவன் சொன்னார்."],
    "Genesis 12:4": ["அழைப்பிற்கு ஆபிராம் கீழ்ப்படிதல்", "ஆபிராம் கர்த்தர் தனக்குச் சொன்னபடியே சாராயையும் லோத்தையும் அழைத்துக்கொண்டு கானான் தேசத்திற்குப் புறப்பட்டுப்போனான்."],
    "Genesis 12:6": ["கானானுக்கு வந்து சேருதல்", "ஆபிராம் அந்தத் தேசத்தில் சீகேம் என்னும் இடம் வரைக்கும் வந்தான்; அங்கே கர்த்தர் அவனுக்குத் தரிசனமானார்."],
    "Genesis 12:7": ["ஆபிராம் பலிபீடம் கட்டுதல்", "தனக்குத் தரிசனமான கர்த்தருக்கு ஆபிராம் அங்கே ஒரு பலிபீடத்தைக் கட்டினான்."],
    "Genesis 12:8": ["ஆபிராம் கர்த்தரைத் தொழுதுகொள்ளுதல்", "ஆபிராம் பெத்தேலுக்குக் கிழக்கே பெயர்ந்துபோய், அங்கே ஒரு பலிபீடத்தைக் கட்டி கர்த்தருடைய நாமத்தைத் தொழுதுகொண்டான்."],
    "Genesis 12:10": ["தேசத்தில் பஞ்சம்", "தேசத்திலே கொடிய பஞ்சம் உண்டானபடியால், ஆபிராம் எகிப்திலே தங்கும்படி அங்கே போனான்."],
    "Genesis 12:11": ["ஆபிராம் உயிருக்கு அஞ்சுதல்", "எகிப்தியர் தம்மைக் கொல்லுவார்கள் என்று அஞ்சி, சாராயைத் தன் சகோதரி என்று சொல்லும்படி ஆபிராம் கேட்டுக்கொண்டான்."],
    "Genesis 12:14": ["சாராய் பார்வோனின் வீட்டிற்குச் செல்லுதல்", "சாராய் மிக அழகாய் இருந்தபடியால், அவள் பார்வோனுடைய அரண்மனைக்கு அழைத்துச் செல்லப்பட்டாள்."],
    "Genesis 12:17": ["பார்வோனை தேவன் தண்டித்தல்", "சாராயின் நிமித்தம் கர்த்தர் பார்வோனையும் அவன் வீட்டாரையும் மகா வாதைகளால் வாதித்தார்."],
    "Genesis 12:19": ["பார்வோன் ஆபிராமைக்கண்டித்தல்", "பார்வோன் ஆபிராமை அழைத்து, அவனைக்கண்டித்து, அவனுடைய மனைவியோடும் அவனுக்குள்ள எல்லாவற்றோடும் அவனை அனுப்பிவிட்டான்."],

    "Genesis 13:1": ["ஆபிராம் எகிப்திலிருந்து திரும்புதல்", "ஆபிராம் தன் மனைவியோடும் லோத்தோடும் தமக்கு உண்டான யாவற்றோடும் எகிப்திலிருந்து திரும்பி வந்தான்."],
    "Genesis 13:3": ["பெத்தேலுக்குத் திரும்புதல்", "ஆபிராம் தான் முன்பு பலிபீடம் கட்டியிருந்த பெத்தேலுக்கும் ஆயிக்கும் இடைப்பட்ட இடத்திற்குத் திரும்பி வந்தான்."],
    "Genesis 13:5": ["மேய்ப்பர்களுக்குள் வாக்குவாதம்", "ஆபிராம் மற்றும் லோத்துடைய மிருகஜீவன்கள் அதிகமாயிருந்தபடியால், அவர்கள் ஒருமித்துக் குடியிருக்க அந்தப் பூமி இடங்கொடுக்கவில்லை; அதனால் மேய்ப்பர்களுக்குள் வாக்குவாதம் உண்டாயிற்று."],
    "Genesis 13:8": ["பிரிந்து போக ஆபிராம் யோசனை சொல்லுதல்", "தங்களுக்குள் சண்டை இல்லாதபடிக்குத் தனித்தனியே பிரிந்து போகலாம் என்று ஆபிராம் லோத்திடம் சொன்னான்."],
    "Genesis 13:10": ["லோத்து யோர்தான் சமபூமியைத் தெரிந்துகொள்ளுதல்", "லோத்து நீர்வளம் நிறைந்த யோர்தான் சமபூமியைத் தெரிந்துகொண்டு, சோதோமுக்கு நேராகப் போனான்."],
    "Genesis 13:12": ["ஆபிராம் கானானில் தங்குதல்", "ஆபிராம் கானான் தேசத்தில் குடியிருந்தான்; லோத்து சமபூமியிலுள்ள பட்டணங்களில் தங்கித் தன் கூடாரத்தைப் போட்டான்."],
    "Genesis 13:14": ["வாக்குத்தத்தத்தை தேவன் உறுதிப்படுத்துதல்", "லோத்து பிரிந்துபோனபின், கர்த்தர் ஆபிராமை நோக்கி: 'நீ பார்க்கிற இந்தத் தேசம் முழுவதையும் உனக்கும் உன் சந்ததிக்கும் தருவேன்' என்றார்."],
    "Genesis 13:16": ["சந்ததி பெருகும் என்ற வாக்குத்தத்தம்", "உன் சந்ததியைப் பூமியின் தூளத்தன்னையாகப் பெருகப்பண்ணுவேன் என்று தேவன் சொன்னார்."],
    "Genesis 13:17": ["தேசத்தைச் சுற்றிப்பார்த்தல்", "இந்தத் தேசத்தை உனக்குத் தருகிறபடியால், நீ இதின் நீளமும் அகலமும் எங்குமாய் நடந்து திரி என்று தேவன் சொன்னார்."],
    "Genesis 13:18": ["எப்ரோனில் பலிபீடம் கட்டுதல்", "ஆபிராம் மம்ரேயினுடைய சமபூமியில் வந்து குடியிருந்து, அங்கே கர்த்தருக்கு ஒரு பலிபீடத்தைக் கட்டினான்."],

    "Genesis 14:1": ["ராஜாக்களின் யுத்தம்", "பல ராஜாக்கள் சோதோம், கொமோரா மற்றும் அதைச் சுற்றியுள்ள ராஜாக்களுக்கு விரோதமாக யுத்தம் பண்ணினார்கள்."],
    "Genesis 14:8": ["சித்தீம் பள்ளத்தாக்கில் போர்", "சோதோம் கொமோரா ராஜாக்கள் எதிர்த்துப் போரிட்டும், படையெடுத்து வந்த ராஜாக்களிடம் தோல்வியடைந்தார்கள்."],
    "Genesis 14:11": ["லோத்து சிறைபிடிக்கப்படுதல்", "எதிரி ராஜாக்கள் லோத்தையும் அவனுடைய சொத்துக்களையும் சிறைபிடித்துக்கொண்டு போனார்கள்."],
    "Genesis 14:13": ["லோத்து பிடிபட்டதை ஆபிராம் அறிதல்", "தன் சகோதரன் குமாரனாகிய லோத்து சிறைபிடிக்கப்பட்ட செய்தியை ஆபிராம் அறிந்தான்."],
    "Genesis 14:14": ["ஆபிராம் லோத்தை மீட்டல்", "ஆபிராம் தன்னிடம் பயிற்சி பெற்றவர்களைத் திரட்டிக்கொண்டு எதிரிகளைத் தொடர்ந்து சென்று லோத்தை மீட்கப் புறப்பட்டான்."],
    "Genesis 14:15": ["ராஜாக்களின் மேல் வெற்றி", "ஆபிராம் இரவிலே எதிரிகளை முறியடித்து, லோத்தையும் மற்றவர்களையும் சொத்துக்களையும் மீட்டுக் கொண்டுவந்தான்."],
    "Genesis 14:17": ["சோதோம் ராஜாவைச் சந்தித்தல்", "யுத்தத்தில் வெற்றி பெற்றுத் திரும்பிய ஆபிராமைச் சந்திக்கச் சோதோம் ராஜா வெளியே வந்தான்."],
    "Genesis 14:18": ["மெல்கிசேதேக்கு ஆபிராமை ஆசீர்வதித்தல்", "சாலெம் ராஜாவும் உன்னதமான தேவனுடைய ஆசாரியனுமாகிய மெல்கிசேதேக்கு அப்பமும் திராட்சரசமும் கொண்டுவந்து ஆபிராமை ஆசீர்வதித்தான்."],
    "Genesis 14:20": ["ஆபிராம் தசமபாகம் கொடுத்தல்", "ஆபிராம் தான் மீட்டுக் கொண்டுவந்த எல்லாவற்றிலும் பத்திலொரு பங்கை மெல்கிசேதேக்குக்குக் கொடுத்தான்."],
    "Genesis 14:21": ["கொள்ளைப் பொருளை ஆபிராம் மறுத்தல்", "தான் ஐசுவரியவானானதற்கு எவரும் உரிமை கொண்டாடாதபடிக்கு, சோதோம் ராஜா கொடுத்த பொருள்களை ஆபிராம் மறுத்துவிட்டான்."],

    "Genesis 15:1": ["ஆபிராமுக்கு தேவனுடைய வாக்குத்தத்தம்", "கர்த்தர் ஆபிராமுக்குத் தரிசனமாகி: 'ஆபிராமே, நீ பயப்படாதே; நான் உனக்குக் கேடகமும் மகா பெரிய பலனுமாயிருக்கிறேன்' என்றார்."],
    "Genesis 15:2": ["ஆபிராம் வாக்குத்தத்தத்தைக் குறித்துக் கேட்டல்", "எனக்கு ஒரு பிள்ளை இன்னும் இல்லையே, என் வீட்டிலுள்ள ஊழியக்காரனா எனக்குச் சுதந்திரவாளி என்று ஆபிராம் கேட்டான்."],
    "Genesis 15:4": ["வாரிசு உண்டாகும் என்ற வாக்குத்தத்தம்", "உன் கர்ப்பப் பிறப்பாயிருப்பவனே உனக்குச் சுதந்திரவாளியாவான் என்று கர்த்தர் சொன்னார்."],
    "Genesis 15:5": ["நட்சத்திரங்களைப் போன்ற சந்ததி", "தேவன் ஆபிராமை வெளியே அழைத்து நட்சத்திரங்களைக் காண்பித்து, 'உன் சந்ததி இவ்வண்ணமாயிருக்கும்' என்றார்."],
    "Genesis 15:6": ["ஆபிராம் தேவனை விசுவாசித்தல்", "ஆபிராம் கர்த்தரை விசுவாசித்தான், அதை அவர் அவனுக்கு நீதியாக எண்ணினார்."],
    "Genesis 15:7": ["தேசத்தைப் பற்றிய வாக்குத்தத்தம்", "இந்தத் தேசத்தை உனக்குச் சுதந்தரமாகக் கொடுக்கும்படி உன்னை ஊர் என்கிற பட்டணத்திலிருந்து அழைத்து வந்தேன் என்று தேவன் சொன்னார்."],
    "Genesis 15:9": ["உடன்படிக்கை பலி", "உடன்படிக்கை சடங்கிற்காகப் பலிமிருகங்களை ஆயத்தம் செய்யும்படி தேவன் ஆபிராமுக்குக் கட்டளையிட்டார்."],
    "Genesis 15:12": ["எதிர்காலத் துன்பங்கள் குறித்த தீர்க்கதரிசனம்", "உன் சந்ததியார் அந்நிய தேசத்தில் அடிமைகளாயிருந்து நானூறு வருஷம் துன்பப்படுவார்கள் என்று தேவன் வெளிப்படுத்தினார்."],
    "Genesis 15:17": ["தேவன் உடன்படிக்கை செய்தல்", "புகைகிற சூளையும் எரிகிற தீவட்டியும் துண்டிக்கப்பட்ட மிருகங்களின் நடுவே கடந்து சென்றது, இது தேவனுடைய உடன்படிக்கையை உறுதிப்படுத்தியது."],
    "Genesis 15:18": ["வாக்குத்தத்தம் பண்ணப்பட்ட தேசத்தின் எல்லைகள்", "எகிப்தின் நதி தொடங்கி ஐப்பிராத்து நதி வரைக்கும் உள்ள தேசத்தை உன் சந்ததிக்குக் கொடுத்தேன் என்று கர்த்தர் சொன்னார்."],

    "Genesis 16:1": ["சாராய் ஆகாரை ஆபிராமுக்குக் கொடுத்தல்", "சாராய்க்குப் பிள்ளைகள் இல்லாததினால், ஆபிராமுக்கு ஒரு பிள்ளை பிறக்கும்படி தன் வேலைக்காரியாகிய ஆகாரை அவனுக்குக் கொடுத்தாள்."],
    "Genesis 16:3": ["ஆகார் ஆபிராமின் மனைவியாதல்", "ஆகார் ஆபிராமுக்குக் கொடுக்கப்பட்டாள், அவள் கர்ப்பவதியானாள்."],
    "Genesis 16:4": ["சாராய்க்கும் ஆகாருக்கும் இடையே மனஸ்தாபம்", "தான் கர்ப்பவதியானதைக் கண்டபோது, ஆகார் தன் நாச்சியாராகிய சாராயை அற்பமாக எண்ணினாள்; இது அவர்களுக்குள் போராட்டத்தை உண்டாக்கியது."],
    "Genesis 16:6": ["ஆகார் ஓடிப்போதல்", "சாராய் ஆகாரைக் கடினமாய் நடத்தினபடியால், அவள் வனாந்தரத்திற்கு ஓடிப்போனாள்."],
    "Genesis 16:7": ["தூதன் ஆகாரைக் கண்டது", "கர்த்தருடைய தூதன் வனாந்தரத்திலுள்ள ஒரு நீரூற்றின் அருகே ஆகாரைக் கண்டார்."],
    "Genesis 16:9": ["திரும்பிச் சென்று கீழ்ப்படிதல்", "தூதன் ஆகாரை நோக்கி: 'நீ உன் நாச்சியாரிடத்திற்குத் திரும்பிப் போய், அவள் கைக்கு அடங்கியிரு' என்றார்."],
    "Genesis 16:10": ["சந்ததி பெருகும் என்ற வாக்குத்தத்தம்", "உன் சந்ததி எண்ணி முடியாதபடிக்கு மிகவும் பெருகப்பண்ணுவேன் என்று தூதன் வாக்குக் கொடுத்தார்."],
    "Genesis 16:11": ["இஸ்மவேலின் பிறப்பு அறிவிக்கப்படுதல்", "ஆகார் ஒரு குமாரனைப் பெறுவாள் என்றும், அவனுக்கு இஸ்மவேல் என்று பெயரிட வேண்டும் என்றும் சொல்லப்பட்டது."],
    "Genesis 16:13": ["ஆகார் கர்த்தருக்குப் பெயரிடுதல்", "ஆகார் கர்த்தரை 'என்னைக்காண்கிற தேவன்' என்று அழைத்தாள்."],
    "Genesis 16:15": ["இஸ்மவேலின் பிறப்பு", "ஆகார் ஆபிராமுக்கு ஒரு குமாரனைப் பெற்றாள்; ஆபிராம் அவனுக்கு இஸ்மவேல் என்று பெயரிட்டான்."],
    "Genesis 16:16": ["ஆபிராமின் வயது", "இஸ்மவேல் பிறந்தபோது ஆபிராம் எண்பத்தாறு வயதாயிருந்தான்."],

    "Genesis 17:1": ["ஆபிராமுக்கு தேவன் தரிசனமாதல்", "ஆபிராம் தொண்ணூற்றொன்பது வயதானபோது, கர்த்தர் அவனுக்குத் தரிசனமாகி, தமக்கு முன்பாக உத்தமனாய் நடக்கும்படி அழைத்தார்."],
    "Genesis 17:2": ["உடன்படிக்கை உறுதிப்படுத்தப்படுதல்", "தேவன் தமது உடன்படிக்கையை ஏற்படுத்தி, ஆபிராமின் சந்ததியை மிகவும் பெருகப்பண்ணுவதாக வாக்குக் கொடுத்தார்."],
    "Genesis 17:4": ["அநேக ஜாதிகளுக்குத் தகப்பன்", "ஆபிராம் அநேக ஜாதிகளுக்குத் தகப்பனாவான் என்று தேவன் அறிவித்தார்."],
    "Genesis 17:5": ["ஆபிராம் 'ஆபிரகாம்' எனப் பெயர் மாறுதல்", "அநேக ஜாதிகளுக்குத் தகப்பனாய் இருப்பதை உணர்த்த, தேவன் ஆபிராமின் பெயரை ஆபிரகாம் என்று மாற்றினார்."],
    "Genesis 17:7": ["நித்திய உடன்படிக்கை", "ஆபிரகாமிடமும் அவன் சந்ததியாரிடமும் தேவன் ஒரு நித்திய உடன்படிக்கையை ஏற்படுத்தினார்."],
    "Genesis 17:9": ["விருத்தசேதனம் என்னும் அடையாளம்", "தேவனுக்கும் ஆபிரகாம் குடும்பத்திற்கும் இடையிலான உடன்படிக்கையின் அடையாளமாக விருத்தசேதனத்தைக் கட்டளையிட்டார்."],
    "Genesis 17:15": ["சாராய் 'சாராள்' எனப் பெயர் மாறுதல்", "தேவன் சாராயின் பெயரை சாராள் என்று மாற்றி, அவள் ஒரு குமாரனைப் பெறுவாள் என்று வாக்குக் கொடுத்தார்."],
    "Genesis 17:17": ["ஆபிரகாம் நகைத்தல்", "முதிர்ந்த வயதில் தனக்கும் சாராளுக்கும் ஒரு பிள்ளை எப்படிப் பிறக்கும் என்று ஆபிரகாம் ஆச்சரியப்பட்டு நகைத்தான்."],
    "Genesis 17:19": ["ஈசாக்கைப் பற்றிய வாக்குத்தத்தம்", "சாராள் ஈசாக்கு என்னும் குமாரனைப் பெறுவாள் என்றும், அவன் மூலம் உடன்படிக்கை தொடரும் என்றும் தேவன் சொன்னார்."],
    "Genesis 17:20": ["இஸ்மவேலுக்கு ஆசீர்வாதம்", "இஸ்மவேலையும் ஆசீர்வதித்து, அவனை ஒரு பெரிய ஜாதியாக்குவேன் என்று தேவன் வாக்குக் கொடுத்தார்."],
    "Genesis 17:23": ["ஆபிரகாம் கீழ்ப்படிதல்", "தேவன் கட்டளையிட்டபடியே ஆபிரகாம் இஸ்மவேலுக்கும் தன் வீட்டிலுள்ள ஆண்களுக்கும் விருத்தசேதனம் செய்தான்."],
    "Genesis 17:24": ["ஆபிரகாமின் வயது", "ஆபிரகாம் விருத்தசேதனம் பண்ணப்பட்டபோது தொண்ணூற்றொன்பது வயதாயிருந்தான்."],
    "Genesis 17:27": ["ஆண்கள் அனைவருக்கும் விருத்தசேதனம்", "ஆபிரகாம் வீட்டிலுள்ள ஆண்கள் அனைவரும் அன்றைய தினமே விருத்தசேதனம் பண்ணப்பட்டார்கள்."],

    "Genesis 18:1": ["ஆபிரகாமுக்கு மூன்று விருந்தினர்கள் வருதல்", "மம்ரேயினுடைய சமபூமியில் ஆபிரகாம் இருக்கும்போது கர்த்தர் அவனுக்குத் தரிசனமானார்; மூன்று புருஷர்கள் அவன் அருகே வந்தார்கள்."],
    "Genesis 18:3": ["ஆபிரகாம் விருந்தினரை உபசரித்தல்", "ஆபிரகாம் அந்த விருந்தினர்களை மரியாதையுடன் வரவேற்று, அவர்களை இளைப்பாறவும் போஜனம் பண்ணவும் அழைத்தான்."],
    "Genesis 18:6": ["உணவு ஆயத்தம் செய்தல்", "ஆபிரகாம் சீக்கிரமாக அப்பம், இறைச்சி மற்றும் பால் ஆகியவற்றை விருந்தினர்களுக்காக ஆயத்தம் செய்தான்."],
    "Genesis 18:9": ["குமாரனைப் பற்றிய வாக்குத்தத்தம்", "விருந்தினர்கள் சாராளைக் குறித்து விசாரித்து, ஒரு வருஷத்திற்குள் அவளுக்கு ஒரு குமாரன் பிறப்பான் என்று வாக்குக் கொடுத்தார்கள்."],
    "Genesis 18:12": ["சாராள் நகைத்தல்", "தாமும் ஆபிரகாமும் முதிர்ந்த வயதானவர்கள் என்பதால் சாராள் தமக்குள்ளே நகைத்துக்கொண்டாள்."],
    "Genesis 18:14": ["கர்த்தரால் ஆகாத காரியம் உண்டோ?", "கர்த்தரால் செய்ய முடியாத கடினமான காரியம் ஒன்றுமில்லை என்று அவர் அவர்களுக்கு நினைவுறுத்தினார்."],
    "Genesis 18:16": ["சோதோமை நோக்கிப் பயணம்", "விருந்தினர்கள் புறப்பட்டுச் சோதோமை நோக்கிப் போனார்கள்; ஆபிரகாம் அவர்களை வழிவிட்டனுப்பக் கூடச் சென்றான்."],
    "Genesis 18:20": ["சோதோமுக்கு எதிரான கூக்குரல்", "சோதோம் கொமோராவின் பாவம் மிகவும் கொடியதாயிருக்கிறது என்று கர்த்தர் வெளிப்படுத்தினார்."],
    "Genesis 18:23": ["சோதோமுக்காக ஆபிரகாம் வேண்டுதல்", "நீதிமான்களைப் பாவியோடு கூட அழிப்பீரோ என்று ஆபிரகாம் அந்த ஊருக்காகத் தேவனிடம் மன்றாடினான்."],
    "Genesis 18:24": ["ஆபிரகாமின் விவாதம்", "ஐம்பது நீதிமான்கள் இருந்தால் அந்த ஊரை அழிப்பீரோ என்று ஆபிரகாம் கேட்கத் தொடங்கினான்."],
    "Genesis 18:32": ["பத்து நீதிமான்கள்", "நீதிமான்களின் எண்ணிக்கை பத்து வரை குறையும் வரை ஆபிரகாம் தொடர்ந்து கெஞ்சிக் கேட்டுக்கொண்டான்."],
    "Genesis 18:33": ["கர்த்தர் செல்லுதல்", "பேசி முடித்தபின் கர்த்தர் சென்றார், ஆபிரகாம் தன் இடத்திற்குத் திரும்பினான்."],

    "Genesis 19:1": ["இரண்டு தூதர்கள் சோதோமுக்கு வருதல்", "சாயங்காலத்திலே இரண்டு தூதர்கள் சோதோமுக்கு வந்தார்கள்; லோத்து அவர்களை வரவேற்றுத் தன் வீட்டுக்கு அழைத்துச் சென்றான்."],
    "Genesis 19:4": ["சோதோமின் அக்கிரமம்", "சோதோம் பட்டணத்து மனிதர்கள் லோத்துவின் வீட்டைச் சூழ்ந்துகொண்டு, அந்த விருந்தினர்களுக்குத் தீமை செய்யும்படி கேட்டார்கள்."],
    "Genesis 19:10": ["தூதர்கள் லோத்தைப் பாதுகாத்தல்", "தூதர்கள் லோத்தை வீட்டுக்குள் இழுத்துக்கொண்டு, வெளியிலிருந்த மனிதர்களுக்குக் குருட்டாட்டம் பிடித்தது."],
    "Genesis 19:12": ["தப்பிப்போக எச்சரிக்கை", "தேவன் இந்தப் பட்டணத்தை அழிக்கப் போகிறார், அதனால் உன் குடும்பத்தோடு இங்கிருந்து வெளியேறு என்று தூதர்கள் லோத்தை எச்சரித்தார்கள்."],
    "Genesis 19:15": ["சீக்கிரம் வெளியேற லோத்தை வற்புறுத்தல்", "பட்டணம் அழியும்போது நீங்களும் அழியாதபடிக்குச் சீக்கிரம் தப்பிப்போங்கள் என்று தூதர்கள் அவசரப்படுத்தினார்கள்."],
    "Genesis 19:17": ["பின்னிட்டுப் பார்க்கக் கூடாது என்ற கட்டளை", "மலைக்குத் தப்பிப்போங்கள், பின்னிட்டுப் பார்க்க வேண்டாம் என்று அவர்களுக்குச் சொல்லப்பட்டது."],
    "Genesis 19:24": ["சோதோம் கொமோராவின் அழிவு", "கர்த்தர் சோதோம் கொமோராவின் மேல் வானத்திலிருந்து அக்கினியையும் கந்தகத்தையும் வருஷிக்கப்பண்ணி அவைகளை அழித்தார்."],
    "Genesis 19:26": ["லோத்துவின் மனைவி பின்னிட்டுப் பார்த்தல்", "லோத்துவின் மனைவி பின்னிட்டுப் பார்த்து, உப்புத்தூணானாள்."],
    "Genesis 19:29": ["தேவன் லோத்தை விடுவித்தல்", "தேவன் ஆபிரகாமை நினைத்தருளி, லோத்தை அந்த அழிவிலிருந்து விடுவித்தார்."],
    "Genesis 19:30": ["லோத்து மலையில் குடியிருத்தல்", "லோத்து தன் இரண்டு குமாரத்திகளோடும் ஒரு மலையிலுள்ள குகையில் குடியிருந்தான்."],
    "Genesis 19:31": ["குமாரத்திகளின் திட்டம்", "தங்களுக்கு வாரிசு இல்லையே என்று அஞ்சி, தங்கள் வம்சத்தைக் காக்க லோத்துவின் குமாரத்திகள் ஒரு திட்டமிட்டார்கள்."],
    "Genesis 19:33": ["லோத்துவின் குமாரத்திகள் கர்ப்பமடைதல்", "ஒவ்வொரு குமாரத்தியும் தங்கள் தகப்பன் மூலமாகவே கர்ப்பவதியானார்கள்."],
    "Genesis 19:37": ["மோவாப் மற்றும் அம்மோனின் பிறப்பு", "அவர்களுக்குப் பிறந்த குமாரர்கள் மோவாபியர் மற்றும் அம்மோனியர்களுக்கு மூதாதையர் ஆனார்கள்."],

    "Genesis 20:1": ["ஆபிரகாம் கேராரில் தங்குதல்", "ஆபிரகாம் கேரார் தேசத்திற்குப் பிரயாணம் பண்ணி, அங்கே கொஞ்சக் காலம் தங்கியிருந்தான்."],
    "Genesis 20:2": ["சாராளைச் சகோதரி என்று சொல்லுதல்", "ஆபிராம் சாராளைத் தன் சகோதரி என்று சொன்னான்; அதனால் கேரார் ராஜாவாகிய அபிமெலேக்கு அவளைத் தன் வீட்டுக்கு அழைத்துச் சென்றான்."],
    "Genesis 20:3": ["அபிமெலேக்கை தேவன் எச்சரித்தல்", "தேவன் அபிமெலேக்குக்குச் சொப்பனத்தில் தோன்றி, சாராள் ஒரு புருஷனுடைய மனைவி என்று எச்சரித்தார்."],
    "Genesis 20:4": ["அபிமெலேக்குத் தன் குற்றமின்மையை விளக்குதல்", "சாராள் ஆபிரகாமின் மனைவி என்று தமக்குத் தெரியாது என்றும், தாம் உத்தமமான இருதயத்தோடே இதைச் செய்ததாகவும் அபிமெலேக்குச் சொன்னான்."],
    "Genesis 20:6": ["அபிமெலேக்கின் உத்தமத்தை தேவன் ஏற்றல்", "அபிமெலேக்கு சாராளைத் தொடாதபடி தடுத்ததாகவும், அவன் பாவம் செய்யாதபடி காத்ததாகவும் தேவன் சொன்னார்."],
    "Genesis 20:7": ["சாராளைத் திரும்பக் கொடுத்தல்", "ஆபிரகாம் ஒரு தீர்க்கதரிசி, அவன் உனக்காக வேண்டிக்கொள்வான்; அதனால் சாராளைத் திரும்பக் கொடுத்துவிடு என்று தேவன் கட்டளையிட்டார்."],
    "Genesis 20:8": ["அபிமெலேக்கு ஆபிரகாமிடம் கேட்டல்", "அபிமெலேக்கு ஆபிரகாமை அழைத்து, ஏன் தமக்கு இப்படிச் செய்தீர் என்று கேட்டார்."],
    "Genesis 20:11": ["ஆபிரகாம் தன் அச்சத்தை விளக்குதல்", "சாராளின் நிமித்தம் மக்கள் தம்மைக் கொன்றுவிடுவார்கள் என்று பயந்ததாக ஆபிரகாம் சொன்னான்."],
    "Genesis 20:14": ["பரிசுகளுடன் சாராளைத் திரும்பக் கொடுத்தல்", "அபிமெலேக்கு ஆபிரகாமுக்கு ஆடுமாடுகளையும் வேலைக்காரர்களையும் கொடுத்துச் சாராளைத் திரும்ப அனுப்பிவைத்தார்."],
    "Genesis 20:17": ["அபிமெலேக்குக்காக ஆபிரகாம் ஜெபித்தல்", "ஆபிரகாம் தேவனிடம் வேண்டிக்கொண்டான்; தேவன் அபிமெலேக்கையும் அவன் வீட்டாரையும் குணமாக்கினார்."],
    "Genesis 20:18": ["அபிமெலேக்கின் குடும்பம் சீர்படுதல்", "சாராயின் நிமித்தம் அடைக்கப்பட்டிருந்த அபிமெலேக்கின் வீட்டார் அனைவரையும் கர்த்தர் சுகப்படுத்தினார்."],

    "Genesis 21:1": ["ஈசாக்கின் பிறப்பு", "கர்த்தர் தாம் சொல்லியிருந்தபடியே சாராளைச் சந்தித்தார்; ஆபிரகாம் முதிர்வயதாயிருக்கையில் சாராள் ஒரு குமாரனைப் பெற்றாள்."],
    "Genesis 21:3": ["ஈசாக்குக்குப் பெயரிடுதல்", "ஆபிரகாம் தனக்குப் பிறந்த குமாரனுக்கு ஈசாக்கு என்று பெயரிட்டு, எட்டாம் நாளில் அவனுக்கு விருத்தசேதனம் பண்ணினான்."],
    "Genesis 21:8": ["ஈசாக்கு பால் மறத்தல்", "பிள்ளை வளர்ந்து பால் மறந்தது; ஈசாக்கு பால் மறந்த நாளில் ஆபிரகாம் பெரிய விருந்து செய்தான்."],
    "Genesis 21:9": ["சாராய்க்கும் ஆகாருக்கும் இடையே மனஸ்தாபம்", "எகிப்து தேசத்து ஆகாரின் குமாரனான இஸ்மவேல் ஈசாக்கைப் பரியாசம் பண்ணுகிறதைச் சாராள் கண்டாள்."],
    "Genesis 21:10": ["ஆகாரும் இஸ்மவேலும் அனுப்பப்படுதல்", "இந்த அடிமைப்பெண்ணின் மகன் என் குமாரனாகிய ஈசாக்கோடே சுதந்தரவாளியாயிருக்கக் கூடாது, இவர்களை அனுப்பிவிடும் என்று ஆபிரகாமிடம் சாராள் சொன்னாள்."],
    "Genesis 21:12": ["ஆபிரகாமுக்குத் தேவன் ஊக்கமளித்தல்", "சாராள் சொல்வதைக் கேள், ஈசாக்கினிடத்திலே உன் சந்ததி விளங்கும் என்று தேவன் ஆபிரகாமுக்குச் சொன்னார்."],
    "Genesis 21:14": ["வனாந்தரத்தில் ஆகார்", "ஆபிரகாம் ஆகாருக்கு உணவும் தண்ணீரும் கொடுத்து அனுப்பிவிட்டான்; அவள் பெயெர்செபா வனாந்தரத்திலே அலைந்து திரிந்தாள்."],
    "Genesis 21:17": ["இஸ்மவேலின் சத்தத்தை தேவன் கேட்டல்", "பிள்ளையின் சத்தத்தை தேவன் கேட்டார்; ஆகாரே பயப்படாதே, அவன் ஒரு பெரிய ஜாதியாவான் என்று தேவதூதன் சொன்னார்."],
    "Genesis 21:19": ["வனாந்தரத்தில் தண்ணீர் கிடைத்தல்", "தேவன் ஆகாரின் கண்களைத் திறந்தபோது, அவள் ஒரு நீரூற்றைக் கண்டு, துருத்தியில் தண்ணீர் நிரப்பிப் பிள்ளைக்குக் கொடுத்தாள்."],
    "Genesis 21:22": ["ஆபிரகாமும் அபிமெலேக்கும் உடன்படிக்கை செய்தல்", "தேவன் உன்னுடனே இருக்கிறார் என்பது தெரிகிறது, அதனால் நமக்குள் ஒரு சமாதான உடன்படிக்கை செய்துகொள்வோம் என்று அபிமெலேக்கு வந்தான்."],
    "Genesis 21:27": ["பெயெர்செபாவில் உடன்படிக்கை", "ஆபிரகாம் ஆடுமாடுகளை அபிமெலேக்குக்குக் கொடுத்து, இருவரும் ஒரு உடன்படிக்கை செய்துகொண்டார்கள்."],
    "Genesis 21:31": ["பெயெர்செபா என்னும் பெயர்", "அவர்கள் இருவரும் அங்கே ஆணையிட்டுக் கொண்டபடியால், அந்த இடத்திற்குப் பெயெர்செபா என்று பெயரிடப்பட்டது."],
    "Genesis 21:33": ["ஆபிரகாம் கர்த்தரைத் தொழுதுகொள்ளுதல்", "ஆபிரகாம் பெயெர்செபாவில் ஒரு தோப்பை உண்டாக்கி, அங்கே நித்திய தேவனாகிய கர்த்தருடைய நாமத்தைத் தொழுதுகொண்டான்."],

    "Genesis 22:1": ["ஆபிரகாமை தேவன் சோதித்தல்", "தேவன் ஆபிரகாமைச் சோதித்து: உன் ஏகசுதனாகிய ஈசாக்கைப் பலியாகச் செலுத்து என்றார்."],
    "Genesis 22:3": ["கட்டளைக்கு ஆபிரகாம் கீழ்ப்படிதல்", "ஆபிரகாம் அதிகாலையில் எழுந்து, ஈசாக்கை அழைத்துக்கொண்டு தேவன் காண்பித்த இடத்திற்குப் புறப்பட்டுப்போனான்."],
    "Genesis 22:6": ["பலி செலுத்தும் இடத்திற்குப் பயணம்", "ஈசாக்கு பலிக்குரிய விறகுகளைச் சுமந்து வந்தான்; ஆபிரகாம் நெருப்பையும் கத்தியையும் எடுத்துக்கொண்டு போனான்."],
    "Genesis 22:7": ["ஈசாக்கின் கேள்வி", "நெருப்பும் விறகும் இருக்கிறது, பலிக்கு ஆட்டுக்குட்டி எங்கே என்று ஈசாக்கு கேட்டான்; தேவன் பார்த்துக்கொள்வார் என்று ஆபிரகாம் பதிலளித்தான்."],
    "Genesis 22:9": ["பலிபீடத்தில் ஈசாக்கு கட்டப்படுதல்", "ஆபிரகாம் ஒரு பலிபீடத்தைக் கட்டி, விறகுகளை அடுக்கி, தன் குமாரனாகிய ஈசாக்கைக் கட்டி விறகுகளின் மேல் வைத்தான்."],
    "Genesis 22:11": ["தூதன் ஆபிரகாமைத் தடுத்தல்", "பிள்ளைமேல் உன் கையைப் போடாதே என்று கர்த்தருடைய தூதன் வானத்திலிருந்து கூப்பிட்டு ஆபிரகாமைத் தடுத்தார்."],
    "Genesis 22:13": ["ஆட்டுக்கடா வழங்கப்படுதல்", "ஆபிரகாம் பின்னிட்டுப் பார்த்தபோது, ஒரு புதரிலே கொம்பு சிக்கிக்கொண்டிருந்த ஆட்டுக்கடாவைக் கண்டு, அதை ஈசாக்குக்குப் பதிலாகப் பலியிட்டான்."],
    "Genesis 22:14": ["யெகோவாயீரே", "ஆபிரகாம் அந்த இடத்திற்கு 'யெகோவாயீரே' (கர்த்தர் பார்த்துக்கொள்வார்) என்று பெயரிட்டான்."],
    "Genesis 22:15": ["வாக்குத்தத்தத்தை தேவன் உறுதிப்படுத்துதல்", "நீ உன் குமாரனென்றும் பாராமல் இந்தக் காரியத்தைச் செய்தபடியால், உன்னை ஆசீர்வதித்து உன் சந்ததியைப் பெருகப்பண்ணுவேன் என்று கர்த்தர் சொன்னார்."],
    "Genesis 22:18": ["சகல ஜாதிகளுக்கும் ஆசீர்வாதம்", "நீ என் சொல்லுக்குக் கீழ்ப்படிந்ததினால், உன் சந்ததிக்குள் பூமியிலுள்ள சகல ஜாதிகளும் ஆசீர்வதிக்கப்படும் என்றார்."],
    "Genesis 22:19": ["பெயெர்செபாவுக்குத் திரும்புதல்", "ஆபிரகாம் தன் ஊழியக்காரரிடத்திற்குத் திரும்பி வந்து, பெயெர்செபாவில் குடியிருந்தான்."],
    "Genesis 22:20": ["நாகோரின் குடும்பம்", "ஆபிரகாமுடைய சகோதரனாகிய நாகோரின் சந்ததியைக் குறித்த செய்திகள் அவனுக்கு எட்டியது."],

    "Genesis 23:1": ["சாராளின் மரணம்", "சாராள் நூற்றிருபத்தேழு வருஷம் உயிர்வாழ்ந்து கானான் தேசத்திலே மரித்தாள்."],
    "Genesis 23:2": ["சாராளுக்காக ஆபிரகாம் துக்கங்கொண்டாடுதல்", "தன் மனைவியாகிய சாராளுக்காக ஆபிரகாம் துக்கங்கொண்டாடி அழுதான்."],
    "Genesis 23:3": ["அடக்கம் செய்ய இடம் கேட்டல்", "ஆபிரகாம் ஏத்தியரிடத்தில் போய், தன் மனைவியை அடக்கம் செய்ய ஒரு நிலத்தைச் சுதந்தரமாகத் தரும்படி கேட்டான்."],
    "Genesis 23:6": ["ஏத்தியரின் மரியாதை", "நீர் எங்களுக்குள்ளே ஒரு பிரபுவாய் இருக்கிறீர், எங்கள் கல்லறைகளில் உமக்கு இஷ்டமான இடத்தில் அடக்கம் செய்யும் என்று ஏத்தியர் சொன்னார்கள்."],
    "Genesis 23:8": ["மக்பேலா குகையைக் கேட்டல்", "எப்பெரோனுக்குச் சொந்தமான மக்பேலா குகையைத் தமக்குக் கிரயத்திற்குக் கொடுக்கும்படி ஆபிரகாம் வேண்டினான்."],
    "Genesis 23:11": ["எப்பெரோன் நிலத்தைத் தருதல்", "எப்பெரோன் அந்த நிலத்தையும் குகையையும் ஆபிரகாமுக்குக் கொடுப்பதாக மக்கள் முன்னிலையில் சொன்னான்."],
    "Genesis 23:13": ["விலை கொடுக்க ஆபிரகாம் உறுதி பூணுதல்", "இலவசமாக வேண்டாம், நான் அந்த நிலத்தின் விலையைக் கொடுக்கிறேன் என்று ஆபிரகாம் சொன்னான்."],
    "Genesis 23:15": ["நிலத்தின் விலை", "அந்த நிலத்தின் விலை நானூறு சேக்கல் வெள்ளி என்று எப்பெரோன் சொன்னான்."],
    "Genesis 23:16": ["ஆபிரகாம் விலை கொடுத்தல்", "ஆபிரகாம் அந்த வெள்ளியை நிறுத்துக் கொடுத்து நிலத்தைக் கிரயத்திற்கு வாங்கினான்."],
    "Genesis 23:19": ["மக்பேலாவில் சாராள் அடக்கம் செய்யப்படுதல்", "ஆபிரகாம் எப்ரோனுக்கு அருகிலுள்ள மக்பேலா குகையில் தன் மனைவி சாராளை அடக்கம் செய்தான்."],
    "Genesis 23:20": ["நிலம் சட்டப்பூர்வமாக உறுதி செய்யப்படுதல்", "அந்த நிலமும் குகையும் ஆபிரகாமுக்குச் சொந்தமான கல்லறைப் பூமியாக உறுதிப்படுத்தப்பட்டது."],

    "Genesis 24:1": ["ஈசாக்குக்குப் பெண் தேடுதல்", "ஆபிரகாம் முதிர்ந்த வயதுள்ளவனானபோது, தன் ஊழியக்காரனை அழைத்து ஈசாக்குக்கு ஒரு மனைவியைத் தேடும்படி கட்டளையிட்டான்."],
    "Genesis 24:3": ["கானானியப் பெண்ணைத் தெரிந்து கொள்ளாதே", "கானானியப் பெண்களில் ஒருத்தியைத் தெரிந்து கொள்ளாமல், என் சொந்த தேசத்திற்கும் உறவினரிடத்திற்கும் போய் பெண் தேடு என்று சொன்னான்."],
    "Genesis 24:10": ["மெசொப்பொத்தாமியாவுக்குப் பயணம்", "ஊழியக்காரன் பத்து ஒட்டகங்களையும் பல பரிசுகளையும் எடுத்துக்கொண்டு நாகோரின் பட்டணத்திற்குப் போனான்."],
    "Genesis 24:12": ["வழிகாட்டுதலுக்காக ஜெபம்", "என் எஜமானாகிய ஆபிரகாமுக்குத் தயவுசெய்து, நான் வந்த காரியம் வாய்க்கும்படி செய்யும் என்று ஊழியக்காரன் வேண்டிக்கொண்டான்."],
    "Genesis 24:15": ["கிணற்றடியில் ரெபெக்காள்", "ஊழியக்காரன் ஜெபித்து முடிக்கும் முன்னே, ரெபெக்காள் தன் தோள்மேல் குடத்தை வைத்துக்கொண்டு கிணற்றடிக்கு வந்தாள்."],
    "Genesis 24:18": ["ரெபெக்காளின் தயவு", "ரெபெக்காள் அந்த ஊழியக்காரனுக்குத் தண்ணீர் கொடுத்ததுமல்லாமல், அவனுடைய ஒட்டகங்களுக்கும் தண்ணீர் இறைத்துக் கொடுத்தாள்."],
    "Genesis 24:22": ["ரெபெக்காளுக்குப் பரிசுகள்", "ஊழியக்காரன் அவளுக்குப் பொன் ஆபரணங்களைக் கொடுத்து, அவளுடைய குடும்பத்தைப் பற்றிக் கேட்டான்."],
    "Genesis 24:27": ["தேவனைப் போற்றுதல்", "தம்முடைய கிருபையை விடாமல் என்னை என் எஜமானுடைய உறவினர் வீட்டிற்கு அழைத்து வந்த கர்த்தர் ஸ்தோத்தரிக்கப்பட்டவர் என்று அவன் துதித்தான்."],
    "Genesis 24:29": ["லாபானைச் சந்தித்தல்", "ரெபெக்காளின் சகோதரனாகிய லாபான் அந்த ஊழியக்காரனைத் தங்கள் வீட்டிற்கு வரவேற்றான்."],
    "Genesis 24:34": ["நோக்கத்தை விளக்குதல்", "ஊழியக்காரன் ஆபிரகாமின் செல்வத்தையும், ஈசாக்குக்காகப் பெண் தேடி வந்த காரியத்தையும் விவரித்தான்."],
    "Genesis 24:50": ["திருமணத்திற்குச் சம்மதம்", "இந்தக் காரியம் கர்த்தரால் வந்தது, இதற்கு நாங்கள் மறுப்புச் சொல்ல முடியாது என்று லாபானும் பெத்துவேலும் சொன்னார்கள்."],
    "Genesis 24:58": ["புறப்பட ரெபெக்காள் சம்மதித்தல்", "நான் இந்தப் புருஷனோடே போகிறேன் என்று ரெபெக்காள் சொன்னாள்; அவர்கள் அவளை அனுப்பிவைத்தார்கள்."],
    "Genesis 24:63": ["ஈசாக்கு ரெபெக்காளைச் சந்தித்தல்", "சாயங்கால வேளையில் ஈசாக்கு தியானம் பண்ண வெளிக்குச் சென்றபோது, ஒட்டகங்கள் வருவதைக் கண்டான்."],
    "Genesis 24:67": ["ஈசாக்கு ரெபெக்காளை மணத்தல்", "ஈசாக்கு ரெபெக்காளைத் தன் தாயின் கூடாரத்திற்கு அழைத்துச் சென்று அவளைத் திருமணம் செய்துகொண்டான்; தன் தாயின் மரணத்திற்குப் பின் அவன் ஆறுதலடைந்தான்."],

    "Genesis 25:1": ["ஆபிரகாம் கேத்தூராளை மணத்தல்", "சாராள் மரித்தபின் ஆபிரகாம் கேத்தூராள் என்னும் பெண்ணை மணந்து, இன்னும் பல குமாரரைப் பெற்றான்."],
    "Genesis 25:5": ["ஈசாக்கு சுதந்தரத்தைப் பெறுதல்", "ஆபிரகாம் தனக்கு உண்டான யாவற்றையும் ஈசாக்குக்குக் கொடுத்தான்."],
    "Genesis 25:7": ["ஆபிரகாமின் மரணம்", "ஆபிரகாம் நூற்றெழுபத்தைந்து வருஷம் உயிர்வாழ்ந்து, நரைத்த முதிர்வயதில் மரித்தான்."],
    "Genesis 25:9": ["ஈசாக்கும் இஸ்மவேலும் அடக்கம் செய்தல்", "ஈசாக்கும் இஸ்மவேலும் ஆபிரகாமை மக்பேலா குகையிலே அடக்கம் செய்தார்கள்."],
    "Genesis 25:12": ["இஸ்மவேலின் சந்ததி", "இஸ்மவேலின் வம்ச வரலாறும், அவன் மூலமாகத் தோன்றிய பன்னிரண்டு பிரபுக்களின் பெயர்களும் பதிவு செய்யப்பட்டன."],
    "Genesis 25:19": ["ஈசாக்கின் குடும்ப வரலாறு", "வாக்குத்தத்தம் பண்ணப்பட்ட வம்சமாக ஈசாக்கின் சந்ததி பற்றிய வரலாறு தொடங்குகிறது."],
    "Genesis 25:21": ["ரெபெக்காளுக்காக ஈசாக்கு ஜெபித்தல்", "ரெபெக்காள் மலடியாயிருந்தபடியால் ஈசாக்கு கர்த்தரை நோக்கி வேண்டிக்கொண்டான்; கர்த்தர் அவன் வேண்டுதலைக் கேட்டு அவளைக் கர்ப்பவதியாக்கினார்."],
    "Genesis 25:22": ["கர்ப்பத்தில் போராட்டம்", "பிள்ளைகள் அவளுடைய கர்ப்பத்திலே ஒன்றோடொன்று முட்டிக்கொண்டிருந்தன; இதைக் குறித்து அவள் கர்த்தரிடம் கேட்டாள்."],
    "Genesis 25:23": ["இரண்டு ஜாதிகளைப் பற்றிய தீர்க்கதரிசனம்", "உன் கர்ப்பத்தில் இரண்டு ஜாதிகள் உண்டு, மூத்தவன் இளையவனுக்கு ஊழியம் செய்வான் என்று தேவன் சொன்னார்."],
    "Genesis 25:24": ["ஏசா மற்றும் யாக்கோபின் பிறப்பு", "ரெபெக்காள் இரட்டைப் பிள்ளைகளைப் பெற்றாள்; முதல் பிள்ளைக்கு ஏசா என்றும், அடுத்தவனுக்கு யாக்கோபு என்றும் பெயரிட்டார்கள்."],
    "Genesis 25:27": ["சகோதரர்களின் மாறுபட்ட வாழ்க்கை", "ஏசா வேட்டையாடுகிறவனாகவும், யாக்கோபு கூடாரங்களில் வாசமாயிருக்கிற அமைதியுள்ளவனுமாயிருந்தான்."],
    "Genesis 25:29": ["ஏசா தன் சேஷ்ட புத்திரபாகத்தை விற்றல்", "பசியாயிருந்த ஏசா, ஒரு கோப்பை கூழுக்காகத் தன் சேஷ்ட புத்திரபாகத்தை (தலைப்பிள்ளை உரிமை) யாக்கோபுக்கு விற்றுப்போட்டான்."],
    "Genesis 25:34": ["ஏசா உரிமையை அலட்சியம் செய்தல்", "ஏசா புசித்துக் குடித்து எழுந்துபோனான்; இவ்வாறு அவன் தன் சேஷ்ட புத்திரபாகத்தை அசட்டை பண்ணினான்."],

    "Genesis 26:1": ["ஈசாக்கு கேராரூக்குப் போதல்", "தேசத்தில் பஞ்சம் உண்டானதினால், ஈசாக்கு அபிமெலேக்கு ராஜாவாயிருந்த கேரார் பட்டணத்திற்குப் போனான்."],
    "Genesis 26:2": ["வாக்குத்தத்தத்தை ஈசாக்குக்கு உறுதிப்படுத்துதல்", "கர்த்தர் ஈசாக்குக்குத் தரிசனமாகி: 'நீ எகிப்துக்குப் போகாமல், நான் உனக்குச் சொல்லும் தேசத்திலே குடியிரு' என்றார்."],
    "Genesis 26:6": ["ஈசாக்கு கேராரில் தங்குதல்", "கர்த்தர் சொன்னபடியே ஈசாக்கு கேராரில் தங்கியிருந்தான்."],
    "Genesis 26:7": ["ரெபெக்காளைச் சகோதரி எனல்", "அந்த இடத்து மனிதர்களுக்குப் பயந்து, ரெபெக்காளைத் தன் சகோதரி என்று ஈசாக்கு சொன்னான்."],
    "Genesis 26:8": ["அபிமெலேக்கு உண்மையை அறிதல்", "ஈசாக்கு ரெபெக்காளோடு விளையாடிக்கொண்டிருந்ததை அபிமெலேக்கு ஜன்னல் வழியாகக் கண்டு, அவள் அவனுடைய மனைவி என்று அறிந்துகொண்டான்."],
    "Genesis 26:12": ["ஈசாக்கு ஐசுவரியவானாதல்", "ஈசாக்கு அந்தத் தேசத்தில் பயிரிட்டு, கர்த்தர் அவனை ஆசீர்வதித்ததினால் நூறு மடங்கு பலன் அடைந்தான்."],
    "Genesis 26:15": ["பெலிஸ்தர் கிணறுகளை அடைத்தல்", "ஆபிரகாமின் ஊழியக்காரர் வெட்டியிருந்த கிணறுகளைப் பெலிஸ்தர் மண்ணைப் போட்டு அடைத்துப்போட்டார்கள்."],
    "Genesis 26:17": ["ஈசாக்கு பள்ளத்தாக்குக்குச் செல்லுதல்", "ஈசாக்கு அங்கிருந்து புறப்பட்டு, கேரார் பள்ளத்தாக்கிலே கூடாரம் போட்டு அங்கே தங்கியிருந்தான்."],
    "Genesis 26:19": ["கிணறுகளைக் குறித்த வாக்குவாதம்", "ஈசாக்கின் ஊழியக்காரர் கிணறுகளை வெட்டினார்கள்; ஆனால் கேரார் நாட்டு மேய்ப்பர்கள் அவைகளுக்காக வாக்குவாதம் பண்ணினார்கள்."],
    "Genesis 26:22": ["இடம் அகலமாதல்", "ஈசாக்கு வேறொரு கிணற்றை வெட்டினான்; அதற்காக அவர்கள் வாக்குவாதம் பண்ணவில்லை; அதனால் அதற்கு 'ரெகொபோத்' (இடம் அகலமானது) என்று பெயரிட்டான்."],
    "Genesis 26:23": ["பெயெர்செபாவில் தேவன் தரிசனமாதல்", "கர்த்தர் அவனுக்குத் தரிசனமாகி, ஆபிரகாமுக்குக் கொடுத்த வாக்குத்தத்தத்தை உறுதிப்படுத்தினார்."],
    "Genesis 26:25": ["ஈசாக்கு பலிபீடம் கட்டுதல்", "ஈசாக்கு அங்கே ஒரு பலிபீடத்தைக் கட்டி, கர்த்தருடைய நாமத்தைத் தொழுதுகொண்டு குடியிருந்தான்."],
    "Genesis 26:26": ["அபிமெலேக்குடன் உடன்படிக்கை", "அபிமெலேக்கு ஈசாக்கிடம் வந்து ஒரு சமாதான உடன்படிக்கை செய்துகொள்ள விரும்பினான்."],
    "Genesis 26:31": ["சமாதான உடன்படிக்கை", "அவர்கள் ஒருவருக்கொருவர் ஆணையிட்டுக்கொண்டு, சமாதானத்துடன் பிரிந்து போனார்கள்."],
    "Genesis 26:34": ["ஏசாவின் ஏத்திய மனைவிகள்", "ஏசா ஏத்தியப் பெண்களை மணந்தான்; இது ஈசாக்குக்கும் ரெபெக்காளுக்கும் மனநோவாயிருந்தது."],

    "Genesis 27:1": ["ஏசாவை ஆசீர்வதிக்க ஈசாக்கு எண்ணுதல்", "ஈசாக்கு முதிர்வயதாகித் தன் பார்வை மங்கியபோது, ஏசாவை அழைத்துத் தனக்கு ஒரு போஜனம் ஆயத்தம் செய்யச் சொன்னான்."],
    "Genesis 27:5": ["ரெபெக்காளின் திட்டம்", "ரெபெக்காள் ஈசாக்கின் திட்டத்தைக் கேட்டு, அந்த ஆசீர்வாதத்தை யாக்கோபு பெறும்படி அவனுக்கு ஒரு யோசனை சொன்னாள்."],
    "Genesis 27:11": ["யாக்கோபின் கவலை", "தன் தகப்பன் தன்னைத் தெரிந்துகொண்டால் ஆசீர்வாதத்திற்குப் பதிலாகச் சாபம் வருமோ என்று யாக்கோபு அஞ்சினான்."],
    "Genesis 27:15": ["ஏசாவைப் போல வேடமிடுதல்", "ரெபெக்காள் ஏசாவின் வஸ்திரங்களை யாக்கோபுக்கு உடுத்தி, அவன் கைகளிலும் கழுத்திலும் வெள்ளாட்டுக்குட்டியின் தோலை மூடினாள்."],
    "Genesis 27:18": ["யாக்கோபு ஈசாக்கை ஏமாற்றுதல்", "யாக்கோபு தான் ஏசா என்று பொய் சொல்லி, தன் தகப்பனிடம் போஜனத்தைக் கொண்டுபோனான்."],
    "Genesis 27:22": ["ஈசாக்கின் சந்தேகம்", "சத்தம் யாக்கோபின் சத்தம் போலவும், கைகள் ஏசாவின் கைகள் போலவும் இருக்கிறதே என்று ஈசாக்கு சொன்னான்."],
    "Genesis 27:27": ["யாக்கோபுக்குக் கிடைத்த ஆசீர்வாதம்", "ஈசாக்கு யாக்கோபை ஆசீர்வதித்து, அவன் சகோதரருக்கு எஜமானாகவும், தேசத்தில் செழிப்புள்ளவனாகவும் இருக்கும்படி சொன்னான்."],
    "Genesis 27:30": ["ஏசா தாமதமாக வருதல்", "ஏசா வேட்டையாடித் திரும்பியபோது, ஈசாக்கு ஏற்கனவே யாக்கோபை ஆசீர்வதித்ததை உணர்ந்தான்."],
    "Genesis 27:34": ["ஏசா அலறி அழுதல்", "ஏசா மிகுந்த கசப்போடு கதறி அழுது, 'தகப்பனே, என்னையும் ஆசீர்வதியும்' என்று கேட்டான்."],
    "Genesis 27:39": ["ஏசாவுக்குக் கிடைத்த குறைந்த ஆசீர்வாதம்", "ஈசாக்கு ஏசாவுக்கு ஒரு குறைந்த ஆசீர்வாதத்தைக் கொடுத்து, அவன் தன் சகோதரனுக்குப் பின்னால் இருப்பான் என்று சொன்னான்."],
    "Genesis 27:41": ["ஏசாவின் பழிவாங்கும் எண்ணம்", "ஏசா தன் தகப்பன் மரித்தபின் யாக்கோபைக் கொல்ல வேண்டும் என்று தன் இருதயத்தில் எண்ணினான்."],
    "Genesis 27:42": ["யாக்கோபு அனுப்பிவைக்கப்படுதல்", "ரெபெக்காள் இதையறிந்து, யாக்கோபை அவன் மாமனாகிய லாபானிடத்திற்கு ஓடிப்போகச் சொன்னாள்."],
    "Genesis 27:46": ["திருமணம் குறித்த ரெபெக்காளின் கவலை", "யாக்கோபு ஏத்தியப் பெண்களை மணக்கக் கூடாது என்று ரெபெக்காள் ஈசாக்கிடம் சொன்னாள்."],

    "Genesis 28:1": ["ஈசாக்கு யாக்கோபை மீண்டும் ஆசீர்வதித்தல்", "ஈசாக்கு யாக்கோபை அழைத்து, கானானியப் பெண்களை மணக்கக் கூடாது என்று கட்டளையிட்டு அவனை ஆசீர்வதித்தார்."],
    "Genesis 28:3": ["ஆபிரகாமின் ஆசீர்வாதம் வழங்கப்படுதல்", "சர்வவல்லமையுள்ள தேவன் உன்னை ஆசீர்வதித்து, ஆபிரகாமுக்குக் கொடுத்த ஆசீர்வாதத்தை உனக்கும் உன் சந்ததிக்கும் தருவாராக என்று ஈசாக்கு ஜெபித்தார்."],
    "Genesis 28:5": ["யாக்கோபு பதான் அராமிற்குச் செல்லுதல்", "யாக்கோபு தன் மாமனாகிய லாபானின் வீட்டிற்குப் பெண் தேடும்படி புறப்பட்டுப் போனான்."],
    "Genesis 28:6": ["ஏசா கவனித்தல்", "கானானியப் பெண்கள் தன் தகப்பனுக்கு இஷ்டமானவர்கள் அல்ல என்பதை ஏசா கண்டான்."],
    "Genesis 28:9": ["இஸ்மவேலின் மகளை ஏசா மணத்தல்", "ஏசா இஸ்மவேலின் குமாரத்தியைத் தனக்கு மனைவியாகக் கொண்டான்."],
    "Genesis 28:10": ["யாக்கோபின் பிரயாணம்", "யாக்கோபு பெயெர்செபாவை விட்டுப் புறப்பட்டு ஆரானுக்குப் போனான்."],
    "Genesis 28:11": ["பெத்தேலில் யாக்கோபின் சொப்பனம்", "யாக்கோபு ஒரு இடத்தில் நித்திரை செய்கையில், பூமியில் ஊன்றப்பட்ட வானத்தை எட்டுகிற ஒரு ஏணியையும், அதில் தேவதூதர்கள் ஏறுவதும் இறங்குவதுமாக இருப்பதையும் கண்டான்."],
    "Genesis 28:13": ["உடன்படிக்கையை உறுதிப்படுத்துதல்", "ஏணியின் மேல் கர்த்தர் நின்று, அந்தத் தேசத்தை யாக்கோபுக்கும் அவன் சந்ததிக்கும் தருவதாக வாக்குக் கொடுத்தார்."],
    "Genesis 28:16": ["யாக்கோபு அச்சத்தோடு விழித்தல்", "நிச்சயமாகவே கர்த்தர் இவ்விடத்தில் இருக்கிறார், இது தேவனுடைய வீடு என்று யாக்கோபு சொல்லி பயந்தான்."],
    "Genesis 28:18": ["பெத்தேலில் நினவுத்தூண்", "யாக்கோபு தான் தலைக்கு வைத்திருந்த கல்லை எடுத்து அதை ஒரு தூணாக நிறுத்தி, அதன்மேல் எண்ணெய் ஊற்றினான்."],
    "Genesis 28:20": ["தேவனுக்கு யாக்கோபு செய்த பொருத்தனை", "தேவன் என்னைப் பாதுகாத்து எனக்கு உணவும் உடையும் தந்தால், கர்த்தர் எனக்குத் தெய்வமாயிருப்பார் என்று பொருத்தனை செய்தான்."],
    "Genesis 28:22": ["பத்திலொரு பாகம் தருவதாக உறுதி", "தேவன் தனக்குத் தரும் எல்லாவற்றிலும் பத்திலொரு பங்கை அவருக்குக் கொடுப்பேன் என்று யாக்கோபு சொன்னான்."],

    "Genesis 29:1": ["யாக்கோபு கிழக்குத் தேசத்திற்கு வருதல்", "யாக்கோபு தன் பிரயாணத்தைத் தொடர்ந்து, கிழக்குத் தேசத்தாருடைய பூமியிலே வந்து சேர்ந்தான்."],
    "Genesis 29:4": ["மேய்ப்பர்களைச் சந்தித்தல்", "யாக்கோபு ஒரு கிணற்றடியில் இருந்த மேய்ப்பர்களிடம் லாபானைக் குறித்து விசாரித்தான்."],
    "Genesis 29:9": ["ராகேலைச் சந்தித்தல்", "ராகேல் தன் தகப்பனுடைய ஆடுகளை ஓட்டிக்கொண்டு வந்தாள்; யாக்கோபு கிணற்றின் கல்லை உருட்டி ஆடுகளுக்குத் தண்ணீர் காட்டினான்."],
    "Genesis 29:11": ["ராகேலை வாழ்த்துதல்", "யாக்கோபு ராகேலை முத்தமிட்டு, சத்தமிட்டு அழுது, தான் அவளுடைய உறவினன் என்று சொன்னான்."],
    "Genesis 29:13": ["லாபான் யாக்கோபை வரவேற்றல்", "லாபான் யாக்கோபின் செய்தியைக் கேட்டு ஓடிவந்து, அவனைக் கட்டித்தழுவித் தன் வீட்டுக்கு அழைத்துச் சென்றான்."],
    "Genesis 29:15": ["லாபானுக்கு ஊழியஞ் செய்யச் சம்மதித்தல்", "ராகேலை மணக்கும் பொருட்டு லாபானுக்கு ஏழு வருஷம் ஊழியஞ் செய்ய யாக்கோபு சம்மதித்தான்."],
    "Genesis 29:20": ["ஏழு வருஷ ஊழியம்", "யாக்கோபு ராகேலுக்காக ஏழு வருஷம் வேலை செய்தான்; அவன் அவள்மேல் வைத்த அன்பினால் அந்த நாட்கள் அவனுக்குக் கொஞ்ச காலமாய்த் தோன்றின."],
    "Genesis 29:23": ["ராகேலுக்குப் பதில் லேயாள்", "லாபான் யாக்கோபை ஏமாற்றி, ராகேலுக்குப் பதிலாக லேயாளை அவனுக்கு மனைவியாகக் கொடுத்தார்."],
    "Genesis 29:25": ["யாக்கோபு லாபானைக் கேட்டல்", "விடிந்தபின் அது லேயாள் என்று கண்ட யாக்கோபு, ஏன் என்னை ஏமாற்றினீர் என்று லாபானிடம் கேட்டான்."],
    "Genesis 29:27": ["ராகேலையும் மணத்தல்", "அந்த வாரம் முடிந்தபின், லாபான் ராகேலையும் யாக்கோபுக்கு மனைவியாகக் கொடுத்தார்; அதற்காக யாக்கோபு இன்னும் ஏழு வருஷம் வேலை செய்ய ஒப்புக்கொண்டான்."],
    "Genesis 29:31": ["லேயாளைத் தேவன் நினைத்தல்", "லேயாள் அற்பமாய் எண்ணப்பட்டதைக் கண்டு கர்த்தர் அவளுக்குப் பிள்ளைப் பேற்றைக் கொடுத்தார்."],
    "Genesis 29:32": ["ரூபனின் பிறப்பு", "லேயாள் ஒரு குமாரனைப் பெற்று, கர்த்தர் என் சிறுமையைப் பார்த்தார் என்று சொல்லி அவனுக்கு 'ரூபன்' என்று பெயரிட்டாள்."],
    "Genesis 29:33": ["சிமியோனின் பிறப்பு", "லேயாள் மீண்டும் ஒரு குமாரனைப் பெற்று அவனுக்கு 'சிமியோன்' என்று பெயரிட்டாள்."],
    "Genesis 29:34": ["லேவியின் பிறப்பு", "இப்போது என் புருஷன் என்னோடு இணைந்திருப்பார் என்று சொல்லி தன் மூன்றாவது மகனுக்கு 'லேவி' என்று பெயரிட்டாள்."],
    "Genesis 29:35": ["யூதாவின் பிறப்பு", "லேயாள் நான்காவது மகனைப் பெற்று, 'இப்போது கர்த்தரைத் துதிப்பேன்' என்று சொல்லி அவனுக்கு 'யூதா' என்று பெயரிட்டாள்."],

    "Genesis 30:1": ["ராகேலின் பொறாமை", "தனக்குப் பிள்ளைகள் இல்லாததைக் கண்டு ராகேல் தன் சகோதரி லேயாள் மேல் பொறாமைப்பட்டாள்."],
    "Genesis 30:3": ["பில்காள் யாக்கோபுக்குக் கொடுக்கப்படுதல்", "ராகேல் தன் வேலைக்காரியாகிய பில்காளை யாக்கோபுக்குக் கொடுத்தாள்; அவள் மூலம் பிள்ளை பெற்றுக்கொள்ள எண்ணினாள்."],
    "Genesis 30:5": ["தாணின் பிறப்பு", "பில்காள் ஒரு குமாரனைப் பெற்றாள்; தேவன் என் வழக்கைத் தீர்த்தார் என்று சொல்லி ராகேல் அவனுக்கு 'தாண்' என்று பெயரிட்டாள்."],
    "Genesis 30:7": ["நப்தாலியின் பிறப்பு", "பில்காள் பெற்ற இரண்டாவது மகனுக்கு ராகேல் 'நப்தாலி' என்று பெயரிட்டாள்."],
    "Genesis 30:9": ["சில்பாள் யாக்கோபுக்குக் கொடுக்கப்படுதல்", "லேயாள் தனக்குப் பிள்ளைப்பேறு நின்றதைக் கண்டு, தன் வேலைக்காரி சில்பாளை யாக்கோபுக்குக் கொடுத்தாள்."],
    "Genesis 30:10": ["காத்தின் பிறப்பு", "சில்பாள் பெற்ற மகனுக்கு லேயாள் 'காத்' என்று பெயரிட்டாள்."],
    "Genesis 30:12": ["ஆசேரின் பிறப்பு", "சில்பாள் பெற்ற இரண்டாவது மகனுக்கு லேயாள் 'ஆசேர்' என்று பெயரிட்டாள்."],
    "Genesis 30:14": ["தூதாயீம் பழங்கள்", "ரூபன் வயலில் கண்டெடுத்த தூதாயீம் பழங்களைக் குறித்து லேயாளுக்கும் ராகேலுக்கும் இடையே பேச்சுவார்த்தை நடந்தது."],
    "Genesis 30:17": ["இசக்காரின் பிறப்பு", "தேவன் லேயாளுக்கு ஐந்தாவது மகனைத் தந்தார்; அவளுக்கு 'இசக்கார்' என்று பெயரிடப்பட்டது."],
    "Genesis 30:19": ["செபுலோனின் பிறப்பு", "லேயாள் ஆறாவது மகனைப் பெற்று அவனுக்கு 'செபுலோன்' என்று பெயரிட்டாள்."],
    "Genesis 30:21": ["தினாள் பிறப்பு", "அதன்பின் லேயாள் 'தினா' என்னும் ஒரு குமாரத்தியைப் பெற்றாள்."],
    "Genesis 30:22": ["ராகேலை தேவன் நினைத்தருளுதல்", "தேவன் ராகேலை நினைத்தருளி, அவள் கர்ப்பந்தரிக்கச் செய்தார்."],
    "Genesis 30:23": ["யோசேப்பின் பிறப்பு", "ராகேல் ஒரு குமாரனைப் பெற்று, கர்த்தர் இன்னும் ஒரு மகனைத் தருவார் என்று சொல்லி அவனுக்கு 'யோசேப்பு' என்று பெயரிட்டாள்."],
    "Genesis 30:25": ["தன் ஊருக்குத் திரும்ப யாக்கோபு விரும்புதல்", "யோசேப்பு பிறந்தபின், யாக்கோபு லாபானிடம் விடைபெற்றுத் தன் சொந்தத் தேசத்திற்குப் போக விரும்பினான்."],
    "Genesis 30:27": ["லாபான் தடுத்து நிறுத்துதல்", "உன் நிமித்தம் கர்த்தர் என்னை ஆசீர்வதித்தார் என்பதை அறிந்திருக்கிறேன், அதனால் என்னோடு இரு என்று லாபான் கேட்டுக்கொண்டான்."],
    "Genesis 30:31": ["யாக்கோபின் சம்பளம்", "புள்ளியும் வரியும் உள்ள ஆடுகளைத் தனக்குச் சம்பளமாகக் கொடுக்க வேண்டும் என்று யாக்கோபு கேட்டான்."],
    "Genesis 30:37": ["யாக்கோபின் வித்தை", "யாக்கோபு பச்சை மரக்கொப்புகளை உரித்து ஆடுகளின் முன்னே வைத்தான்; அதன் மூலம் புள்ளியுள்ள ஆடுகள் பெருகும்படி செய்தான்."],

    "Genesis 31:1": ["லாபானின் மனமாற்றத்தை யாக்கோபு கவனித்தல்", "தன் தகப்பனுடைய சொத்துக்களையெல்லாம் யாக்கோபு எடுத்துக்கொண்டான் என்று லாபானின் குமாரர்கள் பேசிக்கொண்டதை யாக்கோபு கேட்டான்."],
    "Genesis 31:3": ["யாக்கோபைத் திரும்பிப்போக தேவன் சொல்லுதல்", "உன் பிதாக்களுடைய தேசத்திற்கும் உன் இனத்தாரிடத்திற்கும் திரும்பிப்போ; நான் உன்னுடனே இருப்பேன் என்று கர்த்தர் யாக்கோபிடம் சொன்னார்."],
    "Genesis 31:4": ["ராகேல் மற்றும் லேயாளிடம் விளக்குதல்", "யாக்கோபு ராகேலையும் லேயாளையும் வெளியிலே வரவழைத்து, லாபான் தன்னை ஏமாற்றினாலும் தேவன் தன்னை ஆசீர்வதித்ததை விளக்கினான்."],
    "Genesis 31:14": ["ராகேலும் லேயாளும் சம்மதித்தல்", "யாக்கோபு புறப்பட்டுப் போவதற்கு ராகேலும் லேயாளும் முழு ஆதரவு அளித்தார்கள்."],
    "Genesis 31:17": ["யாக்கோபு ரகசியமாகப் புறப்படுதல்", "யாக்கோபு தன் பிள்ளைகளையும் மனைவிகளையும் ஒட்டகங்கள் மேல் ஏற்றி, தன் மந்தை மற்றும் சொத்துக்களுடன் லாபானுக்குத் தெரியாமல் புறப்பட்டான்."],
    "Genesis 31:19": ["ராகேல் சிலைகளைத் திருடுதல்", "புறப்படுவதற்கு முன்பாக ராகேல் தன் தகப்பனுடைய வீட்டிலிருந்த சிலைகளை ரகசியமாகத் திருடிக்கொண்டு போனாள்."],
    "Genesis 31:22": ["லாபான் யாக்கோபைத் தொடர்தல்", "யாக்கோபு ஓடிப்போனதை லாபான் மூன்றாவது நாளில் அறிந்து, அவனைத் துரத்திக்கொண்டு போனான்."],
    "Genesis 31:24": ["லாபானைத் தேவன் எச்சரித்தல்", "தேவன் லாபானுக்குச் சொப்பனத்தில் தோன்றி: 'நீ யாக்கோபோடே நன்மையாவது தீமையாவது பேசாதபடிக்கு எச்சரிக்கையாயிரு' என்றார்."],
    "Genesis 31:26": ["லாபான் யாக்கோபைச் சந்தித்தல்", "லாபான் யாக்கோபைச் சந்தித்து, ஏன் எனக்குத் தெரியாமல் திருட்டுத்தனமாக வந்தாய் என்று கேட்டான்."],
    "Genesis 31:33": ["சிலைகளைத் தேடுதல்", "லாபான் யாக்கோபின் கூடாரங்களில் சிலைகளைத் தேடினான், ஆனால் அவைகள் கிடைக்கவில்லை."],
    "Genesis 31:36": ["யாக்கோபு தன்னை நியாயப்படுத்துதல்", "யாக்கோபு கோபமடைந்து, தான் லாபானுக்கு எவ்வளவு உண்மையாக ஊழியம் செய்தான் என்பதை விவரித்துக் கண்டித்தான்."],
    "Genesis 31:44": ["யாக்கோபுக்கும் லாபானுக்கும் உடன்படிக்கை", "யாக்கோபும் லாபானும் தங்களுக்குள் ஒரு சமாதான உடன்படிக்கை செய்துகொண்டார்கள்."],
    "Genesis 31:48": ["சாட்சியின் குவியல்", "தங்கள் உடன்படிக்கைக்கு அடையாளமாக அவர்கள் கற்களைக் குவித்து ஒரு குவியலை உண்டாக்கினார்கள்."],
    "Genesis 31:53": ["சமாதான உறுதிமொழி", "யாக்கோபும் லாபானும் தேவனுக்கு முன்பாக ஒருவருக்கொருவர் ஆணையிட்டுக்கொண்டார்கள்."],
    "Genesis 31:55": ["லாபான் திரும்புதல்", "லாபான் அதிகாலையில் எழுந்து தன் பேரப்பிள்ளைகளையும் குமாரத்திகளையும் முத்தமிட்டு ஆசீர்வதித்துத் தன் இடத்திற்குத் திரும்பினான்."],

    "Genesis 32:1": ["தேவதூதர்களை யாக்கோபு சந்தித்தல்", "யாக்கோபு தன் வழியே போகும்போது, தேவனுடைய தூதர்கள் அவனுக்கு எதிர்ப்பட்டார்கள்."],
    "Genesis 32:3": ["ஏசாவிடம் ஆட்களை அனுப்புதல்", "யாக்கோபு சேயீர் தேசத்திலுள்ள தன் சகோதரனாகிய ஏசாவிடத்திற்குத் தனக்கு முன்னதாக ஆட்களை அனுப்பினான்."],
    "Genesis 32:6": ["ஏசாவைக் கண்டு யாக்கோபு பயப்படுதல்", "ஏசா நானூறு மனிதரோடு உன்னைச் சந்திக்க வருகிறான் என்று ஆட்கள் சொன்னதைக் கேட்டு யாக்கோபு மிகவும் பயந்தான்."],
    "Genesis 32:9": ["பாதுகாப்பிற்காக யாக்கோபு ஜெபித்தல்", "என் சகோதரன் ஏசாவின் கைக்கு என்னைத் தப்புவியும் என்று யாக்கோபு தேவனிடம் மன்றாடினான்."],
    "Genesis 32:13": ["ஏசாவுக்குப் பரிசுகளை ஆயத்தம் செய்தல்", "ஏசாவின் கோபத்தைத் தணிக்கும்படி யாக்கோபு திரளான ஆடுமாடுகளைப் பரிசாகத் தயாரித்து முன்னதாக அனுப்பினான்."],
    "Genesis 32:22": ["குடும்பத்தை ஆற்றைக் கடக்கச் செய்தல்", "யாக்கோபு அன்று இரவிலே எழுந்து தன் குடும்பத்தையும் சொத்துக்களையும் யாப்போக்கு ஆற்றைக் கடக்கச் செய்தான்."],
    "Genesis 32:24": ["ஒரு புருஷனோடே யாக்கோபு போராடுதல்", "யாக்கோபு தனியே பின் தங்கினான்; அப்பொழுது ஒரு புருஷன் விடியுமளவும் அவனோடே போராடினார்."],
    "Genesis 32:26": ["ஆசீர்வாதம் கிடைக்கும் வரை விடாதிருத்தல்", "நீர் என்னை ஆசீர்வதித்தாலொழிய உம்மைப் போகவிடேன் என்று யாக்கோபு சொன்னான்."],
    "Genesis 32:28": ["இஸ்ரவேல் என்னும் பெயர்", "நீ தேவனோடும் மனிதரோடும் போராடி வென்றபடியால், இனி உன் பெயர் யாக்கோபு என்னப்படாமல் 'இஸ்ரவேல்' என்னப்படும் என்று அவர் சொன்னார்."],
    "Genesis 32:30": ["பெனியேல் என்னும் இடம்", "நான் தேவனை முகமுகமாய்க் கண்டேன், உயிர் தப்பினேன் என்று சொல்லி அந்த இடத்திற்குப் 'பெனியேல்' என்று பெயரிட்டான்."],
    "Genesis 32:31": ["யாக்கோபு முடங்கி நடத்தல்", "அந்தப் போராட்டத்திற்குப் பிறகு யாக்கோபு தொடைச் சந்தில் ஏற்பட்ட காயத்தினால் முடங்கி நடந்தான்."],

    "Genesis 33:1": ["ஏசா வருவதை யாக்கோபு பார்த்தல்", "யாக்கோபு நிமிர்ந்து பார்த்தபோது, ஏசா நானூறு மனிதர்களோடு வருவதைக் கண்டான்."],
    "Genesis 33:3": ["ஏசாவுக்கு முன் யாக்கோபு பணிதல்", "யாக்கோபு ஏசாவிடம் நெருங்கும் முன் ஏழு முறை தரையிலே விழுந்து பணிந்து வணங்கினான்."],
    "Genesis 33:4": ["ஏசா யாக்கோபைத் தழுவுதல்", "ஏசா ஓடிவந்து யாக்கோபைத் தழுவி, அவன் கழுத்தைக் கட்டிக்கொண்டு முத்தமிட்டான்; இருவரும் அழுதார்கள்."],
    "Genesis 33:5": ["தன் குடும்பத்தை அறிமுகப்படுத்துதல்", "யாக்கோபு தன் மனைவிகளையும் பிள்ளைகளையும் ஏசாவுக்கு அறிமுகம் செய்து வைத்தான்."],
    "Genesis 33:8": ["பரிசுகளைப் பற்றி விளக்குதல்", "தமக்கு முன்பாகத் தயவு கிடைக்கும்படி இந்தப் பரிசுகளை அனுப்பினேன் என்று யாக்கோபு சொன்னான்."],
    "Genesis 33:10": ["பரிசுகளை ஏற்க வற்புறுத்தல்", "ஏசா முதலில் மறுத்தாலும், சமாதானத்தின் அடையாளமாகப் பரிசுகளை ஏற்றுக்கொள்ளும்படி யாக்கோபு அவனை வற்புறுத்தினான்."],
    "Genesis 33:12": ["சேர்ந்து பிரயாணம் செய்ய ஏசா அழைத்தல்", "நாம் சேர்ந்து பிரயாணம் பண்ணலாம் என்று ஏசா சொன்னான்."],
    "Genesis 33:13": ["யாக்கோபு மறுத்தல்", "பிள்ளைகளும் ஆடுகளும் மெதுவாக வர வேண்டியிருப்பதால், நீர் முன்னால் செல்லும் என்று யாக்கோபு பணிவாகச் சொன்னான்."],
    "Genesis 33:16": ["ஏசா சேயீருக்குத் திரும்புதல்", "அன்றைய தினமே ஏசா சேயீர் தேசத்திற்குத் திரும்பிப் போனான்."],
    "Genesis 33:17": ["சுக்கோத்தில் யாக்கோபு தங்குதல்", "யாக்கோபு சுக்கோத்திற்குப் போய், அங்கே தனக்கு ஒரு வீடும் மிருகங்களுக்குக் கொட்டாரங்களும் கட்டினான்."],
    "Genesis 33:18": ["சீகேமுக்கு வந்து சேருதல்", "யாக்கோபு கானான் தேசத்திலுள்ள சீகேம் பட்டணத்தைச் சேர்ந்து, பட்டணத்திற்கு முன்னே கூடாரம் போட்டான்."],
    "Genesis 33:19": ["சீகேமில் நிலம் வாங்குதல்", "தான் கூடாரம் போட்டிருந்த நிலத்தின் பகுதியை ஏமோரின் புத்திரரிடத்தில் நூறு வெள்ளிக்காசுக்கு வாங்கினான்."],
    "Genesis 33:20": ["தேவனுக்குப் பலிபீடம்", "அங்கே ஒரு பலிபீடத்தைக் கட்டி, அதற்கு 'ஏல் எலோஹே இஸ்ரவேல்' என்று பெயரிட்டான்."],

    "Genesis 34:1": ["தினா தேசத்துப் பெண்களைக் காணச் செல்லுதல்", "யாக்கோபின் குமாரத்தியாகிய தினாள் அந்தத் தேசத்துப் பெண்களைப் பார்க்கப் போனாள்."],
    "Genesis 34:2": ["சீகேம் தினாளைக் கெடுத்தல்", "ஏவியனாகிய ஏமோரின் குமாரன் சீகேம் தினாளைக் கண்டு, அவளைக் கொண்டுபோய் அவளைக் கெடுத்தான்."],
    "Genesis 34:3": ["சீகேம் தினாளை விரும்பல்", "சீகேம் தினாள் மேல் மிகுந்த ஆசை கொண்டு, அவளைத் திருமணம் செய்யத் தன் தகப்பனிடம் கேட்டான்."],
    "Genesis 34:5": ["யாக்கோபு செய்தியை அறிதல்", "தினாள் தீட்டுப்பட்ட செய்தியை யாக்கோபு அறிந்தான், ஆனால் தன் குமாரர்கள் வரும் வரை அமைதியாயிருந்தான்."],
    "Genesis 34:8": ["ஏமோர் திருமணப் பேச்சு பேசுதல்", "ஏமோர் யாக்கோபிடம் வந்து, தங்கள் பிள்ளைகளை ஒருவருக்கொருவர் திருமணம் செய்து கொடுத்துச் சமாதானமாய் இருக்கலாம் என்று சொன்னான்."],
    "Genesis 34:13": ["யாக்கோபின் குமாரர்கள் சூழ்ச்சி செய்தல்", "தங்கள் சகோதரி தீட்டுப்பட்டதினால், யாக்கோபின் குமாரர்கள் தந்திரமாகப் பதில் சொன்னார்கள்."],
    "Genesis 34:15": ["விருத்தசேதனம் என்னும் நிபந்தனை", "உங்களிலுள்ள ஆண்கள் அனைவரும் விருத்தசேதனம் செய்துகொண்டால் மட்டுமே நாங்கள் பெண் கொடுப்போம் என்று சொன்னார்கள்."],
    "Genesis 34:20": ["ஊர் மக்களை ஏமோர் சம்மதிக்க வைத்தல்", "ஏமோரும் சீகேமும் தங்கள் பட்டணத்து மனிதர்களிடம் பேசி, அவர்களை விருத்தசேதனம் செய்யச் சம்மதிக்க வைத்தார்கள்."],
    "Genesis 34:25": ["சிமியோனும் லேவியும் தாக்குதல்", "மூன்றாம் நாளில் அந்த மனிதர்கள் வேதனையோடு இருக்கையில், சிமியோனும் லேவியும் பட்டணத்திற்குள் புகுந்து ஆண்களைக் கொன்றார்கள்."],
    "Genesis 34:27": ["பட்டணத்தைச் சூறையாடுதல்", "யாக்கோபின் குமாரர்கள் பட்டணத்திலுள்ள சொத்துக்கள், ஆடுமாடுகள் மற்றும் பெண் பிள்ளைகளைச் சிறைபிடித்துக் கொண்டுபோனார்கள்."],
    "Genesis 34:30": ["யாக்கோபு குமாரர்களைக் கண்டித்தல்", "இந்தச் செயலால் தேசத்தாருக்குள் எனக்குக் கெட்ட பெயர் உண்டாக்கிவிட்டீர்கள் என்று யாக்கோபு வருந்தினான்."],
    "Genesis 34:31": ["குமாரர்களின் பதில்", "எங்கள் சகோதரியை ஒரு வேசியைப் போல நடத்தலாமா என்று அவர்கள் கேட்டார்கள்."],

    "Genesis 35:1": ["யாக்கோபு பெத்தேலுக்குத் திரும்புதல்", "நீ பெத்தேலுக்குப் போய், அங்கே குடியிருந்து தேவனுக்கு ஒரு பலிபீடத்தைக் கட்டு என்று தேவன் யாக்கோபிடம் சொன்னார்."],
    "Genesis 35:2": ["அந்நிய தெய்வங்களை நீக்குதல்", "உங்கள் நடுவிலிருக்கிற அந்நிய தெய்வங்களை அகற்றிவிட்டு, உங்களைச் சுத்திகரித்துக் கொள்ளுங்கள் என்று யாக்கோபு தன் வீட்டாரிடம் சொன்னான்."],
    "Genesis 35:4": ["சீகேமில் சிலைகளைப் புதைத்தல்", "யாக்கோபு தன்னிடம் கொடுக்கப்பட்ட அந்நிய தெய்வங்களையும் காதணிகளையும் சீகேமுக்கு அருகிலுள்ள ஒரு கருவாலி மரத்தடியிலே புதைத்தான்."],
    "Genesis 35:5": ["தேவன் யாக்கோபைப் பாதுகாத்தல்", "சுற்றுப் பட்டணத்தாருக்குத் தேவனால் பயம் உண்டானதினால், அவர்கள் யாக்கோபின் குமாரர்களைத் தொடரவில்லை."],
    "Genesis 35:6": ["பெத்தேலுக்கு வந்து சேருதல்", "யாக்கோபும் அவனோடே இருந்த ஜனங்களும் பெத்தேலுக்கு வந்து சேர்ந்தார்கள்."],
    "Genesis 35:7": ["பெத்தேலில் பலிபீடம்", "யாக்கோபு அங்கே ஒரு பலிபீடத்தைக் கட்டி, அந்த இடத்திற்கு 'ஏல் பெத்தேல்' என்று பெயரிட்டான்."],
    "Genesis 35:9": ["தேவன் மீண்டும் தரிசனமாதல்", "தேவன் மீண்டும் யாக்கோபுக்குத் தரிசனமாகி அவனை ஆசீர்வதித்தார்."],
    "Genesis 35:10": ["இஸ்ரவேல் என மீண்டும் பெயரிடுதல்", "இனி உன் பெயர் யாக்கோபு என்னப்படாமல் இஸ்ரவேல் என்னப்படும் என்று தேவன் உறுதிப்படுத்தினார்."],
    "Genesis 35:11": ["ஜாதிகளும் ராஜாக்களும் தோன்றுவார்கள்", "உன்னிலிருந்து ஜாதிகளும் ராஜாக்களும் தோன்றுவார்கள் என்று தேவன் வாக்குக் கொடுத்தார்."],
    "Genesis 35:14": ["யாக்கோபு தூண் நாட்டுதல்", "யாக்கோபு ஒரு கற்தூணை நிறுத்தி, அதன்மேல் பானபலியையும் எண்ணெயையும் ஊற்றினான்."],
    "Genesis 35:16": ["ராகேலின் மரணம்", "பெத்லகேமுக்கு அருகே பிரயாணம் பண்ணும்போது ராகேல் பிரசவ வேதனையினால் மரித்தாள்."],
    "Genesis 35:18": ["பென்யமீனின் பிறப்பு", "ராகேலின் குமாரனுக்குப் 'பென்யமீன்' என்று பெயரிடப்பட்டது."],
    "Genesis 35:22": ["ரூபனின் பாவம்", "ரூபன் தன் தகப்பனுடைய மறுமனையாட்டியாகிய பில்காளோடு சயனித்தான்; இதை இஸ்ரவேல் அறிந்தான்."],
    "Genesis 35:23": ["யாக்கோபின் குமாரர்கள்", "யாக்கோபின் பன்னிரண்டு குமாரர்களின் பெயர்கள் வரிசைப்படுத்தப்பட்டன."],
    "Genesis 35:27": ["ஈசாக்கிடம் யாக்கோபு திரும்புதல்", "யாக்கோபு மம்ரேயிலிருந்த தன் தகப்பனாகிய ஈசாக்கிடம் வந்து சேர்ந்தான்."],
    "Genesis 35:29": ["ஈசாக்கின் மரணம்", "ஈசாக்கு முதிர்வயதில் மரித்தான்; அவன் குமாரராகிய ஏசாவும் யாக்கோபும் அவனை அடக்கம் செய்தார்கள்."],

    "Genesis 36:1": ["ஏசாவின் வம்ச வரலாறு", "இந்த அதிகாரம் ஏதோம் என்று அழைக்கப்படும் ஏசாவின் சந்ததியினரைப் பற்றி விவரிக்கிறது."],
    "Genesis 36:6": ["ஏசா சேயீருக்குச் செல்லுதல்", "ஏசா யாக்கோபை விட்டுப் பிரிந்து, சேயீர் மலைத்தேசத்தில் குடியேறினான்."],
    "Genesis 36:9": ["ஏதோமிலுள்ள ஏசாவின் சந்ததி", "ஏதோம் தேசத்தில் வாழ்ந்த ஏசாவின் குடும்ப வம்சாவளி பதிவு செய்யப்பட்டுள்ளது."],
    "Genesis 36:15": ["ஏதோமின் பிரபுக்கள்", "ஏசாவின் சந்ததியில் தலைவர்களாக இருந்தவர்கள் ஏதோமின் பிரபுக்களாகப் பட்டியலிடப்பட்டுள்ளனர்."],
    "Genesis 36:20": ["சேயீரின் குடிகள்", "சேயீர் தேசத்தில் ஏற்கனவே வாழ்ந்த பூர்வ குடிகளும் அவர்களுடைய குடும்பங்களும் பதிவு செய்யப்பட்டுள்ளன."],
    "Genesis 36:31": ["ஏதோமை ஆண்ட ராஜாக்கள்", "இஸ்ரவேலில் எந்த ராஜாவும் தோன்றுவதற்கு முன்பே, ஏதோம் தேசத்தை ஆண்ட ராஜாக்கள் பட்டியலிடப்பட்டுள்ளனர்."],
    "Genesis 36:40": ["தேசங்களின்படி பிரபுக்கள்", "ஏதோமின் பிரபுக்கள் அவர்களுடைய குடும்பங்கள் மற்றும் நிலப்பகுதிகளின்படி வரிசைப்படுத்தப்பட்டுள்ளனர்."],

    "Genesis 37:1": ["யோசேப்பின் சொப்பனங்கள்", "யாக்கோபின் குமாரனாகிய யோசேப்பு, கானான் தேசத்தில் தன் சகோதரர்களுடன் வாழ்ந்து வந்தான்."],
    "Genesis 37:3": ["யாக்கோபு யோசேப்பை அதிகம் நேசித்தல்", "யாக்கோபு தன் மற்ற குமாரர்களை விட யோசேப்பை அதிகம் நேசித்து, அவனுக்கு ஒரு பலவண்ண அங்கியைத் தைத்துக் கொடுத்தான்."],
    "Genesis 37:5": ["யோசேப்பின் முதல் சொப்பனம்", "தன் சகோதரர்களின் அரிக்கட்டுகள் தன் அரிக்கட்டை வணங்குவது போல யோசேப்பு சொப்பனம் கண்டான்."],
    "Genesis 37:9": ["யோசேப்பின் இரண்டாம் சொப்பனம்", "சூரியனும், சந்திரனும், பதினொரு நட்சத்திரங்களும் தன்னை வணங்குவது போல யோசேப்பு மற்றொரு சொப்பனம் கண்டான்."],
    "Genesis 37:12": ["சகோதரர்களிடம் யோசேப்பு அனுப்பப்படுதல்", "மந்தைகளை மேய்த்துக் கொண்டிருந்த தன் சகோதரர்களைப் பார்த்து வரும்படி யாக்கோபு யோசேப்பை அனுப்பினான்."],
    "Genesis 37:18": ["யோசேப்புக்கு எதிரான சூழ்ச்சி", "யோசேப்பு வருவதைக் கண்ட அவன் சகோதரர்கள், அவனைக் கொல்லும்படி தங்களுக்குள் சதி செய்தார்கள்."],
    "Genesis 37:21": ["ரூபன் யோசேப்பை மீட்க முயலுதல்", "அவனைக் கொல்ல வேண்டாம், வனாந்தரத்திலுள்ள ஒரு குழியில் போடுங்கள் என்று ரூபன் அவர்களைச் சம்மதிக்க வைத்தான்."],
    "Genesis 37:23": ["யோசேப்பு குழியில் தள்ளப்படுதல்", "சகோதரர்கள் யோசேப்பின் அங்கியை உரிந்துவிட்டு, அவனைத் தண்ணீர் இல்லாத ஒரு வெற்றுக்குழியில் தள்ளினார்கள்."],
    "Genesis 37:26": ["யோசேப்பை விற்க யூதா ஆலோசனை கூறுதல்", "அவனைக் கொல்வதை விட, இஸ்மவேலர்களுக்கு அவனை விற்றுவிடலாம் என்று யூதா சொன்னான்."],
    "Genesis 37:28": ["யோசேப்பு அடிமையாக விற்கப்படுதல்", "யோசேப்பு இருபது வெள்ளிக்காசுக்கு இஸ்மவேலர்களிடம் விற்கப்பட்டான்; அவர்கள் அவனை எகிப்துக்குக் கொண்டு போனார்கள்."],
    "Genesis 37:31": ["யாக்கோபை ஏமாற்றுதல்", "சகோதரர்கள் ஒரு வெள்ளாட்டுக்கடாத்தைக் கொன்று, அதன் இரத்தத்தில் யோசேப்பின் அங்கியைத் தோய்த்து யாக்கோபிடம் காட்டினார்கள்."],
    "Genesis 37:33": ["யோசேப்பு இறந்துவிட்டதாக யாக்கோபு நம்புதல்", "ஒரு துஷ்ட மிருகம் யோசேப்பைப் பட்சித்தது என்று யாக்கோபு நம்பிப் புலம்பினான்."],
    "Genesis 37:35": ["யாக்கோபின் துக்கம்", "யாக்கோபு தன் குமாரனுக்காக மிகவும் துக்கப்பட்டு, ஆறுதலடைய மறுத்தான்."],
    "Genesis 37:36": ["எகிப்தில் யோசேப்பு", "எகிப்தில் பார்வோனுடைய அதிகாரியும் தலையாரிகளுக்கு அதிபதியுமாகிய போத்திப்பாரிடம் யோசேப்பு விற்கப்பட்டான்."],

    "Genesis 38:1": ["யூதா சகோதரர்களை விட்டுப் பிரிதல்", "யூதா தன் சகோதரர்களை விட்டுப் பிரிந்து, ஈரா என்னும் அதல்லாம் ஊரானிடம் போய்த் தங்கினான்."],
    "Genesis 38:2": ["யூதாவின் குடும்பம்", "யூதா ஒரு கானானியப் பெண்ணை மணந்து ஏர், ஓனான், ஷேலா என்னும் மூன்று குமாரர்களைப் பெற்றான்."],
    "Genesis 38:6": ["தாமார் ஏரை மணத்தல்", "யூதா தன் மூத்த மகனாகிய ஏருக்குத் தாமார் என்னும் பெண்ணைத் திருமணம் செய்து வைத்தான்."],
    "Genesis 38:7": ["ஏரின் மரணம்", "ஏர் கர்த்தரின் பார்வைக்குப் பொல்லாதவனாயிருந்தபடியால், கர்த்தர் அவனைக் கொன்றுபோட்டார்."],
    "Genesis 38:8": ["ஓனானின் கடமை", "தன் சகோதரனின் வம்சத்தை நிலைநிறுத்த தாமாரை மணக்கும்படி யூதா ஓனானுக்குக் கட்டளையிட்டான்."],
    "Genesis 38:9": ["ஓனான் மறுத்தல்", "பிறக்கும் பிள்ளை தனக்குச் சேராது என்பதால், ஓனான் தாமார் கர்ப்பமடைவதைத் தடுத்தான்."],
    "Genesis 38:10": ["ஓனானின் மரணம்", "ஓனான் செய்த காரியம் கர்த்தருக்குப் பிடிக்காததினால், அவரையும் கொன்றுபோட்டார்."],
    "Genesis 38:11": ["தாமார் அனுப்பிவைக்கப்படுதல்", "தன் இளைய மகன் ஷேலா வளரும் வரை உன் தகப்பன் வீட்டில் கைம்பெண்ணாக இரு என்று யூதா தாமாரை அனுப்பிவைத்தான்."],
    "Genesis 38:12": ["யூதா திம்னாவுக்கு வருதல்", "யூதாவின் மனைவி மரித்த பிறகு, அவன் தன் ஆடுகளை மயிர்க்கத்தரிக்கத் திம்னாவுக்குப் போனான்."],
    "Genesis 38:14": ["தாமாரின் திட்டம்", "ஷேலா வளர்ந்தும் தனக்குத் திருமணம் செய்யப்படாததைக் கண்ட தாமார், வேசி வேடமிட்டு யூதாவுக்காகக் காத்திருந்தாள்."],
    "Genesis 38:16": ["யூதா தாமாரைச் சந்தித்தல்", "யூதா அவளை அறியாமல் அவளுடன் சயனித்து, அதற்கு அடையாளமாகத் தன் முத்திரை மோதிரத்தையும், தடியையும் கொடுத்தான்."],
    "Genesis 38:24": ["தாமார் மேல் குற்றம் சுமத்தப்படுதல்", "தாமார் கர்ப்பவதியான செய்தியைக் கேட்டு, அவளைத் தண்டிக்கும்படி யூதா உத்தரவிட்டான்."],
    "Genesis 38:25": ["தாமார் உண்மையை வெளிப்படுத்துதல்", "யூதா கொடுத்த அடையாளப் பொருட்களைக் காட்டி, குழந்தையின் தந்தை யார் என்பதைத் தாமார் புரியவைத்தாள்."],
    "Genesis 38:26": ["யூதா தன் தவற்றை ஒப்புக்கொள்ளுதல்", "தாமார் என்னிலும் நீதி உள்ளவள் என்று யூதா ஒப்புக்கொண்டான்."],
    "Genesis 38:27": ["இரட்டைப் பிள்ளைகளின் பிறப்பு", "தாமார் பேரேஸ், சேரா என்னும் இரட்டைப் பிள்ளைகளைப் பெற்றாள்."],

    "Genesis 39:1": ["போத்திப்பார் வீட்டில் யோசேப்பு", "எகிப்துக்குக் கொண்டு போகப்பட்ட யோசேப்பைப் பார்வோனின் அதிகாரியான போத்திப்பார் விலைக்கு வாங்கினான்."],
    "Genesis 39:2": ["யோசேப்பை கர்த்தர் ஆசீர்வதித்தல்", "கர்த்தர் யோசேப்போடே இருந்தார்; அவன் செய்த காரியங்கள் அனைத்தும் வாய்த்தன."],
    "Genesis 39:4": ["யோசேப்புக்குக் கிடைத்த பொறுப்பு", "போத்திப்பார் யோசேப்பு மேல் தயவு கொண்டு, தன் வீட்டு நிர்வாகம் அனைத்தையும் அவன் கையில் ஒப்புவித்தான்."],
    "Genesis 39:6": ["யோசேப்பின் அழகு", "யோசேப்பு அழகான ரூபமும் களைமுகமும் உள்ளவனாயிருந்தான்."],
    "Genesis 39:7": ["போத்திப்பாரின் மனைவி யோசேப்பைச் சோதித்தல்", "போத்திப்பாரின் மனைவி யோசேப்பைத் தன்னுடன் சயனிக்கும்படி பலமுறை வற்புறுத்தினாள்."],
    "Genesis 39:8": ["யோசேப்பு பாவத்தை மறுத்தல்", "தன் எஜமானுக்குத் துரோகம் செய்யவும், தேவனுக்கு விரோதமாகப் பாவம் செய்யவும் மாட்டேன் என்று யோசேப்பு மறுத்தான்."],
    "Genesis 39:11": ["சோதனையிலிருந்து யோசேப்பு தப்பித்தல்", "அவள் யோசேப்பின் வஸ்திரத்தைப் பிடித்து இழுத்தபோது, அவன் வஸ்திரத்தை அவளிடம் விட்டுவிட்டு வெளியிலே ஓடிப்போனான்."],
    "Genesis 39:13": ["பொய்க் குற்றம்", "யோசேப்பு தனக்குத் தீமை செய்ய முயன்றதாகப் போத்திப்பாரின் மனைவி பழி சுமத்தினாள்."],
    "Genesis 39:19": ["யோசேப்பு சிறையில் அடைக்கப்படுதல்", "போத்திப்பார் கோபமடைந்து, யோசேப்பை ராஜாங்கக் கைதிகள் இருக்கும் சிறையில் அடைத்தான்."],
    "Genesis 39:21": ["சிறையிலும் யோசேப்புக்குக் கிடைத்த தயவு", "கர்த்தர் யோசேப்போடே இருந்து, சிறைச்சாலை அதிகாரியின் பார்வையில் அவனுக்குத் தயவு கிடைக்கும்படி செய்தார்."],
    "Genesis 39:22": ["யோசேப்புக்குக் கிடைத்த அதிகாரம்", "சிறைச்சாலை அதிகாரி அங்கிருந்த கைதிகள் அனைவரையும் யோசேப்பின் பொறுப்பில் விட்டார்."],
    "Genesis 39:23": ["கர்த்தர் யோசேப்பைச் செழிக்கப்பண்ணுதல்", "கர்த்தர் யோசேப்போடே இருந்ததினால், அவன் எதைச் செய்தாலும் அது வெற்றியாக முடிந்தது."],

    "Genesis 40:1": ["பார்வோனின் அதிகாரிகளுக்குச் சிறைத்தண்டனை", "பார்வோனின் பானபாத்திரக்காரனும் சுயம்பாகியும் ராஜாவுக்குக் குற்றம் செய்ததினால் சிறையில் அடைக்கப்பட்டார்கள்."],
    "Genesis 40:4": ["சிறையில் அவர்களுக்கு யோசேப்பு ஊழியம் செய்தல்", "அந்த அதிகாரிகளுக்குப் பணிவிடை செய்யும்படி யோசேப்பு நியமிக்கப்பட்டான்."],
    "Genesis 40:5": ["இரண்டு சொப்பனங்கள்", "சிறையிலிருந்த அந்த இருவரும் ஒரே இரவில் தங்களை வருத்தப்படச் செய்த வெவ்வேறு சொப்பனங்களைக் கண்டார்கள்."],
    "Genesis 40:8": ["யோசேப்பு விளக்கம் அளிக்க முன்வருதல்", "சொப்பனங்களுக்கு விளக்கம் சொல்லுதல் தேவனுக்கே உரியது என்று சொல்லி, யோசேப்பு அவர்களிடம் சொப்பனங்களைக் கேட்டான்."],
    "Genesis 40:9": ["பானபாத்திரக்காரனின் சொப்பனம்", "மூன்று கிளைகளுள்ள ஒரு திராட்சச் செடியிலிருந்து திராட்சைப் பழங்களைப் பிழிந்து பார்வோனின் கிண்ணத்தில் கொடுப்பது போலச் சொப்பனம் கண்டான்."],
    "Genesis 40:12": ["சொப்பனத்தின் அர்த்தம்", "மூன்று கிளைகள் என்பது மூன்று நாட்கள்; மூன்று நாட்களுக்குள் நீ மீண்டும் உன் வேலையில் சேர்வாய் என்று யோசேப்பு சொன்னான்."],
    "Genesis 40:14": ["யோசேப்பின் வேண்டுகோள்", "நீ நன்மையடையும்போது என்னை நினைத்து, பார்வோனிடம் பேசி இந்தச் சிறையிலிருந்து என்னை விடுவிக்க வேண்டும் என்று யோசேப்பு கேட்டான்."],
    "Genesis 40:16": ["சுயம்பாகியின் சொப்பனம்", "தன் தலையின் மேல் மூன்று கூடைகளில் இருந்த பலகாரங்களைப் பறவைகள் வந்து தின்பது போல சுயம்பாகி சொப்பனம் கண்டான்."],
    "Genesis 40:18": ["சுயம்பாகியின் சொப்பனத்திற்கு அர்த்தம்", "மூன்று நாட்களுக்குள் பார்வோன் உன் தலையைத் துண்டித்துக் கழுமரத்தில் உன்னை ஏற்றுவார் என்று யோசேப்பு சொன்னான்."],
    "Genesis 40:20": ["சொப்பனங்கள் நிறைவேறுதல்", "பார்வோனின் பிறந்தநாளில் யோசேப்பு சொன்னபடியே பானபாத்திரக்காரன் மீண்டும் பணியில் அமர்த்தப்பட்டான், சுயம்பாகி கொல்லப்பட்டான்."],
    "Genesis 40:23": ["யோசேப்பு மறக்கப்படுதல்", "பானபாத்திரக்காரன் யோசேப்பை நினைக்காமல் அவனை மறந்துவிட்டான்."],

    "Genesis 41:1": ["பார்வோனின் சொப்பனங்கள்", "இரண்டு வருஷங்களுக்குப் பின்பு, பார்வோன் பசுக்களையும் கதிர்களையும் குறித்து வருத்தமளிக்கக்கூடிய சொப்பனங்களைக் கண்டான்."],
    "Genesis 41:8": ["பார்வோன் விளக்கம் தேடுதல்", "பார்வோன் தன் மந்திரவாதிகளையும் சாஸ்திரிகளையும் அழைத்தான், ஆனால் ஒருவராலும் சொப்பனங்களுக்கு விளக்கம் சொல்ல முடியவில்லை."],
    "Genesis 41:9": ["பானபாத்திரக்காரன் யோசேப்பை நினைவுகூருதல்", "பானபாத்திரக்காரன் யோசேப்பை நினைவுகூர்ந்து, அவனைப் பற்றிப் பார்வோனிடம் சொன்னான்."],
    "Genesis 41:14": ["பார்வோன் முன் யோசேப்பு", "யோசேப்பு சீக்கிரமாகச் சிறையிலிருந்து அழைத்து வரப்பட்டு, பார்வோன் முன்னால் நின்றான்."],
    "Genesis 41:16": ["தேவனுக்கே மகிமை", "விளக்கம் சொல்லுதல் என்னால் ஆகாது, தேவனே பார்வோனுக்குச் சமாதானமான உத்தரவு அருளுவார் என்று யோசேப்பு சொன்னான்."],
    "Genesis 41:25": ["சொப்பனங்களின் அர்த்தம்", "ஏழு வருஷத்துப் பஞ்சத்திற்குப் பின் ஏழு வருஷத்துப் பஞ்சம் வரும் என்பதையே இந்தச் சொப்பனங்கள் குறிக்கின்றன என்று யோசேப்பு விளக்கினான்."],
    "Genesis 41:33": ["பார்வோனுக்கு யோசேப்பின் ஆலோசனை", "விவேகமும் ஞானமுமுள்ள ஒரு மனுஷனைத் தேடி, செழிப்பான வருஷங்களில் தானியங்களைச் சேர்த்து வைக்க அதிகாரிகளை நியமிக்கும்படி யோசேப்பு ஆலோசனை கூறினான்."],
    "Genesis 41:39": ["யோசேப்பு அதிபதியாக்கப்படுதல்", "எகிப்து தேசம் முழுவதற்கும் யோசேப்பை அதிகாரியாகப் பார்வோன் நியமித்தான்."],
    "Genesis 41:45": ["யோசேப்புக்கு புதிய பெயர்", "பார்வோன் யோசேப்புக்கு 'சாப்நாத் பானேயா' என்று பெயரிட்டு, ஆஸ்நாத் என்னும் பெண்ணை அவனுக்கு மனைவியாகக் கொடுத்தான்."],
    "Genesis 41:50": ["மனாசேயின் பிறப்பு", "யோசேப்பின் மூத்த குமாரன் மனாசே பிறந்தான்."],
    "Genesis 41:52": ["எப்பிராயீமின் பிறப்பு", "யோசேப்பின் இரண்டாம் குமாரன் எப்பிராயீம் பிறந்தான்."],
    "Genesis 41:53": ["செழிப்பான வருஷங்கள் முடிவடைதல்", "ஏழு வருஷத்துப் பூரிப்பு முடிவுக்கு வந்தது."],
    "Genesis 41:54": ["பஞ்சம் தொடங்குதல்", "எல்லாத் தேசங்களிலும் பஞ்சம் உண்டானது, ஆனால் எகிப்து தேசத்திலோ தானியம் இருந்தது."],
    "Genesis 41:57": ["தேசத்தார் எகிப்துக்கு வருதல்", "யோசேப்பினிடம் தானியம் வாங்கும்படி சகல தேசத்தாரும் எகிப்துக்கு வந்தார்கள்."],

    "Genesis 42:1": ["யாக்கோபு தன் குமாரர்களை எகிப்துக்கு அனுப்புதல்", "எகிப்தில் தானியம் உண்டு என்று அறிந்து, யாக்கோபு தன் குமாரர்களை அங்கே உணவு வாங்க அனுப்பினான்."],
    "Genesis 42:6": ["யோசேப்பு தன் சகோதரர்களைச் சந்தித்தல்", "எகிப்தின் அதிபதியாயிருந்த யோசேப்பு, தானியம் வாங்க வந்த தன் சகோதரர்களைக் கண்டான்."],
    "Genesis 42:7": ["யோசேப்பு சகோதரர்களைச் சோதித்தல்", "யோசேப்பு அவர்களை அடையாளம் கண்டுகொண்டான், ஆனால் தன்னை ஒரு அந்நியனைப் போலக் காட்டிக்கொண்டு அவர்களிடத்தில் கடினமாய்ப் பேசினான்."],
    "Genesis 42:9": ["ஒற்றர்கள் என்று குற்றம் சுமத்துதல்", "அவர்களைச் சோதிக்கும் பொருட்டு, நீங்கள் தேசத்தின் நிலைமையை உளவு பார்க்க வந்த ஒற்றர்கள் என்று யோசேப்பு சொன்னான்."],
    "Genesis 42:13": ["சகோதரர்கள் குடும்பத்தைப் பற்றி விளக்குதல்", "தாங்கள் பன்னிரண்டு சகோதரர்கள் என்றும், இளையவன் தன் தகப்பனுடன் இருப்பதாகவும், ஒருவன் இல்லையென்றும் சொன்னார்கள்."],
    "Genesis 42:17": ["சகோதரர்கள் சிறைவைக்கப்படுதல்", "யோசேப்பு அவர்களை மூன்று நாள் காவலில் வைத்தான்."],
    "Genesis 42:19": ["சிமியோன் பிணையாக வைக்கப்படுதல்", "யோசேப்பு சிமியோனை மட்டும் சிறையில் வைத்துக்கொண்டு, மற்றவர்களைத் தானியத்தோடு வீட்டுக்கு அனுப்பிவைத்தான்."],
    "Genesis 42:21": ["சகோதரர்கள் குற்ற உணர்வு கொள்ளுதல்", "யோசேப்புக்கு நாம் செய்த தீமையினால்தான் இந்த ஆபத்து நமக்கு நேரிட்டது என்று அவர்கள் தங்களுக்குள் பேசிக்கொண்டார்கள்."],
    "Genesis 42:24": ["யோசேப்பு அழுதல்", "அவர்கள் வருந்துவதைக் கேட்ட யோசேப்பு, ரகசியமாகத் திரும்பிப் போய் அழுதான்."],
    "Genesis 42:25": ["பணத்தைத் தானியப்பைகளில் மறைத்து வைத்தல்", "யோசேப்பு அவர்கள் கொண்டு வந்த பணத்தை ரகசியமாக அவர்களுடைய தானியப்பைகளுக்குள் வைக்கும்படி கட்டளையிட்டான்."],
    "Genesis 42:27": ["வெள்ளியைக் கண்டுபிடித்தல்", "திரும்பிப் போகும் வழியில் ஒருவன் தன் பையைத் திறந்தபோது, அதிலிருந்த பணத்தைக் கண்டு அதிர்ச்சியடைந்தான்."],
    "Genesis 42:29": ["யாக்கோபிடம் விவரித்தல்", "அவர்கள் கானான் தேசத்திற்கு வந்து, எகிப்தில் நடந்த அனைத்தையும் தங்கள் தகப்பனிடம் சொன்னார்கள்."],
    "Genesis 42:36": ["யாக்கோபின் துக்கம்", "யோசேப்பும் இல்லை, சிமியோனும் இல்லை, இப்போது பென்யமீனையும் கொண்டு போக வேண்டுமா என்று யாக்கோபு வருந்தினான்."],

    "Genesis 43:1": ["பஞ்சம் தொடருதல்", "தேசத்தில் பஞ்சம் கொடிதாயிருந்தது, எகிப்திலிருந்து கொண்டு வந்த தானியமும் தீர்ந்துபோனது."],
    "Genesis 43:3": ["யூதா யாக்கோபிடம் பேசுதல்", "பென்யமீன் எங்களுடன் வராவிட்டால் அந்த அதிபதி எங்களைப் பார்க்க மாட்டார் என்று யூதா சொன்னான்."],
    "Genesis 43:8": ["பென்யமீனுக்கு யூதா பொறுப்பேற்றல்", "பிள்ளைக்கு நான் பொறுப்பு, அவனுக்கு ஏதாகிலும் நேரிட்டால் அந்தப் பழியை நான் சுமப்பேன் என்று யூதா உறுதி அளித்தான்."],
    "Genesis 43:11": ["யாக்கோபு பரிசுகளை அனுப்புதல்", "தேசத்தின் சிறந்த கனிகளையும், இரட்டிப்புப் பணத்தையும், பென்யமீனையும் அழைத்துக்கொண்டு போங்கள் என்று யாக்கோபு சொன்னான்."],
    "Genesis 43:15": ["சகோதரர்கள் மீண்டும் எகிப்துக்கு வருதல்", "சகோதரர்கள் பென்யமீனை அழைத்துக்கொண்டு மீண்டும் எகிப்துக்கு வந்து யோசேப்பு முன் நின்றார்கள்."],
    "Genesis 43:16": ["யோசேப்பு விருந்துக்கு ஏற்பாடு செய்தல்", "யோசேப்பு தன் சகோதரர்களைக் கண்டபோது, தன் வீட்டில் அவர்களுக்காக விருந்து ஆயத்தம் செய்யச் சொன்னான்."],
    "Genesis 43:18": ["சகோதரர்கள் பயப்படுதல்", "தாங்கள் யோசேப்பின் வீட்டுக்கு அழைத்துச் செல்லப்படுவதைக் கண்டு, பணத்தின் நிமித்தம் ஏதோ ஆபத்து வருமோ என்று சகோதரர்கள் பயந்தார்கள்."],
    "Genesis 43:23": ["யோசேப்பின் வீட்டு விசாரணைக்காரன் தேற்றுதல்", "பயப்படாதீர்கள், உங்கள் தேவன் உங்கள் பைகளில் திரவியத்தைத் தந்தார் என்று அவன் அவர்களைத் தேற்றினான்."],
    "Genesis 43:26": ["சகோதரர்கள் யோசேப்பை வணங்குதல்", "சகோதரர்கள் தாங்கள் கொண்டு வந்த பரிசுகளைக் கொடுத்து, யோசேப்பைத் தரையிலே விழுந்து வணங்கினார்கள்."],
    "Genesis 43:29": ["யோசேப்பு பென்யமீனைக் காணுதல்", "யோசேப்பு தன் தம்பியாகிய பென்யமீனைக் கண்டபோது, அவனுக்குத் தேவகிருபை உண்டாகட்டும் என்று ஆசீர்வதித்தான்."],
    "Genesis 43:30": ["யோசேப்பு ரகசியமாக அழுதல்", "தம்பியைப் பார்த்ததும் உருக்கம் மேலிட்டதால், யோசேப்பு அறைக்குள் போய் அழுதுவிட்டு, முகம் கழுவித் திரும்பி வந்தான்."],
    "Genesis 43:32": ["யோசேப்பின் பந்தியில் போஜனம்", "வழக்கத்தின்படி எகிப்தியர் தனித்தும், எபிரெயர் தனித்தும் அமர்ந்து சாப்பிட்டார்கள்."],
    "Genesis 43:33": ["வயது வரிசைப்படி அமரவைத்தல்", "சகோதரர்கள் தங்கள் வயது வரிசைப்படி அமரவைக்கப்பட்டதைக் கண்டு ஆச்சரியப்பட்டார்கள்."],
    "Genesis 43:34": ["பென்யமீனுக்கு அதிகப் பங்கு", "மற்ற சகோதரர்களை விட பென்யமீனுக்கு ஐந்து மடங்கு அதிகப் பங்கு உணவு கொடுக்கப்பட்டது."],

    "Genesis 44:1": ["யோசேப்பின் இறுதிச் சோதனை", "சகோதரர்களுடைய பைகளில் தானியத்தை நிரப்பி, பென்யமீனுடைய பையில் தன் வெள்ளிப் பாத்திரத்தை ரகசியமாக வைக்கும்படி யோசேப்பு கட்டளையிட்டான்."],
    "Genesis 44:4": ["சகோதரர்களைத் தொடர்தல்", "அவர்கள் புறப்பட்டுச் சென்ற சிறிது நேரத்திலேயே, யோசேப்பு தன் விசாரணைக்காரனை அனுப்பி அவர்களைப் பிடிக்கச் சொன்னான்."],
    "Genesis 44:6": ["திருட்டுக் குற்றம் சுமத்துதல்", "என் எஜமானுடைய வெள்ளிப் பாத்திரத்தை ஏன் திருடினீர்கள் என்று விசாரணைக்காரன் கேட்டான்."],
    "Genesis 44:8": ["சகோதரர்கள் மறுத்தல்", "நாங்கள் அப்படிப்பட்டவர்கள் அல்ல, யாரிடத்தில் பாத்திரம் இருக்கிறதோ அவன் சாகட்டும் என்று சகோதரர்கள் சொன்னார்கள்."],
    "Genesis 44:12": ["பென்யமீன் பையில் பாத்திரம் கிடைத்தல்", "பைகளைச் சோதித்தபோது, பென்யமீனுடைய பையில் அந்த வெள்ளிப் பாத்திரம் இருந்தது."],
    "Genesis 44:13": ["சகோதரர்களின் வேதனை", "அவர்கள் துக்கத்தினால் தங்கள் வஸ்திரங்களைக் கிழித்துக்கொண்டு, மீண்டும் பட்டணத்திற்குத் திரும்பினார்கள்."],
    "Genesis 44:14": ["மீண்டும் யோசேப்பு முன்", "யூதாவும் அவன் சகோதரர்களும் யோசேப்பு முன் வந்து தரையிலே விழுந்தார்கள்."],
    "Genesis 44:16": ["யூதா பொறுப்பேற்றல்", "எங்கள் அக்கிரமத்தை தேவன் வெளிப்படுத்தினார், நாங்கள் அனைவரும் உமக்கு அடிமைகளாகிறோம் என்று யூதா சொன்னான்."],
    "Genesis 44:18": ["பென்யமீனுக்காக யூதா வேண்டுதல்", "யூதா யோசேப்பிடம் நெருங்கிப்போய், பென்யமீனை விட்டுவிடும்படி உருக்கமாக வேண்டினான்."],
    "Genesis 44:30": ["தகப்பனின் நிலையை விளக்குதல்", "பிள்ளையின் உயிர் எங்கள் தகப்பனுடைய உயிரோடு இணைந்திருக்கிறது என்று யூதா விளக்கினான்."],
    "Genesis 44:33": ["யூதா தன்னை அடிமையாகத் தருதல்", "பிள்ளைக்குப் பதிலாக என்னை அடிமையாக வைத்துக்கொண்டு, பிள்ளையை அவன் சகோதரர்களோடு அனுப்பிவிடும் என்று யூதா வேண்டினான்."],
    "Genesis 44:34": ["யூதாவின் இறுதி வேண்டுகோள்", "பிள்ளை இல்லாமல் நான் எப்படி என் தகப்பனிடம் போவேன், என் தகப்பனுக்கு வரும் துயரத்தை நான் எப்படிப் பார்ப்பேன் என்று கதறினான்."],

    "Genesis 45:1": ["யோசேப்பு தன்னை வெளிப்படுத்துதல்", "யோசேப்பினால் தன் உணர்ச்சிகளைக் கட்டுப்படுத்த முடியவில்லை; 'நான் உங்கள் சகோதரன் யோசேப்பு' என்று தன்னை வெளிப்படுத்தினான்."],
    "Genesis 45:3": ["தகப்பனைப் பற்றிக் கேட்டல்", "என் தகப்பன் இன்னும் உயிரோடு இருக்கிறாரா என்று கேட்டான்; அவன் சகோதரர்கள் அதிர்ச்சியடைந்து பேச முடியாமல் நின்றார்கள்."],
    "Genesis 45:4": ["சகோதரர்களைத் தேற்றுதல்", "என்னை விற்றுப்போட்டதற்காக நீங்கள் வருந்த வேண்டாம்; ஜீவரட்சணை செய்யும்படிக்கே தேவன் என்னை உங்களுக்கு முன்னால் அனுப்பினார் என்று தேற்றினான்."],
    "Genesis 45:6": ["பஞ்சத்தைக் குறித்த தேவ திட்டம்", "இன்னும் ஐந்து வருஷங்கள் உழவும் அறுப்பும் இல்லாத பஞ்சம் இருக்கும் என்று யோசேப்பு சொன்னான்."],
    "Genesis 45:8": ["தேவனே யோசேப்பை உயர்த்தினார்", "என்னை இங்கே அனுப்பியது நீங்களல்ல, தேவனே; அவர் என்னை எகிப்து முழுவதற்கும் அதிபதியாக்கினார் என்றான்."],
    "Genesis 45:9": ["யாக்கோபை எகிப்துக்கு அழைத்தல்", "சீக்கிரமாக என் தகப்பனிடம் போய், அவரை எகிப்துக்கு அழைத்து வாருங்கள் என்று சொன்னான்."],
    "Genesis 45:14": ["பென்யமீனைத் தழுவுதல்", "யோசேப்பு தன் தம்பியாகிய பென்யமீனைக் கட்டிக்கொண்டு அழுதான்; பென்யமீனும் அழுதான்."],
    "Genesis 45:15": ["சகோதரர்களுடன் சமாதானம்", "யோசேப்பு தன் சகோதரர்கள் எல்லாரையும் முத்தமிட்டு அழுதான்; அதன்பின் அவர்கள் அவனோடே பேசினார்கள்."],
    "Genesis 45:16": ["பார்வோன் வரவேற்பு அளித்தல்", "யோசேப்பின் சகோதரர்கள் வந்த செய்தியை அறிந்து பார்வோனும் அவன் ஊழியக்காரரும் மகிழ்ச்சியடைந்தார்கள்."],
    "Genesis 45:19": ["பயணத்திற்கான ஏற்பாடுகள்", "யாக்கோபையும் அவர் குடும்பத்தையும் அழைத்து வரப் பார்வோன் வண்டிகளையும் வசதிகளையும் செய்து கொடுத்தான்."],
    "Genesis 45:25": ["சகோதரர்கள் கானானுக்குத் திரும்புதல்", "சகோதரர்கள் கானான் தேசத்திற்கு வந்து, 'யோசேப்பு இன்னும் உயிரோடு இருக்கிறான்' என்ற செய்தியை யாக்கோபிடம் சொன்னார்கள்."],
    "Genesis 45:26": ["யாக்கோபின் ஆச்சரியம்", "யாக்கோபு அந்தச் செய்தியைக் கேட்டுத் திகைத்து, அதை நம்ப முடியாமல் இருந்தார்."],
    "Genesis 45:27": ["யாக்கோபு நம்புதல்", "யோசேப்பு அனுப்பிவைத்த வண்டிகளைக் கண்டபோது, யாக்கோபு அந்தச் செய்தியை நம்பி உற்சாகமடைந்தார்."],
    "Genesis 45:28": ["யோசேப்பைக் காண யாக்கோபு ஆயத்தமாதல்", "என் குமாரன் யோசேப்பு இன்னும் உயிரோடு இருக்கிறானே, நான் சாகுமுன்னே போய் அவனைப் பார்ப்பேன் என்று யாக்கோபு சொன்னார்."],

    "Genesis 46:1": ["யாக்கோபு எகிப்திற்குப் பிரயாணமாதல்", "யாக்கோபு எகிப்திற்குப் புறப்பட்டு, பெயெர்செபாவுக்கு வந்து, தன் தகப்பனாகிய ஈசாக்கின் தேவனுக்குப் பலியிட்டான்."],
    "Genesis 46:2": ["யாக்கோபிடம் தேவன் பேசுதல்", "தேவன் இராக்காலத் தரிசனத்திலே யாக்கோபை நோக்கி: 'எகிப்துக்குப் போகப் பயப்படாதே' என்று சொன்னார்."],
    "Genesis 46:3": ["பெரிய ஜாதியாக்குவேன் என்னும் வாக்கு", "நீ எகிப்திலே பெரிய ஜாதியாவாய்; நான் உன்னுடனே எகிப்துக்கு வருவேன் என்று தேவன் வாக்குக் கொடுத்தார்."],
    "Genesis 46:5": ["குடும்பம் எகிப்துக்கு வருதல்", "யாக்கோபும் அவன் குமாரர்களும் தங்கள் குடும்பத்தாரோடும் உடைமைகளோடும் எகிப்துக்கு வந்தார்கள்."],
    "Genesis 46:8": ["யாக்கோபின் சந்ததியினரின் பெயர்கள்", "யாக்கோபோடே எகிப்துக்கு வந்த அவனுடைய குமாரர்கள் மற்றும் சந்ததியினரின் பெயர்கள் பட்டியலிடப்பட்டுள்ளன."],
    "Genesis 46:26": ["குடும்ப உறுப்பினர்களின் எண்ணிக்கை", "யாக்கோபின் சந்ததியாக எகிப்துக்கு வந்தவர்களின் மொத்த எண்ணிக்கை கணக்கிடப்பட்டது."],
    "Genesis 46:28": ["யூதாவை முன்னால் அனுப்புதல்", "கோசேன் தேசத்திற்குத் தங்களை வழிநடத்தும்படி, யாக்கோபு யூதாவைத் தனக்கு முன்னால் யோசேப்பிடத்திற்கு அனுப்பினான்."],
    "Genesis 46:29": ["யோசேப்பு யாக்கோபைச் சந்தித்தல்", "யோசேப்பு தன் தகப்பனாகிய யாக்கோபைச் சந்தித்து, அவன் கழுத்தைக் கட்டிக்கொண்டு வெகுநேரம் அழுதான்."],
    "Genesis 46:31": ["பார்வோனிடம் பேச யோசேப்பின் திட்டம்", "பார்வோனிடம் தங்களை எப்படி அறிமுகப்படுத்திக் கொள்ள வேண்டும் என்று யோசேப்பு தன் சகோதரர்களுக்குச் சொன்னான்."],
    "Genesis 46:34": ["மேய்ப்பர்கள் கோசேனில் குடியேறுதல்", "தாங்கள் மேய்ப்பர்கள் என்று சொன்னால், கோசேன் தேசத்தில் குடியிருக்க அனுமதி கிடைக்கும் என்று யோசேப்பு அவர்களுக்குக் கற்பித்தான்."],

    "Genesis 47:1": ["சகோதரர்களைப் பார்வோனுக்கு அறிமுகப்படுத்துதல்", "யோசேப்பு தன் சகோதரர்களில் சிலரைப் பார்வோனுக்கு முன்பாக நிறுத்தி, அவர்கள் மேய்ப்பர்கள் என்று சொன்னான்."],
    "Genesis 47:4": ["கோசேனில் தங்க அனுமதி கோருதல்", "பஞ்சம் கொடியதாயிருப்பதால் கோசேன் தேசத்தில் தங்க அனுமதிக்கும்படி சகோதரர்கள் பார்வோனிடம் கேட்டார்கள்."],
    "Genesis 47:5": ["யாக்கோபின் குடும்பத்தைப் பார்வோன் வரவேற்றல்", "பார்வோன் யோசேப்பின் குடும்பத்தாரைக் கோசேனில் குடியேற்றவும், தன் மந்தைகளை மேய்க்கவும் அனுமதி அளித்தான்."],
    "Genesis 47:7": ["யாக்கோபு பார்வோனைச் சந்தித்தல்", "யோசேப்பு தன் தகப்பனாகிய யாக்கோபைப் பார்வோன் முன் கொண்டு வந்தான்; யாக்கோபு பார்வோனை ஆசீர்வதித்தார்."],
    "Genesis 47:11": ["யோசேப்பு குடும்பத்தை நிலைநிறுத்துதல்", "யோசேப்பு தன் தகப்பனுக்கும் சகோதரர்களுக்கும் எகிப்திலே நிலத்தைக் கொடுத்து, அவர்களுக்குத் தேவையான உணவை அளித்தான்."],
    "Genesis 47:13": ["தேசத்தில் கொடிய பஞ்சம்", "எகிப்து தேசத்திலும் கானான் தேசத்திலும் பஞ்சம் மிகவும் கொடியதாயிருந்தது."],
    "Genesis 47:16": ["மிருகங்களுக்குப் பதிலாக உணவு", "ஜனங்களிடத்தில் பணம் தீர்ந்துபோனபோது, யோசேப்பு மிருகங்களை ஏற்றுக்கொண்டு அதற்குப் பதிலாகத் தானியம் கொடுத்தான்."],
    "Genesis 47:18": ["உணவிற்காக நிலத்தைக் கொடுத்தல்", "எகிப்தியர்கள் உணவிற்காகத் தங்கள் நிலங்களையும் தங்களையும் பார்வோனுக்கு அடிமைகளாகக் கொடுத்தார்கள்."],
    "Genesis 47:23": ["நிலத்திற்கான சட்டம்", "விளைச்சலில் ஐந்தில் ஒரு பங்கு பார்வோனுக்குச் சேர வேண்டும் என்ற சட்டத்தை யோசேப்பு ஏற்படுத்தினான்."],
    "Genesis 47:27": ["கோசேனில் இஸ்ரவேலர் செழித்தல்", "யாக்கோபின் குடும்பத்தார் கோசேனில் குடியேறி, மிகவும் பெருகிச் செழித்தார்கள்."],
    "Genesis 47:28": ["யாக்கோபின் இறுதி ஆண்டுகள்", "யாக்கோபு எகிப்து தேசத்திலே பதினேழு வருஷங்கள் உயிரோடிருந்தார்."],
    "Genesis 47:29": ["யோசேப்பிடம் யாக்கோபின் வேண்டுகோள்", "தன்னை எகிப்திலே அடக்கம் பண்ணாமல், தன் முன்னோர்களின் கல்லறையிலேயே அடக்கம் பண்ணும்படி யாக்கோபு யோசேப்பிடம் ஆணையிடச் சொன்னார்."],

    "Genesis 48:1": ["யாக்கோபை யோசேப்பு சந்தித்தல்", "தன் தகப்பன் வியாதியாயிருக்கிறார் என்று அறிந்து, யோசேப்பு தன் குமாரர்களாகிய மனாசே, எப்பிராயீம் ஆகியோருடன் அவரைப் பார்க்கப் போனான்."],
    "Genesis 48:3": ["தேவனுடைய வாக்கை யாக்கோபு நினைவுகூருதல்", "தேவன் தனக்குத் தரிசனமாகி, தன் சந்ததியை ஆசீர்வதிப்பதாகச் சொன்ன வாக்குத்தத்தத்தை யாக்கோபு யோசேப்புக்குச் சொன்னார்."],
    "Genesis 48:5": ["எப்பிராயீம் மற்றும் மனாசேயைச் சுவீகரித்தல்", "யோசேப்பின் குமாரர்களாகிய எப்பிராயீமையும் மனாசேயையும் தன் சொந்தக் குமாரர்களாக யாக்கோபு ஏற்றுக்கொண்டார்."],
    "Genesis 48:8": ["யோசேப்பின் குமாரர்களை யாக்கோபு அடையாளம் காணுதல்", "இவர்கள் யார் என்று யாக்கோபு கேட்டு, அவர்களை ஆசீர்வதிக்க ஆயத்தமானார்."],
    "Genesis 48:10": ["பிள்ளைகளைத் தழுவுதல்", "யாக்கோபுக்குக் கண்கள் மங்கியிருந்ததால், பிள்ளைகளைத் தன்னிடம் அழைத்து அவர்களை முத்தமிட்டுத் தழுவிக்கொண்டார்."],
    "Genesis 48:13": ["யோசேப்பு பிள்ளைகளை நிறுத்துதல்", "யோசேப்பு மனாசையை யாக்கோபின் வலது கைக்கும், எப்பிராயீமை இடது கைக்கும் நேராக நிறுத்தினான்."],
    "Genesis 48:14": ["யாக்கோபு கைகளை மாற்றி வைத்தல்", "யாக்கோபு தன் கைகளை மாற்றி வைத்து, வலது கையை இளையவனாகிய எப்பிராயீம் தலைமேல் வைத்தார்."],
    "Genesis 48:17": ["ஆசீர்வாதத்தை யோசேப்பு கேள்வி கேட்டல்", "மூத்தவன் மனாசே என்பதால், தன் தகப்பனின் கையை மாற்ற யோசேப்பு முயன்றான்."],
    "Genesis 48:19": ["எப்பிராயீமுக்கு மேலான ஆசீர்வாதம்", "மனாசேயும் பெரிய ஜாதியாவான்; ஆனால் அவன் தம்பியாகிய எப்பிராயீம் அவனைவிடப் பெரியவனாவான் என்று யாக்கோபு சொன்னார்."],
    "Genesis 48:20": ["குமாரர்களை ஆசீர்வதித்தல்", "இஸ்ரவேலர் ஆசீர்வதிக்கும்போது உங்கள் பெயர்களைச் சொல்லி ஆசீர்வதிப்பார்கள் என்று அவர்களை வாழ்த்தினார்."],
    "Genesis 48:21": ["தேசத்திற்குத் திரும்புவார்கள் என்னும் உறுதி", "தேவன் உங்களோடு இருந்து, உங்களைத் திரும்பவும் உங்கள் பிதாக்களின் தேசத்திற்கு அழைத்துச் செல்வார் என்று யோசேப்பிடம் சொன்னார்."],

    "Genesis 49:1": ["யாக்கோபு தன் குமாரர்களை அழைத்தல்", "பிற்காலங்களில் உங்களுக்குச் சம்பவிக்கப்போவதை அறிவிப்பேன் என்று யாக்கோபு தன் குமாரர்களைத் தன்னருகே அழைத்தார்."],
    "Genesis 49:3": ["ரூபனுக்கு ஆசீர்வாதம்", "ரூபன் முதல்பேறானவன்; ஆனால் அவன் செய்த குற்றத்தினால் தன் மேன்மையையும் முதன்மையையும் இழந்தான்."],
    "Genesis 49:5": ["சிமியோன் மற்றும் லேவியைக் கண்டித்தல்", "சிமியோனும் லேவியும் தங்கள் கோபத்தினால் செய்த வன்முறைக்காகக் கண்டிக்கப்பட்டார்கள்."],
    "Genesis 49:8": ["யூதாவுக்கு ஆசீர்வாதம்", "யூதா தன் சகோதரர்களால் துதிக்கப்படுவான்; உன் சகோதரர் உன்னை வணங்குவார்கள் என்று ஆசீர்வதிக்கப்பட்டான்."],
    "Genesis 49:10": ["ஆளுகையின் வாக்குத்தத்தம்", "சமாதான பிரபு (ஷைலோ) வருமளவும் செங்கோல் யூதாவை விட்டு நீங்குவதில்லை."],
    "Genesis 49:13": ["செபுலோனுக்கு ஆசீர்வாதம்", "செபுலோன் கடற்கரையிலே குடியிருந்து கப்பல்களுக்குத் துறைமுகமாயிருப்பான்."],
    "Genesis 49:14": ["இசக்காருக்கு ஆசீர்வாதம்", "இசக்கார் பாரத்தைச் சுமக்கிற பலத்த கழுதையைப் போலத் தேசத்தில் உழைப்பான்."],
    "Genesis 49:16": ["தாணுக்கு ஆசீர்வாதம்", "தாண் தன் ஜனங்களுக்கு நியாயம் விசாரிப்பான்."],
    "Genesis 49:19": ["காத்துக்கு ஆசீர்வாதம்", "காத் ஒரு படையால் நெருக்கப்படுவான்; ஆனால் அவன் இறுதியில் அவர்களைத் தோற்கடிப்பான்."],
    "Genesis 49:20": ["ஆசேருக்கு ஆசீர்வாதம்", "ஆசேருடைய ஆகாரம் கொழுமையுள்ளதாயிருக்கும்; அவன் ராஜாக்களுக்குச் சுவையான போஜனம் கொடுப்பான்."],
    "Genesis 49:21": ["நப்தாலிக்கு ஆசீர்வாதம்", "நப்தாலி விடுதலையான பெண்மான் போல இனிய சொற்களைச் சொல்லுவான்."],
    "Genesis 49:22": ["யோசேப்புக்கு ஆசீர்வாதம்", "யோசேப்பு கனிதரும் செடி; அவன் சர்வவல்லமையுள்ள தேவனால் ஆசீர்வதிக்கப்பட்டவன்."],
    "Genesis 49:27": ["பென்யமீனுக்கு ஆசீர்வாதம்", "பென்யமீன் இரை கவ்வித் தின்னும் ஓநாய் போல இருப்பான்."],
    "Genesis 49:29": ["யாக்கோபின் அடக்க வேண்டுகோள்", "தன்னை மக்பேலா குகையிலே தன் முன்னோர்களோடு அடக்கம் பண்ணும்படி கட்டளையிட்டார்."],
    "Genesis 49:33": ["யாக்கோபின் மரணம்", "யாக்கோபு தன் குமாரர்களுக்குக் கட்டளை கொடுத்து முடித்தபின் மரித்தார்."],

    "Genesis 50:1": ["யாக்கோபுக்காக யோசேப்பு துக்கித்தல்", "யோசேப்பு தன் தகப்பன் முகத்தின் மேல் விழுந்து அழுது அவரை முத்தமிட்டான்."],
    "Genesis 50:2": ["உடலைப் பதப்படுத்துதல்", "தன் தகப்பனின் உடலைப் பதப்படுத்தும்படி (embalm) வைத்தியர்களுக்கு யோசேப்பு கட்டளையிட்டான்."],
    "Genesis 50:4": ["பார்வோனிடம் அனுமதி கேட்டல்", "தன் தகப்பனை அவர் சொன்ன இடத்திலேயே அடக்கம் செய்ய எகிப்தை விட்டுச் செல்லப் பார்வோனிடம் அனுமதி கேட்டான்."],
    "Genesis 50:7": ["கானானுக்கு ஈமச்சடங்குப் பயணம்", "யோசேப்பு, அவன் சகோதரர்கள் மற்றும் எகிப்தின் பெரிய அதிகாரிகள் அனைவரும் கானானுக்குச் சென்றார்கள்."],
    "Genesis 50:10": ["பெரிய துக்கம்", "அவர்கள் ஆத்தாத்தின் போரடிக்கிற களத்திலே வந்து, யாக்கோபுக்காக ஏழு நாட்கள் மகா பெரிய துக்கம் கொண்டாடினார்கள்."],
    "Genesis 50:12": ["மக்பேலாவில் அடக்கம்", "யாக்கோபின் குமாரர்கள் அவரை அவர் சொன்னபடியே மக்பேலா குகையிலே அடக்கம் செய்தார்கள்."],
    "Genesis 50:15": ["சகோதரர்கள் யோசேப்புக்குப் பயப்படுதல்", "தகப்பன் மரித்தபின் யோசேப்பு தங்களைப் பழிவாங்குவானோ என்று சகோதரர்கள் பயந்தார்கள்."],
    "Genesis 50:16": ["மன்னிப்புக் கோருதல்", "தங்கள் குற்றத்தை மன்னிக்கும்படி அவர்கள் யோசேப்பிடம் ஆள் அனுப்பி வேண்டினார்கள்."],
    "Genesis 50:19": ["யோசேப்பு அவர்களைத் தேற்றுதல்", "பயப்படாதீர்கள், நான் தேவனா? நீங்கள் எனக்குத் தீமை செய்ய நினைத்தீர்கள்; ஆனால் தேவனோ அதை நன்மையாக முடித்தார்."],
    "Genesis 50:20": ["தீமையை நன்மையாக்கினார்", "பல ஜனங்களை உயிரோடு காக்கும்படி தேவன் இந்தக் காரியத்தை அனுமதித்தார் என்று யோசேப்பு சொன்னான்."],
    "Genesis 50:22": ["யோசேப்பின் இறுதி ஆண்டுகள்", "யோசேப்பு தன் தகப்பன் குடும்பத்தாரோடு எகிப்தில் வாழ்ந்து தன் பேரன் பேத்திகளைக் கண்டான்."],
    "Genesis 50:24": ["தேவன் உங்களை அழைத்துச் செல்வார்", "நிச்சயமாகவே தேவன் உங்களைச் சந்தித்து, இந்தத் தேசத்திலிருந்து வாக்குத்தத்தம் பண்ணப்பட்ட தேசத்திற்கு அழைத்துச் செல்வார் என்று சொன்னான்."],
    "Genesis 50:25": ["யோசேப்பின் இறுதி வேண்டுகோள்", "தேவன் உங்களை அழைத்துச் செல்லும்போது, என் எலும்புகளை இங்கிருந்து கொண்டு போக வேண்டும் என்று ஆணையிடச் செய்தான்."],
    "Genesis 50:26": ["யோசேப்பின் மரணம்", "யோசேப்பு நூற்றப்பத்து வயதில் மரித்தான்; அவன் உடல் பதப்படுத்தப்பட்டு எகிப்திலே ஒரு பெட்டியில் வைக்கப்பட்டது."],

    "Deuteronomy 1:1": ["மோசே தனது உரையைத் தொடங்குதல்", "மோசே வனாந்தரத்தில் இஸ்ரவேலர் அனைவருக்கும் உரையாற்றி, அவர்களின் பயணம் மற்றும் கர்த்தர் அவர்களுக்குக் கொடுத்த கட்டளைகளை நினைவுபடுத்துகிறார்."],
    "Deuteronomy 1:6": ["ஓரேப் மலையை விட்டுப் புறப்படக் கட்டளை", "இஸ்ரவேலர் ஓரேப்பில் தங்கியிருந்தது போதும் என்றும், முன்னோர்களுக்கு வாக்குத்தத்தம் பண்ணப்பட்ட தேசத்தைச் சுதந்தரிக்கப் புறப்பட வேண்டும் என்றும் கர்த்தர் கூறுகிறார்."],
    "Deuteronomy 1:9": ["தலைவர்கள் நியமிக்கப்படல்", "தனியாகப் பாரத்தைச் சுமக்க முடியாது என்பதால், ஒவ்வொரு கோத்திரத்திற்கும் தலைவர்களும் நியாயாதிபதிகளும் நியமிக்கப்பட்டதை மோசே விளக்குகிறார்."],
    "Deuteronomy 1:19": ["வாக்குத்தத்தம் பண்ணப்பட்ட தேசத்தை நோக்கிய பயணம்", "இஸ்ரவேலர் வனாந்தரம் வழியாகப் பயணம் செய்து, வாக்குத்தத்தம் பண்ணப்பட்ட தேசத்திற்கு அருகிலுள்ள காதேஸ்-பர்னேயாவை அடைகிறார்கள்."],
    "Deuteronomy 1:22": ["கானானுக்குள் உளவாளிகள் அனுப்பப்படல்", "தேசத்தைச் சோதித்துப் பார்த்து அறிக்கை கொண்டு வர மனிதர்களை அனுப்பும்படி மக்கள் கேட்கிறார்கள்."],
    "Deuteronomy 1:26": ["தேசத்திற்குள் நுழைய இஸ்ரவேலர் மறுத்தல்", "உளவாளிகளின் அறிக்கையைக் கேட்ட பிறகு, மக்கள் கர்த்தருக்கு விரோதமாகக் கலகம் செய்து, தேசத்தைச் சுதந்தரிக்கப் போக மறுக்கிறார்கள்."],
    "Deuteronomy 1:34": ["விசுவாசியாத சந்ததியினருக்குத் தீர்ப்பு", "கர்த்தர் கோபமடைந்து, எகிப்திலிருந்து வந்த அந்தச் சந்ததியினர் வாக்குத்தத்தம் பண்ணப்பட்ட தேசத்திற்குள் நுழைய மாட்டார்கள் என்று அறிவிக்கிறார்."],
    "Deuteronomy 1:37": ["மோசேயும் நுழையத் தடை செய்யப்படல்", "மக்களின் செயல்களினிமித்தம், மோசேயும் வாக்குத்தத்தம் பண்ணப்பட்ட தேசத்திற்குள் நுழைய மாட்டார் என்று சொல்லப்படுகிறது."],
    "Deuteronomy 1:38": ["யோசுவா தலைவராக நியமிக்கப்படல்", "மோசேயின் பணிவிடைக்காரனாகிய யோசுவா தேசத்திற்குள் நுழைந்து, இஸ்ரவேலரை அதைச் சுதந்தரிக்க வழிநடத்துவார்."],
    "Deuteronomy 1:41": ["இஸ்ரவேலரின் துணிகரமானத் தாக்குதல்", "தேவன் எச்சரித்த பின்பும் மக்கள் போரிடச் செல்கிறார்கள், ஆனால் அவர்கள் எதிரிகளால் தோற்கடிக்கப்படுகிறார்கள்."],
    "Deuteronomy 1:45": ["இஸ்ரவேலர் அழுதலும் கர்த்தர் கேளாதிருத்தலும்", "மக்கள் திரும்பி வந்து கர்த்தருக்கு முன்பாக அழுகிறார்கள், ஆனால் அவர்களின் கலகத்தினிமித்தம் அவர் செவிகொடுக்கவில்லை."],

    "Deuteronomy 2:1": ["இஸ்ரவேலர் வனாந்தரத்தை நோக்கித் திரும்புதல்", "தோல்விக்குப்பிறகு, இஸ்ரவேலர் மீண்டும் வனாந்தரத்தை நோக்கிச் சென்று, சேயீர் மலையைச் சுற்றிப் பல ஆண்டுகள் அலைகிறார்கள்."],
    "Deuteronomy 2:2": ["வடக்கு நோக்கிச் செல்லக் கட்டளை", "மலைப்பகுதியைச் சுற்றி வந்தது போதும் என்றும், இப்போது வடக்கு நோக்கித் திரும்ப வேண்டும் என்றும் கர்த்தர் கூறுகிறார்."],
    "Deuteronomy 2:4": ["ஏதோமின் வழியாகக் கடந்து செல்லுதல்", "ஏசாவின் சந்ததியினரான தங்கள் சகோதரர்களுடன் சண்டையிடாமல், அவர்கள் தேசத்தின் வழியாகக் கடந்து செல்லுமாறு தேவன் பணிக்கிறார்."],
    "Deuteronomy 2:8": ["ஏதோமைத் தாண்டிப் பயணம் செய்தல்", "இஸ்ரவேலர் ஏதோம் தேசத்தைத் தாண்டி, மோவாப் வனாந்தரத்தை நோக்கித் தங்கள் பயணத்தைத் தொடர்கிறார்கள்."],
    "Deuteronomy 2:9": ["மோவாபைத் தொந்தரவு செய்யாதிருத்தல்", "மோவாபின் தேசத்தை லோத்தின் சந்ததியினருக்குக் கொடுத்திருப்பதால், அவர்களுடன் போரிட வேண்டாம் என்று கர்த்தர் கட்டளையிடுகிறார்."],
    "Deuteronomy 2:13": ["சேரேத் பள்ளத்தாக்கைக் கடத்தல்", "புதிய சந்ததியினர் பயணத்தைத் தொடரும்போது, சேரேத் பள்ளத்தாக்கைக் கடந்து செல்லும்படி கர்த்தர் கூறுகிறார்."],
    "Deuteronomy 2:16": ["முதல் சந்ததியின் முடிவு", "வனாந்தரத்தில் பழைய சந்ததியினர் அனைவரும் இறந்த பிறகு, இஸ்ரவேலரை முன்னோக்கிச் செல்லும்படி கர்த்தர் பணிக்கிறார்."],
    "Deuteronomy 2:18": ["மோவாப் வழியாகக் கடத்தல்", "மோவாப் எல்லையைத் தாக்காமல் அதன் வழியாகக் கடந்து செல்லும்படி இஸ்ரவேலருக்குச் சொல்லப்படுகிறது."],
    "Deuteronomy 2:24": ["சீகோனுடன் போரிடக் கட்டளை", "அமோரியரின் ராஜாவான சீகோனை எதிர்த்துத் தேசத்தைச் சுதந்தரிக்கத் தொடங்கும்படி தேவன் கூறுகிறார்."],
    "Deuteronomy 2:26": ["மோசே சமாதானச் செய்தி அனுப்புதல்", "சீகோனின் தேசம் வழியாகச் சமாதானமாகச் செல்ல அனுமதி கேட்டு மோசே தூதர்களை அனுப்புகிறார்."],
    "Deuteronomy 2:30": ["சீகோன் சமாதானத்தை மறுத்தல்", "கர்த்தர் சீகோனின் இருதயத்தைக் கடினப்படுத்தியதால், அவன் இஸ்ரவேலரைச் செல்ல அனுமதிக்க மறுக்கிறான்."],
    "Deuteronomy 2:32": ["சீகோனின் தோல்வி", "இஸ்ரவேலர் சீகோனுடன் போரிட்டு அவனைத் தோற்கடித்து, அவனுடைய பட்டணங்களையும் தேசத்தையும் கைப்பற்றுகிறார்கள்."],

    "Deuteronomy 3:1": ["பாசான் ராஜா ஓக்கின் தோல்வி", "இஸ்ரவேலர் பாசானை நோக்கித் திரும்புகிறார்கள், கர்த்தர் பாசான் ராஜாவாகிய ஓக்கை அவர்கள் கையில் ஒப்புக்கொடுத்து, வெற்றியளிக்கிறார்."],
    "Deuteronomy 3:4": ["பாசான் பட்டணங்களைக் கைப்பற்றுதல்", "ஓக்கின் ராஜ்யத்திலிருந்த அனைத்து அரணான பட்டணங்களையும் இஸ்ரவேலர் கைப்பற்றி, பாசான் முழுவதையும் பிடிக்கிறார்கள்."],
    "Deuteronomy 3:8": ["யோர்தானுக்குக் கிழக்கே உள்ள நிலம் கைப்பற்றப்படல்", "யோர்தானுக்குக் கிழக்கே இருந்த சீகோன் மற்றும் ஓக்கின் தேசங்கள் இஸ்ரவேலரின் வசமாகின்றன."],
    "Deuteronomy 3:12": ["கிழக்குக் கோத்திரங்களுக்கு நிலம் வழங்கப்படல்", "யோர்தானுக்குக் கிழக்கே உள்ள நிலம் ரூபன், காத் மற்றும் மனாசேயின் பாதிக்கோத்திரத்தாருக்கு வழங்கப்படுகிறது."],
    "Deuteronomy 3:18": ["கிழக்குக் கோத்திரங்கள் உதவக் கட்டளை", "இந்தக் கோத்திரங்களின் போர்வீரர்கள் யோர்தானைக் கடந்து சென்று, மற்ற இஸ்ரவேலர்கள் தேசத்தைக் கைப்பற்ற உதவ வேண்டும் என்று மோசே நினைவூட்டுகிறார்."],
    "Deuteronomy 3:21": ["யோசுவாவுக்கு ஊக்கமளித்தல்", "கர்த்தர் இந்த ராஜாக்களைத் தோற்கடித்தது போலவே, இனிவரும் ராஜ்யங்களையும் தோற்கடிப்பார் என்று மோசே யோசுவாவிடம் கூறுகிறார்."],
    "Deuteronomy 3:23": ["தேசத்திற்குள் நுழைய மோசே வேண்டுதல்", "தான் யோர்தானைக் கடந்து, வாக்குத்தத்தம் பண்ணப்பட்ட அந்த நல்ல தேசத்தைப் பார்க்க அனுமதிக்குமாறு மோசே கர்த்தரிடம் வேண்டுகிறார்."],
    "Deuteronomy 3:26": ["மோசேயின் கோரிக்கையை தேவன் மறுத்தல்", "மோசே யோர்தானைக் கடக்க மாட்டார் என்றும், மலையின் உச்சியிலிருந்து தேசத்தைப் பார்க்க மட்டுமே முடியும் என்றும் கர்த்தர் கூறுகிறார்."],
    "Deuteronomy 3:28": ["யோசுவாவைத் தலைவராக உறுதிப்படுத்துதல்", "யோசுவா மக்களை வழிநடத்திச் செல்வார் என்பதால், அவரைத் திடப்படுத்தவும் ஊக்கப்படுத்தவும் மோசேக்குப் பணிக்கப்படுகிறது."],

    "Deuteronomy 4:1": ["தேவனுடைய சட்டங்களுக்குக் கீழ்ப்படிய அழைப்பு", "இஸ்ரவேலர் பிழைத்திருந்து, தேசத்திற்குள் நுழைவதற்காகக் கட்டளைகளுக்கும் நியாயங்களுக்கும் செவிகொடுத்து நடக்கும்படி மோசே வலியுறுத்துகிறார்."],
    "Deuteronomy 4:9": ["தேவன் செய்தவற்றை நினைவில் கொள்ளுதல்", "தாங்கள் கண்ட காரியங்களை மறக்காமலும், தங்கள் பிள்ளைகளுக்குத் தேவனுடைய கிரியைகளைக் கற்பிக்கும்படியும் மக்கள் எச்சரிக்கப்படுகிறார்கள்."],
    "Deuteronomy 4:15": ["விக்கிரகாராதனைக்கு எதிரான எச்சரிக்கை", "ஓரேப்பில் தேவன் பேசியபோது அவர்கள் எந்த உருவத்தையும் காணாததால், எந்தவொரு சிலையையோ உருவத்தையோ செய்யக்கூடாது என்று எச்சரிக்கப்படுகிறார்கள்."],
    "Deuteronomy 4:25": ["விக்கிரகாராதனையின் விளைவுகள்", "இஸ்ரவேலர் சிலைகளை வணங்கத் தொடங்கினால், அவர்கள் புறஜாதிகளுக்குள்ளே சிதறடிக்கப்படுவார்கள் என்று மோசே எச்சரிக்கிறார்."],
    "Deuteronomy 4:29": ["மறுசீரமைப்பு வாக்குத்தத்தம்", "சிதறடிக்கப்பட்ட பிறகு மக்கள் முழு இருதயத்தோடும் கர்த்தரைத் தேடினால், அவரைக் கண்டடைவார்கள்."],
    "Deuteronomy 4:32": ["தேவனுடைய மகத்துவம்", "வேறு எந்தத் தேசமும் இஸ்ரவேலரைப் போலத் தேவனுடைய வல்லமையான செயல்களை அனுபவித்ததில்லை என்பதை மோசே நினைவூட்டுகிறார்."],
    "Deuteronomy 4:41": ["யோர்தானுக்குக் கிழக்கே புகலிட நகரங்கள்", "தெரியாமல் கொலை செய்தவர்கள் தப்பி ஓடுவதற்காக யோர்தானுக்குக் கிழக்கே மூன்று புகலிட நகரங்களை மோசே பிரிக்கிறார்."],
    "Deuteronomy 4:44": ["நியாயப்பிரமாணத்தின் அறிமுகம்", "இந்தப் பகுதி மோசே இஸ்ரவேல் மக்களுக்கு முன்பாக வைத்த நியாயப்பிரமாணத்தை அறிமுகப்படுத்துகிறது."],

    "Deuteronomy 5:1": ["உடன்படிக்கையைக் கேட்க அழைப்பு", "மோசே இஸ்ரவேலர் அனைவரையும் கூட்டி, கர்த்தர் கொடுத்த கட்டளைகளையும் நியாயங்களையும் கேட்டுப் படிக்கும்படி அழைக்கிறார்."],
    "Deuteronomy 5:6": ["பத்துக் கட்டளைகள் அறிவிக்கப்படல்", "தாம் அவர்களை எகிப்திலிருந்து மீட்டதை நினைவுபடுத்தி, தேவன் தமது கட்டளைகளை அறிவிக்கத் தொடங்குகிறார்."],
    "Deuteronomy 5:7": ["அந்நிய தெய்வங்களுக்கு எதிரான கட்டளை", "இஸ்ரவேலர் கர்த்தரை மட்டுமே வழிபட வேண்டும், வேறு தெய்வங்கள் அவர்களுக்கு இருக்கக்கூடாது என்று கட்டளையிடப்படுகிறது."],
    "Deuteronomy 5:11": ["தேவனுடைய திருநாமம் குறித்த கட்டளை", "மக்கள் தங்கள் தேவனாகிய கர்த்தருடைய நாமத்தை வீணாக வழங்கக்கூடாது."],
    "Deuteronomy 5:12": ["ஓய்வுநாளைக் கடைப்பிடிக்கக் கட்டளை", "ஓய்வுநாளைப் பரிசுத்தமாக ஆசரிக்கும்படி இஸ்ரவேலருக்கு அறிவுறுத்தப்படுகிறது."],
    "Deuteronomy 5:16": ["பெற்றோரைக் கனம்பண்ணக் கட்டளை", "தேசத்தில் நீடித்து வாழும்படி பிள்ளைகள் தங்கள் தாய் தந்தையைக் கனம்பண்ண வேண்டும் என்று கட்டளையிடப்படுகிறது."],
    "Deuteronomy 5:17": ["மனித நடத்தைகள் குறித்த கட்டளைகள்", "கொலை, விபச்சாரம், களவு மற்றும் பொய்ச்சாட்சி ஆகியவற்றுக்கு எதிரான கட்டளைகளைத் தேவன் வழங்குகிறார்."],
    "Deuteronomy 5:21": ["இச்சை கொள்ளாமை குறித்த கட்டளை", "பிறருக்குரிய எதையும் மக்கள் இச்சிக்கக்கூடாது என்று எச்சரிக்கப்படுகிறார்கள்."],
    "Deuteronomy 5:22": ["மலையிலிருந்து தேவன் பேசுதல்", "அக்கினி, மேகம் மற்றும் அந்தகாரத்தின் நடுவிலிருந்து தேவன் இந்தக் கட்டளைகளை இஸ்ரவேலர் அனைவருக்கும் பேசினார்."],
    "Deuteronomy 5:23": ["தேவனுடைய சத்தத்திற்கு மக்கள் அஞ்சுதல்", "தேவனுடைய சத்தத்தை நேரடியாகக் கேட்க அஞ்சி, மோசே தங்களுக்குப் பதிலாகத் தேவனிடம் பேசும்படி தலைவர்கள் கேட்டுக்கொள்கிறார்கள்."],
    "Deuteronomy 5:28": ["மக்களின் பக்தியைத் தேவன் மெச்சுதல்", "மக்கள் தமக்கு அஞ்சிய விதத்தை தேவன் அங்கீகரித்து, அவர்கள் எப்போதும் தம் கட்டளைகளைக் கைக்கொள்ள வேண்டும் என்று விரும்புகிறார்."],
    "Deuteronomy 5:31": ["மோசே நியாயப்பிரமாணத்தைப் பெறுதல்", "இஸ்ரவேலருக்குக் கற்பிக்கும் பொருட்டு, மோசே அங்கேயே தங்கி எல்லாக் கட்டளைகளையும் பெற்றுக்கொள்ளும்படி தேவன் கூறுகிறார்."],

    "Deuteronomy 6:1": ["கட்டளைகளுக்குக் கீழ்ப்படிய அழைப்பு", "இஸ்ரவேலர் கர்த்தருக்கு அஞ்சி, நீடித்து வாழ்ந்து, தேசத்தில் செழிக்க வேண்டும் என்பதற்காகவே இந்தக் கட்டளைகள் கொடுக்கப்பட்டுள்ளன என்று மோசே நினைவூட்டுகிறார்."],
    "Deuteronomy 6:4": ["கர்த்தர் ஒருவரே", "கர்த்தர் ஒருவரே தேவன் என்பதை இஸ்ரவேலர் கேட்கும்படி அழைக்கப்படுகிறார்கள் (ஷேமா)."],
    "Deuteronomy 6:5": ["கர்த்தரிடத்தில் முழுமையாக அன்பு கூருதல்", "மக்கள் தங்கள் முழு இருதயத்தோடும், முழு ஆத்துமாவோடும், முழு பலத்தோடும் தங்கள் தேவனாகிய கர்த்தரிடத்தில் அன்பு கூர வேண்டும் என்று கட்டளையிடப்படுகிறார்கள்."],
    "Deuteronomy 6:6": ["தேவனுடைய வார்த்தைகளைக் கவனமாகக் கற்பித்தல்", "தேவனுடைய கட்டளைகள் இருதயத்தில் இருக்க வேண்டும், மேலும் அவை பிள்ளைகளுக்குக் கருத்தாகக் கற்பிக்கப்பட வேண்டும்."],
    "Deuteronomy 6:10": ["கர்த்தரை மறக்க வேண்டாம் என்ற எச்சரிக்கை", "தேசத்தில் செழிப்பாக இருக்கும்போது, தங்களை எகிப்திலிருந்து மீட்ட கர்த்தரை இஸ்ரவேலர் மறந்துவிடக்கூடாது."],
    "Deuteronomy 6:13": ["கர்த்தருக்கு அஞ்சி அவருக்குச் சேவை செய்தல்", "மக்கள் கர்த்தருக்கு அஞ்சி, அவருக்கு மட்டுமே சேவை செய்ய வேண்டும், மேலும் அவருடைய நாமத்திலே ஆணையிட வேண்டும்."],
    "Deuteronomy 6:16": ["கர்த்தரைச் சோதிக்காதிருத்தல்", "மாசாவிலே செய்தது போல இஸ்ரவேலர் கர்த்தரைச் சோதிக்கக்கூடாது."],
    "Deuteronomy 6:20": ["வருங்கால சந்ததியினருக்குக் கற்பித்தல்", "பிள்ளைகள் இந்தக் கட்டளைகளைப் பற்றிக் கேட்கும்போது, கர்த்தர் எவ்வாறு தங்களை எகிப்திலிருந்து மீட்டு நியாயப்பிரமாணத்தைக் கொடுத்தார் என்பதைப் பெற்றோர்கள் விளக்க வேண்டும்."],

    "Deuteronomy 7:1": ["புறஜாதிகளைத் துரத்திவிடுதல்", "இஸ்ரவேலரைத் தேசத்திற்குள் அழைத்துச் செல்வதாகக் கர்த்தர் வாக்குறுதி அளித்து, சுற்றியுள்ள ஜாதிகளைத் துரத்திவிடும்படி கட்டளையிடுகிறார்."],
    "Deuteronomy 7:2": ["விக்கிரகாராதனையை முழுமையாக அழித்தல்", "இஸ்ரவேலர் அந்த ஜாதிகளுடன் உடன்படிக்கை செய்யவோ அல்லது இரக்கம் காட்டவோ கூடாது, மாறாக அவர்களின் சிலைகளை அழிக்க வேண்டும்."],
    "Deuteronomy 7:3": ["அந்நிய விவாகம் செய்யாதிருத்தல்", "அந்நிய ஜாதிகளுடன் திருமணம் செய்வது மக்களின் இருதயத்தைத் தேவனை விட்டு விலகச் செய்யும் என்பதால் அவ்வாறு செய்யக்கூடாது என்று எச்சரிக்கப்படுகிறார்கள்."],
    "Deuteronomy 7:6": ["தெரிந்துகொள்ளப்பட்ட பரிசுத்த மக்கள்", "சகல ஜனங்களிலும் இஸ்ரவேலர் தமக்குச் சொந்தமான ஜனமாயிருக்கும்படி கர்த்தரால் தெரிந்துகொள்ளப்பட்டிருக்கிறார்கள்."],
    "Deuteronomy 7:7": ["தேவனுடைய அன்பினால் தெரிந்துகொள்ளப்பட்டவர்கள்", "இஸ்ரவேலர் எண்ணிக்கையில் அதிகமானவர்கள் என்பதால் அல்ல, கர்த்தர் அவர்கள் மேல் அன்பு கூர்ந்ததாலேயே அவர்களைத் தெரிந்துகொண்டார்."],
    "Deuteronomy 7:9": ["தேவன் தமது உடன்படிக்கையில் உண்மையுள்ளவர்", "தம்மிடம் அன்பு கூர்ந்து தமது கட்டளைகளைக் கைக்கொள்ளுகிறவர்களுக்குக் கர்த்தர் ஆயிரம் தலைமுறை வரை உடன்படிக்கையையும் கிருபையையும் காக்கிறார்."],
    "Deuteronomy 7:12": ["கீழ்ப்படிதலுக்கான ஆசீர்வாதங்கள்", "இஸ்ரவேலர் தேவனுடைய கட்டளைகளுக்குக் கீழ்ப்படிந்தால், அவர் அவர்களை ஆசீர்வதித்து தேசத்தில் பெருகச் செய்வார்."],
    "Deuteronomy 7:17": ["ஜாதிகளுக்கு அஞ்சாதிருத்தல்", "தங்களை விடப் பலமான ஜாதிகளைக் கண்டு இஸ்ரவேலர் பயப்படக்கூடாது, ஏனெனில் கர்த்தர் அவர்களைத் தோற்கடிப்பார்."],
    "Deuteronomy 7:20": ["தேவன் அனுப்பும் திகிலும் குளவிகளும்", "எதிரிகள் அழியும் வரை கர்த்தர் அவர்களுக்குள்ளே திகிலையும் குளவிகளையும் அனுப்பி அவர்களைத் துரத்துவார்."],
    "Deuteronomy 7:22": ["படிப்படியாக தேசத்தைக் கைப்பற்றுதல்", "தேசம் பாழாகாதபடிக்கு, தேவன் அந்த ஜாதிகளைக் கொஞ்சம் கொஞ்சமாகத் துரத்திவிடுவார்."],
    "Deuteronomy 7:25": ["சிலைகளை அழித்தல்", "இஸ்ரவேலர் அந்த ஜாதிகளின் சிலைகளைச் சுட்டெரிக்க வேண்டும், அவற்றின் மேல் உள்ள வெள்ளி அல்லது பொன்னை இச்சிக்கக்கூடாது."],
    "Deuteronomy 7:26": ["அருவருப்பானவற்றைத் தவிர்த்தல்", "அருவருப்பான எதையும் மக்கள் தங்கள் வீட்டிற்குள் கொண்டு வரக்கூடாது, அவற்றை முற்றிலும் வெறுக்க வேண்டும்."],

    "Deuteronomy 8:1": ["தேவனுடைய கட்டளைகளை நினைத்து நடத்தல்", "இஸ்ரவேலர் பிழைத்திருந்து வாக்குத்தத்தம் பண்ணப்பட்ட தேசத்தைச் சுதந்தரிக்கத் தேவனுடைய கட்டளைகளுக்குக் கவனமாகக் கீழ்ப்படியும்படி மோசே வலியுறுத்துகிறார்."],
    "Deuteronomy 8:2": ["வனாந்தரத்தில் தேவன் இஸ்ரவேலைச் சோதித்தல்", "மக்களைச் சிறுமைப்படுத்தவும் சோதிக்கவும் கர்த்தர் அவர்களை நாற்பது ஆண்டுகள் வனாந்தரத்தில் வழிநடத்தினார்."],
    "Deuteronomy 8:3": ["தேவன் மன்னாவை வழங்கியது", "மனுஷன் அப்பத்தினால் மாத்திரமல்ல, கர்த்தருடைய வாயிலிருந்து புறப்படுகிற ஒவ்வொரு வார்த்தையினாலும் பிழைப்பான் என்பதைக் கற்பிக்கத் தேவன் அவர்களுக்கு மன்னாவை உணவாக அளித்தார்."],
    "Deuteronomy 8:4": ["தேவன் அவர்களைப் பராமரித்தது", "அந்த நாற்பது ஆண்டுகளில் அவர்கள் உடுத்திய வஸ்திரம் பழையாகிப் போகவில்லை, அவர்கள் கால் வீங்கவுமில்லை."],
    "Deuteronomy 8:5": ["தந்தை போல தேவன் சிட்சிக்கிறார்", "ஒரு தந்தை தன் மகனைச் சிட்சிக்கிறது போல, கர்த்தர் தம் மக்களைச் சிட்சிக்கிறார்."],
    "Deuteronomy 8:7": ["வாக்குத்தத்தம் பண்ணப்பட்ட நல்ல தேசம்", "நீர்நிலைகளும், பயிர்களும், வளமான வளங்களும் கொண்ட ஒரு நல்ல தேசத்திற்குள் கர்த்தர் இஸ்ரவேலை அழைத்துச் செல்கிறார்."],
    "Deuteronomy 8:10": ["தேவனுக்கு நன்றி சொல்ல நினைவில் கொள்க", "சாப்பிட்டுத் திருப்தியடைந்த பிறகு, அந்த நல்ல தேசத்திற்காக மக்கள் கர்த்தரை ஸ்தோத்திரிக்க வேண்டும்."],
    "Deuteronomy 8:11": ["தேவனை மறக்க வேண்டாம் என எச்சரிக்கை", "தேவனுடைய கட்டளைகளைக் கைக்கொள்ளத் தவறுவதன் மூலம் கர்த்தரை மறந்துவிடக்கூடாது என்று எச்சரிக்கப்படுகிறார்கள்."],
    "Deuteronomy 8:12": ["செல்வச் செழிப்பில் வரும் அகங்காரத்தின் ஆபத்து", "வாழ்வில் செழிப்பு வரும்போது, மக்கள் தங்கள் இருதயம் மேட்டிமையாகாதபடி பார்த்துக் கொள்ள வேண்டும்."],
    "Deuteronomy 8:17": ["தேவனே செல்வத்தைத் தருகிறார்", "தங்கள் சொந்தப் பலத்தினால் இந்தச் செல்வம் வந்தது என்று மக்கள் சொல்லக்கூடாது, ஏனெனில் செல்வத்தைப் பெறுவதற்கான ஆற்றலைத் தேவனே தருகிறார்."],
    "Deuteronomy 8:19": ["தேவனை மறந்தால் வரும் தண்டனை", "இஸ்ரவேலர் கர்த்தரை மறந்து அந்நிய தெய்வங்களைப் பின்பற்றினால், அவர்கள் நிச்சயமாக அழிந்து போவார்கள்."],

    "Deuteronomy 9:1": ["இஸ்ரவேலர் யோர்தானைக் கடத்தல்", "தங்களை விடப் பலமுள்ள ஜாதிகளைத் துரத்திவிட இஸ்ரவேலர் யோர்தானைக் கடக்கப்போகிறார்கள் என்று மோசே கூறுகிறார்."],
    "Deuteronomy 9:4": ["இஸ்ரவேலின் நீதியினிமித்தம் அல்ல", "தங்கள் நீதியினிமித்தம் இந்தத் தேசம் தங்களுக்குக் கிடைக்கிறது என்று மக்கள் நினைக்கக்கூடாது, அந்த ஜாதிகளின் அக்கிரமத்தினிமித்தமே தேவன் அவர்களைத் துரத்துகிறார்."],
    "Deuteronomy 9:6": ["வணங்காக்கழுத்துள்ள ஜனங்கள்", "இஸ்ரவேலர் பிடிவாதமுள்ள ஜனங்கள் என்றும், அவர்கள் தங்கள் நற்குணத்தினால் இந்தத் தேசத்தைப் பெறவில்லை என்றும் மோசே நினைவூட்டுகிறார்."],
    "Deuteronomy 9:7": ["கலகத்தை நினைவில் கொள்க", "வனாந்தரத்தில் தாங்கள் அடிக்கடி கர்த்தருக்குக் கோபமூட்டியதை நினைவில் கொள்ளும்படி இஸ்ரவேலருக்குச் சொல்லப்படுகிறது."],
    "Deuteronomy 9:9": ["சீனாய் மலையில் மோசே", "உடன்படிக்கைப் பலகைகளைப் பெறுவதற்காகத் தான் மலையின் மேல் ஏறி, நாற்பது பகலும் நாற்பது இரவும் உபவாசம் இருந்ததை மோசே விவரிக்கிறார்."],
    "Deuteronomy 9:12": ["பொற்கன்றுக்குட்டி பாவம்", "மோசே மலையில் இருந்தபோதே, மக்கள் சீக்கிரமாய் வழிவிலகித் தங்களுக்கு ஒரு வார்ப்பிக்கப்பட்ட கன்றுக்குட்டியைச் செய்தார்கள்."],
    "Deuteronomy 9:15": ["உடைக்கப்பட்ட பலகைகள்", "மோசே மலையிலிருந்து இறங்கி மக்களின் பாவத்தைக் கண்டு, உடன்படிக்கைப் பலகைகளைத் தூக்கி எறிந்து உடைத்தார்."],
    "Deuteronomy 9:18": ["இஸ்ரவேலுக்காக மோசே பரிந்து பேசுதல்", "மக்களின் பாவத்தினிமித்தம் மோசே நாற்பது பகலும் நாற்பது இரவும் கர்த்தருடைய சமூகத்தில் விழுந்து கிடந்து ஜெபித்தார்."],
    "Deuteronomy 9:20": ["ஆரோனின் பாவமும் மோசேயின் ஜெபமும்", "ஆரோன் செய்த பாவத்தினிமித்தம் கர்த்தர் அவர் மேல் கோபமாயிருந்தார், ஆனால் மோசே அவனுக்காகவும் ஜெபித்தார்."],
    "Deuteronomy 9:22": ["இஸ்ரவேலின் தொடர் கலகம்", "தபேரா, மாசா, கிப்ரோத்-அத்தாவா ஆகிய இடங்களிலும் அவர்கள் கர்த்தருக்குக் கோபமூட்டியதை மோசே நினைவூட்டுகிறார்."],
    "Deuteronomy 9:25": ["இரக்கத்திற்காக மோசே கெஞ்சுதல்", "தம் ஜனங்களை அழிக்க வேண்டாம் என்று மோசே மீண்டும் கர்த்தரிடம் பரிந்து பேசினார்."],
    "Deuteronomy 9:26": ["தேவனுடைய உடன்படிக்கையை நினைவூட்டுதல்", "ஆபிரகாம், ஈசாக்கு, யாக்கோபு ஆகியோருக்குச் செய்த வாக்குறுதியை நினைத்து இஸ்ரவேலை மன்னிக்கும்படி மோசே வேண்டினார்."],

    "Deuteronomy 10:1": ["புதிய உடன்படிக்கைப் பலகைகள்", "இரண்டு புதிய கற்பலகைகளைச் செதுக்கிக்கொண்டு மீண்டும் மலையின் மேல் வரும்படி கர்த்தர் மோசேயிடம் கூறுகிறார்."],
    "Deuteronomy 10:3": ["மீண்டும் நியாயப்பிரமாணத்தைப் பெறுதல்", "மோசே பலகைகளைச் செய்து மலையின் மேல் ஏறுகிறார், அங்கே கர்த்தர் மீண்டும் பத்துக் கட்டளைகளை எழுதுகிறார்."],
    "Deuteronomy 10:6": ["ஆரோனின் மரணமும் ஆசாரியத்துவத் தொடர்ச்சியும்", "ஆரோன் மரிக்கிறார், அவருக்குப் பதிலாக அவருடைய மகன் எலெயாசார் ஆசாரியராகிறார்."],
    "Deuteronomy 10:8": ["லேவி கோத்திரம் பிரிக்கப்படல்", "உடன்படிக்கைப் பெட்டியைச் சுமக்கவும் கர்த்தருக்குப் பணிவிடை செய்யவும் லேவி கோத்திரத்தைக் கர்த்தர் பிரித்தெடுத்தார்."],
    "Deuteronomy 10:10": ["மோசேயின் ஜெபத்தைக் கர்த்தர் கேட்டார்", "மோசே நாற்பது பகலும் இரவும் மலையில் இருந்தார், கர்த்தர் மீண்டும் இஸ்ரவேலை அழிக்காதிருக்கச் சித்தமானார்."],
    "Deuteronomy 10:12": ["கர்த்தர் விரும்புவது என்ன?", "கர்த்தருக்கு அஞ்சி, அவருடைய வழிகளில் நடந்து, அவரிடத்தில் அன்பு கூர்ந்து, முழு இருதயத்தோடும் அவருக்குச் சேவை செய்வதையே தேவன் எதிர்பார்க்கிறார் என்று மோசே கூறுகிறார்."],
    "Deuteronomy 10:14": ["வானமும் பூமியும் தேவனுக்குரியவை", "வானங்களும் பூமியும் கர்த்தருக்கே சொந்தமானவை, இருப்பினும் அவர் இஸ்ரவேலைத் தெரிந்துகொண்டார்."],
    "Deuteronomy 10:16": ["இருதய விருத்தசேதனம்", "மக்கள் தங்கள் இருதயத்தைச் சீர்ப்படுத்தி, பிடிவாதத்தைக் கைவிட வேண்டும் என்று வலியுறுத்தப்படுகிறார்கள்."],
    "Deuteronomy 10:17": ["தேவன் பெரியவரும் நீதியுள்ளவருமானவர்", "கர்த்தர் தேவாதி தேவனாயிருக்கிறார்; அவர் பட்சபாதம் காட்டாதவர், லஞ்சம் வாங்காதவர்."],
    "Deuteronomy 10:18": ["எளியவர்கள் மேல் தேவன் காட்டும் அக்கறை", "தேவன் திக்கற்ற பிள்ளைகளுக்கும் விதவைகளுக்கும் நியாயம் செய்கிறார், அந்நியரை நேசிக்கிறார்."],
    "Deuteronomy 10:19": ["அந்நியரை நேசியுங்கள்", "இஸ்ரவேலர் எகிப்தில் அந்நியர்களாய் இருந்ததால், அவர்களும் அந்நியரை நேசிக்க வேண்டும் என்று கட்டளையிடப்படுகிறார்கள்."],
    "Deuteronomy 10:20": ["கர்த்தருக்கு அஞ்சி அவருக்குச் சேவை செய்", "மக்கள் கர்த்தருக்கு அஞ்சி, அவருக்குச் சேவை செய்து, அவரை உறுதியாகப் பற்றிக்கொள்ள அழைக்கப்படுகிறார்கள்."],

    "Deuteronomy 11:1": ["கர்த்தரை நேசித்துக் கீழ்ப்படிதல்", "இஸ்ரவேலர் கர்த்தரிடத்தில் அன்பு கூர்ந்து, அவருடைய கட்டளைகளையும் நியாயங்களையும் எக்காலமும் கைக்கொள்ள வேண்டும்."],
    "Deuteronomy 11:2": ["தேவனுடைய வல்லமையான கிரியைகளை நினைவுகூர்தல்", "தாங்கள் நேரில் கண்ட கர்த்தருடைய மகத்துவத்தையும் கிரியைகளையும் நினைவில் கொள்ளும்படி மோசே கூறுகிறார்."],
    "Deuteronomy 11:8": ["கீழ்ப்படிதலின் மூலம் வரும் பலம்", "தேவனுடைய கட்டளைகளைக் கைக்கொள்வது, இஸ்ரவேலர் தேசத்திற்குள் நுழைந்து அதைச் சுதந்தரிக்க அவர்களுக்குப் பலத்தைத் தரும்."],
    "Deuteronomy 11:10": ["தேவன் கொடுக்கும் தேசம்", "வாக்குத்தத்தம் பண்ணப்பட்ட தேசம் எகிப்தைப் போன்றது அல்ல, அது வானத்தின் மழையினால் தண்ணீர் குடிக்கும் தேசம்."],
    "Deuteronomy 11:13": ["தேவனை நேசிப்பதற்கான ஆசீர்வாதங்கள்", "இஸ்ரவேலர் முழு இருதயத்தோடும் கர்த்தரை நேசித்துச் சேவை செய்தால், அவர் ஏற்ற காலத்தில் மழையைத் தந்து அறுவடையை ஆசீர்வதிப்பார்."],
    "Deuteronomy 11:16": ["விக்கிரகாராதனைக்கு எதிரான எச்சரிக்கை", "மக்கள் வழிவிலகி அந்நிய தெய்வங்களை வழிபடாதபடி எச்சரிக்கப்படுகிறார்கள்."],
    "Deuteronomy 11:18": ["தேவனுடைய வார்த்தையை வாழ்வாக்குதல்", "தேவனுடைய வார்த்தைகளை இருதயத்தில் பதித்து, பிள்ளைகளுக்குப் போதித்து, அன்றாடம் அவற்றை நினைவில் கொள்ள வேண்டும்."],
    "Deuteronomy 11:22": ["வெற்றிக்கான வாக்குறுதி", "இஸ்ரவேலர் கர்த்தருக்குக் கவனமாகக் கீழ்ப்படிந்தால், அவர் அவர்களுக்கு முன்பாக இருக்கும் ஜாதிகளைத் துரத்திவிடுவார்."],
    "Deuteronomy 11:24": ["வாக்குத்தத்தம் பண்ணப்பட்ட தேசத்தின் எல்லைகள்", "இஸ்ரவேலரின் உள்ளங்கால் மிதிக்கும் இடமெல்லாம் தேவன் வாக்குறுதி அளித்தபடி அவர்களுக்குச் சொந்தமாகும்."],
    "Deuteronomy 11:26": ["ஆசீர்வாதமும் சாபமும்", "கீழ்ப்படிதலுக்கு ஆசீர்வாதத்தையும், கீழ்ப்படியாமைக்குச் சாபத்தையும் மோசே மக்கள் முன் வைக்கிறார்."],
    "Deuteronomy 11:29": ["கெரிசீம் மலை மற்றும் ஏபால் மலை", "கெரிசீம் மலையில் ஆசீர்வாதங்களையும், ஏபால் மலையில் சாபங்களையும் கூற வேண்டும்."],

    "Deuteronomy 12:1": ["அந்நிய வழிபாட்டுத் தலங்களை அழித்தல்", "புறஜாதிகள் தங்கள் தெய்வங்களை வழிபட்ட இடங்களை இஸ்ரவேலர் முற்றிலும் அழிக்க வேண்டும்."],
    "Deuteronomy 12:4": ["தேவன் தெரிந்து கொள்ளும் இடத்திலேயே வழிபாடு", "புறஜாதிகளைப் போல வழிபடாமல், கர்த்தர் தெரிந்து கொள்ளும் குறிப்பிட்ட இடத்திலேயே மக்கள் ஆராதனை செய்ய வேண்டும்."],
    "Deuteronomy 12:8": ["தன் இஷ்டப்படி செய்யாதிருத்தல்", "இஸ்ரவேலர் தங்கள் பார்வைக்குச் சரி என்று தோன்றுகிறபடி செய்யாமல், தேவனுடைய கட்டளைகளுக்குக் கீழ்ப்படிய வேண்டும்."],
    "Deuteronomy 12:10": ["வாக்குத்தத்தம் பண்ணப்பட்ட தேசத்தில் இளைப்பாறுதல்", "கர்த்தர் தேசத்தில் இளைப்பாறுதலைத் தரும்போது, அவர் தெரிந்து கொள்ளும் இடத்திற்குத் தங்கள் காணிக்கைகளைக் கொண்டு வர வேண்டும்."],
    "Deuteronomy 12:13": ["குறிப்பிட்ட இடத்தில் பலியிடுதல்", "தோன்றிய இடமெல்லாம் சர்வாங்க தகனபலிகளை இடாமல், கர்த்தர் நியமிக்கும் இடத்திலேயே பலியிட வேண்டும்."],
    "Deuteronomy 12:15": ["மாமிசம் உண்ணும் சுதந்திரம்", "சுத்தமானவர்களும் அசுத்தமானவர்களும் கர்த்தருடைய ஆசீர்வாதத்தின்படி தங்கள் ஊர்களில் மாமிசம் புசிக்கலாம்."],
    "Deuteronomy 12:20": ["எல்லைகள் விரிவடையும்போது", "கர்த்தர் எல்லையை விரிவுபடுத்தும்போது, மக்கள் தங்கள் விருப்பப்படி மாமிசம் புசிக்கலாம்."],
    "Deuteronomy 12:23": ["இரத்தத்தைப் புசிக்க வேண்டாம்", "இரத்தம் உயிராயிருப்பதால், எக்காரணத்தைக் கொண்டும் இரத்தத்தைப் புசிக்கக்கூடாது."],
    "Deuteronomy 12:29": ["விக்கிரகாராதனைக்கு எதிரான எச்சரிக்கை", "ஜாதிகளைத் துரத்திய பிறகு, அவர்களின் வழிபாட்டு முறைகளைப் பின்பற்றிச் சிக்கிக் கொள்ளக்கூடாது."],
    "Deuteronomy 12:32": ["கூட்டவோ குறைக்கவோ கூடாது", "தேவனுடைய கட்டளைகளுடன் எதையும் கூட்டவோ அதிலிருந்து எதையும் குறைக்கவோ செய்யாமல் கவனமாக நடக்க வேண்டும்."],

    "Deuteronomy 13:1": ["கள்ளத்தீர்க்கதரிசிகள் குறித்த எச்சரிக்கை", "ஒரு தீர்க்கதரிசி அடையாளம் காட்டினாலும், அவன் அந்நிய தெய்வங்களை வழிபடச் சொன்னால் அவனுக்குச் செவிகொடுக்கக்கூடாது."],
    "Deuteronomy 13:3": ["தேவன் காட்டும் சோதனை", "தங்கள் ஜனங்கள் தம்மை முழு இருதயத்தோடும் நேசிக்கிறார்களா என்பதை அறியவே கர்த்தர் இத்தகைய சோதனைகளை அனுமதிக்கிறார்."],
    "Deuteronomy 13:5": ["கள்ளத்தீர்க்கதரிசிகளுக்குத் தண்டனை", "இஸ்ரவேலரைத் தேவனை விட்டு விலகச் செய்யும் தீர்க்கதரிசிக்கு மரணதண்டனை விதிக்கப்பட வேண்டும்."],
    "Deuteronomy 13:6": ["உறவினர்கள் விக்கிரகாராதனைக்குத் தூண்டினால்", "நெருங்கிய உறவினர்களே ரகசியமாக அந்நிய தெய்வங்களை வணங்கத் தூண்டினாலும் அவர்களுக்கு இணங்கக்கூடாது."],
    "Deuteronomy 13:9": ["தீமையை அகற்றுதல்", "விக்கிரகாராதனைக்குத் தூண்டுகிறவர்களைத் தண்டிப்பதன் மூலம் சமூகத்திலிருந்து தீமையை அகற்ற வேண்டும்."],
    "Deuteronomy 13:12": ["விக்கிரகாராதனையில் வீழ்ந்த பட்டணங்கள்", "ஏதாவது ஒரு பட்டணம் அந்நிய தெய்வ வழிபாட்டிற்குத் திரும்பினால், அதைப்பற்றிக் கவனமாக விசாரணை செய்ய வேண்டும்."],
    "Deuteronomy 13:15": ["கெட்டுப்போன பட்டணத்திற்குத் தீர்ப்பு", "விசாரணையில் அது உண்மை என்று தெரிந்தால், அந்தப் பட்டணத்தை முற்றிலும் அழித்துவிட வேண்டும்."],
    "Deuteronomy 13:17": ["தண்டனைக்குப் பின் தேவனுடைய இரக்கம்", "இஸ்ரவேலர் தீமையை அகற்றித் தேவனுக்குக் கீழ்ப்படிந்தால், அவர் அவர்கள் மேல் இரக்கம் காட்டி ஆசீர்வதிப்பார்."],

    "Deuteronomy 14:1": ["இஸ்ரவேல் தேவனுடைய பரிசுத்த ஜனங்கள்", "இஸ்ரவேலர் கர்த்தருடைய பிள்ளைகள் என்பதால், புறஜாதிகளின் துக்க ஆசாரங்களைப் பின்பற்றக்கூடாது."],
    "Deuteronomy 14:3": ["சுத்தமான மற்றும் அசுத்தமான உணவுகள்", "அருவருப்பான எதையும் புசிக்கக்கூடாது என்று மக்களுக்குக் கட்டளையிடப்படுகிறது."],
    "Deuteronomy 14:4": ["புசிக்கத்தக்க விலங்குகள்", "மாடு, ஆடு, மான் போன்ற குறிப்பிட்ட விலங்குகளை உணவாகக் கொள்ளலாம்."],
    "Deuteronomy 14:6": ["சுத்தமான விலங்குகளின் அடையாளங்கள்", "வெட்டப்பட்ட குளம்புள்ளவைகளும் அசைபோடுகிறவைகளுமான விலங்குகளைப் புசிக்கலாம்."],
    "Deuteronomy 14:9": ["சுத்தமான மற்றும் அசுத்தமான நீர்வாழ்வன", "செதில்களும் துடுப்புகளும் உள்ள நீர்வாழ்வனவற்றைப் புசிக்கலாம்."],
    "Deuteronomy 14:11": ["சுத்தமான பறவைகள்", "சுத்தமான பறவைகளைப் புசிக்கலாம், ஆனால் குறிப்பிட்ட சில பறவைகள் விலக்கப்பட்டுள்ளன."],
    "Deuteronomy 14:21": ["பிற ஜாதிகளிலிருந்து பிரிக்கப்பட்ட இஸ்ரவேல்", "தானாகச் செத்ததைப் புசிக்கக்கூடாது, அதை அந்நியர்களுக்குக் கொடுக்கலாம்."],
    "Deuteronomy 14:22": ["விளைச்சலில் தசமபாகம்", "ஒவ்வொரு ஆண்டும் விளைச்சலில் பத்திலொரு பங்கைப் பிரித்து வைக்க வேண்டும்."],
    "Deuteronomy 14:23": ["தசமபாகத்தின் நோக்கம்", "தசமபாகம் செலுத்துவது மக்கள் எக்காலமும் தங்கள் தேவனாகிய கர்த்தருக்கு அஞ்சக் கற்றுக்கொள்ள உதவும்."],
    "Deuteronomy 14:28": ["எளியவர்களுக்கான தசமபாகம்", "ஒவ்வொரு மூன்றாம் ஆண்டும் தசமபாகம் லேவியர்கள், அந்நியர்கள், திக்கற்றவர்கள் மற்றும் விதவைகளை ஆதரிக்கச் சேமிக்கப்பட வேண்டும்."],

    "Deuteronomy 15:1": ["கடன்களை ரத்து செய்யும் ஆண்டு", "ஒவ்வொரு ஏழு ஆண்டுகளுக்கும் ஒருமுறை இஸ்ரவேலர்கள் தங்கள் மக்களுக்குள்ளே இருக்கும் கடன்களை ரத்து செய்ய வேண்டும்."],
    "Deuteronomy 15:3": ["அந்நிய நாட்டு கடன்கள் தொடரலாம்", "அந்நியர்களிடம் உள்ள கடன்கள் அப்படியே இருக்கலாம், ஆனால் இஸ்ரவேலர்களுக்கு இடையே உள்ள கடன்கள் மன்னிக்கப்பட வேண்டும்."],
    "Deuteronomy 15:4": ["உங்களுக்குள் ஏழைகள் இருக்கமாட்டார்கள்", "இஸ்ரவேலர் கர்த்தருக்குக் கீழ்ப்படிந்தால், தேவன் அவர்களை ஆசீர்வதிப்பதினால் அவர்களுக்குள் ஏழைகள் இருக்கமாட்டார்கள்."],
    "Deuteronomy 15:7": ["ஏழைகள் மீது அக்கறை கொள்ளுதல்", "மக்கள் ஏழைகளுக்கு எதிராகத் தங்கள் இருதயத்தைக் கடினப்படுத்தாமல், தாராள மனதுடன் இருக்க வேண்டும்."],
    "Deuteronomy 15:10": ["தாராளமாகக் கொடுத்தல்", "தேவையுள்ளவர்களுக்குத் தாராளமாகத் தர வேண்டும், ஏனெனில் கர்த்தர் அவர்கள் செய்யும் வேலையை ஆசீர்வதிப்பார்."],
    "Deuteronomy 15:12": ["எபிரெய வேலைக்காரர்களை விடுவித்தல்", "ஒரு எபிரெய வேலைக்காரன் ஆறு ஆண்டுகள் பணியாற்றிய பிறகு ஏழாம் ஆண்டில் விடுவிக்கப்பட வேண்டும்."],
    "Deuteronomy 15:13": ["விடுதலையான வேலைக்காரருக்கு வழங்குதல்", "ஒரு வேலைக்காரனை விடுவிக்கும்போது, எஜமான் தனது மந்தை மற்றும் அறுவடையிலிருந்து அவருக்குத் தாராளமாக வழங்க வேண்டும்."],
    "Deuteronomy 15:16": ["வேலைக்காரன் தங்கியிருக்க விரும்புதல்", "ஒரு வேலைக்காரன் தன் எஜமான் மேல் உள்ள அன்பினால் அங்கேயே தங்கியிருக்க விரும்பினால், நிரந்தரப் பணிக்கு அடையாளமாக அவனுடைய காது துளைக்கப்பட வேண்டும்."],
    "Deuteronomy 15:19": ["தலைச்சன் மிருகங்கள் தேவனுக்குரியவை", "கால்நடைகளின் தலைச்சன் குட்டிகள் கர்த்தருக்குப் பிரதிஷ்டை செய்யப்பட வேண்டும்."],
    "Deuteronomy 15:21": ["பழுதற்ற காணிக்கைகள் மட்டுமே", "குறைபாடுள்ள விலங்குகளைக் கர்த்தருக்குப் பலியிடக்கூடாது, ஆனால் அவற்றை உணவாக உட்கொள்ளலாம்."],

    "Deuteronomy 16:1": ["பஸ்கா பண்டிகை ஆசரிப்பு", "கர்த்தர் தங்களை எகிப்திலிருந்து எவ்வாறு வெளியே கொண்டு வந்தார் என்பதை நினைவுகூர இஸ்ரவேலர் பஸ்கா பண்டிகையைக் கொண்டாட வேண்டும்."],
    "Deuteronomy 16:9": ["வாரங்களின் பண்டிகை", "அறுவடை தொடங்கிய ஏழு வாரங்களுக்குப் பிறகு, மக்கள் கர்த்தருக்கு முன்பாக மகிழ்ச்சியுடன் வாரங்களின் பண்டிகையைக் கொண்டாட வேண்டும்."],
    "Deuteronomy 16:13": ["கூடாரப் பண்டிகை", "விளைச்சலைச் சேகரித்த பிறகு, இஸ்ரவேலர் ஏழு நாட்கள் கூடாரப் பண்டிகையைக் கொண்டாட வேண்டும்."],
    "Deuteronomy 16:16": ["மூன்று வருடாந்திர பண்டிகைகள்", "இஸ்ரவேல் ஆண்கள் அனைவரும் ஆண்டுக்கு மூன்று முறை கர்த்தர் தெரிந்து கொள்ளும் இடத்தில் அவர் சமூகத்தில் வர வேண்டும்."],
    "Deuteronomy 16:18": ["நியாயாதிபதிகளையும் அதிகாரிகளையும் நியமித்தல்", "மக்களை நீதியுடன் நியாயந்தீர்க்க ஒவ்வொரு பட்டணத்திலும் நியாயாதிபதிகளை நியமிக்க வேண்டும்."],
    "Deuteronomy 16:19": ["ஊழலற்ற நீதி", "நியாயாதிபதிகள் நீதியைப் புரட்டவோ, பட்சபாதம் காட்டவோ, லஞ்சம் வாங்கவோ கூடாது."],
    "Deuteronomy 16:21": ["விக்கிரகாராதனை பழக்கங்களைத் தவிர்த்தல்", "கர்த்தருடைய பலிபீடத்தின் அருகே விக்கிரகத் தோப்புகளையோ சிலைகளையோ நிறுத்தக்கூடாது."],

    "Deuteronomy 17:1": ["கர்த்தருக்கு ஏற்ற பலிகள்", "கர்த்தருக்குச் செலுத்தும் விலங்குகள் பழுதுள்ளவைகளாக இருக்கக்கூடாது; அத்தகைய காணிக்கைகள் அருவருப்பானவை."],
    "Deuteronomy 17:2": ["விக்கிரகாராதனைக்கான தண்டனை", "யாராவது அந்நிய தெய்வங்களையோ, சூரியன், சந்திரன் அல்லது நட்சத்திரங்களையோ வழிபடுவது கண்டறியப்பட்டால், அவர்கள் விசாரணைக்கு உட்படுத்தப்பட வேண்டும்."],
    "Deuteronomy 17:4": ["கவனமான விசாரணை அவசியம்", "தண்டனை வழங்குவதற்கு முன், அந்த விவகாரத்தை முழுமையாக விசாரிக்க வேண்டும்."],
    "Deuteronomy 17:6": ["இரண்டு அல்லது மூன்று சாட்சிகள்", "இரண்டு அல்லது மூன்று சாட்சிகளின் வாக்குமூலத்தின் அடிப்படையில் மட்டுமே ஒருவருக்கு மரணதண்டனை விதிக்கப்படலாம்."],
    "Deuteronomy 17:8": ["கடினமான வழக்குகள் ஆசாரியர்களிடம் கொண்டு செல்லப்படல்", "கடினமான சட்ட வழக்குகளைக் கர்த்தர் தெரிந்து கொள்ளும் இடத்தில் உள்ள ஆசாரியர்களிடமும் நியாயாதிபதிகளிடமும் கொண்டு செல்ல வேண்டும்."],
    "Deuteronomy 17:10": ["நீதிமன்றத் தீர்ப்புக்குக் கீழ்ப்படிதல்", "ஆசாரியர்களும் நியாயாதிபதிகளும் வழங்கும் தீர்ப்பை மக்கள் பின்பற்ற வேண்டும்."],
    "Deuteronomy 17:12": ["அதிகாரத்தை எதிர்ப்பதற்கான தண்டனை", "ஆசாரியர் அல்லது நியாயாதிபதியின் தீர்ப்புக்குக் கீழ்ப்படிய மறுப்பவர் தண்டிக்கப்பட வேண்டும்."],
    "Deuteronomy 17:14": ["இஸ்ரவேல் ராஜாவிற்கான வழிகாட்டுதல்கள்", "இஸ்ரவேலர் ஒரு ராஜாவை நியமிக்கும்போது, அவர் கர்த்தரால் தெரிந்துகொள்ளப்பட்டவராக இருக்க வேண்டும்."],
    "Deuteronomy 17:16": ["ராஜாவிற்கான கட்டுப்பாடுகள்", "ராஜா தனக்காகக் குதிரைகளையும், மனைவிகளையும், அதிகப்படியான செல்வத்தையும் பெருக்கிக் கொள்ளக்கூடாது."],
    "Deuteronomy 17:18": ["ராஜா நியாயப்பிரமாணத்தைப் படிக்க வேண்டும்", "ராஜா நியாயப்பிரமாணத்தின் ஒரு பிரதியைத் தனக்காக எழுதி வைத்துக்கொண்டு, தன் வாழ்நாளெல்லாம் அதைப் படிக்க வேண்டும்."],
    "Deuteronomy 17:20": ["தாழ்மையான தலைமை", "ராஜா தன் உள்ளத்தில் மேட்டிமையடையாமல், தேவனுடைய கட்டளைகளுக்குக் கீழ்ப்படிந்து நடக்க வேண்டும்."],

    "Deuteronomy 18:1": ["லேவியர்களுக்கான ஏற்பாடுகள்", "லேவியர்களுக்கு நிலச் சுதந்திரம் இருக்காது; அவர்கள் கர்த்தருக்குச் செலுத்தப்படும் காணிக்கைகளைக் கொண்டே பிழைக்க வேண்டும்."],
    "Deuteronomy 18:6": ["லேவியர்கள் குறிப்பிட்ட இடத்தில் சேவை செய்தல்", "எந்தவொரு லேவியனும் கர்த்தர் தெரிந்து கொள்ளும் இடத்திற்கு வந்து அங்கே பணிவிடை செய்யலாம்."],
    "Deuteronomy 18:9": ["தடை செய்யப்பட்ட புறஜாதி பழக்கங்கள்", "குறிகூறுதல், சூனியம், மந்திரவாதம் போன்ற ஜாதிகளின் அருவருப்பான பழக்கங்களை இஸ்ரவேலர் பின்பற்றக்கூடாது."],
    "Deuteronomy 18:13": ["கர்த்தருக்கு முன்பாக உத்தமனாயிரு", "மக்கள் தங்கள் தேவனாகிய கர்த்தருக்கு முன்பாக உத்தமர்களாகவும் உண்மையுள்ளவர்களாகவும் இருக்க வேண்டும்."],
    "Deuteronomy 18:15": ["மோசேயைப் போன்ற ஒரு தீர்க்கதரிசி", "தங்களுக்குள்ளிருந்து மோசேயைப் போன்ற ஒரு தீர்க்கதரிசியை எழுப்புவதாகத் தேவன் வாக்குறுதி அளிக்கிறார்; அவருக்கு மக்கள் செவிகொடுக்க வேண்டும்."],
    "Deuteronomy 18:18": ["தீர்க்கதரிசியின் வாயில் தேவனுடைய வார்த்தைகள்", "கர்த்தர் தமது வார்த்தைகளை அந்தத் தீர்க்கதரிசியின் வாயில் அருளுவார்; அவர் கட்டளையிடுவதையெல்லாம் அவர் பேசுவார்."],
    "Deuteronomy 18:20": ["கள்ளத்தீர்க்கதரிசிகள் கண்டிக்கப்படல்", "கர்த்தர் சொல்லாததைச் சொன்னதாகத் துணிகரமாகப் பேசும் அல்லது அந்நிய தெய்வங்களின் பெயரால் பேசும் தீர்க்கதரிசி கொல்லப்பட வேண்டும்."],
    "Deuteronomy 18:21": ["கள்ளத்தீர்க்கதரிசியை அடையாளம் காண்பது எப்படி?", "ஒரு தீர்க்கதரிசி சொன்ன காரியம் நடக்காவிட்டால், அது கர்த்தர் சொன்ன வார்த்தை அல்ல."],

    "Deuteronomy 19:1": ["புகலிட நகரங்கள் நிறுவப்படல்", "இஸ்ரவேலர் தேசத்தைச் சுதந்தரிக்கும்போது, அறியாமல் கொலை செய்தவர் தப்பியோட புகலிட நகரங்களைப் பிரிக்க வேண்டும்."],
    "Deuteronomy 19:4": ["தற்செயலான கொலைக்கான பாதுகாப்பு", "அறியாமல் ஒருவரைக் கொன்றவர் தன் உயிரைக் காப்பாற்றிக்கொள்ளப் புகலிட நகரத்திற்குத் தப்பியோடலாம்."],
    "Deuteronomy 19:8": ["புகலிட நகரங்களை விரிவுபடுத்துதல்", "கர்த்தர் இஸ்ரவேலின் எல்லையை விரிவுபடுத்தினால், இன்னும் அதிகமான புகலிட நகரங்களைச் சேர்க்க வேண்டும்."],
    "Deuteronomy 19:11": ["கொலைக்கான தண்டனை", "வேண்டுமென்றே ஒருவரைக் கொன்றவர் நீதியின் முன் ஒப்படைக்கப்பட வேண்டும்."],
    "Deuteronomy 19:14": ["சொத்து எல்லைகளை மதித்தல்", "முன்னோர்கள் குறித்த அண்டை வீட்டாரின் எல்லைக் கல்லுகளை மக்கள் மாற்றக்கூடாது."],
    "Deuteronomy 19:15": ["சாட்சிகளின் அவசியம்", "இரண்டு அல்லது மூன்று சாட்சிகளின் வாக்குமூலத்தின் அடிப்படையில் மட்டுமே ஒரு காரியம் உறுதிப்படுத்தப்பட வேண்டும்."],
    "Deuteronomy 19:16": ["பொய்ச்சாட்சிகளைக் கையாளுதல்", "யாராவது ஒருவர் மேல் பொய்யான குற்றச்சாட்டுகளைச் சுமத்தினால், அந்த வழக்கு நியாயாதிபதிகளால் விசாரிக்கப்பட வேண்டும்."],
    "Deuteronomy 19:19": ["பொய்ச்சாட்சிக்கான நீதி", "பொய்ச்சாட்சி சொன்னவர் மற்றவருக்கு என்ன தண்டனை கிடைக்க வேண்டும் என்று நினைத்தாரோ, அதே தண்டனை அவருக்கு வழங்கப்பட வேண்டும்."],
    "Deuteronomy 19:21": ["இரக்கமற்ற நீதி", "நீதியின் கொள்கை அறிவிக்கப்படுகிறது: உயிருக்கு உயிர், கண்ணுக்குக் கண், பல்லுக்குப் பல்."],

    "Deuteronomy 20:1": ["போரில் தேவனை நம்புதல்", "இஸ்ரவேலர் போருக்குச் செல்லும்போது பலமான படைகளைக் கண்டால் அஞ்சக்கூடாது; அவர்களை எகிப்திலிருந்து மீட்ட கர்த்தர் அவர்களுடன் இருக்கிறார்."],
    "Deuteronomy 20:2": ["ஆசாரியர் இராணுவத்தை ஊக்கப்படுத்துதல்", "போருக்கு முன், வெற்றி பெறக் கர்த்தரை நம்பியிருக்கும்படி ஆசாரியர் வீரர்களுக்கு நினைவூட்டுகிறார்."],
    "Deuteronomy 20:5": ["இராணுவப் பணியிலிருந்து விலக்கு", "புதிய வீடு கட்டியவர்கள், திராட்சைத் தோட்டம் நாட்டியவர்கள் அல்லது நிச்சயிக்கப்பட்டவர்கள் வீட்டிற்குத் திரும்ப அனுமதிக்கப்படலாம்."],
    "Deuteronomy 20:8": ["பயந்தவர்கள் வீட்டிற்கு அனுப்பப்படல்", "மற்ற வீரர்களின் தைரியத்தைக் குலைக்காதபடி, பயந்தவர்கள் போரிலிருந்து விலகிச் செல்ல அனுமதிக்கப்படுகிறார்கள்."],
    "Deuteronomy 20:10": ["தூரத்திலுள்ள பட்டணங்களுக்குச் சமாதானம் பேசுதல்", "ஒரு தூரமான பட்டணத்தை நெருங்கும்போது, இஸ்ரவேலர் முதலில் சமாதானத்தைப் பேச வேண்டும்."],
    "Deuteronomy 20:13": ["எதிர்க்கும் பட்டணங்களுக்கு எதிரான போர்", "ஒரு பட்டணம் சமாதானத்தை மறுத்துப் போரிட்டால், இஸ்ரவேலர் அதைத் தோற்கடிக்கலாம்."],
    "Deuteronomy 20:16": ["கானானிய ஜாதிகளை முற்றிலும் அழித்தல்", "விக்கிரகாராதனையை ஒழிக்க, வாக்குத்தத்தம் பண்ணப்பட்ட தேசத்திலுள்ள ஜாதிகளின் பட்டணங்கள் முற்றிலும் அழிக்கப்பட வேண்டும்."],
    "Deuteronomy 20:19": ["போரில் கனி தரும் மரங்களைப் பாதுகாத்தல்", "ஒரு பட்டணத்தை முற்றுகையிடும்போது, உணவளிக்கும் கனி தரும் மரங்களை இஸ்ரவேலர் அழிக்கக்கூடாது."],

    "Deuteronomy 21:1": ["துப்பு துலங்காத கொலைக்கான நிவிர்த்தி", "கொலை செய்யப்பட்ட ஒருவர் கண்டெடுக்கப்பட்டு, அதற்குக் காரணமானவர் தெரியாவிட்டால், அருகிலுள்ள ஊர் அந்தப் பாவத்தைப் போக்க ஒரு சடங்கு செய்ய வேண்டும்."],
    "Deuteronomy 21:10": ["சிறைபிடிக்கப்பட்ட பெண்ணைத் திருமணம் செய்தல்", "போரில் சிறைபிடிக்கப்பட்ட ஒரு பெண்ணைத் திருமணம் செய்வதற்கான விதிகள் வழங்கப்பட்டு, அவளை மரியாதையுடன் நடத்த வலியுறுத்தப்படுகிறது."],
    "Deuteronomy 21:15": ["தலைச்சன் மகனின் உரிமைகள்", "விரும்பப்படாத மனைவியின் மகனாக இருந்தாலும், தலைச்சன் மகனுக்குரிய சுதந்திர பாகம் அவருக்கு வழங்கப்பட வேண்டும்."],
    "Deuteronomy 21:18": ["கலகக்கார மகன்", "அடங்காதவனும் பிடிவாதமுள்ளவனுமான மகன் தன் பெற்றோரின் சொல்லுக்குக் கீழ்ப்படியாவிட்டால், அவன் மூப்பர்களிடம் விசாரணைக்குக் கொண்டு வரப்படலாம்."],
    "Deuteronomy 21:22": ["மரத்தில் தொங்கவிடப்பட்ட உடல்", "மரணதண்டனை விதிக்கப்பட்டு மரத்தில் தொங்கவிடப்பட்ட உடல் அன்று இரவே அடக்கம் செய்யப்பட வேண்டும்; அது மறுநாள் வரை அங்கே இருக்கக்கூடாது."],

    "Deuteronomy 22:1": ["அண்டை வீட்டாரின் சொத்து மேல் அக்கறை", "அண்டை வீட்டாரின் கால்நடைகள் வழிதப்பிப்போவதைக் கண்டால், அவற்றைப் புறக்கணிக்காமல் உரியவரிடம் ஒப்படைக்க வேண்டும்."],
    "Deuteronomy 22:5": ["ஆடை அணிவதில் வித்தியாசம்", "ஆண்களும் பெண்களும் ஒருவருக்கொருவர் மாற்று ஆடைகளை அணியக்கூடாது என்று அறிவுறுத்தப்படுகிறார்கள்."],
    "Deuteronomy 22:6": ["பறவைகள் மேல் இரக்கம்", "பறவைக் கூட்டிலிருந்து முட்டைகளையோ குஞ்சுகளையோ எடுக்கும்போது, தாய்ப் பறவையை விடுவிக்க வேண்டும்."],
    "Deuteronomy 22:8": ["வீட்டின் கூரையில் பாதுகாப்பு", "தற்செயலான மரணங்களைத் தவிர்க்க, வீட்டின் கூரையைச் சுற்றி ஒரு தடுப்புச் சுவர் (கைப்பிடிச் சுவர்) கட்டப்பட வேண்டும்."],
    "Deuteronomy 22:9": ["வெவ்வேறு காரியங்களைக் கலப்பதைத் தவிர்த்தல்", "விதை, விலங்கு அல்லது துணிகளில் தேவனுடைய அறிவுறுத்தல்களுக்கு மாறாகக் கலப்படம் செய்யக்கூடாது."],
    "Deuteronomy 22:12": ["ஆடைகளின் ஓரங்களில் குஞ்சங்கள்", "தேவனுடைய கட்டளைகளை நினைவூட்டும் விதமாக ஆடைகளின் நான்கு ஓரங்களிலும் குஞ்சங்களைத் தைக்க வேண்டும்."],
    "Deuteronomy 22:13": ["மனைவி மீதான குற்றச்சாட்டு", "ஒரு மணமகளின் கற்பு குறித்த குற்றச்சாட்டுகளைக் கையாள்வதற்கான விதிகள் வழங்கப்பட்டுள்ளன."],
    "Deuteronomy 22:22": ["விபச்சாரத்திற்கான தண்டனை", "விபச்சாரத்தில் ஈடுபடும் ஆணும் பெண்ணும் தண்டிக்கப்பட வேண்டும்."],
    "Deuteronomy 22:25": ["அப்பாவி பெண்களுக்குப் பாதுகாப்பு", "வெளியில் ஒரு பெண் தாக்கப்பட்டால், தாக்கியவர் மட்டுமே குற்றவாளியாகக் கருதப்படுவார்."],
    "Deuteronomy 22:28": ["கன்னிகையைத் தீட்டுப்படுத்தினால் வரும் திருமணம்", "ஒருவன் ஒரு கன்னிகையைத் தீட்டுப்படுத்தினால், அவன் அவளைத் திருமணம் செய்து வாழ்நாள் முழுவதும் பராமரிக்க வேண்டும்."],

    "Deuteronomy 23:1": ["சபையில் சேர்க்கப்படாதவர்கள்", "குறிப்பிட்ட உடல்நிலை உள்ளவர்கள் கர்த்தருடைய சபையில் நுழைய அனுமதிக்கப்படுவதில்லை."],
    "Deuteronomy 23:3": ["அம்மோனியர்களும் மோவாபியர்களும் விலக்கப்படல்", "எகிப்திலிருந்து வரும் வழியில் இஸ்ரவேலரை எதிர்த்ததால், அம்மோனியர்களும் மோவாபியர்களும் சபையில் சேரத் தடை விதிக்கப்படுகிறது."],
    "Deuteronomy 23:7": ["ஏதோமியர்களையும் எகிப்தியர்களையும் வெறுக்காதே", "கடந்த கால உறவின் அடிப்படையில் இஸ்ரவேலர் ஏதோமியர்களையோ எகிப்தியர்களையோ வெறுக்கக்கூடாது."],
    "Deuteronomy 23:9": ["பாளயத்தைப் பரிசுத்தமாக வைத்திருத்தல்", "கர்த்தர் உலாவுவதால், இராணுவப் பாளயம் சுத்தமாகவும் பரிசுத்தமாகவும் இருக்க வேண்டும்."],
    "Deuteronomy 23:15": ["தப்பியோடிய அடிமைகளுக்குப் பாதுகாப்பு", "தப்பியோடிய அடிமைகளை மீண்டும் எஜமான்களிடம் ஒப்படைக்காமல், அவர்கள் சுதந்திரமாக வாழ அனுமதிக்கப்பட வேண்டும்."],
    "Deuteronomy 23:17": ["விலக்கப்பட்ட விபச்சாரம்", "புறஜாதி வழிபாட்டோடு தொடர்புடைய விபச்சாரங்களை இஸ்ரவேலருக்குள் அனுமதிக்கக்கூடாது."],
    "Deuteronomy 23:19": ["இஸ்ரவேலருக்குள் வட்டி வாங்கக்கூடாது", "தன் சகோதரனாகிய இஸ்ரவேலனுக்குக் கடன் கொடுக்கும்போது வட்டி வாங்கக்கூடாது."],
    "Deuteronomy 23:21": ["தேவனுக்குச் செய்த பொருத்தனையை நிறைவேற்று", "கர்த்தருக்குச் செய்த பொருத்தனையைத் தாமதிக்காமல் நிறைவேற்ற வேண்டும்."],
    "Deuteronomy 23:24": ["அயலானின் திராட்சைத் தோட்டத்தில் உரிமை", "அயலானின் திராட்சைத் தோட்டத்தில் பழங்களை உண்ணலாம், ஆனால் அவற்றைப் பாத்திரத்தில் எடுத்துச் செல்லக்கூடாது."],
    "Deuteronomy 23:25": ["அயலானின் விளைச்சலில் உரிமை", "அயலானின் வயலில் கதிர்களைக் கையால் பறிக்கலாம், ஆனால் அறுவடைக் கருவியைப் பயன்படுத்தக்கூடாது."],

    "Deuteronomy 24:1": ["விவாகரத்து குறித்த சட்டம்", "ஒருவன் தன் மனைவியை விவாகரத்து செய்து, அவள் வேறொருவனை மணந்த பிறகு, முதல் கணவன் அவளை மீண்டும் ஏற்றுக் கொள்ளக்கூடாது."],
    "Deuteronomy 24:5": ["புதிதாகத் திருமணமானவருக்குப் போர் விலக்கு", "புதிதாகத் திருமணமான ஒருவன் ஒரு வருடம் தன் மனைவியுடன் மகிழ்ச்சியாக இருக்க வீட்டிலேயே தங்க வேண்டும்."],
    "Deuteronomy 24:6": ["வாழ்வாதாரத்தைப் பாதுகாத்தல்", "ஒருவருடைய பிழைப்பிற்குக் காரணமான இயந்திரக் கல்லை (ஏந்திரக்கல்) அடமானமாக வாங்கக்கூடாது."],
    "Deuteronomy 24:7": ["ஆட்கடத்தலுக்கான தண்டனை", "இஸ்ரவேலரைக் கடத்தி அடிமையாக நடத்துபவருக்கு மரணதண்டனை விதிக்கப்பட வேண்டும்."],
    "Deuteronomy 24:8": ["சுகாதாரச் சட்டங்களில் கீழ்ப்படிதல்", "தொற்று நோய்கள் குறித்து ஆசாரியர்கள் கொடுக்கும் அறிவுறுத்தல்களை மக்கள் கவனமாகப் பின்பற்ற வேண்டும்."],
    "Deuteronomy 24:10": ["அடமானத்தை வாங்கும்போது மரியாதை", "ஒரு கடனுக்காக அடமானத்தை வாங்கும்போது, கடன் கொடுத்தவர் கடனாளியின் வீட்டிற்குள் நுழையக்கூடாது."],
    "Deuteronomy 24:14": ["வேலையாட்களை நியாயமாக நடத்துதல்", "கூலி வேலை செய்பவர்களை, குறிப்பாக ஏழைகளையும் அந்நியர்களையும் ஒடுக்கக்கூடாது."],
    "Deuteronomy 24:16": ["தனிமனிதப் பொறுப்பு", "பிள்ளைகளுக்காகப் பெற்றோரோ, பெற்றோருக்காகப் பிள்ளைகளோ கொல்லப்படக்கூடாது; அவரவர் பாவத்திற்காக அவரவரே தண்டிக்கப்படுவார்கள்."],
    "Deuteronomy 24:17": ["எளியவர்களுக்கு நீதி", "அந்நியர்களுக்கும் திக்கற்றவர்களுக்கும் நீதியை மறுக்கக்கூடாது; விதவையின் ஆடையை அடமானமாக வாங்கக்கூடாது."],
    "Deuteronomy 24:19": ["எளியவர்களுக்காக அறுவடையை விட்டுவிடுதல்", "அறுவடை செய்யும்போது, அந்நியர்கள் மற்றும் ஏழைகளுக்காகச் சிலவற்றை வயலிலேயே விட்டுவிட வேண்டும்."],

    "Deuteronomy 25:1": ["நீதிமன்றங்களில் நீதி", "வழக்குகள் வரும்போது, நியாயாதிபதிகள் நீதிமானை நீதிமானென்றும், குற்றவாளியைக் குற்றவாளியென்றும் தீர்க்க வேண்டும்."],
    "Deuteronomy 25:2": ["தண்டனையின் எல்லை", "குற்றவாளிக்குக் கொடுக்கப்படும் அடி நாற்பதுக்கு மிகக்கூடாது."],
    "Deuteronomy 25:4": ["போரடிக்கிற எருதை வாய்க்கட்டாதே", "தானியத்தைப் போரடிக்கிற எருது உண்ணாதபடி அதன் வாயைக் கட்டக்கூடாது."],
    "Deuteronomy 25:5": ["சகோதரனின் வம்சத்தைப் பாதுகாத்தல்", "ஒருவன் புத்திரன் இல்லாமல் மரித்தால், அவன் சகோதரன் அந்த விதவையை மணந்து வம்சத்தைத் தொடர வேண்டும்."],
    "Deuteronomy 25:7": ["கடமையை மறுப்பதற்கான சடங்கு", "அந்தச் சகோதரன் மணக்க மறுத்தால், பகிரங்கமான சடங்கின் மூலம் அவன் பொறுப்பிலிருந்து நீக்கப்பட்டு அவமானப்படுத்தப்படுவான்."],
    "Deuteronomy 25:11": ["சண்டையில் முறையற்ற நடத்தை", "சண்டையின் போது தலையிடும் முறையற்ற நடத்தைகள் குறித்த விதிகள் வழங்கப்பட்டுள்ளன."],
    "Deuteronomy 25:13": ["நேர்மையான தராசும் அளவுகளும்", "வியாபாரத்தில் நேர்மையான தராசு கற்களையும் அளவுகளையும் பயன்படுத்த வேண்டும்."],
    "Deuteronomy 25:17": ["அமலேக்கியரை நினைவில் கொள்க", "எகிப்திலிருந்து வரும் வழியில் அமலேக்கியர் செய்த தீமையை நினைவில் கொள்ளும்படி இஸ்ரவேலர் பணிக்கப்படுகிறார்கள்."],
    "Deuteronomy 25:19": ["அமலேக்கியரை ஒழித்தல்", "தேசத்தில் அமைதி கிடைக்கும்போது, அமலேக்கியரின் நினைவை முற்றிலும் அழித்துவிட வேண்டும்."],

    "Deuteronomy 26:1": ["முதற்பலனைக் காணிக்கையாக்குதல்", "தேசத்திற்குள் நுழைந்ததும், அறுவடையின் முதற்பலனைக் கர்த்தர் தெரிந்து கொள்ளும் இடத்திற்குக் கொண்டு வர வேண்டும்."],
    "Deuteronomy 26:5": ["தேவனுடைய மீட்பை அறிக்கையிடுதல்", "கர்த்தர் தங்களை எகிப்திலிருந்து மீட்டு இந்தத் தேசத்தைத் தந்ததை வணங்குபவர் அறிக்கையிட வேண்டும்."],
    "Deuteronomy 26:10": ["முதற்பலனைச் சமர்ப்பித்தல்", "ஆராதனை மற்றும் நன்றியறிதலின் அடையாளமாக முதற்பலன்கள் கர்த்தருக்கு முன்பாக வைக்கப்படுகின்றன."],
    "Deuteronomy 26:12": ["எளியவர்களுக்கான தசமபாகம்", "ஒவ்வொரு மூன்றாம் ஆண்டும் தசமபாகம் லேவியர்களுக்கும் எளியவர்களுக்கும் வழங்கப்பட வேண்டும்."],
    "Deuteronomy 26:13": ["கீழ்ப்படிதலின் பிரகடனம்", "தசமபாகம் குறித்த தேவனுடைய கட்டளைகளைப் பின்பற்றியதாக மக்கள் கர்த்தருக்கு முன்பாக அறிவிக்கிறார்கள்."],
    "Deuteronomy 26:16": ["கட்டளைகளுக்கு அர்ப்பணித்தல்", "முழு இருதயத்தோடும் ஆத்துமாவோடும் கர்த்தருடைய கட்டளைகளுக்குக் கீழ்ப்படிய இஸ்ரவேலர் அழைக்கப்படுகிறார்கள்."],
    "Deuteronomy 26:17": ["கர்த்தரே தேவன் என இஸ்ரவேல் அறிவித்தல்", "கர்த்தரே தங்கள் தேவன் என்றும், அவருடைய வழிகளில் நடப்போம் என்றும் மக்கள் உறுதிப்படுத்துகிறார்கள்."],
    "Deuteronomy 26:18": ["இஸ்ரவேல் தேவனுடைய விசேஷித்த ஜனங்கள்", "இஸ்ரவேலர் தமக்குச் சொந்தமான ஜனங்கள் என்று கர்த்தர் அறிவிக்கிறார்."],
    "Deuteronomy 26:19": ["ஜாதிகளுக்கு மேலாக உயர்த்தப்படல்", "இஸ்ரவேலைப் புகழ்ச்சியிலும், கனத்திலும், பரிசுத்தத்திலும் மற்ற ஜாதிகளுக்கு மேலாக உயர்த்துவதாகத் தேவன் வாக்குறுதி அளிக்கிறார்."],

    "Deuteronomy 27:1": ["கற்களில் நியாயப்பிரமாணத்தை எழுதுதல்", "யோர்தானைக் கடந்த பிறகு பெரிய கற்களில் நியாயப்பிரமாணத்தை எழுதும்படி மோசேயும் மூப்பர்களும் கட்டளையிடுகிறார்கள்."],
    "Deuteronomy 27:4": ["ஏபால் மலையில் பலிபீடம்", "ஏபால் மலையில் கர்த்தருக்கு ஒரு பலிபீடத்தைக் கட்டி அங்கே பலியிட வேண்டும்."],
    "Deuteronomy 27:9": ["இஸ்ரவேல் தேவனுடைய ஜனமாக அறிவிக்கப்படல்", "இஸ்ரவேலர் கர்த்தருடைய ஜனங்களாக மாறிவிட்டார்கள் என்றும், அவருடைய சத்தத்திற்குக் கீழ்ப்படிய வேண்டும் என்றும் மோசே கூறுகிறார்."],
    "Deuteronomy 27:11": ["ஆசீர்வாதம் மற்றும் சாபத்திற்கான மலைகள்", "ஆசீர்வாதங்களைக் கூற கெரிசீம் மலையிலும், சாபங்களைக் கூற ஏபால் மலையிலும் கோத்திரங்கள் நிற்க வேண்டும்."],
    "Deuteronomy 27:14": ["லேவியர்கள் கூறும் சாபங்கள்", "தேவனுடைய கட்டளைகளை மீறுபவர்களுக்கான சாபங்களை லேவியர்கள் உரக்கக் கூறுகிறார்கள்."],
    "Deuteronomy 27:15": ["விக்கிரகாராதனைக்கான சாபம்", "சிலைகளைச் செய்பவன் சாபத்திற்குரியவன் என்று அறிவிக்கப்படுகிறது."],
    "Deuteronomy 27:16": ["பெற்றோரை அவமதிப்பவருக்குச் சாபம்", "தன் தாய் தந்தையை அவமதிக்கிறவன் சாபத்திற்குரியவன்."],
    "Deuteronomy 27:17": ["எல்லைக் கல்லை மாற்றுபவருக்குச் சாபம்", "அயலானின் எல்லைக் கல்லை மாற்றுகிறவன் சாபத்திற்குரியவன்."],
    "Deuteronomy 27:18": ["குருடனை வழிதவறச் செய்பவருக்குச் சாபம்", "குருடனை வழியில் தடம்மாறச் செய்கிறவன் சாபத்திற்குரியவன்."],
    "Deuteronomy 27:19": ["அநீதி இழைப்பவருக்குச் சாபம்", "அந்நியர்களுக்கும் எளியவர்களுக்கும் நீதியை மறுப்பவன் சாபத்திற்குரியவன்."],
    "Deuteronomy 27:26": ["கீழ்ப்படியாதவருக்குச் சாபம்", "நியாயப்பிரமாண வார்த்தைகளின்படி நடக்காதவன் சாபத்திற்குரியவன்."],

    "Deuteronomy 28:1": ["கீழ்ப்படிதலுக்கான ஆசீர்வாதங்கள்", "இஸ்ரவேலர் கர்த்தருக்கு முழுமையாகக் கீழ்ப்படிந்தால், அவர் அவர்களை உயர்த்தி ஆசீர்வதிப்பார்."],
    "Deuteronomy 28:3": ["பட்டணத்திலும் வெளியிலும் ஆசீர்வாதம்", "பட்டணத்திலும் வயல்வெளியிலும், எல்லா இடங்களிலும் தேவன் ஆசீர்வாதத்தை வாக்குறுதி அளிக்கிறார்."],
    "Deuteronomy 28:7": ["எதிரிகள் மேல் வெற்றி", "இஸ்ரவேலுக்கு எதிராக எழும் எதிரிகள் தோற்கடிக்கப்பட்டு சிதறி ஓடுவார்கள்."],
    "Deuteronomy 28:11": ["தேசத்தில் செழிப்பு", "விளைச்சலிலும், கால்நடைகளிலும், வாழ்விலும் கர்த்தர் இஸ்ரவேலைச் செழிக்கச் செய்வார்."],
    "Deuteronomy 28:12": ["தேவனுடைய பொக்கிஷசாலை திறக்கப்படல்", "ஏற்ற காலத்தில் மழையைத் தந்து, கைகளின் பிரயாசத்தை ஆசீர்வதிக்கத் தேவன் வானத்தைத் திறப்பார்."],
    "Deuteronomy 28:15": ["கீழ்ப்படியாமைக்கான சாபங்கள்", "இஸ்ரவேலர் கர்த்தருக்குக் கீழ்ப்படியாவிட்டால், அவர்கள் மேல் பல சாபங்கள் வரும்."],
    "Deuteronomy 28:16": ["பட்டணத்திலும் வெளியிலும் சாபம்", "கீழ்ப்படியாமை எல்லா இடங்களிலும் வறுமையையும் கஷ்டத்தையும் கொண்டு வரும்."],
    "Deuteronomy 28:20": ["குழப்பமும் தவிப்பும்", "அவர்கள் செய்யும் எல்லாவற்றிலும் கர்த்தர் குழப்பத்தையும் தோல்வியையும் அனுப்புவார்."],
    "Deuteronomy 28:25": ["எதிரிகளிடம் தோல்வி", "இஸ்ரவேலர் எதிரிகளால் தோற்கடிக்கப்பட்டு, ஜாதிகளுக்குள்ளே சிதறடிக்கப்படுவார்கள்."],
    "Deuteronomy 28:36": ["அந்நிய தேசத்திற்குச் சிறைப்படல்", "கர்த்தர் இஸ்ரவேலையும் அவர்கள் ராஜாவையும் தாங்கள் அறியாத ஒரு ஜாதிக்குள்ளே கொண்டு போவார்."],
    "Deuteronomy 28:45": ["சாபங்கள் பின் தொடரும்", "தேவனுடைய கட்டளைகளுக்குக் கீழ்ப்படியாததால், இந்தச் சாபங்கள் அவர்களைத் தொடர்ந்து வந்து பிடிக்கும்."],
    "Deuteronomy 28:64": ["ஜாதிகளுக்குள்ளே சிதறடிக்கப்படல்", "இஸ்ரவேலர் பூமியின் ஒரு முனை முதல் மறுமுனை வரை சிதறடிக்கப்பட்டு அந்நிய தெய்வங்களைச் சேவிப்பார்கள்."],
    "Deuteronomy 28:68": ["மீண்டும் அடிமைத்தனம்", "கீழ்ப்படியாமை இஸ்ரவேலரை மீண்டும் அடிமைத்தனத்திற்கும் துன்பத்திற்கும் கொண்டு செல்லும்."],

    "Deuteronomy 29:1": ["மோவாபில் உடன்படிக்கை புதுப்பிக்கப்படல்", "மோவாப் தேசத்தில் கர்த்தர் இஸ்ரவேலருடன் செய்த உடன்படிக்கையை மோசே நினைவுபடுத்துகிறார்."],
    "Deuteronomy 29:2": ["தேவனுடைய மகத்துவத்தை நினைவுகூர்தல்", "எகிப்திலும் வனாந்தரத்திலும் தேவன் செய்த அடையாளங்களையும் அற்புதங்களையும் மக்கள் நினைவுகூர அழைக்கப்படுகிறார்கள்."],
    "Deuteronomy 29:5": ["வனாந்தரத்தில் தேவன் பராமரித்தது", "நாற்பது ஆண்டுகள் வனாந்தரத்தில் அவர்கள் உடுத்திய ஆடைகளும் காலணிகளும் பழையாகிப் போகவில்லை."],
    "Deuteronomy 29:10": ["இஸ்ரவேல் சமூகம் தேவன் முன் நிற்றல்", "உடன்படிக்கையைப் புதுப்பிக்க இஸ்ரவேல் சமூகம் முழுவதும் தேவன் முன் நிற்கிறது."],
    "Deuteronomy 29:14": ["வருங்கால சந்ததியினருக்கான உடன்படிக்கை", "இந்த உடன்படிக்கை அங்கிருப்பவர்களோடு மட்டுமல்லாமல், வருங்கால சந்ததியினரோடும் செய்யப்படுகிறது."],
    "Deuteronomy 29:16": ["விக்கிரகாராதனை குறித்த எச்சரிக்கை", "தாங்கள் கடந்து வந்த ஜாதிகளின் சிலைகளைப் பின்பற்றக்கூடாது என்று எச்சரிக்கப்படுகிறார்கள்."],
    "Deuteronomy 29:18": ["கலகக்கார இருதயத்தின் ஆபத்து", "கர்த்தரை விட்டு விலகிச் செல்பவன் தனக்குத் தானே அழிவைத் தேடிக்கொள்வான்."],
    "Deuteronomy 29:22": ["வருங்காலத் தீர்ப்பைக் காணுதல்", "கீழ்ப்படியாமையினால் தேசத்திற்கு வரும் அழிவை வருங்காலச் சந்ததியினர் காண்பார்கள்."],
    "Deuteronomy 29:24": ["ஏன் இது நடந்தது?", "தேசம் ஏன் இப்படிப் பாழானது என்று மக்கள் ஆச்சரியத்துடன் கேட்பார்கள்."],
    "Deuteronomy 29:25": ["உடன்படிக்கையை மீறியதாலே", "இஸ்ரவேலர் கர்த்தருடைய உடன்படிக்கையைக் கைவிட்டதாலேயே இந்த அழிவு வந்தது என்பதே பதிலாக இருக்கும்."],
    "Deuteronomy 29:29": ["மறைவானவை தேவனுக்குரியவை", "மறைவானவை கர்த்தருக்கே உரியவை, ஆனால் வெளிப்படுத்தப்பட்டவை நாம் கீழ்ப்படியும்படி நமக்கும் நம் பிள்ளைகளுக்கும் உரியவை."],

    "Deuteronomy 30:1": ["மறுசீரமைப்பு வாக்குறுதி", "சிறையிருப்பில் இருக்கும்போது இஸ்ரவேலர் கர்த்தரிடம் திரும்பினால், அவர் அவர்களை மீண்டும் நிலைநிறுத்துவார்."],
    "Deuteronomy 30:3": ["சிதறடிக்கப்பட்டவர்களைத் தேவன் கூட்டுதல்", "தேவன் இரக்கமுற்று, ஜாதிகளுக்குள்ளே சிதறிக் கிடக்கும் தம் ஜனங்களை மீண்டும் ஒன்று சேர்ப்பார்."],
    "Deuteronomy 30:6": ["இருதய விருத்தசேதனம்", "மக்கள் உண்மையாக அன்பு கூர்ந்து கீழ்ப்படியும்படி தேவன் அவர்களின் இருதயங்களை மாற்றுவார்."],
    "Deuteronomy 30:9": ["புதுப்பிக்கப்பட்ட ஆசீர்வாதம்", "இஸ்ரவேலர் மீண்டும் கீழ்ப்படியும்போது, தேவன் அவர்களை ஆசீர்வதித்துச் செழிக்கச் செய்வார்."],
    "Deuteronomy 30:11": ["தேவனுடைய கட்டளை தூரத்தில் இல்லை", "கர்த்தருடைய கட்டளை மிகவும் கடினமானதோ அல்லது எட்டாத தூரத்தில் இருப்பதோ அல்ல."],
    "Deuteronomy 30:15": ["ஜீவனும் மரணமும்", "வாழ்வு மற்றும் செழிப்பு அல்லது மரணம் மற்றும் அழிவு ஆகியவற்றில் ஒன்றைத் தேர்ந்தெடுக்கும் வாய்ப்பை மோசே மக்கள் முன் வைக்கிறார்."],
    "Deuteronomy 30:19": ["ஜீவனைத் தெரிந்துகொள்", "வானத்தையும் பூமியையும் சாட்சியாக வைத்து, தேவனை நேசித்து ஜீவனைத் தெரிந்துகொள்ளும்படி மோசே கெஞ்சுகிறார்."],
    "Deuteronomy 30:20": ["கர்த்தரை உறுதியாகப் பற்றிக்கொள்", "தேவனை நேசித்து அவருக்குக் கீழ்ப்படிந்து நடப்பதே ஆசீர்வாதமான வாழ்விற்கு வழியாகும்."],

    "Deuteronomy 31:1": ["இஸ்ரவேலருக்கு மோசே ஊக்கமளித்தல்", "கர்த்தர் அவர்களுடன் வருவார் என்பதால், மக்கள் பலங்கொண்டு தைரியமாக இருக்கும்படி மோசே கூறுகிறார்."],
    "Deuteronomy 31:7": ["யோசுவா தலைவராக நியமிக்கப்படல்", "இஸ்ரவேலரை வாக்குத்தத்தம் பண்ணப்பட்ட தேசத்திற்கு வழிநடத்திச் செல்லுமாறு மோசே பகிரங்கமாக யோசுவாவை ஊக்குவிக்கிறார்."],
    "Deuteronomy 31:9": ["ஆசாரியர்களிடம் நியாயப்பிரமாணம் வழங்கப்படல்", "மோசே நியாயப்பிரமாணத்தை எழுதி, அதை ஆசாரியர்களிடமும் மூப்பர்களிடமும் ஒப்படைக்கிறார்."],
    "Deuteronomy 31:10": ["ஏழு ஆண்டுகளுக்கு ஒருமுறை நியாயப்பிரமாணத்தை வாசித்தல்", "ஒவ்வொரு ஏழு ஆண்டுகளுக்கு ஒருமுறை கூடாரப் பண்டிகையின் போது இஸ்ரவேலர் அனைவருக்கும் நியாயப்பிரமாணம் வாசிக்கப்பட வேண்டும்."],
    "Deuteronomy 31:14": ["கர்த்தரால் யோசுவாவுக்குப் பொறுப்பு வழங்கப்படல்", "கர்த்தர் ஆசரிப்புக் கூடாரத்தில் தோன்றி, மக்களை வழிநடத்த யோசுவாவுக்குப் பொறுப்பளிக்கிறார்."],
    "Deuteronomy 31:16": ["எதிர்கால கலகம் குறித்த எச்சரிக்கை", "இஸ்ரவேலர்கள் பின்னாளில் விலகிப்போய் அந்நிய தெய்வங்களை வழிபடுவார்கள் என்று தேவன் மோசேயிடம் கூறுகிறார்."],
    "Deuteronomy 31:19": ["சாட்சியாக ஒரு பாட்டு", "இஸ்ரவேலர் தேவனை மறக்கும்போது அவர்களுக்கு எதிராகச் சாட்சி சொல்லும்படி ஒரு பாட்டை எழுத மோசேக்குப் பணிப்புரை வழங்கப்படுகிறது."],
    "Deuteronomy 31:24": ["உடன்படிக்கைப் பெட்டியின் அருகே நியாயப்பிரமாணம்", "நியாயப்பிரமாணப் புஸ்தகம் ஒரு சாட்சியாக இருக்கும்படி உடன்படிக்கைப் பெட்டியின் ஓரத்தில் வைக்கப்படுகிறது."],
    "Deuteronomy 31:27": ["இஸ்ரவேலின் கலகம் குறித்து மோசே எச்சரித்தல்", "தனது மரணத்திற்குப் பிறகும் மக்கள் பிடிவாதமாகவும் கலகம் செய்பவர்களாகவும் இருப்பார்கள் என்று மோசே கூறுகிறார்."],
    "Deuteronomy 31:30": ["மோசே அந்தப் பாட்டைப் பாடுதல்", "மோசே இஸ்ரவேல் சபையார் அனைவருக்கும் முன்பாக அந்தப் பாட்டை முழுமையாகச் சொல்லுகிறார்."],

    "Deuteronomy 32:1": ["மோசேயின் பாட்டு தொடங்குதல்", "மோசே தனது பாட்டின் வார்த்தைகளை அறிவிக்கும்போது வானத்தையும் பூமியையும் செவிகொடுக்க அழைக்கிறார்."],
    "Deuteronomy 32:4": ["தேவனுடைய பரிபூரண குணாதிசயம்", "கர்த்தர் ஒரு கன்மலை; அவருடைய கிரியை உத்தமமானது, அவருடைய வழிகளெல்லாம் நியாயமானவை."],
    "Deuteronomy 32:7": ["தேவனுடைய உண்மையுள்ளத்தை நினைவுகூர்தல்", "பழைய நாட்களை நினைத்துப் பார்த்து, தேவன் தங்களை எவ்வாறு வழிநடத்தினார் என்பதைச் சிந்திக்கும்படி மக்கள் கேட்டுக்கொள்ளப்படுகிறார்கள்."],
    "Deuteronomy 32:10": ["இஸ்ரவேல் மேல் தேவனுடைய பராமரிப்பு", "தேவன் இஸ்ரவேலை வனாந்தரத்தில் கண்டு, கண்ணின் மணியைப் போலப் பராமரித்தார்."],
    "Deuteronomy 32:15": ["இஸ்ரவேலின் கலகம்", "இஸ்ரவேலர் செழிப்படைந்தபோது, தங்களைப் படைத்த தேவனை விட்டு விலகிச் சென்றார்கள்."],
    "Deuteronomy 32:19": ["விக்கிரகாராதனையால் தேவனுக்கு வந்த கோபம்", "தமது ஜனங்கள் பொய் தெய்வங்களிடம் திரும்பியதால் கர்த்தர் அவர்கள் மேல் கோபமடைந்தார்."],
    "Deuteronomy 32:23": ["கீழ்ப்படியாமைக்கான தண்டனை", "கலகத்தினிமித்தம் அவர்களுக்குப் பல ஆபத்துகளும் துயரங்களும் வரும் என்று தேவன் எச்சரிக்கிறார்."],
    "Deuteronomy 32:34": ["தேவனுடைய நீதி சேமிக்கப்பட்டுள்ளது", "நீதித்தீர்ப்பு தயாராக இருப்பதாகவும், அது ஏற்ற காலத்தில் வரும் என்றும் கர்த்தர் அறிவிக்கிறார்."],
    "Deuteronomy 32:39": ["கர்த்தர் ஒருவரே தேவன்", "வாழ்வு மற்றும் மரணத்தின் மேல் தமக்கு மட்டுமே அதிகாரம் உண்டு என்று தேவன் பறைசாற்றுகிறார்."],
    "Deuteronomy 32:43": ["தேவனுடைய ஜனங்களோடு மகிழுங்கள்", "தேவன் தமது ஜனங்களுக்காகப் பழிவாங்குவார் என்பதால் ஜாதிகள் மகிழ அழைக்கப்படுகிறார்கள்."],
    "Deuteronomy 32:44": ["மோசே பாட்டை முடித்தல்", "மோசேயும் யோசுவாவும் அந்தப் பாட்டின் வார்த்தைகளை மக்களுக்குச் சொல்லி முடிக்கிறார்கள்."],
    "Deuteronomy 32:48": ["வாக்குத்தத்தம் பண்ணப்பட்ட தேசத்தைப் பார்க்க அனுமதி", "மரிப்பதற்கு முன் நேபோ மலையில் ஏறி தேசத்தைப் பார்க்கும்படி கர்த்தர் மோசேயிடம் கூறுகிறார்."],

    "Deuteronomy 33:1": ["கோத்திரங்களுக்கு மோசே ஆசீர்வாதம் அளித்தல்", "மரிப்பதற்கு முன் மோசே இஸ்ரவேல் கோத்திரங்களை ஆசீர்வதிக்கிறார்."],
    "Deuteronomy 33:2": ["தேவன் மகத்துவத்துடன் வருதல்", "சீனாய் மலையிலிருந்து கர்த்தர் வல்லமையோடும் மகிமையோடும் எழுந்தருளுவதை மோசே விவரிக்கிறார்."],
    "Deuteronomy 33:6": ["ரூபனுக்கு ஆசீர்வாதம்", "ரூபன் கோத்திரத்தார் அழியாமல் பிழைத்திருக்க வேண்டும் என்று மோசே ஆசீர்வதிக்கிறார்."],
    "Deuteronomy 33:7": ["யூதாவிற்கு ஆசீர்வாதம்", "கர்த்தர் யூதாவிற்கு உதவி செய்து, எதிரிகள் மேல் வெற்றியளிக்க வேண்டும் என்று மோசே வேண்டுகிறார்."],
    "Deuteronomy 33:8": ["லேவிக்கு ஆசீர்வாதம்", "தேவனுடைய நியாயப்பிரமாணத்தைக் கற்பித்தலிலும் அவருக்குச் சேவை செய்வதிலும் உண்மையாக இருந்ததற்காக லேவி ஆசீர்வதிக்கப்படுகிறான்."],
    "Deuteronomy 33:12": ["பென்யமீனுக்கு ஆசீர்வாதம்", "பென்யமீன் கர்த்தருக்குப் பிரியமானவன் என்றும், அவர் பாதுகாப்பில் சுகமாயிருப்பான் என்றும் விவரிக்கப்படுகிறது."],
    "Deuteronomy 33:13": ["யோசேப்பிற்கு ஆசீர்வாதம்", "வானத்திலிருந்தும் பூமியிலிருந்தும் யோசேப்பு ஏராளமான ஆசீர்வாதங்களைப் பெறுகிறான்."],
    "Deuteronomy 33:18": ["செபுலோன் மற்றும் இசக்காருக்கு ஆசீர்வாதம்", "இந்தக் கோத்திரங்கள் தங்கள் வேலையிலும் செழிப்பிலும் மகிழ்ச்சியடைய ஆசீர்வதிக்கப்படுகிறார்கள்."],
    "Deuteronomy 33:20": ["காத்திற்கு ஆசீர்வாதம்", "காத் கோத்திரத்தார் போரில் காட்டிய தைரியத்திற்காகவும் பலத்திற்காகவும் புகழப்படுகிறார்கள்."],
    "Deuteronomy 33:22": ["தாணிற்கு ஆசீர்வாதம்", "தாண் பாசானிலிருந்து பாய்கிற சிங்கக்குட்டிக்கு ஒப்பிடப்படுகிறான்."],
    "Deuteronomy 33:23": ["நப்தலிக்கு ஆசீர்வாதம்", "நப்தலி கர்த்தருடைய ஆசீர்வாதத்தினாலும் தயவினாலும் நிறைந்திருக்கிறான்."],
    "Deuteronomy 33:24": ["ஆசேருக்கு ஆசீர்வாதம்", "ஆசேர் செழிப்பினாலும் பாதுகாப்பினாலும் ஆசீர்வதிக்கப்படுகிறான்."],
    "Deuteronomy 33:26": ["நித்திய தேவன் இஸ்ரவேலைப் பாதுகாக்கிறார்", "இஸ்ரவேலின் தேவனைப் போல வேறு யாருமில்லை; அவர் தமது ஜனங்களுக்குத் துணையாக இருக்கிறார்."],
    "Deuteronomy 33:29": ["இஸ்ரவேலே நீ பாக்கியவான்", "கர்த்தர் தங்களுக்குக் கேடயமும் துணையுமாய் இருப்பதால் இஸ்ரவேலர் பாக்கியவான்கள் என்று அழைக்கப்படுகிறார்கள்."],

    "Deuteronomy 34:1": ["வாக்குத்தத்தம் பண்ணப்பட்ட தேசத்தை மோசே காணுதல்", "கர்த்தர் மோசேயை நேபோ மலைக்கு அழைத்துச் சென்று, இஸ்ரவேலுக்கு வாக்குறுதி அளித்த தேசம் முழுவதையும் காட்டுகிறார்."],
    "Deuteronomy 34:4": ["தேவனுடைய வாக்குறுதி நிறைவேறல்", "ஆபிரகாம், ஈசாக்கு, யாக்கோபு ஆகியோருக்குத் தாம் ஆணையிட்ட தேசம் இதுவே என்று தேவன் கூறுகிறார், ஆனால் மோசே அதில் நுழைய மாட்டார்."],
    "Deuteronomy 34:5": ["மோசேயின் மரணம்", "கர்த்தருடைய வார்த்தையின்படியே மோசே மோவாப் தேசத்தில் மரிக்கிறார்."],
    "Deuteronomy 34:6": ["மோசே அடக்கம் செய்யப்படல்", "கர்த்தர் மோசேயை மோவாபில் அடக்கம் செய்தார், ஆனால் அவருடைய கல்லறை இருக்குமிடம் எவருக்கும் தெரியாது."],
    "Deuteronomy 34:7": ["மரணத்தின் போது மோசேயின் பலம்", "மோசே 120 வயதில் மரித்தபோது, அவருடைய கண்கள் மங்கவில்லை, அவருடைய பலமும் குறையவில்லை."],
    "Deuteronomy 34:8": ["இஸ்ரவேலர் மோசேக்காகத் துக்கங்கொண்டாடுதல்", "இஸ்ரவேல் மக்கள் மோவாப் சமவெளியில் முப்பது நாட்கள் மோசேக்காகத் துக்கம் கொண்டாடினார்கள்."],
    "Deuteronomy 34:9": ["ஞானத்தினால் நிறைந்த யோசுவா", "யோசுவா இஸ்ரவேலை வழிநடத்தத் தொடங்கியபோது, அவர் ஞானத்தின் ஆவியினால் நிறைந்திருந்தார்."],
    "Deuteronomy 34:10": ["மோசேயைப் போல ஒரு தீர்க்கதரிசி இல்லை", "கர்த்தரை நேருக்கு நேர் அறிந்த மோசேயைப் போல ஒரு தீர்க்கதரிசியும் இஸ்ரவேலில் எழும்பியதில்லை."],
    "Deuteronomy 34:11": ["மகிமையான அடையாளங்களும் அற்புதங்களும்", "மோசே எகிப்திலும் இஸ்ரவேலருக்கு முன்பாகவும் பெரிய அடையாளங்களையும் அற்புதங்களையும் செய்தார்."],
    "Deuteronomy 34:12": ["மோசேயின் மகா வல்லமை", "இஸ்ரவேலர் அனைவரும் காணும்படி மோசே மகா வல்லமையையும் பயங்கரமான கிரியைகளையும் செய்தார்."],

    // ===========================
    // NEW TESTAMENT
    // ===========================

    "Matthew 1:1": ["இயேசு கிறிஸ்துவின் வம்ச வரலாறு", "ஆபிரகாம் மற்றும் தாவீதின் வழியில் வந்த இயேசுவின் அரச குல வம்சாவளியை மத்தேயு அறிமுகப்படுத்துகிறார்."],
    "Matthew 1:2": ["ஆபிரகாம் முதல் தாவீது வரை", "வம்சாவளியானது ஆபிரகாமில் தொடங்கி ஈசாக்கு, யாக்கோபு, யூதா வழியாகத் தாவீது ராஜா வரையிலான தலைமுறைகளைத் தொடர்கிறது."],
    "Matthew 1:6": ["தாவீது முதல் எகிப்து சிறையிருப்பு வரை", "தாவீது முதல் பாபிலோனுக்குச் சிறைப்பட்டுப் போன காலம் வரையிலான யூத ராஜாக்களின் வம்சாவளி தொடர்கிறது."],
    "Matthew 1:12": ["சிறையிருப்பு முதல் இயேசு வரை", "பாபிலோன் சிறையிருப்புக்குப் பிறகு, மரியாளினுடைய கணவராகிய யோசேப்பு வரையிலான தலைமுறைகள் விவரிக்கப்பட்டுள்ளன."],
    "Matthew 1:17": ["தலைமுறைகளின் சுருக்கம்", "ஆபிரகாம் முதல் தாவீது வரை, தாவீது முதல் சிறையிருப்பு வரை, சிறையிருப்பு முதல் கிறிஸ்து வரை என வம்சாவளியை மூன்று பதினான்கு தலைமுறைகளாக மத்தேயு சுருக்கிக் கூறுகிறார்."],
    "Matthew 1:18": ["இயேசு கிறிஸ்துவின் பிறப்பு", "மரியாள் பரிசுத்த ஆவியினால் கர்ப்பவதியானார் என்பதை விளக்கி, இயேசுவின் பிறப்பு வரலாற்றை மத்தேயு தொடங்குகிறார்."],
    "Matthew 1:20": ["யோசேப்புக்குத் தூதன் தரிசனமாதல்", "யோசேப்புக்கு ஒரு தூதன் சொப்பனத்தில் தோன்றி, மரியாள் வயிற்றில் இருப்பது பரிசுத்த ஆவியினால் உண்டானது என்று உறுதிப்படுத்தினார்."],
    "Matthew 1:21": ["இயேசு என்னும் பெயர்", "அவர் தம்முடைய ஜனங்களின் பாவங்களை நீக்கி அவர்களை இரட்சிப்பார், அதனால் அவருக்கு 'இயேசு' என்று பேரிட வேண்டும் எனத் தூதன் சொன்னார்."],
    "Matthew 1:22": ["இம்மானுவேல் தீர்க்கதரிசனம் நிறைவேறுதல்", "ஒரு கன்னி கர்ப்பவதியாகி ஒரு குமாரனைப் பெறுவாள், அவருக்கு இம்மானுவேல் என்று பேரிடுவார்கள் என்னும் தீர்க்கதரிசனம் இயேசுவின் பிறப்பால் நிறைவேறியது."],
    "Matthew 1:24": ["தூதருக்கு யோசேப்பு கீழ்ப்படிதல்", "யோசேப்பு தூதன் கட்டளையிட்டபடியே மரியாளைத் தன் மனைவியாக ஏற்றுக்கொண்டார்."],

    "Matthew 2:1": ["சாஸ்திரிகள் இயேசுவைச் சந்தித்தல்", "இயேசு பெத்லகேமில் பிறந்த பிறகு, கிழக்கிலிருந்து வந்த சாஸ்திரிகள் யூதர்களுக்கு ராஜாவாகப் பிறந்தவரைத் தேடி எருசலேமுக்கு வந்தார்கள்."],
    "Matthew 2:3": ["ஏரோது கலங்குதல்", "யூதர்களின் ராஜா பிறந்த செய்தியைக் கேட்ட ஏரோது ராஜாவும் எருசலேம் நகரமும் கலங்கினார்கள்."],
    "Matthew 2:4": ["பெத்லகேம் தீர்க்கதரிசனம்", "கிறிஸ்து பெத்லகேமில் பிறப்பார் என்று தீர்க்கதரிசனங்களில் எழுதப்பட்டுள்ளதை ஆசாரியர்களும் வேதபாரகர்களும் விளக்கினார்கள்."],
    "Matthew 2:7": ["சாஸ்திரிகளிடம் ஏரோது விசாரித்தல்", "ஏரோது சாஸ்திரிகளை ரகசியமாக அழைத்து, நட்சத்திரம் தோன்றின காலத்தைக் குறித்து விசாரித்து, அவர்களைப் பெத்லகேமுக்கு அனுப்பினான்."],
    "Matthew 2:9": ["நட்சத்திரம் சாஸ்திரிகளை வழிநடத்துதல்", "வானத்தில் தோன்றிய நட்சத்திரம் சாஸ்திரிகளுக்கு முன்னால் சென்று, குழந்தை இருந்த இடத்திற்கு மேலே வந்து நின்றது."],
    "Matthew 2:11": ["இயேசுவுக்குப் பரிசுகள் அளித்தல்", "சாஸ்திரிகள் இயேசுவை வணங்கி, பொன்னையும், தூபவர்க்கத்தையும், வெள்ளப்போளத்தையும் காணிக்கையாக வைத்தார்கள்."],
    "Matthew 2:12": ["சொப்பனத்தில் எச்சரிக்கை", "ஏரோதிடம் திரும்பிப் போக வேண்டாம் என்று சாஸ்திரிகள் சொப்பனத்தில் எச்சரிக்கப்பட்டு, வேறு வழியாகத் தங்கள் தேசத்திற்குத் திரும்பினார்கள்."],
    "Matthew 2:13": ["எகிப்திற்குத் தப்பி ஓடுதல்", "ஏரோது குழந்தையைக் கொல்லத் தேடுவதால், குழந்தையையும் தாயையும் அழைத்துக் கொண்டு எகிப்திற்கு ஓடிப்போகுமாறு யோசேப்பைத் தூதன் எச்சரித்தார்."],
    "Matthew 2:16": ["குழந்தைகளை ஏரோது கொல்லுதல்", "ஏரோது கோபமடைந்து, பெத்லகேமிலும் அதன் எல்லைகளிலும் இருந்த இரண்டு வயதுக்குட்பட்ட ஆண் குழந்தைகள் அனைவரையும் கொன்று போட்டான்."],
    "Matthew 2:19": ["எகிப்திலிருந்து திரும்புதல்", "ஏரோது இறந்த பிறகு, இஸ்ரவேல் தேசத்திற்குத் திரும்புவது பாதுகாப்பானது என்று ஒரு தூதன் யோசேப்புக்குச் சொப்பனத்தில் சொன்னார்."],
    "Matthew 2:22": ["நாசரேத்தில் குடியேறுதல்", "யோசேப்பு கலிலேயா நாட்டிலுள்ள நாசரேத் ஊருக்குப் போய் குடியேறினார்; இதன் மூலம் இயேசு 'நாசரேயன்' எனப்படுவார் என்ற தீர்க்கதரிசனம் நிறைவேறியது."],

    "Matthew 3:1": ["யோவான் ஸ்நானகனின் ஊழியத் தொடக்கம்", "யோவான் ஸ்நானகன் யூதேயாவின் வனாந்தரத்தில் தோன்றி: 'மனந்திரும்புங்கள், பரலோக ராஜ்யம் சமீபத்திருக்கிறது' என்று பிரசங்கித்தார்."],
    "Matthew 3:4": ["யோவானின் வாழ்க்கை முறை", "யோவான் ஒட்டக மயிர் உடையைத் தரித்து, வெட்டுக்கிளியையும் காட்டுத்தேனையும் உணவாகக் கொண்டு எளிமையாக வாழ்ந்தார்."],
    "Matthew 3:5": ["ஜனங்கள் ஞானஸ்நானம் பெறுதல்", "எருசலேமிலும் யூதேயாவிலும் யோர்தான் நதிக்கு அருகிலும் இருந்த ஜனங்கள் யோவானிடம் வந்து, தங்கள் பாவங்களை அறிக்கையிட்டு ஞானஸ்நானம் பெற்றார்கள்."],
    "Matthew 3:7": ["பரிசேயர்களுக்கும் சதுசேயர்களுக்கும் எச்சரிக்கை", "மதத் தலைவர்களை யோவான் கண்டித்து, மனந்திரும்புதலுக்கு ஏற்ற கனிகளைக் கொடுங்கள் என்று எச்சரித்தார்."],
    "Matthew 3:10": ["வரப்போகும் நியாயத்தீர்ப்பு", "நல்ல கனிகொடுக்காத மரமெல்லாம் வெட்டப்பட்டு அக்கினியிலே போடப்படும் என்று எச்சரித்தார்."],
    "Matthew 3:11": ["யோவானிலும் பெரியவர்", "எனக்குப்பின் வருகிறவர் என்னிலும் வல்லவர், அவர் பரிசுத்த ஆவியினாலும் அக்கினியினாலும் உங்களுக்கு ஞானஸ்நானம் கொடுப்பார் என்று யோவான் கூறினார்."],
    "Matthew 3:13": ["இயேசு ஞானஸ்நானம் பெறுதல்", "இயேசு யோவானால் ஞானஸ்நானம் பெறுவதற்காகக் கலிலேயாவிலிருந்து யோர்தானுக்கு வந்தார்."],
    "Matthew 3:14": ["யோவான் தயங்குதல்", "நான் உம்மால் ஞானஸ்நானம் பெற வேண்டியிருக்க, நீர் என்னிடம் வரலாமா என்று யோவான் அவரைத் தடுக்க முயன்றார்."],
    "Matthew 3:15": ["இயேசு வற்புறுத்துதல்", "இப்பொழுது இதற்கு இடங்கொடு, இப்படி எல்லா நீதியையும் நிறைவேற்றுவது நமக்கு ஏற்றதாயிருக்கிறது என்று இயேசு சொன்னார்."],
    "Matthew 3:16": ["வானம் திறக்கப்படுதல்", "இயேசு ஞானஸ்நானம் பெற்று கரையேறினபோது, வானம் திறக்கப்பட்டது; தேவ ஆவியானவர் புறாவைப் போல அவர் மேல் இறங்கினார்."],
    "Matthew 3:17": ["பிதாவின் சத்தம்", "வானத்திலிருந்து ஒரு சத்தம்: 'இவர் என்னுடைய நேச குமாரன், இவரில் பிரியமாயிருக்கிறேன்' என்று உரைத்தது."],

    "Matthew 4:1": ["வனாந்தரத்தில் இயேசு சோதிக்கப்படுதல்", "இயேசு ஆவியானவரால் வனாந்தரத்திற்குக் கொண்டு செல்லப்பட்டு, நாற்பது நாள் உபவாசம் இருந்தபின் பிசாசினால் சோதிக்கப்பட்டார்."],
    "Matthew 4:5": ["இரண்டாம் சோதனை", "பிசாசு இயேசுவை தேவாலயத்தின் உப்பரிகையில் நிறுத்தி, கீழே குதிக்கும்படி சவால் விட்டான்."],
    "Matthew 4:8": ["மூன்றாம் சோதனை", "பிசாசு உலகத்தின் சகல ராஜ்யங்களையும் காட்டி, தன்னை வணங்கினால் இவைகளையெல்லாம் தருவதாகச் சொன்னான்."],
    "Matthew 4:11": ["தூதர்கள் பணிவிடை செய்தல்", "இயேசு சோதனைகளை வென்ற பிறகு, பிசாசு அவரை விட்டுப் போனான்; தூதர்கள் வந்து அவருக்குப் பணிவிடை செய்தார்கள்."],
    "Matthew 4:12": ["கலிலேயாவில் ஊழியத் தொடக்கம்", "யோவான் காவலில் வைக்கப்பட்டதை அறிந்து, இயேசு கலிலேயாவுக்குச் சென்று பிரசங்கிக்கத் தொடங்கினார்."],
    "Matthew 4:13": ["கப்பர்நகூமில் வாசம்", "நாசரேத்தை விட்டு கப்பர்நகூமில் தங்கி, கலிலேயாவில் ஒளி பிரகாசிக்கும் என்ற தீர்க்கதரிசனத்தை நிறைவேற்றினார்."],
    "Matthew 4:17": ["மனந்திரும்புதல் செய்தி", "பரலோக ராஜ்யம் சமீபத்திருக்கிறது, மனந்திரும்புங்கள் என்று இயேசு பிரசங்கிக்கத் தொடங்கினார்."],
    "Matthew 4:18": ["முதல் சீஷர்களை அழைத்தல்", "மீன் பிடித்துக் கொண்டிருந்த பேதுருவையும் அந்திரேயாவையும் அழைத்து, 'மனுஷர்களைப் பிடிக்கிறவர்களாக்குவேன்' என்றார்."],
    "Matthew 4:21": ["மேலும் சில சீஷர்கள்", "செபெதேயுவின் குமாரர்களாகிய யாக்கோபையும் யோவானையும் அவர் அழைக்க, அவர்கள் உடனடியாக அவரைப் பின்பற்றினார்கள்."],
    "Matthew 4:23": ["இயேசு ஜனங்களைக் குணமாக்குதல்", "இயேசு கலிலேயா எங்கும் சுற்றித் திரிந்து, ராஜ்யத்தின் சுவிசேஷத்தைப் பிரசங்கித்து, சகல நோய்களையும் நீக்கினார்."],
    "Matthew 4:24": ["புகழ் பரவுதல்", "இயேசுவைப் பற்றிய செய்தி சீரியா எங்கும் பரவியது; வியாதிஸ்தர்களும் பிசாசு பிடித்தவர்களும் அவரிடம் குணமடைய அழைத்து வரப்பட்டார்கள்."],
    "Matthew 4:25": ["திரளான ஜனங்கள் பின்தொடருதல்", "கலிலேயா, தெக்கப்போலி, எருசலேம் போன்ற இடங்களிலிருந்து திரளான ஜனங்கள் அவரைப் பின்தொடர்ந்தார்கள்."],

    "Matthew 5:1": ["மலைப்பிரசங்கம் தொடக்கம்", "ஜனங்களைக் கண்டபோது இயேசு மலையின் மேல் ஏறி அமர்ந்து, தம் சீஷர்களுக்கு உபதேசிக்கத் தொடங்கினார்."],
    "Matthew 5:3": ["மலைப்பிரசங்க ஆசீர்வாதங்கள்", "ஆவியில் எளிமையுள்ளவர்கள், துயரப்படுகிறவர்கள், சாந்தகுணமுள்ளவர்கள் என நீதியைத் தேடுகிறவர்களை இயேசு ஆசீர்வதித்தார்."],
    "Matthew 5:13": ["பூமிக்கு உப்பு", "நீங்கள் பூமிக்கு உப்பாயிருக்கிறீர்கள் என்று இயேசு தம்மைப் பின்பற்றுபவர்களிடம் சொன்னார்."],
    "Matthew 5:14": ["உலகிற்கு ஒளி", "நீங்கள் உலகிற்கு ஒளியாயிருக்கிறீர்கள்; உங்கள் வெளிச்சம் மனுஷருக்கு முன்பாகப் பிரகாசிக்க வேண்டும் என்று கற்பித்தார்."],
    "Matthew 5:17": ["நியாயப்பிரமாணத்தை நிறைவேற்றுதல்", "நான் நியாயப்பிரமாணத்தை அழிக்க வரவில்லை, அதை நிறைவேற்றவே வந்தேன் என்று இயேசு விளக்கினார்."],
    "Matthew 5:21": ["கோபத்தைக் குறித்த போதனை", "கோபம் கொலையை விட மோசமானது என்றும், மற்றவர்களுடன் சமாதானமாவது அவசியம் என்றும் கற்பித்தார்."],
    "Matthew 5:27": ["விபச்சாரத்தைக் குறித்த போதனை", "ஒரு பெண்ணை இச்சையோடு பார்ப்பதே இதயத்தில் விபச்சாரம் செய்வதாகும் என்று இயேசு கற்பித்தார்."],
    "Matthew 5:31": ["விவாகரத்தைக் குறித்த போதனை", "விவாகரத்து மற்றும் திருமணத்தில் உண்மையுடன் இருப்பது குறித்து இயேசு போதித்தார்."],
    "Matthew 5:33": ["சத்தியத்தைக் குறித்த போதனை", "ஆணையிடாமல் உண்மையாகப் பேசுங்கள்; ஆம் என்றால் ஆம் என்றும், இல்லை என்றால் இல்லை என்றும் சொல்லுங்கள் என்றார்."],
    "Matthew 5:38": ["தீமைக்குத் தீமை செய்யாதிருத்தல்", "தீமை செய்கிறவனுக்கு எதிராக நிற்காமல், ஒரு கன்னத்தில் அறைந்தால் மறு கன்னத்தையும் காட்டுங்கள் என்று பொறுமையைப் போதித்தார்."],
    "Matthew 5:43": ["சத்துருக்களை நேசித்தல்", "உங்கள் பகைவர்களையும் நேசியுங்கள், உங்களைத் துன்பப்படுத்துகிறவர்களுக்காக வேண்டிக்கொள்ளுங்கள் என்று போதித்தார்."],
    "Matthew 5:48": ["பூரணராயிருத்தல்", "உங்கள் பரம பிதா பூரணராயிருக்கிறது போல, நீங்களும் பூரணராயிருக்கக் கடவீர்கள் என்று அழைப்பு விடுத்தார்."],

    "Matthew 6:1": ["தர்மம் செய்தல்", "மனுஷர் காணும்படி தர்மம் செய்யாமல், பிதாவுக்கு முன்பாக ரகசியமாகச் செய்ய வேண்டும் என்று கற்பித்தார்."],
    "Matthew 6:5": ["ஜெபத்தைக் குறித்த போதனை", "மனுஷர் பார்க்கும்படி வீதிகளில் நின்று ஜெபிக்காமல், ரகசியமாக ஜெபிக்க வேண்டும் என்றார்."],
    "Matthew 6:9": ["பரமண்டல ஜெபம்", "எங்கள் பரம பிதாவே என்று தொடங்கும் ஒரு மாதிரி ஜெபத்தை இயேசு கற்றுக்கொடுத்தார்."],
    "Matthew 6:16": ["உபவாசத்தைக் குறித்த போதனை", "உபவாசிக்கும்போது மற்றவர்கள் அறியாதபடி முகத்தைக் கழுவி, உண்மையாக உபவாசிக்க வேண்டும் என்றார்."],
    "Matthew 6:19": ["பரலோக பொக்கிஷம்", "பூமியிலே பொக்கிஷங்களைச் சேர்க்காமல், பரலோகத்திலே பொக்கிஷங்களைச் சேர்த்து வையுங்கள் என்று போதித்தார்."],
    "Matthew 6:22": ["சரீரத்தின் விளக்கு", "கண் சரீரத்தின் விளக்காயிருக்கிறது; நம்முடைய பார்வைத் தெளிவு முழு வாழ்வையும் பாதிக்கும் என்று விளக்கினார்."],
    "Matthew 6:24": ["தேவனும் உலக ஐசுவரியமும்", "தேவனுக்கும் உலக ஐசுவரியத்திற்கும் (பணம்) ஊழியஞ்செய்ய ஒருவனாலும் முடியாது என்று எச்சரித்தார்."],
    "Matthew 6:25": ["கவலைப்படாதிருத்தல்", "உண்ணும் உணவு, உடுக்கும் உடை ஆகியவற்றைக் குறித்துக் கவலைப்பட வேண்டாம் என்று இயேசு சொன்னார்."],
    "Matthew 6:33": ["முதலாவது ராஜ்யத்தைத் தேடுதல்", "தேவனுடைய ராஜ்யத்தையும் அவருடைய நீதியையும் முதலாவது தேடுங்கள்; அப்பொழுது இவையெல்லாம் உங்களுக்குக் கொடுக்கப்படும் என்றார்."],
    "Matthew 6:34": ["நாளைக்காகக் கவலைப்படாதிருத்தல்", "அந்தந்த நாளுக்கு அந்தந்த நாள் பாடு போதும், நாளைக்காகக் கவலைப்பட வேண்டாம் என்று நினைவுறுத்தினார்."],

    "Matthew 7:1": ["மற்றவர்களை விமரிசிக்காதிருத்தல்", "நீங்கள் மற்றவர்களை நியாயந்தீர்க்காதீர்கள், அப்பொழுது நீங்களும் நியாயந்தீர்க்கப்பட மாட்டீர்கள் என்று கற்பித்தார்."],
    "Matthew 7:6": ["பரிசுத்தமானதை நாய்களுக்குக் கொடுக்காதிருத்தல்", "பரிசுத்தமானதை நாய்களுக்குக் கொடுக்காதீர்கள், உங்கள் முத்துக்களைப் பன்றிகளுக்கு முன்பாகப் போடாதீர்கள் என்று எச்சரித்தார்."],
    "Matthew 7:7": ["கேளுங்கள், தேடுங்கள், தட்டுங்கள்", "ஜெபத்தில் விடாமுயற்சியோடு இருங்கள்; கேட்கிறவனுக்குக் கிடைக்கும், தேடுகிறவன் கண்டடைவான் என்று ஊக்கப்படுத்தினார்."],
    "Matthew 7:12": ["பொன் விதி (Golden Rule)", "மனுஷர் உங்களுக்கு எவைகளைச் செய்ய வேண்டும் என்று விரும்புகிறீர்களோ, அவைகளை நீங்களும் அவர்களுக்குச் செய்யுங்கள்."],
    "Matthew 7:13": ["இடுக்கமான வாசல்", "ஜீவனுக்குப் போகிற வாசல் இடுக்கமானது, அழிவுக்குப் போகிற வாசல் அகலமானது என்று எச்சரித்தார்."],
    "Matthew 7:15": ["கள்ளத் தீர்க்கதரிசிகள்", "ஆட்டுத் தோலைப் போர்த்துக் கொண்டு வரும் ஓநாய்களாகிய கள்ளத் தீர்க்கதரிசிகள் குறித்து எச்சரிக்கையாக இருங்கள்."],
    "Matthew 7:21": ["உண்மையான சீஷர்கள்", "என்னை 'கர்த்தாவே, கர்த்தாவே' என்று கூப்பிடுகிறவன் பரலோகில் நுழைவதில்லை, பிதாவின் சித்தத்தின்படி செய்கிறவனே நுழைவான் என்றார்."],
    "Matthew 7:24": ["புத்தியுள்ள மற்றும் புத்தியில்லாத வீடுகட்டுவோர்", "தன் வார்த்தைகளைக் கேட்டு நடப்பவனைப் பாறையின் மேல் வீடு கட்டிய புத்தியுள்ள மனுஷனுக்கு ஒப்பிட்டார்."],
    "Matthew 7:28": ["இயேசுவின் அதிகாரமுள்ள போதனை", "இயேசு அதிகாரத்தோடு போதித்ததைக் கண்டு ஜனங்கள் ஆச்சரியப்பட்டார்கள்."],

    "Matthew 8:1": ["குஷ்டரோகியைக் குணமாக்குதல்", "மலையிலிருந்து இறங்கி வந்தபோது, தம்மைச் சுத்தமாக்கக் கேட்ட ஒரு குஷ்டரோகியை இயேசு குணமாக்கினார்."],
    "Matthew 8:5": ["நூற்றுக்கு அதிபதியின் விசுவாசம்", "ரோம நூற்றுக்கு அதிபதி தன் ஊழியனுக்காகப் பரிந்து பேசி, இயேசுவின் அதிகாரத்தின் மேல் இருந்த விசுவாசத்தைக் காட்டினான்."],
    "Matthew 8:10": ["பெரிய விசுவாசம் அங்கீகரிக்கப்படுதல்", "இஸ்ரவேலிலும் இவ்வளவு பெரிய விசுவாசத்தைக் காணவில்லை என்று இயேசு பாராட்டி, புறஜாதிகளும் ராஜ்யத்தில் நுழைவார்கள் என்றார்."],
    "Matthew 8:14": ["பலரைக் குணமாக்குதல்", "பேதுருவின் மாமியாரையும், பிசாசு பிடித்த பலரையும் இயேசு குணமாக்கினார்."],
    "Matthew 8:18": ["பின்பற்றுவதற்கான விலைக்கிரயம்", "இயேசுவைப் பின்பற்றுவதற்குத் தேவையான அர்ப்பணிப்பைக் குறித்து அவர் பேசினார்."],
    "Matthew 8:23": ["இயேசு புயலை அடக்குதல்", "கடலில் புயல் எழுந்தபோது, இயேசு காற்றையும் கடலையும் அதட்டிப் பெரும் அமைதியை உண்டாக்கினார்."],
    "Matthew 8:28": ["பிசாசு பிடித்த இருவர்", "கெர்கெசேனர் தேசத்தில் பிசாசு பிடித்த இருவரை விடுவித்து, அந்தப் பிசாசுகளைப் பன்றிக்கூட்டத்திற்குள் போகச் செய்தார்."],
    "Matthew 8:34": ["இயேசுவை வெளியேறக் கேட்டல்", "இந்த அற்புதத்தைக் கண்ட ஊர் மக்கள் பயந்து, இயேசுவைத் தங்கள் எல்லைகளை விட்டுப் போகும்படி கேட்டுக்கொண்டார்கள்."],

    "Matthew 9:1": ["திமிர்வாதக்காரனைக் குணமாக்குதல்", "ஒரு திமிர்வாதக்காரனைக் குணப்படுத்தி, அவனுடைய பாவங்களை மன்னித்து, தமக்குள்ள மன்னிக்கும் அதிகாரத்தை இயேசு வெளிப்படுத்தினார்."],
    "Matthew 9:9": ["மத்தேயுவை அழைத்தல்", "ஆயக்காரனான மத்தேயுவை இயேசு அழைக்க, அவர் உடனடியாகப் பின்தொடர்ந்து சீஷரானார்."],
    "Matthew 9:10": ["பாவிகளோடு இயேசு உணவு அருந்துதல்", "ஆயக்காரரோடும் பாவிகளோடும் இயேசு உணவு அருந்தியபோது, நீதியுள்ளவர்களையல்ல, பாவிகளையே மனந்திரும்ப அழைக்க வந்தேன் என்றார்."],
    "Matthew 9:14": ["உபவாசத்தைக் குறித்த கேள்வி", "யோவானின் சீஷர்கள் உபவாசம் குறித்துக் கேட்டபோது, மணவாளன் தங்களோடு இருக்கும் வரை அவர்கள் உபவாசிக்க மாட்டார்கள் என்றார்."],
    "Matthew 9:18": ["தலைவனுடைய குமாரத்தியும் வியாதியுள்ள பெண்ணும்", "மரித்துப்போன ஒரு தலைவனுடைய குமாரத்தியை எழுப்பினார், இரத்தப்போக்குள்ள பெண்ணைக் குணமாக்கினார்."],
    "Matthew 9:27": ["இரு குருடர்களைக் குணமாக்குதல்", "விசுவாசத்தோடு பின்தொடர்ந்த இரண்டு குருடர்களுடைய கண்களை இயேசு திறந்தார்."],
    "Matthew 9:32": ["ஊமையைக் குணமாக்குதல்", "ஊமையாயிருந்த ஒருவனிடமிருந்த பிசாசைத் துரத்தி அவனைப் பேச வைத்தார்."],
    "Matthew 9:35": ["திரளான ஜனங்களுக்கு ஊழியம்", "இயேசு எல்லா ஊர்களிலும் சுற்றித் திரிந்து பிரசங்கித்து, சகல நோய்களையும் குணமாக்கினார்."],
    "Matthew 9:37": ["அறுப்பு மிகுதி", "அறுப்பு மிகுதி, வேலையாட்களோ குறைவு; அறுப்புக்கு வேலையாட்களை அனுப்பும்படி எஜமானிடம் வேண்டிக் கொள்ளுங்கள் என்றார்."],

    "Matthew 10:1": ["பன்னிரண்டு அப்போஸ்தலர்கள் தெரிந்துகொள்ளப்படல்", "இயேசு தம் பன்னிரண்டு சீஷர்களுக்கும் அசுத்த ஆவிகளைத் துரத்தவும், நோய்களைக் குணமாக்கவும் அதிகாரத்தைக் கொடுத்தார்."],
    "Matthew 10:2": ["பன்னிரண்டு அப்போஸ்தலர்களின் பெயர்கள்", "இயேசு தெரிந்துகொண்ட பன்னிரண்டு அப்போஸ்தலர்களின் பெயர்கள் மத்தேயுவால் பட்டியலிடப்பட்டுள்ளன."],
    "Matthew 10:5": ["பன்னிரண்டு பேர் அனுப்பப்படுதல்", "இஸ்ரவேல் வம்சத்தின் காணாமற்போன ஆடுகளிடத்திற்குப் போய் பிரசங்கிக்கும்படி அவர்களை அனுப்பினார்."],
    "Matthew 10:7": ["ராஜ்யத்தின் செய்தி", "பரலோக ராஜ்யம் சமீபத்திருக்கிறது என்று பிரசங்கியுங்கள் எனக் கட்டளையிட்டார்."],
    "Matthew 10:9": ["ஊழியத்திற்கான அறிவுரைகள்", "கூடுதல் உடைமைகளை எடுத்துச் செல்லாமல் தேவனுடைய பராமரிப்பை நம்பிச் செல்லச் சொன்னார்."],
    "Matthew 10:14": ["செய்தியை மறுத்தல்", "யாராவது உங்களை ஏற்க மறுத்தால், உங்கள் கால்களில் படிந்த தூசியை உதறிப் போடுங்கள் என்றார்."],
    "Matthew 10:16": ["விவேகமும் கள்ளமின்மையும்", "நீங்கள் ஓநாய்களுக்குள்ளே ஆடுகளைப் போல அனுப்பப்படுகிறீர்கள், பாம்புகளைப் போல விவேகிகளும் புறாக்களைப் போலக் கள்ளமற்றவர்களுமாயிருங்கள் என்றார்."],
    "Matthew 10:21": ["துன்புறுத்தல் குறித்த எச்சரிக்கை", "தன்னைப் பின்பற்றுபவர்களுக்குத் துன்புறுத்தல்களும் துரோகங்களும் வரும் என்று எச்சரித்தார்."],
    "Matthew 10:26": ["மனுஷருக்குப் பயப்படாதிருத்தல்", "மனுஷர்களுக்குப் பயப்படாமல், தேவனுக்குப் பயந்து அவரை நம்பும்படி ஊக்கப்படுத்தினார்."],
    "Matthew 10:32": ["கிறிஸ்துவை அறிக்கை செய்தல்", "மனுஷருக்கு முன்பாக என்னை அறிக்கை செய்கிறவனை, நானும் பரலோகப் பிதாவுக்கு முன்பாக அறிக்கை செய்வேன் என்றார்."],
    "Matthew 10:34": ["சமாதானமல்ல, பட்டயம்", "இயேசுவைப் பின்பற்றுவதால் குடும்பங்களுக்குள்ளும் பிரிவினைகள் ஏற்படலாம் என்று விளக்கினார்."],
    "Matthew 10:37": ["சீஷத்துவத்தின் விலைக்கிரயம்", "தன்னைவிடத் தன் குடும்பத்தை அதிகம் நேசிப்பவன் தமக்கு பாத்திரன் அல்ல என்று இயேசு போதித்தார்."],
    "Matthew 10:40": ["சீஷர்களை ஏற்பவர்களுக்குப் பலன்", "உங்களை ஏற்றுக்கொள்கிறவன் என்னை ஏற்றுக்கொள்கிறான்; அவனுக்கு அதற்குரிய பலன் கிடைக்கும் என்றார்."],

    "Matthew 11:1": ["இயேசு ஊழியத்தைத் தொடருதல்", "தம்முடைய சீஷர்களுக்குக் கட்டளைகளைக் கொடுத்து முடித்தபின், இயேசு கலிலேயாவிலுள்ள பட்டணங்களில் உபதேசிக்கவும் பிரசங்கிக்கவும் சென்றார்."],
    "Matthew 11:2": ["யோவான் ஸ்நானகனின் கேள்வி", "சிறையிலிருந்த யோவான் ஸ்நானகன், வரப்போகிற மேசியா நீர்தானா அல்லது வேறொருவர் வரக் காத்திருக்க வேண்டுமா என்று கேட்கத் தன் சீஷர்களை அனுப்பினார்."],
    "Matthew 11:4": ["யோவானுக்கு இயேசுவின் பதில்", "தாம் செய்யும் அற்புதங்களையும் கிரியைகளையும் சுட்டிக்காட்டி, மேசியா வந்துவிட்டார் என்பதற்கு அவைகளை அத்தாட்சியாக இயேசு கூறினார்."],
    "Matthew 11:7": ["யோவானைக் குறித்து இயேசுவின் சாட்சி", "வாக்குத்தத்தம் பண்ணப்பட்ட தூதனாகிய யோவான் ஸ்நானகனின் பங்கைக் குறித்து இயேசு ஜனங்களுக்கு விளக்கினார்."],
    "Matthew 11:11": ["யோவானின் மேன்மை", "ஸ்திரீகளிடத்தில் பிறந்தவர்களில் யோவான் ஸ்நானகனை விடப் பெரியவன் ஒருவனுமில்லை; ஆனாலும் பரலோக ராஜ்யத்தில் மிகச் சிறியவனும் அவனை விடப் பெரியவனாயிருக்கிறான் என்றார்."],
    "Matthew 11:16": ["இந்தச் சந்ததியினருக்கு ஒப்பனை", "எதற்கும் திருப்தியடையாத பிள்ளைகளுக்கு இந்தச் சந்ததியினரை இயேசு ஒப்பிட்டுக் கூறினார்."],
    "Matthew 11:20": ["மனந்திரும்பாத பட்டணங்களுக்கு ஐயோ", "தம்முடைய பலத்த செய்கைகளைக் கண்டும் மனந்திரும்பாத பட்டணங்களை இயேசு கடிந்துகொண்டார்."],
    "Matthew 11:25": ["பிதாவை இயேசு துதித்தல்", "ஞானிகளுக்கும் விவேகிகளுக்கும் உண்மைகளை மறைத்து, அவைகளை குழந்தைகளுக்கு (தாழ்மையுள்ளவர்களுக்கு) வெளிப்படுத்தியதற்காகப் பிதாவிற்கு நன்றி சொன்னார்."],
    "Matthew 11:28": ["இளைப்பாறுதல் தரும் அழைப்பு", "வருத்தப்பட்டுப் பாரஞ்சுமக்கிறவர்களே, நீங்கள் எல்லாரும் என்னிடத்தில் வாருங்கள், நான் உங்களுக்கு இளைப்பாறுதல் தருவேன் என்று அழைத்தார்."],

    "Matthew 12:1": ["ஓய்வுநாளின் ஆண்டவர்", "இயேசுவின் சீஷர்கள் ஓய்வுநாளில் கதிர்களைக் கொய்து தின்றபோது, தாம் ஓய்வுநாளுக்கும் ஆண்டவர் என்று இயேசு கற்பித்தார்."],
    "Matthew 12:9": ["சூம்பின கையையுடைய மனுஷன்", "ஓய்வுநாளில் சடங்குகளை விட இரக்கமே முக்கியம் என்பதைச் சுட்டிக்காட்டி, ஒருவனுடைய சூம்பின கையை இயேசு குணமாக்கினார்."],
    "Matthew 12:14": ["பரிசேயர்களின் சதி", "இயேசுவை எப்படிக் கொலை செய்யலாம் என்று பரிசேயர்கள் ஆலோசனை பண்ணத் தொடங்கினார்கள்."],
    "Matthew 12:15": ["தேவன் தெரிந்துகொண்ட ஊழியக்காரர்", "திரளான ஜனங்கள் பின்தொடர்ந்தபோது, சாந்தகுணமுள்ள ஊழியக்காரரைக் குறித்த தீர்க்கதரிசனத்தை நிறைவேற்றும் விதமாக இயேசு அங்கிருந்து விலகிச் சென்றார்."],
    "Matthew 12:22": ["பிசாசு பிடித்தவனைக் குணமாக்குதல்", "பிசாசு பிடித்த குருடனும் ஊமையனுமான ஒருவனை இயேசு குணமாக்கினார்; ஜனங்கள் இதைக் கண்டு ஆச்சரியப்பட்டார்கள்."],
    "Matthew 12:24": ["சாத்தானின் வல்லமை என்று குற்றம் சுமத்துதல்", "இயேசு பெயல்செபூலினால் (பிசாசுகளின் தலைவன்) பிசாசுகளைத் துரத்துகிறார் என்று பரிசேயர்கள் குற்றம் சுமத்தினார்கள்."],
    "Matthew 12:25": ["தனக்குத்தானே விரோதமான வீடு", "தனக்குத்தானே விரோதமாய் எழும்புகிற எந்த ராஜ்யமும் நிலைநிற்காது என்று இயேசு விளக்கினார்."],
    "Matthew 12:31": ["பரிசுத்த ஆவிக்கு விரோதமான தூஷணம்", "பரிசுத்த ஆவிக்கு விரோதமான தூஷணம் மன்னிக்கப்படமாட்டாது என்று இயேசு எச்சரித்தார்."],
    "Matthew 12:33": ["மரமும் அதன் கனியும்", "மரமானது அதன் கனியினால் அறியப்படும்; அதுபோலவே ஒருவனுடைய இருதயத்தின் தன்மையை அவன் வார்த்தைகள் வெளிப்படுத்தும் என்றார்."],
    "Matthew 12:38": ["யோனாவின் அடையாளம்", "யூதத் தலைவர்கள் அடையாளம் கேட்டபோது, யோனாவின் அடையாளத்தைத் தவிர வேறொன்றும் கொடுக்கப்படமாட்டாது என்றார்."],
    "Matthew 12:43": ["அசுத்த ஆவி திரும்பி வருதல்", "ஒருவனிடமிருந்து வெளியேறிய அசுத்த ஆவி, அதைவிட மோசமான ஏழு ஆவிகளுடன் திரும்பி வரக்கூடும் என்று விளக்கினார்."],
    "Matthew 12:46": ["இயேசுவின் உண்மையான குடும்பம்", "பரலோகத்திலிருக்கிற என் பிதாவின் சித்தத்தைச் செய்கிறவனே எனக்குச் சகோதரனும் சகோதரியும் தாயுமாயிருக்கிறான் என்றார்."],

    "Matthew 13:1": ["விதைக்கிறவன் உவமை", "கடற்கரையில் திரண்டிருந்த ஜனங்களுக்கு, நான்கு வகையான நிலங்களில் விழுந்த விதைகளைக் குறித்து உவமையின் மூலம் இயேசு போதித்தார்."],
    "Matthew 13:10": ["உவமைகளின் நோக்கம்", "தாம் ஏன் ஜனங்களுக்கு உவமைகளின் வாயிலாகப் பேசுகிறார் என்பதன் காரணத்தைச் சீஷர்களுக்கு விளக்கினார்."],
    "Matthew 13:18": ["விதைக்கிறவன் உவமையின் விளக்கம்", "வசனத்தைக் கேட்கிறவர்களின் வெவ்வேறு நிலைகளை அந்த நான்கு வகையான நிலங்கள் குறிக்கின்றன என்று விளக்கினார்."],
    "Matthew 13:24": ["கோதுமையும் களைகளும் உவமை", "நல்ல விதைகளுக்கு இடையே சத்துருவானவன் களைகளை விதைத்ததைப் பற்றிய உவமையைச் சொன்னார்."],
    "Matthew 13:31": ["கடுகு விதை உவமை", "பரலோக ராஜ்யம் ஒரு சிறிய கடுகு விதை வளர்ந்து பெரிய மரமாவது போலப் பெருகும் என்று ஒப்பிட்டார்."],
    "Matthew 13:33": ["புளித்த மாவு உவமை", "பரலோக ராஜ்யம் மாவு முழுவதையும் புளிக்கப்பண்ணும் கொஞ்சமான புளித்த மாவுக்கு ஒப்பாயிருக்கிறது என்றார்."],
    "Matthew 13:36": ["களைகளின் உவமை விளக்கம்", "கோதுமை என்பது ராஜ்யத்தின் புத்திரர் என்றும், களைகள் என்பது பொல்லாங்கனின் புத்திரர் என்றும் விளக்கினார்."],
    "Matthew 13:44": ["புதைந்திருக்கும் பொக்கிஷம்", "பரலோக ராஜ்யம் நிலத்தில் மறைந்திருக்கும் பொக்கிஷத்திற்கு ஒப்பாயிருக்கிறது."],
    "Matthew 13:45": ["விலையேறப்பெற்ற முத்து", "பரலோக ராஜ்யம் நல்ல முத்துக்களைத் தேடுகிற வியாபாரிக்கு ஒப்பாயிருக்கிறது; அவன் விலையேறப்பெற்ற ஒரு முத்தைக் கண்டு தன் ஆஸ்திகளையெல்லாம் விற்று அதை வாங்கினான்."],
    "Matthew 13:47": ["வலை உவமை", "பரலோக ராஜ்யம் கடலில் போடப்பட்டுச் சகலவித மீன்களையும் சேர்த்த வலைக்கு ஒப்பாயிருக்கிறது."],
    "Matthew 13:53": ["நாசரேத்தில் புறக்கணிக்கப்படல்", "இயேசு தம்முடைய சொந்த ஊருக்கு வந்தபோது, அங்கிருந்த ஜனங்கள் விசுவாசிக்காமல் அவரைப் புறக்கணித்தார்கள்."],

    "Matthew 14:1": ["இயேசுவைக் குறித்து ஏரோது கேட்டல்", "இயேசுவின் புகழ் பரவியபோது, அவர் மரித்தோரிலிருந்து எழுந்த யோவான் ஸ்நானகனோ என்று ஏரோது சந்தேகித்தான்."],
    "Matthew 14:3": ["யோவான் சிறைவைக்கப்படல்", "ஏரோது தன் சகோதரன் மனைவியாகிய ஏரோதியாளை வைத்துக்கொண்டதைக் கண்டித்ததால், யோவான் சிறையில் அடைக்கப்பட்டிருந்தார்."],
    "Matthew 14:5": ["ஜனங்களுக்குப் பயப்படுதல்", "யோவானைக் கொல்ல ஏரோது விரும்பினான், ஆனால் ஜனங்கள் அவரைத் தீர்க்கதரிசி என்று கருதியதால் அவர்களுக்குப் பயந்தான்."],
    "Matthew 14:6": ["ஏரோதின் பிறந்தநாள் விருந்து", "ஏரோதின் பிறந்தநாளில் ஏரோதியாளின் குமாரத்தி நடனமாடி ஏரோதை மகிழ்ச்சிப்படுத்தினாள்."],
    "Matthew 14:8": ["யோவான் தலை துண்டிக்கப்படல்", "தன் தாயின் தூண்டுதலால் அவள் கேட்டபடியே, ஏரோது யோவான் ஸ்நானகனின் தலையைச் சிறைச்சாலையில் துண்டிக்கும்படி கட்டளையிட்டான்."],
    "Matthew 14:13": ["இயேசு தனியே செல்லுதல்", "யோவானின் மரணத்தைக் கேட்ட இயேசு படகேறி வனாந்தரமான இடத்திற்குச் சென்றார்; ஜனங்கள் அதையறிந்து கால்நடையாகப் பின்தொடர்ந்தார்கள்."],
    "Matthew 14:14": ["வியாதிஸ்தர்களைக் குணமாக்குதல்", "திரளான ஜனங்களைக் கண்டபோது இயேசு அவர்கள் மேல் மனதுருகி, அவர்களிலிருந்த வியாதிஸ்தர்களைக் குணமாக்கினார்."],
    "Matthew 14:15": ["ஐயாயிரம் பேருக்கு உணவளித்தல்", "சாயங்காலமானபோது ஜனங்கள் உணவு வாங்கச் செல்ல வேண்டியிருந்தது, ஆனால் இயேசு அவர்களை உட்காரச் சொன்னார்."],
    "Matthew 14:17": ["ஐந்து அப்பங்களும் இரண்டு மீன்களும்", "சீஷர்களிடம் ஐந்து அப்பங்களும் இரண்டு மீன்களும் மட்டுமே இருந்தன."],
    "Matthew 14:19": ["இயேசு உணவை ஆசீர்வதித்தல்", "அப்பங்களையும் மீன்களையும் எடுத்து வானத்தை நோக்கிப் பார்த்து, ஆசீர்வதித்து, பிட்டுச் சீஷர்களிடம் கொடுக்க, அவர்கள் ஜனங்களுக்குப் பரிமாறினார்கள்."],
    "Matthew 14:20": ["அனைவரும் திருப்தியடைதல்", "எல்லாரும் சாப்பிட்டுத் திருப்தியடைந்தார்கள்; மீதியான துணிக்கைகள் பன்னிரண்டு கூடைகள் நிறைய எடுக்கப்பட்டன."],
    "Matthew 14:22": ["இயேசு கடலின் மேல் நடத்தல்", "சீஷர்களைப் படகேறிப் போகச் சொல்லிவிட்டு, இயேசு ஜெபம் பண்ணுவதற்காகத் தனியே ஒரு மலையின் மேல் ஏறினார்."],
    "Matthew 14:25": ["படகை நோக்கி இயேசு வருதல்", "இராக்காலத்தின் நான்காம் ஜாமத்தில், இயேசு கடலின் மேல் நடந்து சீஷர்களிடம் வந்தார்."],
    "Matthew 14:28": ["பேதுரு கடலின் மேல் நடத்தல்", "பேதுரு இயேசுவை நோக்கித் தானும் தண்ணீரின் மேல் நடக்கக் கேட்டான்; அவன் நடக்கத் தொடங்கினான், ஆனால் காற்றைக் கண்டு பயந்து மூழ்கத் தொடங்கினான்."],
    "Matthew 14:31": ["பேதுருவை இயேசு இரட்சித்தல்", "இயேசு உடனே தன் கையை நீட்டி அவனைப் பிடித்து, 'அற்ப விசுவாசியே, ஏன் சந்தேகப்பட்டாய்?' என்றார்."],
    "Matthew 14:33": ["சீஷர்கள் இயேசுவை வணங்குதல்", "அவர்கள் படகில் ஏறியதும் காற்று அமர்ந்தது; சீஷர்கள் அவரை வணங்கி, 'மெய்யாகவே நீர் தேவனுடைய குமாரன்' என்றார்கள்."],
    "Matthew 14:34": ["கெந்நேசரேத்துக்கு வருதல்", "அவர்கள் அக்கரை சேர்ந்து கெந்நேசரேத் நாட்டுக்கு வந்தபோது, ஜனங்கள் அவரை அடையாளம் கண்டு சகல வியாதிஸ்தர்களையும் கொண்டு வந்தார்கள்."],
    "Matthew 14:36": ["பலரைக் குணமாக்குதல்", "அவருடைய வஸ்திரத்தின் ஓரத்தையாவது தொட அனுமதி கேட்டார்கள்; தொட்ட யாவரும் சொஸ்தமானார்கள்."],

    "Matthew 15:1": ["பரிசேயர்களின் கேள்வி", "எருசலேமிலிருந்து வந்த பரிசேயர்கள், உங்கள் சீஷர்கள் ஏன் முன்னோர்களின் பாரம்பரியத்தை மீறிக் கைகழுவாமல் சாப்பிடுகிறார்கள் என்று கேட்டார்கள்."],
    "Matthew 15:2": ["பாரம்பரியம் vs கட்டளை", "சடங்காச்சாரங்களைக் கடைப்பிடிக்காதது குறித்து அவர்கள் கேள்வி எழுப்பினார்கள்."],
    "Matthew 15:3": ["இயேசு அவர்களைக் கண்டித்தல்", "உங்கள் பாரம்பரியத்தினால் தேவனுடைய கற்பனையை ஏன் மீறுகிறீர்கள் என்று இயேசு பதிலளித்தார்."],
    "Matthew 15:6": ["காணிக்கை (கொர்பான்) விளக்கம்", "பெற்றோரை மதிப்பதைக் காட்டிலும், 'கொர்பான்' என்ற பெயரில் பணத்தைச் சேமிப்பதையே அவர்கள் முக்கியமாகக் கருதினார்கள்."],
    "Matthew 15:8": ["ஏசாயாவின் தீர்க்கதரிசனம்", "இந்த ஜனங்கள் உதடுகளினால் என்னை விசுவாசிக்கிறார்கள், இவர்கள் இருதயமோ எனக்குத் தூரமாய் இருக்கிறது என்று ஏசாயா சொன்னதை இயேசு மேற்கோள் காட்டினார்."],
    "Matthew 15:10": ["ஜனங்களுக்குப் போதித்தல்", "வாய்க்குள்ளே போகிறது மனுஷனைத் தீட்டுப்படுத்தாது, வாயிலிருந்து புறப்படுகிறதே மனுஷனைத் தீட்டுப்படுத்தும் என்று கற்பித்தார்."],
    "Matthew 15:12": ["சீஷர்களின் கவலை", "இந்த உவமையின் பொருளைத் தங்களுக்கு விளக்கச் சீஷர்கள் கேட்டார்கள்."],
    "Matthew 15:17": ["இருதயத்திலிருந்து வரும் பொல்லாங்கு", "சாப்பிடும் உணவு மனுஷனைத் தீட்டுப்படுத்தாது; ஆனால் இருதயத்திலிருந்து வரும் பொல்லாத சிந்தனைகள், கொலை, விபச்சாரம், திருட்டு போன்றவைகளே தீட்டுப்படுத்தும் என்றார்."],
    "Matthew 15:21": ["தீரு சீதோன் பகுதிகளுக்குச் செல்லுதல்", "இயேசு அங்கிருந்து விலகித் தீரு சீதோன் திசைகளுக்குச் சென்றார்."],
    "Matthew 15:22": ["கானானிய ஸ்திரீயின் வேண்டுதல்", "ஒரு கானானிய ஸ்திரீ வந்து, பிசாசு பிடித்த தன் குமாரத்தியைக் குணமாக்கும்படி கெஞ்சினாள்."],
    "Matthew 15:25": ["ஸ்திரீயின் விசுவாசம்", "முதலில் இயேசு மௌனமாக இருந்தார், ஆனால் அவள் விடாமல் அவரைத் தொழுதுகொண்டாள்."],
    "Matthew 15:28": ["குணமாக்குதல் அருளப்படல்", "அவளுடைய விசுவாசம் பெரியது என்று மெச்சி, அந்த நாழிகையிலேயே அவள் குமாரத்தியைக் குணமாக்கினார்."],
    "Matthew 15:29": ["பலரைக் குணமாக்குதல்", "இயேசு ஒரு மலையின் மேல் ஏறி உட்கார்ந்தார்; அநேக குருடர், ஊமையர், சப்பாணிகள் போன்றவர்கள் அவரிடம் கொண்டு வரப்பட்டுக் குணமடைந்தார்கள்."],
    "Matthew 15:32": ["நாலாயிரம் பேருக்கு உணவளித்தல்", "ஜனங்கள் மேல் மனதுருகி, ஏழு அப்பங்களையும் சில சிறு மீன்களையும் கொண்டு நாலாயிரம் பேருக்கு இயேசு உணவளித்தார்."],
    "Matthew 15:38": ["ஏழு கூடைகள் மீதி", "எல்லாரும் சாப்பிட்டுத் திருப்தியான பின், மீதியான துணிக்கைகள் ஏழு கூடைகள் நிறைய எடுக்கப்பட்டன."],

    "Matthew 16:1": ["பரிசேயர்கள் சோதித்தல்", "பரிசேயர்களும் சதுசேயர்களும் வந்து, வானத்திலிருந்து ஓர் அடையாளத்தைக் காட்டும்படி இயேசுவைச் சோதித்தார்கள்."],
    "Matthew 16:2": ["அடையாளத்தைக் கொடுக்க மறுத்தல்", "வானத்தின் தோற்றத்தைப் பார்த்து வானிலையைச் சொல்லத் தெரிந்த உங்களுக்கு, இந்தக் காலத்தின் அடையாளங்களை அறியத் தெரியவில்லையா என்று கேட்டார்."],
    "Matthew 16:4": ["வேறு அடையாளம் இல்லை", "யோனாவின் அடையாளத்தைத் தவிர வேறு அடையாளம் கொடுக்கப்படமாட்டாது என்று சொல்லிவிட்டு இயேசு அங்கிருந்து சென்றார்."],
    "Matthew 16:5": ["பரிசேயர்களின் புளித்த மாவு", "சீஷர்கள் அப்பம் கொண்டுவர மறந்தார்கள்; அப்போது பரிசேயர், சதுசேயர் என்பவர்களின் புளித்த மாவைக் குறித்து எச்சரிக்கையாயிருங்கள் என்றார்."],
    "Matthew 16:8": ["சீஷர்கள் தவறாகப் புரிந்துகொள்ளுதல்", "தங்களிடம் அப்பம் இல்லாததைக் குறித்து இயேசு பேசுகிறார் என்று அவர்கள் நினைத்தார்கள்; ஆனால் அவர் அவர்களின் போதனையைக் குறித்தே பேசினார்."],
    "Matthew 16:13": ["பேதுருவின் அறிக்கை", "மனுஷகுமாரனாகிய என்னை ஜனங்கள் யார் என்று சொல்லுகிறார்கள் என்று இயேசு கேட்டார்; பேதுரு: 'நீர் ஜீவனுள்ள தேவனுடைய குமாரனாகிய கிறிஸ்து' என்றான்."],
    "Matthew 16:17": ["பரலோக வெளிப்பாடு", "இதை உனக்கு மாம்சமும் இரத்தமும் வெளிப்படுத்தவில்லை, பரலோகத்திலிருக்கிற என் பிதாவே வெளிப்படுத்தினார் என்று இயேசு அவனை ஆசீர்வதித்தார்."],
    "Matthew 16:18": ["சபையின் அஸ்திவாரம்", "இந்தக் கல்லின் (பேதுருவின் அறிக்கை) மேல் என் சபையைக் கட்டுவேன், பாதாளத்தின் வாசல்கள் அதை மேற்கொள்வதில்லை என்றார்."],
    "Matthew 16:19": ["பரலோக ராஜ்யத்தின் திறவுகோல்கள்", "பரலோக ராஜ்யத்தின் திறவுகோல்களை உனக்குத் தருவேன்; பூமியில் எதைக் கட்டுகிறாயோ அது பரலோகிலும் கட்டப்படும் என்றார்."],
    "Matthew 16:21": ["மரணத்தைக் குறித்து முன்னறிவித்தல்", "தாம் எருசலேமுக்குப் போய், அநேக பாடுகளைப் பட்டு, கொல்லப்பட்டு, மூன்றாம் நாளில் உயிர்த்தெழுந்திருக்க வேண்டும் என்பதை இயேசு அறிவிக்கத் தொடங்கினார்."],
    "Matthew 16:23": ["பேதுருவை கடிந்துகொள்ளுதல்", "இப்படி உமக்கு நேரிடக்கூடாது என்று சொன்ன பேதுருவை நோக்கி: 'எனக்குப் பின்னாகப் போ சாத்தானே, நீ எனக்கு இடறலாயிருக்கிறாய்' என்றார்."],
    "Matthew 16:24": ["தன் சிலுவையைச் சுமத்தல்", "ஒருவன் என்னைப் பின்பற்றி வர விரும்பினால், அவன் தன்னைத்தான் வெறுத்து, தன் சிலுவையை எடுத்துக்கொண்டு என்னைப் பின்பற்றி வரக்கடவன்."],
    "Matthew 16:26": ["உலகம் vs ஆத்துமா", "மனுஷன் உலகம் முழுவதையும் ஆதாயப்படுத்திக்கொண்டாலும், தன் ஆத்துமாவை நஷ்டப்படுத்தினால் அவனுக்கு லாபம் என்ன?"],
    "Matthew 16:27": ["மகிமையுடன் திரும்புதல்", "மனுஷகுமாரன் தம்முடைய பிதாவின் மகிமை பொருந்தினவராய்த் தூதர்களோடும் வருவார்; அப்பொழுது அவனவன் கிரியைக்குத் தக்கதாகப் பலன் அளிப்பார்."],

    "Matthew 17:1": ["மறுரூபமாதல்", "இயேசு பேதுரு, யாக்கோபு, யோவான் ஆகியோரை ஒரு உயர்ந்த மலைக்கு அழைத்துச் சென்றார்; அங்கே அவர் அவர்களுக்கு முன்பாக மறுரூபமானார்; அவர் முகம் சூரியனைப் போலப் பிரகாசித்தது."],
    "Matthew 17:3": ["மோசேயும் எலியாவும் தோன்றுதல்", "மோசேயும் எலியாவும் தோன்றி இயேசுவோடே பேசிக்கொண்டிருந்தார்கள்."],
    "Matthew 17:5": ["மேகத்திலிருந்து தேவ சத்தம்", "ஒளியுள்ள ஒரு மேகம் அவர்கள் மேல் நிழலிட்டது: 'இவர் என்னுடைய நேச குமாரன், இவரில் பிரியமாயிருக்கிறேன், இவருக்குச் செவிகொடுங்கள்' என்ற சத்தம் கேட்டது."],
    "Matthew 17:6": ["சீஷர்கள் பயப்படுதல்", "சீஷர்கள் இதைக் கேட்டு மகா பயந்து முகங்குப்புற விழுந்தார்கள்."],
    "Matthew 17:7": ["இயேசு அவர்களைத் தேற்றுதல்", "இயேசு வந்து அவர்களைத் தொட்டு: 'எழுந்திருங்கள், பயப்படாதிருங்கள்' என்றார்."],
    "Matthew 17:9": ["இதை யாரிடமும் சொல்ல வேண்டாம்", "மனுஷகுமாரன் மரித்தோரிலிருந்து உயிர்த்தெழுந்திருக்கும் வரை இந்தத் தரிசனத்தை ஒருவருக்கும் சொல்ல வேண்டாம் என்று கட்டளையிட்டார்."],
    "Matthew 17:14": ["பிசாசு பிடித்த சிறுவனைக் குணமாக்குதல்", "பிசாசு பிடித்து வேதனைப்பட்ட தன் மகனை ஒரு மனுஷன் கொண்டு வந்தான்; மற்ற சீஷர்களால் அவனைக் குணமாக்க முடியவில்லை."],
    "Matthew 17:17": ["விசுவாசமில்லாத சந்ததி", "விசுவாசமில்லாத சந்ததியே என்று இயேசு கடிந்துகொண்டு, அந்தப் பிசாசை அதட்டினார்; உடனே சிறுவன் குணமானான்."],
    "Matthew 17:19": ["தோல்விக்கான காரணம்", "ஏன் எங்களால் அதைத் துரத்த முடியவில்லை என்று சீஷர்கள் கேட்க, உங்கள் அவிசுவாசமே காரணம் என்றார் இயேசு."],
    "Matthew 17:20": ["விசுவாசம் மலையைப் பெயர்க்கும்", "உங்களுக்குக் கடுகுவிதை அளவு விசுவாசம் இருந்தால், இந்த மலையைப் பார்த்துப் பெயர்ந்து போ என்று சொன்னால் அது பெயர்ந்து போகும்."],
    "Matthew 17:22": ["மரணத்தை மீண்டும் அறிவித்தல்", "தாம் வாரிக்கொடுக்கப்பட்டு, கொல்லப்பட்டு, மூன்றாம் நாளில் உயிர்த்தெழுவதைக் குறித்து மீண்டும் சீஷர்களிடம் கூறினார்."],
    "Matthew 17:24": ["தேவாலய வரி", "இயேசு தேவாலய வரி செலுத்துகிறாரா என்று பேதுருவிடம் கேட்கப்பட்டது; இயேசு மீனின் வாயில் ஒரு வெள்ளிக்காசை எடுக்கச் செய்து வரி செலுத்தினார்."],

    "Matthew 18:1": ["பெரியவன் யார்?", "பரலோக ராஜ்யத்தில் எவன் பெரியவன் என்று சீஷர்கள் இயேசுவிடம் கேட்டார்கள்."],
    "Matthew 18:2": ["ஒரு சிறு பிள்ளையை அழைத்தல்", "இயேசு ஒரு சிறு பிள்ளையை அழைத்து அவர்கள் நடுவே நிறுத்தினார்."],
    "Matthew 18:3": ["பிள்ளைகளைப் போல மாறுதல்", "நீங்கள் மனந்திரும்பிப் பிள்ளைகளைப் போலாகாவிட்டால், பரலோக ராஜ்யத்தில் பிரவேசிக்க மாட்டீர்கள் என்றார்."],
    "Matthew 18:4": ["தாழ்மையே மேன்மை", "இந்தச் சிறு பிள்ளையைப் போலத் தன்னைத் தாழ்த்துகிறவனே பரலோக ராஜ்யத்தில் பெரியவனாயிருப்பான்."],
    "Matthew 18:5": ["பிள்ளையை ஏற்றுக்கொள்வது", "என் நாமத்தினாலே இப்படிப்பட்ட ஒரு சிறு பிள்ளையை ஏற்றுக்கொள்கிறவன் என்னை ஏற்றுக்கொள்கிறான்."],
    "Matthew 18:6": ["இடறல் உண்டாக்குதல்", "இந்தச் சிறியவர்களில் ஒருவனுக்கு இடறல் உண்டாக்குகிறவனுக்கு, அவனுடைய கழுத்தில் ஏந்திரக்கல்லைக் கட்டி சமுத்திரத்தில் தள்ளப்படுவது நலமாயிருக்கும்."],
    "Matthew 18:9": ["பாவத்தைத் தவிர்த்தல்", "உன் கண் உனக்கு இடறல் உண்டாக்கினால் அதைப் பிடுங்கி எறிந்து போ; நரகத்தில் தள்ளப்படுவதை விட ஒற்றைக்கண்ணனாய் ஜீவனுக்குள் பிரவேசிப்பது நலம்."],
    "Matthew 18:10": ["பிள்ளைகளின் தூதர்கள்", "இந்தச் சிறியவர்களை அற்பமாய் எண்ணாதிருங்கள்; இவர்களுடைய தூதர்கள் பரலோகத்தில் என் பிதாவின் முகத்தைத் தரிசிக்கிறார்கள்."],
    "Matthew 18:12": ["காணாமற்போன ஆடு", "நூறு ஆடுகளில் ஒன்று காணாமற்போனால், மேய்ப்பன் மற்றவைகளை விட்டுவிட்டுப் போன அந்த ஒன்றைத் தேடிச் செல்வான்."],
    "Matthew 18:15": ["சகோதரனைச் சீர்ப்படுத்துதல்", "உன் சகோதரன் உனக்கு விரோதமாய்ப் பாவஞ்செய்தால், அவனிடம் தனியே போய்க் கடிந்துகொள்; அவன் கேட்டால் அவனை ஆதாயப்படுத்திக்கொண்டாய்."],
    "Matthew 18:16": ["இரண்டு மூன்று சாட்சிகள்", "அவன் கேளாவிட்டால், இரண்டு மூன்று சாட்சிகளுடைய வாயினால் எல்லாம் நிலைபெறும்படி ஒருவனை அல்லது இருவரை அழைத்துக்கொண்டு போ."],
    "Matthew 18:17": ["சபைக்குத் தெரிவித்தல்", "அவன் சபைக்கும் கேளாவிட்டால், அவனை ஒரு புறஜாதியைப் போலவும் ஆயக்காரனைப் போலவும் எண்ணக்கடவாய்."],
    "Matthew 18:18": ["கட்டுதல் மற்றும் அவிழ்த்தல்", "பூமியிலே நீங்கள் எவைகளைக் கட்டுவீர்களோ அவைகள் பரலோகிலும் கட்டப்படும்."],
    "Matthew 18:21": ["மன்னித்தல்", "என் சகோதரனை எத்தனை முறை மன்னிக்க வேண்டும், ஏழு முறை போதுமா என்று பேதுரு கேட்டான்; இயேசு: 'எழுபது எழுமுறை' என்றார்."],
    "Matthew 18:23": ["மன்னிக்காத ஊழியக்காரன் உவமை", "தன் எஜமான் மன்னித்த பெரிய கடனை மறந்த ஒரு ஊழியக்காரன், தன் சக ஊழியனின் சிறிய கடனை மன்னிக்காததைப் பற்றிய உவமையைச் சொன்னார்."],
    "Matthew 18:32": ["மன்னிப்பின் பாடம்", "நீ இரக்கம் பெற்றது போல உன் சக ஊழியனுக்கும் இரக்கம் காட்ட வேண்டாமா என்று எஜமான் அவனைக் கண்டித்தான்."],

    "Matthew 19:1": ["கலிலேயாவை விட்டுச் செல்லுதல்", "இயேசு கலிலேயாவை விட்டுப் புறப்பட்டு யூதேயா திசைகளுக்குச் சென்றார்; திரளான ஜனங்கள் அவரைப் பின்தொடர்ந்தார்கள்."],
    "Matthew 19:3": ["விவாகரத்து குறித்த கேள்வி", "எந்தக் காரணத்துக்காகவாவது புருஷன் தன் மனைவியைத் தள்ளிவிடுவது நியாயமா என்று பரிசேயர்கள் கேட்டார்கள்."],
    "Matthew 19:4": ["ஆணும் பெண்ணுமாகப் படைத்தார்", "ஆதியிலே தேவன் அவர்களை ஆணும் பெண்ணுமாகப் படைத்தார்; மனுஷன் தன் பெற்றோரை விட்டு மனைவியுடன் இசைந்திருப்பான் என்று இயேசு பதிலளித்தார்."],
    "Matthew 19:6": ["ஒரு மாம்சமாயிருப்பார்கள்", "தேவன் இணைத்ததை மனுஷன் பிரிக்காதிருக்கக்கடவன் என்றார்."],
    "Matthew 19:7": ["மோசே ஏன் அனுமதித்தார்?", "உங்கள் இருதயக் கடினத்தினிமித்தம் மோசே அனுமதித்தார், ஆனால் ஆதியிலே அப்படியிருக்கவில்லை என்றார்."],
    "Matthew 19:9": ["விதிவிலக்கு", "வேசித்தன முகாந்தரத்தினால் ஒழிய, தன் மனைவியைத் தள்ளிவிட்டு வேறொருத்தியை விவாகஞ்செய்கிறவன் விபச்சாரஞ்செய்கிறான் என்றார்."],
    "Matthew 19:13": ["சிறு பிள்ளைகளை ஆசீர்வதித்தல்", "பிள்ளைகளை இயேசுவிடம் கொண்டு வந்தபோது சீஷர்கள் தடுத்தார்கள்."],
    "Matthew 19:14": ["பிள்ளைகளை வரவேற்றல்", "சிறு பிள்ளைகள் என்னிடத்தில் வருகிறதற்கு இடங்கொடுங்கள்; பரலோக ராஜ்யம் இப்படிப்பட்டவர்களுடையது என்றார்."],
    "Matthew 19:16": ["ஐசுவரியமுள்ள வாலிபன்", "நித்திய ஜீவனை அடைய நான் என்ன நன்மை செய்ய வேண்டும் என்று ஒருவன் கேட்டான்."],
    "Matthew 19:18": ["கற்பனைகளைக் கைக்கொள்", "கொலை செய்யாதே, விபச்சாரம் செய்யாதே, திருடாதே, உன் பெற்றோரை மதி, பிறரை நேசி ஆகிய கற்பனைகளை இயேசு சொன்னார்."],
    "Matthew 19:21": ["ஆஸ்திகளை விற்றுப் பின்செல்", "நீ பூரணராயிருக்க விரும்பினால், உனக்குள்ளவைகளை விற்றுத் தர்மஞ்செய்து, என்னைப் பின்பற்றி வா என்றார்."],
    "Matthew 19:23": ["ஐசுவரியவான்களுக்குக் கடினம்", "ஐசுவரியவான் பரலோக ராஜ்யத்தில் பிரவேசிப்பது அரிது என்று இயேசு சொன்னார்."],
    "Matthew 19:26": ["தேவனால் எல்லாம் கூடும்", "மனுஷரால் இது கூடாத காரியம், ஆனால் தேவனால் எல்லாம் கூடும் என்றார்."],

    "Matthew 20:1": ["திராட்சைத் தோட்ட வேலையாட்கள் உவமை", "வெவ்வேறு நேரங்களில் வேலைக்கு அமர்த்தப்பட்ட வேலையாட்களைப் பற்றிய உவமையை இயேசு சொன்னார்."],
    "Matthew 20:4": ["கூலி உடன்படிக்கை", "முதலில் வந்தவர்களுக்கும், பின்னர் வந்தவர்களுக்கும் ஒரே விதமான கூலி (ஒரு பணம்) தருவதாக எஜமான் சொன்னார்."],
    "Matthew 20:6": ["பின்னே வந்த வேலையாட்கள்", "மூன்றாம், ஆறாம், ஒன்பதாம் மற்றும் பதினோராம் மணி நேரத்திலும் எஜமான் வேலையாட்களைச் சேர்த்தார்."],
    "Matthew 20:8": ["கூலி கொடுத்தல்", "வேலை முடிந்ததும், கடைசியில் வந்தவர்களுக்கு முதலில் கூலி கொடுத்து, பின்னர் முதலில் வந்தவர்களுக்குக் கொடுத்தார்."],
    "Matthew 20:10": ["ஒரே அளவு கூலி", "முதலில் வந்தவர்கள் தங்களுக்குக் கூடுதல் கிடைக்கும் என்று நினைத்தார்கள், ஆனால் எல்லாருக்கும் ஒரே பணமே கிடைத்தது."],
    "Matthew 20:12": ["எஜமானின் பதில்", "நானும் நீயும் ஒரு பணத்திற்கு உடன்படவில்லையா? நான் தாராளமாக இருப்பது உனக்கு ஏன் பொறாமையாக இருக்கிறது என்று எஜமான் கேட்டான்."],
    "Matthew 20:16": ["முந்தினோர் பிந்தினோர்", "இப்படியே பிந்தினோர் முந்தினோராகவும், முந்தினோர் பிந்தினோராகவும் இருப்பார்கள் என்றார்."],
    "Matthew 20:20": ["யாக்கோபு, யோவான் தாயின் வேண்டுதல்", "தன் குமாரர்கள் உம்முடைய ராஜ்யத்தில் உமது வலது பாரிசத்திலும் இடது பாரிசத்திலும் அமர வேண்டும் என்று அவள் கேட்டாள்."],
    "Matthew 20:23": ["பாத்திரம் குடித்தல்", "நீங்கள் என் பாத்திரத்தில் குடிப்பீர்கள்; ஆனால் என் வலது இடது பாரிசங்களில் அமரச் செய்வது பிதாவினால் நியமிக்கப்பட்டவர்களுக்கே உரியது என்றார்."],
    "Matthew 20:25": ["தலைமைத்துவம் என்பது ஊழியம்", "உங்களில் பெரியவனாயிருக்க விரும்புகிறவன் உங்களுக்கு ஊழியக்காரனாயிருக்கக்கடவன்."],
    "Matthew 20:28": ["மனுஷகுமாரன் ஊழியம் செய்ய வந்தார்", "மனுஷகுமாரனும் ஊழியம் கொள்ளும்படி வராமல், ஊழியம் செய்யவும், அநேகரை மீட்கும்பொருளாகத் தம்முடைய ஜீவனைக் கொடுக்கவும் வந்தார்."],

    "Matthew 21:1": ["வெற்றிப் பயணம்", "இயேசு சீஷர்களை முன்னால் உள்ள கிராமத்திற்கு அனுப்பி, அங்கே கட்டப்பட்டிருக்கிற ஒரு கழுதையையும் அதன் குட்டியையும் கொண்டுவரச் சொன்னார்."],
    "Matthew 21:5": ["தீர்க்கதரிசனம் நிறைவேறுதல்", "சீயோன் குமாரத்தியே, இதோ உன் ராஜா சாந்தகுணமுள்ளவராய், கழுதையின் மேல் ஏறி உன்னிடம் வருகிறார் என்ற தீர்க்கதரிசன வசனம் இதன் மூலம் நிறைவேறியது."],
    "Matthew 21:7": ["சீஷர்கள் கீழ்ப்படிதல்", "சீஷர்கள் அந்தக் கழுதையின் மேல் தங்கள் வஸ்திரங்களைப் போட்டார்கள்; இயேசு அதன் மேல் ஏறி எருசலேமுக்குள் சென்றார்."],
    "Matthew 21:8": ["திரளான ஜனங்கள் போற்றுதல்", "ஜனங்கள் தங்கள் வஸ்திரங்களையும் மரக்கிளைகளையும் வழியில் விரித்து: 'தாவீதின் குமாரனுக்கு ஓசன்னா! கர்த்தரின் நாமத்தினாலே வருகிறவர் ஸ்தோத்தரிக்கப்பட்டவர்!' என்று ஆர்ப்பரித்தார்கள்."],
    "Matthew 21:12": ["தேவாலயத்தைச் சுத்திகரித்தல்", "இயேசு தேவாலயத்திற்குள் சென்று, அங்கே விற்பவர்களையும் வாங்குபவர்களையும் வெளியே துரத்தி, காசுக்காரர்களின் பலகைகளைக் கவிழ்த்துப் போட்டார்."],
    "Matthew 21:13": ["தேவாலயம் ஜெப வீடு", "என்னுடைய வீடு ஜெப வீடு என்னப்படும் என்று எழுதியிருக்கிறது; நீங்களோ அதைத் கள்ளர் குகையாக்கினீர்கள் என்றார்."],
    "Matthew 21:18": ["அத்திமரம் உலர்ந்து போதல்", "மறுநாள் காலையில், இயேசு ஒரு அத்திமரத்தில் கனிகள் இல்லாததைக் கண்டு அதைச் சபிக்க, அது உடனே உலர்ந்து போனது."],
    "Matthew 21:21": ["விசுவாசம் மலையைப் பெயர்க்கும்", "நீங்கள் விசுவாசமுள்ளவர்களாயிருந்து சந்தேகப்படாமலிருந்தால், இந்த அத்திமரத்திற்குச் செய்ததை விடப் பெரிய காரியங்களைச் செய்வீர்கள் என்று சீஷர்களிடம் கூறினார்."],
    "Matthew 21:23": ["அதிகாரத்தைக் குறித்துக் கேள்வி", "பிரதான ஆசாரியர்களும் ஜனத்தின் மூப்பர்களும் இயேசுவிடம் வந்து: 'நீர் எந்த அதிகாரத்தினால் இவைகளைச் செய்கிறீர்?' என்று கேட்டார்கள்."],
    "Matthew 21:28": ["இரண்டு குமாரர்கள் உவமை", "வேலைக்குப்போக மறுத்துப் பின்போன ஒரு மகனையும், போவதாகச் சொல்லிப் போகாத மற்றொரு மகனையும் பற்றிய உவமையை இயேசு சொன்னார்."],
    "Matthew 21:33": ["திராட்சைத் தோட்டக் குத்தகைக்காரர் உவமை", "ஒரு எஜமான் தோட்டத்தைக் குத்தகைக்கு விட்டுச் சென்றார்; அவர் அனுப்பிய ஊழியர்களையும் அவருடைய குமாரனையும் அந்தக் குத்தகைக்காரர்கள் கொன்று போட்டார்கள்."],
    "Matthew 21:42": ["வீடு கட்டுகிறவர்கள் தள்ளின கல்", "வீடு கட்டுகிறவர்கள் ஆகாதென்று தள்ளின கல்லே மூலைக்குத் தலைக்கல்லாயிற்று என்ற சங்கீத வசனத்தை இயேசு மேற்கோள் காட்டினார்."],

    "Matthew 22:1": ["கல்யாண விருந்து உவமை", "ஒரு ராஜா தன் குமாரனுக்குக் கல்யாண விருந்து ஆயத்தம் செய்ததைப் பற்றிய உவமையை இயேசு சொன்னார்."],
    "Matthew 22:3": ["அழைக்கப்பட்டவர்கள் வர மறுத்தல்", "விருந்திற்கு அழைக்கப்பட்டவர்கள் வர மனதில்லாமல் சாக்குப்போக்குச் சொல்லித் தட்டிக்கழித்தார்கள்."],
    "Matthew 22:6": ["பொல்லாதவர்களுக்குத் தண்டனை", "ராஜா கோபமடைந்து, தன் சேனைகளை அனுப்பி அந்தச் கொலைபாதகர்களை அழித்து, அவர்கள் பட்டணத்தைச் சுட்டெரித்தான்."],
    "Matthew 22:8": ["மற்றவர்களுக்கு அழைப்பு", "சாலையோரங்களில் காணப்படுகிற யாவரையும் கல்யாண விருந்துக்கு அழைத்து வரத் தன் ஊழியக்காரர்களுக்கு ராஜா கட்டளையிட்டான்."],
    "Matthew 22:11": ["கல்யாண வஸ்திரம் இல்லாத மனுஷன்", "விருந்தினரைப் பார்க்க ராஜா வந்தபோது, அங்கே கல்யாண வஸ்திரம் தரிக்காத ஒரு மனுஷனைக் கண்டு அவனிடம் கேள்வி கேட்டான்."],
    "Matthew 22:13": ["வெளியே தள்ளப்படுதல்", "அவனுடைய கை கால்களைக் கட்டி, அழுகையும் பற்கடிப்பும் நிறைந்த புறம்பான இருளிலே தள்ளிப்போடும்படி ராஜா சொன்னான்."],
    "Matthew 22:15": ["பரிசேயர்கள் இயேசுவைச் சோதித்தல்", "ராயனுக்கு (Caesar) வரி செலுத்துவது நியாயமா என்று கேட்டு இயேசுவை பேச்சிலே சிக்க வைக்கப் பரிசேயர்கள் சூழ்ச்சி செய்தார்கள்."],
    "Matthew 22:18": ["இயேசுவின் ஞானம்", "அவர்களுடைய பொல்லாங்கை இயேசு அறிந்து, ஒரு வரிப்பணத்தைக் காட்டச் சொல்லி, அதிலுள்ள ரூபமும் எழுத்தும் யாருடையது என்று கேட்டார்."],
    "Matthew 22:21": ["ராயனுடையதை ராயனுக்கும் தேவனுடையதை தேவனுக்கும்", "ராயனுடையதை ராயனுக்கும், தேவனுடையதை தேவனுக்கும் செலுத்துங்கள் என்று அவர் பதிலளித்தார்."],
    "Matthew 22:23": ["உயிர்த்தெழுதல் குறித்த கேள்வி", "உயிர்த்தெழுதல் இல்லை என்று சொல்லுகிற சதுசேயர்கள் வந்து, மறுமையில் திருமண உறவு எப்படிக் கணக்கிடப்படும் என்று கேட்டார்கள்."],
    "Matthew 22:29": ["இயேசு அவர்களைத் திருத்துதல்", "நீங்கள் வேதவாக்கியங்களையும் தேவனுடைய வல்லமையையும் அறியாமல் தப்பான எண்ணம் கொள்கிறீர்கள் என்றார்."],
    "Matthew 22:32": ["உயிருள்ளோரின் தேவன்", "தேவன் ஆபிரகாம், ஈசாக்கு, யாக்கோபின் தேவனாயிருக்கிறார்; அவர் மரித்தோருக்குத் தேவனல்ல, உயிருள்ளோருக்கே தேவனாயிருக்கிறார் என்றார்."],
    "Matthew 22:37": ["முதலாம் கற்பனை", "உன் தேவனாகிய கர்த்தரிடத்தில் உன் முழு இருதயத்தோடும், உன் முழு ஆத்துமாவோடும், உன் முழு மனதோடும் அன்புகூருவாயாக என்பதே முதலாம் கற்பனை."],
    "Matthew 22:39": ["இரண்டாம் கற்பனை", "உன்னிடத்தில் நீ அன்புகூருவது போலப் பிறனிடத்திலும் அன்புகூருவாயாக என்பது இதற்கு ஒப்பான இரண்டாம் கற்பனை."],
    "Matthew 22:41": ["கிறிஸ்து யாருடைய குமாரன்?", "கிறிஸ்து யாருடைய குமாரன் என்று இயேசு கேட்க, 'தாவீதின் குமாரன்' என்று பரிசேயர்கள் பதிலளித்தார்கள்."],
    "Matthew 22:44": ["கிறிஸ்து ஆண்டவர்", "தாவீது பரிசுத்த ஆவியினாலே அவரை 'ஆண்டவர்' என்று அழைத்திருக்கும்போது, அவர் எப்படி அவருக்குக் குமாரனாவார் என்று இயேசு கேட்டார்."],

    "Matthew 23:1": ["பரிசேயர்களுக்கு எச்சரிக்கை", "இயேசு ஜனங்களுக்கும் தம்முடைய சீஷர்களுக்கும் வேதபாரகர் மற்றும் பரிசேயர்களைக் குறித்துப் போதித்தார்."],
    "Matthew 23:2": ["வேதபாரகரின் அதிகாரம்", "வேதபாரகரும் பரிசேயரும் மோசேயின் இருக்கையில் அமர்ந்திருக்கிறார்கள்; எனவே அவர்கள் சொல்லுகிறபடி செய்யுங்கள்."],
    "Matthew 23:3": ["அவர்கள் செய்கைகளைப் பின்பற்றாதிருங்கள்", "அவர்கள் சொல்லுகிறார்கள், ஆனால் தாங்கள் சொல்லுகிறபடி செய்வதில்லை; எனவே அவர்கள் கிரியைகளின்படி செய்யாதிருங்கள்."],
    "Matthew 23:4": ["மனுஷர் மேல் சுமத்தப்படும் சுமை", "சுமப்பதற்கு அரிய பாரமான சுமைகளைக் கட்டி மனுஷர் தோள்களின் மேல் சுமத்துகிறார்கள்; ஆனால் அவர்கள் ஒரு விரலினாலும் அவைகளைத் தொடமாட்டார்கள்."],
    "Matthew 23:5": ["புகழுக்காகச் செய்தல்", "மனுஷர் காணும்படி தங்கள் கிரியைகளைச் செய்கிறார்கள்; தங்கள் வஸ்திர ஓரங்களைத் தொங்கவிட்டுப் பெருமை பாராட்டுகிறார்கள்."],
    "Matthew 23:7": ["முதன்மை இடங்களை விரும்புதல்", "விருந்துகளில் முதன்மையான இடங்களையும், சந்தைகளில் தங்களை 'ரபீ' (போதகரே) என்று அழைப்பதையும் விரும்புகிறார்கள்."],
    "Matthew 23:8": ["நீங்கள் அனைவரும் சகோதரர்கள்", "நீங்கள் ரபீ என்று அழைக்கப்படாதிருங்கள்; கிறிஸ்து ஒருவரே உங்களுக்குப் போதகர், நீங்கள் எல்லாரும் சகோதரர்களாயிருக்கிறீர்கள்."],
    "Matthew 23:13": ["வேதபாரகரே, பரிசேயரே, உங்களுக்கு ஐயோ!", "பரலோக ராஜ்யத்தை மனுஷருக்கு முன்பாகப் பூட்டிப்போடுகிற மாயக்காரராகிய உங்களுக்கு ஐயோ!"],
    "Matthew 23:15": ["மதமாற்றம் செய்தல்", "ஒருவனை உங்கள் மதத்தில் சேர்க்கக் கடலையும் நிலத்தையும் சுற்றித் திரிகிறீர்கள்; அவன் சேர்ந்தபின் அவனை உங்களை விட இரண்டு மடங்கு நரகத்தின் மகனாக்குகிறீர்கள்."],
    "Matthew 23:23": ["நீதியையும் இரக்கத்தையும் கைவிடுதல்", "சீரகம், வெந்தயம் ஆகியவற்றில் தசமபாகம் செலுத்தி, நியாயப்பிரமாணத்தில் விசேஷித்தவைகளாகிய நீதி, இரக்கம், விசுவாசம் ஆகியவைகளைக் கைவிடுகிறீர்கள்."],
    "Matthew 23:25": ["வெளிப்பகட்டு", "கிண்ணத்தின் வெளிப்புறத்தைச் சுத்தமாக்குகிறீர்கள், ஆனால் உட்புறமோ கொள்ளையினாலும் இச்சையினாலும் நிறைந்திருக்கிறது."],
    "Matthew 23:27": ["வெள்ளையடிக்கப்பட்ட கல்லறைகள்", "வெளியே அழகாய்த் தோன்றும், உள்ளே எலும்புகளினாலும் சகல அசுத்தத்தினாலும் நிறைந்திருக்கிற கல்லறைகளுக்கு ஒப்பாயிருக்கிறீர்கள்."],
    "Matthew 23:29": ["தீர்க்கதரிசிகளின் கல்லறைகள்", "நீதிமான்களின் கல்லறைகளைக் கட்டுகிறீர்கள், ஆனால் உங்கள் முன்னோர்கள் தீர்க்கதரிசிகளைக் கொன்றது போல நீங்களும் செய்கிறீர்கள்."],
    "Matthew 23:36": ["பொறுப்புக்கூறல்", "இவைகளெல்லாம் இந்தச் சந்ததியின் மேல் வரும் என்று மெய்யாகவே உங்களுக்குச் சொல்லுகிறேன்."],

    "Matthew 24:1": ["தேவாலய அழிவை முன்னறிவித்தல்", "தேவாலயத்தின் கட்டிடங்களைச் சீஷர்கள் காட்டியபோது, இங்கே ஒரு கல்லின் மேல் ஒரு கல் இராதபடி எல்லாம் இடிக்கப்படும் என்று இயேசு சொன்னார்."],
    "Matthew 24:3": ["முடிவு காலத்தைப் பற்றிய கேள்விகள்", "இவை எப்பொழுது நடக்கும்? உம்முடைய வருகைக்கும் உலகத்தின் முடிவுக்கும் அடையாளம் என்ன? என்று சீஷர்கள் கேட்டார்கள்."],
    "Matthew 24:4": ["வஞ்சிக்கப்படாதிருங்கள்", "ஒருவனும் உங்களை வஞ்சிக்காதபடி எச்சரிக்கையாயிருங்கள்; அநேகர் என் நாமத்தைத் தரித்துக்கொண்டு வந்து வஞ்சிப்பார்கள்."],
    "Matthew 24:6": ["யுத்தங்களும் செய்திகளும்", "யுத்தங்களையும் யுத்தங்களின் செய்திகளையும் கேள்விப்படுவீர்கள்; பஞ்சங்களும், கொள்ளைநோய்களும், பூமியதிர்ச்சிகளும் உண்டாகும்; இவையே வேதனைகளின் ஆரம்பம்."],
    "Matthew 24:9": ["விசுவாசிகளுக்குத் துன்புறுத்தல்", "என் நாமத்தினிமித்தம் நீங்கள் சகல ஜனங்களாலும் பகைக்கப்படுவீர்கள், உங்களைத் துன்புறுத்திக் கொலை செய்வார்கள்."],
    "Matthew 24:12": ["அன்பு தணிந்து போதல்", "அக்கிரமம் மிகுதியாவதினால் அநேகருடைய அன்பு தணிந்து போகும்; முடிவு வரை நிலைநிற்பவனே இரட்சிக்கப்படுவான்."],
    "Matthew 24:14": ["உலகெங்கும் சுவிசேஷம்", "ராஜ்யத்தின் இந்தச் சுவிசேஷம் உலகமெங்கும் பிரசங்கிக்கப்படும், அப்போது முடிவு வரும்."],
    "Matthew 24:15": ["பாழாக்கும் அருவருப்பு", "தீர்க்கதரிசியால் சொல்லப்பட்ட பாழாக்கும் அருவருப்பைப் பரிசுத்த ஸ்தலத்தில் காணும்போது, யூதேயாவில் இருக்கிறவர்கள் மலைகளுக்கு ஓடிப்போகக்கடவர்கள்."],
    "Matthew 24:21": ["மிகுந்த உபத்திரவம்", "உலகம் உண்டானது முதல் இதுவரைக்கும் சம்பவித்திராத மிகுந்த உபத்திரவம் அப்போது உண்டாகும்."],
    "Matthew 24:24": ["கள்ளக் கிறிஸ்துக்கள்", "கள்ளக் கிறிஸ்துக்களும் கள்ளத் தீர்க்கதரிசிகளும் எழும்பி, தெரிந்தெடுக்கப்பட்டவர்களையும் வஞ்சிக்கத்தக்கதாகப் பெரிய அடையாளங்களைச் செய்வார்கள்."],
    "Matthew 24:29": ["மனுஷகுமாரன் வருதல்", "உபத்திரவத்திற்குப் பின் சூரியன் அந்தகாரப்படும், சந்திரன் ஒளியைக் கொடாது, நட்சத்திரங்கள் விழும், வானத்தின் சத்துவங்கள் அசைக்கப்படும்."],
    "Matthew 24:30": ["மகிமையோடு வருதல்", "மனுஷகுமாரன் வல்லமையோடும் மிகுந்த மகிமையோடும் வானத்தின் மேகங்கள் மேல் வருவதை உலகத்தின் கோத்திரங்கள் யாவரும் காண்பார்கள்."],
    "Matthew 24:32": ["அத்திமர உவமை", "அத்திமரம் துளிர்க்கும்போது கோடைக்காலம் சமீபமென்று அறிவீர்கள்; அப்படியே இவைகளை நீங்கள் காணும்போது அவர் வாசலருகே வந்திருக்கிறார் என்று அறியுங்கள்."],
    "Matthew 24:36": ["நாளும் நாழிகையும் இரகசியம்", "அந்த நாளையும் நாழிகையையும் பிதா ஒருவரே தவிர, பரலோகத் தூதர்களாவது குமாரனாவது அறியார்கள்."],
    "Matthew 24:42": ["விழிப்புடன் இருங்கள்", "உங்கள் ஆண்டவர் எந்த நாழிகையில் வருவார் என்று நீங்கள் அறியாதிருப்பதால் விழித்திருங்கள்."],
    "Matthew 24:44": ["ஆயத்தமாயிருங்கள்", "நீங்கள் நினையாத நாழிகையிலே மனுஷகுமாரன் வருவார், அதனால் நீங்களும் ஆயத்தமாயிருங்கள்."],

    "Matthew 25:1": ["பத்து கன்னிகைகள் உவமை", "தங்கள் விளக்குகளை எடுத்துக்கொண்டு மணவாளனுக்கு எதிர்கொண்டு போகப் புறப்பட்ட பத்து கன்னிகைகளைப்பற்றிய உவமையை இயேசு சொன்னார்."],
    "Matthew 25:3": ["புத்தியுள்ளவர் மற்றும் புத்தியில்லாதவர்", "ஐந்து பேர் புத்தியுள்ளவர்கள், அவர்கள் விளக்குகளோடே எண்ணெயையும் கொண்டு போனார்கள்; மற்ற ஐந்து பேர் எண்ணெயைக் கொண்டு போகவில்லை."],
    "Matthew 25:6": ["மணவாளன் வருதல்", "நடுராத்திரியிலே: 'மணவாளன் வருகிறார், அவருக்கு எதிர்கொண்டு போங்கள்' என்ற சத்தம் கேட்டது."],
    "Matthew 25:7": ["எண்ணெய் தீர்ந்து போதல்", "புத்தியில்லாத கன்னிகைகள் தங்கள் விளக்குகள் அணைந்து போவதால் புத்தியுள்ளவர்களிடம் எண்ணெய் கேட்டார்கள்; ஆனால் அவர்கள் கொடுக்க மறுத்துவிட்டார்கள்."],
    "Matthew 25:10": ["வாசல் அடைக்கப்படல்", "மணவாளன் வந்தபோது ஆயத்தமாயிருந்தவர்கள் உட்பிரவேசித்தார்கள், வாசல் அடைக்கப்பட்டது."],
    "Matthew 25:12": ["ஆயத்தம் குறித்த பாடம்", "ஆயத்தமில்லாதவர்களை நோக்கி: 'உங்களை அறியேன்' என்று மணவாளன் சொன்னார்; எனவே விழித்திருங்கள் என்றார் இயேசு."],
    "Matthew 25:14": ["தாலந்து உவமை", "ஒரு மனுஷன் தூரதேசத்திற்குப் போகும்போது, தன் ஊழியக்காரரை அழைத்து, அவர்கள் திறமைக்குத் தக்கதாகத் தாலந்துகளை (பணம்) ஒப்புவித்தான்."],
    "Matthew 25:16": ["தாலந்துகளைப் பெருக்குதல்", "ஐந்து தாலந்து பெற்றவன் அதைக் கொண்டு வியாபாரம் செய்து மேலும் ஐந்து தாலந்துகளைச் சம்பாதித்தான்; இரண்டு தாலந்து பெற்றவனும் அப்படியே செய்தான்."],
    "Matthew 25:18": ["தாலந்தைப் புதைத்து வைத்தல்", "ஒரு தாலந்து பெற்றவனோ நிலத்தைத் தோண்டி தன் எஜமானுடைய பணத்தைப் புதைத்து வைத்தான்."],
    "Matthew 25:20": ["எஜமான் கணக்குக் கேட்டல்", "எஜமான் திரும்பி வந்து கணக்குக் கேட்டபோது, ஐந்து மற்றும் இரண்டு தாலந்து பெற்றவர்கள் தங்கள் லாபத்தைக் காட்டினார்கள்."],
    "Matthew 25:23": ["உண்மையுள்ள ஊழியக்காரர்களுக்குப் பலன்", "நல்லது, உண்மையுள்ள ஊழியக்காரனே, கொஞ்சத்திலே உண்மையாயிருந்தாய், உன்னை அநேகத்தின் மேல் அதிகாரியாக வைப்பேன் என்று எஜமான் பாராட்டினான்."],
    "Matthew 25:28": ["சோம்பேறி ஊழியக்காரனுக்குத் தண்டனை", "தாலந்தைப் புதைத்து வைத்தவனைப் பொல்லாத சோம்பேறி ஊழியக்காரன் என்று கடிந்து, அவனைப் புறம்பான இருளிலே தள்ளச் சொன்னான்."],
    "Matthew 25:31": ["செம்மறியாடுகளும் வெள்ளாடுகளும்", "மனுஷகுமாரன் தம்முடைய மகிமை பொருந்தினவராய்த் தூதர்களோடும் வரும்போது, சகல ஜனங்களும் அவருக்கு முன்பாகச் சேர்க்கப்படுவார்கள்."],
    "Matthew 25:33": ["மனுஷரைப் பிரித்தல்", "மேய்ப்பன் செம்மறியாடுகளையும் வெள்ளாடுகளையும் பிரிப்பது போல, அவர் ஜனங்களைப் பிரிப்பார்."],
    "Matthew 25:35": ["நீதிமான்களுக்குப் பலன்", "பசியாயிருந்தேன் ஆகாரங்கொடுத்தீர்கள், தாகமாயிருந்தேன் தாகந்தீர்த்தீர்கள், அந்நியனாயிருந்தேன் என்னைச் சேர்த்துக்கொண்டீர்கள் என்று நீதிமான்களை ஆசீர்வதிப்பார்."],
    "Matthew 25:41": ["துன்மார்க்கருக்கு நியாயத்தீர்ப்பு", "எளியவர்களுக்கு உதவி செய்யத் தவறியவர்களை நோக்கி: 'சபிக்கப்பட்டவர்களே, என்னை விட்டுப் போங்கள்' என்று நித்திய அக்கினியிலே தள்ளுவார்."],

    "Matthew 26:1": ["மரணத்தை முன்னறிவித்தல்", "இரண்டு நாளுக்குப் பின்பு பஸ்கா பண்டிகை வரும், அப்போது மனுஷகுமாரன் சிலுவையில் அறையப்படுவதற்காக வாரிக்கொடுக்கப்படுவார் என்று இயேசு சொன்னார்."],
    "Matthew 26:6": ["பெத்தானியாவில் அபிஷேகம்", "இயேசு குஷ்டரோகியான சீமோன் வீட்டில் இருந்தபோது, ஒரு ஸ்திரீ விலையேறப்பெற்ற தைலத்தை அவர் தலையின் மேல் ஊற்றினாள்."],
    "Matthew 26:8": ["சீஷர்கள் கடிந்துகொள்ளுதல்", "இந்தத் தைலத்தை விற்றுத் தரித்திரருக்குக் கொடுக்கலாமே, ஏன் வீணாக்கினீர்கள் என்று சீஷர்கள் கோபித்துக்கொண்டார்கள்."],
    "Matthew 26:10": ["இயேசு அவளைப் பாராட்டுதல்", "அவள் என்னிடத்தில் நற்செய்கையைச் செய்தாள்; என் அடக்கத்திற்காக என்னை ஆயத்தம் செய்தாள்; சுவிசேஷம் பிரசங்கிக்கப்படும் இடமெல்லாம் இவள் செய்ததும் சொல்லப்படும் என்றார்."],
    "Matthew 26:14": ["யூதாஸ் காட்டிக்கொடுக்கச் சம்மதித்தல்", "யூதாஸ்காரியோத்து பிரதான ஆசாரியர்களிடம் சென்று, முப்பது வெள்ளிக்காசுக்காக இயேசுவைக் காட்டிக்கொடுக்கச் சம்மதித்தான்."],
    "Matthew 26:17": ["பஸ்கா ஆயத்தம்", "பஸ்கா புசிக்கிறதற்கு எங்கே ஆயத்தம் செய்ய வேண்டும் என்று சீஷர்கள் இயேசுவிடம் கேட்டார்கள்."],
    "Matthew 26:26": ["திருவிருந்து நியமித்தல்", "போஜனம் பண்ணும்போது இயேசு அப்பத்தை எடுத்து ஆசீர்வதித்து, இது என் சரீரமாயிருக்கிறது என்று சீஷர்களுக்குக் கொடுத்தார்."],
    "Matthew 26:27": ["புதிய உடன்படிக்கையின் பாத்திரம்", "பாத்திரத்தையும் எடுத்து, இது பாவமன்னிப்புண்டாகும்படி அநேகருக்காகச் சிந்தப்படுகிற புதிய உடன்படிக்கைக்குரிய என் இரத்தமாயிருக்கிறது என்றார்."],
    "Matthew 26:31": ["பேதுரு மறுதலிப்பதை முன்னறிவித்தல்", "இன்றிரவு நீங்கள் எல்லாரும் என்னிமித்தம் இடறலடைவீர்கள் என்றார்; ஆனால் பேதுரு தான் ஒருபோதும் இடறலடையமாட்டேன் என்றான்."],
    "Matthew 26:36": ["கெத்செமனே ஜெபம்", "இயேசு சீஷர்களோடு கெத்செமனேக்குச் சென்று: 'பிதாவே, இந்தப்பாத்திரம் என்னை விட்டு நீங்கக்கூடுமானால் நீங்கட்டும்; ஆயினும் என் சித்தமல்ல, உம்முடைய சித்தமே ஆகக்கடவது' என்று ஜெபித்தார்."],
    "Matthew 26:40": ["சீஷர்கள் தூங்குதல்", "சீஷர்கள் தூங்குவதைக் கண்டு: 'சோதனையில் அகப்படாதபடிக்கு விழித்திருந்து ஜெபம்பண்ணுங்கள்' என்றார்."],
    "Matthew 26:47": ["இயேசு கைது செய்யப்படல்", "யூதாஸ் திரளான ஜனங்களோடு வந்து, இயேசுவை முத்தமிட்டுக் காட்டிக்கொடுத்தான்; அவர்கள் அவரைப் பிடித்தார்கள்."],
    "Matthew 26:57": ["ஆசாரியனிடம் இயேசு கொண்டு செல்லப்படல்", "இயேசு பிரதான ஆசாரியனாகிய காய்பாவிடம் கொண்டு செல்லப்பட்டார்; அங்கே வேதபாரகரும் மூப்பர்களும் கூடியிருந்தார்கள்."],
    "Matthew 26:69": ["பேதுரு மறுதலித்தல்", "பேதுரு வெளியே உட்கார்ந்திருந்தபோது, மூன்று முறை இயேசுவை அறியேன் என்று மறுதலித்தான்."],
    "Matthew 26:75": ["பேதுரு அழுதல்", "சேவல் கூவினபோது இயேசு சொன்ன வார்த்தையை நினைவு கூர்ந்து, பேதுரு வெளியே போய்ப் மனம் கசந்து அழுதான்."],

    "Matthew 27:1": ["பிலாத்துவினிடம் இயேசு", "காலையானபோது பிரதான ஆசாரியர்கள் இயேசுவைக் கட்டி, தேசாதிபதியாகிய பிலாத்துவினிடம் ஒப்புவித்தார்கள்."],
    "Matthew 27:3": ["யூதாஸ் மனஸ்தாபப்படுதல்", "இயேசு மரண ஆக்கினைக்குள்ளானதைக் கண்ட யூதாஸ், தான் செய்த பாவத்திற்காக வருந்தி முப்பது வெள்ளிக்காசுகளைத் திருப்பிக் கொடுத்தான்."],
    "Matthew 27:6": ["இரத்தப்பணம்", "இது இரத்தப்பணமானதால் இதைத் தேவாலயப் பொக்கிஷத்தில் சேர்க்கக் கூடாது என்று சொல்லி, அதைக் கொண்டு மட்கலக்காரன் நிலத்தை வாங்கினார்கள்."],
    "Matthew 27:11": ["பிலாத்துவின் விசாரணை", "நீர் யூதருடைய ராஜாவா என்று பிலாத்து கேட்டான்; அதற்கு இயேசு: 'நீர் சொல்லுகிறபடிதான்' என்றார்."],
    "Matthew 27:15": ["காவலனை விடுதலை செய்யும் வழக்கம்", "பண்டிகைக் காலத்தில் ஒரு காவலாளியை விடுதலை செய்வது வழக்கம்; ஜனங்கள் இயேசுவுக்குப் பதிலாகப் பரபாஸை (Barabbas) விடுதலை செய்யக் கேட்டார்கள்."],
    "Matthew 27:19": ["பிலாத்துவின் மனைவி எச்சரிக்கை", "அந்த நீதிமானைக் குறித்து நான் சொப்பனத்தில் மிகவும் வருத்தப்பட்டேன், அவருக்கும் உமக்கும் ஒரு சம்பந்தமும் வேண்டாம் என்று பிலாத்துவின் மனைவி செய்தி அனுப்பினாள்."],
    "Matthew 27:22": ["சிலுவையில் அறையக் கேட்டல்", "இயேசுவை என்ன செய்ய வேண்டும் என்று பிலாத்து கேட்க, 'சிலுவையில் அறையப்பட வேண்டும்' என்று ஜனங்கள் சத்தமிட்டார்கள்."],
    "Matthew 27:26": ["தீர்ப்பு வழங்கப்படல்", "பிலாத்து பரபாஸை விடுவித்து, இயேசுவை வாரினால் அடிப்பவித்து, சிலுவையில் அறையும்படி ஒப்புக்கொடுத்தான்."],
    "Matthew 27:27": ["சேவகர்கள் பரியாசம் செய்தல்", "சேவகர்கள் இயேசுவுக்குச் சிவப்பான அங்கியை உடுத்தி, முள்முடி சூட்டி, 'யூதருடைய ராஜாவே வாழ்க' என்று அவரைப் பரியாசம் செய்தார்கள்."],
    "Matthew 27:32": ["சீமோன் சிலுவை சுமத்தல்", "சீரேனே ஊரானாகிய சீமோன் என்பவனை இயேசுவின் சிலுவையைச் சுமக்கும்படி கட்டாயப்படுத்தினார்கள்."],
    "Matthew 27:33": ["சிலுவையில் அறையப்படுதல்", "கொல்கொதா என்ற இடத்திற்கு அவரைக் கொண்டு சென்று சிலுவையில் அறைந்தார்கள்; அவருடைய வஸ்திரங்களைச் சீட்டுப் போட்டுப் பங்கிட்டுக் கொண்டார்கள்."],
    "Matthew 27:37": ["சிலுவையின் மேல் எழுதப்பட்ட வாசகம்", "இவன் யூதருடைய ராஜாவாகிய இயேசு என்று அவர் செய்த குற்றத்தைச் சிலுவையின் மேல் எழுதினார்கள்."],
    "Matthew 27:46": ["இயேசுவின் கூக்குரல்", "ஏலீ! ஏலீ! லாமா சபக்தானி? (என் தேவனே! என் தேவனே! ஏன் என்னைக் கைவிட்டீர்?) என்று இயேசு மகா சத்தமிட்டுக் கூப்பிட்டார்."],
    "Matthew 27:50": ["இயேசுவின் மரணம்", "இயேசு மறுபடியும் மகா சத்தமாய் கூப்பிட்டு ஆவியை விட்டார்."],
    "Matthew 27:51": ["தேவாலயத் திரை கிழிதல்", "தேவாலயத் திரை மேல்தொடங்கி கீழ்வரைக்கும் இரண்டாகக் கிழிந்தது; பூமியதிர்ச்சி உண்டானது, கன்மலைகள் பிளந்தன, கல்லறைகள் திறந்தன."],
    "Matthew 27:57": ["இயேசுவின் அடக்கம்", "அரிமத்தியா ஊரானாகிய யோசேப்பு பிலாத்துவினிடம் போய் இயேசுவின் சரீரத்தைக் கேட்டு வாங்கி, ஒரு மெல்லிய துணியால் சுற்றி, தன் புதிய கல்லறையில் வைத்தார்."],

    "Matthew 28:1": ["உயிர்த்தெழுந்த காலை", "ஓய்வுநாள் முடிந்து வாரத்தின் முதல் நாள் காலையில், மகதலேனா மரியாளும் மற்ற மரியாளும் கல்லறையைப் பார்க்க வந்தார்கள்."],
    "Matthew 28:2": ["தூதன் கல்லைப் புரட்டுதல்", "பெரிய பூமியதிர்ச்சி உண்டானது; கர்த்தருடைய தூதன் வானத்திலிருந்து இறங்கி வந்து, கல்லறையின் வாசலிலிருந்த கல்லைப் புரட்டி அதன் மேல் உட்கார்ந்தான்."],
    "Matthew 28:5": ["தூதன் ஸ்திரீகளிடம் பேசுதல்", "பயப்படாதிருங்கள், சிலுவையில் அறையப்பட்ட இயேசுவைத் தேடுகிறீர்கள் என்று அறிவேன்; அவர் இங்கே இல்லை, அவர் சொன்னபடியே உயிர்த்தெழுந்தார்."],
    "Matthew 28:7": ["சீஷர்களுக்குச் சொல்லுங்கள்", "இயேசு உயிர்த்தெழுந்தார் என்றும், உங்களுக்கு முன்னால் கலிலேயாவுக்குப் போகிறார் என்றும் சீஷர்களிடம் போய்ச் சொல்லுங்கள் என்றார் தூதன்."],
    "Matthew 28:9": ["இயேசு ஸ்திரீகளுக்குக் காட்சி அளித்தல்", "அவர்கள் போய்க்கொண்டிருக்கும்போது இயேசு அவர்களுக்கு எதிர்கொண்டு வந்து: 'வாழ்க' என்றார்; அவர்கள் அவரை வணங்கினார்கள்."],
    "Matthew 28:11": ["காவலர்கள் அறிக்கை செய்தல்", "காவல் காத்தவர்களில் சிலர் பட்டணத்திற்குள் போய் நடந்த யாவற்றையும் பிரதான ஆசாரியர்களுக்கு அறிவித்தார்கள்."],
    "Matthew 28:12": ["சேவகர்களுக்கு லஞ்சம்", "நாங்கள் தூங்கும்போது அவருடைய சீஷர்கள் வந்து சரீரத்தைத் திருடிக்கொண்டு போனார்கள் என்று சொல்லும்படி ஆசாரியர்கள் சேவகர்களுக்குப் பணம் கொடுத்தார்கள்."],
    "Matthew 28:16": ["சீஷர்கள் கலிலேயாவுக்குச் செல்லுதல்", "பதினொரு சீஷர்களும் இயேசு தங்களுக்குக் குறித்திருந்த கலிலேயாவிலுள்ள மலைக்குச் சென்றார்கள்."],
    "Matthew 28:18": ["இயேசுவின் அதிகாரம்", "இயேசு அவர்களிடம் வந்து: 'வானத்திலும் பூமியிலும் சகல அதிகாரமும் எனக்குக் கொடுக்கப்பட்டிருக்கிறது' என்றார்."],
    "Matthew 28:19": ["பெரிய கட்டளை (Great Commission)", "நீங்கள் புறப்பட்டுப் போய், சகல ஜாதிகளையும் சீஷராக்கி, பிதா குமாரன் பரிசுத்த ஆவியின் நாமத்திலே அவர்களுக்கு ஞானஸ்நானம் கொடுங்கள்."],
    "Matthew 28:20": ["உபதேசமும் உடன் இருப்பும்", "நான் உங்களுக்குக் கட்டளையிட்ட யாவையும் அவர்கள் கைக்கொள்ளும்படி அவர்களுக்கு உபதேசம் பண்ணுங்கள்; இதோ, உலகத்தின் முடிவுவரைக்கும் சகல நாட்களிலும் நான் உங்களுடனே இருக்கிறேன்."],

    "Mark 1:1": ["சுவிசேஷத்தின் ஆரம்பம்", "தேவனுடைய குமாரனாகிய இயேசு கிறிஸ்துவைப் பற்றிய நற்செய்தியின் ஆரம்பத்தை மாற்கு விவரிக்கிறார்."],
    "Mark 1:2": ["வழியை ஆயத்தப்படுத்தும் யோவான்", "கர்த்தருக்கு வழியை ஆயத்தப்படுத்தும் தூதனைப் பற்றிய தீர்க்கதரிசனங்கள் அறிமுகப்படுத்தப்படுகின்றன."],
    "Mark 1:4": ["யோவான் ஸ்நானகனின் ஊழியம்", "யோவான் வனாந்தரத்தில் தோன்றி, மனந்திரும்புதலுக்கான ஞானஸ்நானத்தைப் பிரசங்கித்தார்."],
    "Mark 1:9": ["இயேசுவின் ஞானஸ்நானம்", "யோர்தான் நதியில் யோவானால் இயேசு ஞானஸ்நானம் பெற்றார்; வானம் திறக்கப்பட்டு, 'இவர் என் நேச குமாரன்' என்று பிதாவின் சத்தம் கேட்டது."],
    "Mark 1:12": ["இயேசு சோதனை செய்யப்படுதல்", "ஆவியானவர் இயேசுவை வனாந்தரத்திற்கு அனுப்பினார்; அங்கே அவர் நாற்பது நாட்கள் சாத்தானால் சோதிக்கப்பட்டார்."],
    "Mark 1:14": ["இயேசு ஊழியத்தைத் தொடங்குதல்", "யோவான் கைது செய்யப்பட்ட பிறகு, இயேசு கலிலேயாவில் தேவனுடைய ராஜ்யத்தைப் பிரசங்கிக்கத் தொடங்கினார்."],
    "Mark 1:16": ["முதல் சீஷர்களை அழைத்தல்", "சீமோன், அந்திரேயா, யாக்கோபு மற்றும் யோவான் ஆகியோரைத் தம்மைப் பின்பற்றும்படி இயேசு அழைத்தார்."],
    "Mark 1:21": ["அதிகாரத்துடன் போதித்தல்", "கப்பர்நகூமில் உள்ள ஜெப ஆலயத்தில் இயேசு போதித்தார்; அவருடைய அதிகாரத்தைக் கண்டு ஜனங்கள் ஆச்சரியப்பட்டார்கள்."],
    "Mark 1:23": ["அசுத்த ஆவியைத் துரத்துதல்", "ஜெப ஆலயத்தில் அசுத்த ஆவி பிடித்திருந்த ஒரு மனுஷனை இயேசு விடுவித்தார்."],
    "Mark 1:29": ["பலரைக் குணமாக்குதல்", "சீமோனின் மாமியாரையும், வியாதிப்பட்டிருந்த அநேகரையும் இயேசு குணமாக்கினார்."],
    "Mark 1:35": ["தனியான இடத்தில் ஜெபித்தல்", "இயேசு அதிகாலையிலேயே எழுந்து, வனாந்தரமான ஒரு இடத்திற்குச் சென்று ஜெபம் பண்ணினார்."],
    "Mark 1:40": ["குஷ்டரோகியைக் குணமாக்குதல்", "விசுவாசத்துடன் வந்த ஒரு குஷ்டரோகியை இயேசு தொட்டு குணமாக்கினார்."],

    "Mark 2:1": ["திமிர்வாதக்காரனைக் குணமாக்குதல்", "வீட்டின் கூரையைப் பிரித்து இறக்கப்பட்ட திமிர்வாதக்காரனுக்கு இயேசு பாவமன்னிப்பு அளித்து அவனைக் குணமாக்கினார்."],
    "Mark 2:13": ["லேவியை அழைத்தல்", "ஆயக்காரனாகிய லேவியைத் தம்மைப் பின்பற்றும்படி இயேசு அழைத்தார்; அவன் எல்லாவற்றையும் விட்டுவிட்டுப் பின்தொடர்ந்தான்."],
    "Mark 2:15": ["பாவிகளுடன் போஜனம்", "பாவிகளையும் ஆயக்காரர்களையும் அழைப்பதே என் நோக்கம் என்று கூறி, அவர்களுடன் இயேசு பந்தியில் அமர்ந்தார்."],
    "Mark 2:18": ["உபவாசம் குறித்த கேள்வி", "உமது சீஷர்கள் ஏன் உபவாசம் பண்ணுவதில்லை என்று கேட்டபோது, மணவாளன் தங்களோடு இருக்கும்போது அவர்கள் எப்படி உபவாசிப்பார்கள் என்று பதிலளித்தார்."],
    "Mark 2:21": ["புதிய துணியும் புதிய திராட்சரசமும்", "புதிய துணியைப் பழைய வஸ்திரத்தோடும், புதிய திராட்சரசத்தைப் பழைய துருத்திகளோடும் ஒப்பிடக்கூடாது என்று கற்பித்தார்."],
    "Mark 2:23": ["ஓய்வுநாளின் ஆண்டவர்", "ஓய்வுநாள் மனுஷனுக்காக உண்டாக்கப்பட்டது என்றும், மனுஷகுமாரன் ஓய்வுநாளுக்கும் ஆண்டவர் என்றும் விளக்கினார்."],

    "Mark 3:1": ["சூம்பின கையையுடைய மனுஷன்", "ஓய்வுநாளில் நன்மை செய்வது நியாயம் என்று கூறி, சூம்பின கையையுடைய ஒருவனை இயேசு குணமாக்கினார்."],
    "Mark 3:6": ["இயேசுவுக்கு எதிரான சதி", "பரிசேயர்கள் ஏரோதியரோடு சேர்ந்து இயேசுவை எப்படிக் கொலை செய்யலாம் என்று ஆலோசனை பண்ணினார்கள்."],
    "Mark 3:7": ["திரளான ஜனங்கள்", "இயேசு செய்த அற்புதங்களைக் கேள்விப்பட்டுப் பல இடங்களிலிருந்தும் திரளான ஜனங்கள் அவரிடம் வந்தார்கள்."],
    "Mark 3:13": ["பன்னிரண்டு அப்போஸ்தலர் நியமனம்", "தம்முடன் இருக்கவும், பிரசங்கம் பண்ணவும், பிசாசுகளைத் துரத்தவும் பன்னிரண்டு சீஷர்களை இயேசு நியமித்தார்."],
    "Mark 3:20": ["இயேசுவும் பெயல்செபூலும்", "இயேசு பிசாசுகளின் தலைவனாலே பிசாசுகளைத் துரத்துகிறார் என்று சிலர் குற்றம் சுமத்தினார்கள்."],
    "Mark 3:23": ["தனக்குத்தானே விரோதமான வீடு", "சாத்தான் சாத்தானைத் துரத்தினால் அவன் ராஜ்யம் எப்படி நிலைநிற்கும் என்று இயேசு விளக்கினார்."],
    "Mark 3:28": ["பரிசுத்த ஆவிக்கு விரோதமான தூஷணம்", "பரிசுத்த ஆவிக்கு விரோதமாகத் தூஷணம் சொல்லுகிறவனுக்கு ஒருபோதும் மன்னிப்பு இல்லை என்று எச்சரித்தார்."],
    "Mark 3:31": ["உண்மையான குடும்பம்", "தேவனுடைய சித்தத்தைச் செய்கிறவர்களே எனக்குச் சகோதரனும், சகோதரியும், தாயுமாய் இருக்கிறார்கள் என்றார்."],

    "Mark 4:1": ["விதைக்கிறவன் உவமை", "கடற்கரையிலிருந்து இயேசு ஜனங்களுக்கு விதைக்கிறவன் உவமையைப் போதித்தார்."],
    "Mark 4:10": ["உவமைகளின் நோக்கம்", "வெளிப்படையான உண்மைகளைத் தகுதியுள்ளவர்களுக்கு வெளிப்படுத்தவே உவமைகளைப் பயன்படுத்துவதாக விளக்கினார்."],
    "Mark 4:13": ["உவமையின் விளக்கம்", "நான்கு வகையான நிலங்கள் இறைவசனத்திற்கு மனுஷர்கள் காட்டும் வெவ்வேறு பதில்களைக் குறிக்கின்றன என்று விளக்கினார்."],
    "Mark 4:21": ["தண்டின் மேல் வைத்த விளக்கு", "விளக்கானது மறைத்து வைக்கப்படாமல், வெளிச்சம் கொடுப்பதற்காகத் தண்டின் மேலேயே வைக்கப்பட வேண்டும் என்றார்."],
    "Mark 4:26": ["வளருகிற விதை உவமை", "தேவனுடைய ராஜ்யம் நிலத்தில் விதைக்கப்பட்ட விதை தானாகவே வளர்ந்து பலன் கொடுப்பதற்கு ஒப்பாயிருக்கிறது."],
    "Mark 4:30": ["கடுகு விதை உவமை", "மிகச் சிறிய கடுகு விதை வளர்ந்து பெரிய மரமாவது போலத் தேவனுடைய ராஜ்யம் பெருகும் என்றார்."],
    "Mark 4:35": ["புயலை அடக்குதல்", "கடலில் பெரிய புயல் உண்டானபோது, இயேசு காற்றையும் கடலையும் அதட்டி அமைதிப்படுத்தினார்."],

    "Mark 5:1": ["கெரெசேனர் நாட்டில் அசுத்த ஆவி", "கல்லறைகளில் வசித்த அசுத்த ஆவி பிடித்த மனுஷனை இயேசு விடுவித்தார்; அந்த ஆவிகள் பன்றிக் கூட்டத்திற்குள் சென்று கடலில் விழுந்தன."],
    "Mark 5:14": ["ஜனங்களின் பயம்", "நடந்ததைக் கேள்விப்பட்ட ஜனங்கள் பயந்து, இயேசுவைத் தங்கள் எல்லைகளை விட்டுப் போகும்படி கேட்டுக்கொண்டார்கள்."],
    "Mark 5:18": ["சாட்சி சொல்ல அனுப்புதல்", "குணமடைந்த மனுஷன் இயேசுவுடன் வர விரும்பினான், ஆனால் அவன் தன் வீட்டிற்குப் போய் கர்த்தர் செய்தவைகளைச் சொல்லும்படி இயேசு அனுப்பினார்."],
    "Mark 5:21": ["யவீருவின் வேண்டுதல்", "ஜெப ஆலயத் தலைவனாகிய யவீரு, சாகக்கிடந்த தன் மகளைக் குணமாக்கும்படி இயேசுவை வேண்டிக்கொண்டான்."],
    "Mark 5:25": ["பெரும்பாடுள்ள ஸ்திரீ", "பன்னிரண்டு வருஷங்களாகப் பெரும்பாடுள்ள ஒரு ஸ்திரீ, இயேசுவின் வஸ்திரத்தைத் தொட்டு விசுவாசத்தால் குணமடைந்தாள்."],
    "Mark 5:30": ["விசுவாசத்தைப் பாராட்டுதல்", "உன் விசுவாசம் உன்னை இரட்சித்தது, சமாதானத்தோடே போ என்று அவளை இயேசு தேற்றினார்."],
    "Mark 5:35": ["மரணச் செய்தி", "யவீருவின் மகள் மரித்துவிட்டதாகச் செய்தி வந்தது, ஆனால் 'பயப்படாதே, விசுவாசமுள்ளவனாயிரு' என்று இயேசு அவனுக்குச் சொன்னார்."],
    "Mark 5:38": ["சிறுமி உயிர் பெறுதல்", "இயேசு அந்தச் சிறுமியின் கையைப் பிடித்து 'தலிதா கூமி' என்று சொல்ல, அவள் உயிர் பெற்று எழுந்தாள்."],
    "Mark 5:43": ["ஆச்சரியம்", "இதைக் கண்டவர்கள் பிரமித்தார்கள்; அவளுக்கு ஆகாரம் கொடுக்கச் சொன்னார் இயேசு."],

    "Mark 6:1": ["சொந்த ஊரில் புறக்கணிக்கப்படல்", "இயேசு நாசரேத்துக்குச் சென்றபோது, அங்கிருந்தவர்கள் அவருடைய குடும்பத்தைக் காரணமாகக் காட்டி அவரைப் புறக்கணித்தார்கள்."],
    "Mark 6:6": ["அவிசுவாசம்", "அவர்களுடைய அவிசுவாசத்தைக் கண்டு அவர் ஆச்சரியப்பட்டு, அங்கே சில அற்புதங்களை மட்டும் செய்துவிட்டு வேறு ஊர்களுக்குச் சென்றார்."],
    "Mark 6:7": ["சீஷர்களை அனுப்புதல்", "பன்னிரண்டு சீஷர்களையும் இரண்டு இரண்டு பேராக அனுப்பி, அவர்களுக்கு அசுத்த ஆவிகள் மேல் அதிகாரம் கொடுத்தார்."],
    "Mark 6:14": ["ஏரோதின் சந்தேகம்", "இயேசுவின் புகழைக் கேட்ட ஏரோது, மரித்த யோவான் ஸ்நானகன் உயிர்த்தெழுந்தாரோ என்று பயந்தான்."],
    "Mark 6:17": ["யோவான் சிறைவாசம்", "ஏரோது தன் சகோதரன் மனைவியை மணந்ததைக் கண்டித்ததால் யோவான் சிறையில் அடைக்கப்பட்டிருந்தார்."],
    "Mark 6:21": ["யோவான் தலை துண்டிக்கப்படல்", "ஏரோதியாளின் மகளின் நடனத்தால் மகிழ்ந்த ஏரோது, அவளது வேண்டுகோளின்படி யோவானின் தலையைத் துண்டித்துக் கொடுத்தான்."],
    "Mark 6:30": ["சீஷர்கள் திரும்புதல்", "தாங்கள் செய்த ஊழியம் மற்றும் போதனைகளைப் பற்றிச் சீஷர்கள் இயேசுவிடம் வந்து விவரித்தார்கள்."],
    "Mark 6:34": ["ஜனங்கள் மேல் மனதுருக்கம்", "மேய்ப்பனில்லாத ஆடுகளைப் போல இருந்த திரளான ஜனங்களைக் கண்டு இயேசு அவர்கள் மேல் மனதுருகினார்."],
    "Mark 6:35": ["ஐயாயிரம் பேருக்கு உணவளித்தல்", "ஐந்து அப்பங்களையும் இரண்டு மீன்களையும் கொண்டு ஐயாயிரம் பேருக்கு இயேசு அற்புதமாக உணவளித்தார்."],
    "Mark 6:45": ["கடலின் மேல் நடத்தல்", "சீஷர்கள் படகில் தத்தளித்தபோது, இயேசு கடலின் மேல் நடந்து அவர்களிடம் வந்து காற்றை அமர்த்தினார்."],
    "Mark 6:53": ["வியாதிஸ்தர்கள் குணமாதல்", "கெந்நேசரேத்து பகுதியில் அவருடைய வஸ்திரத்தின் ஓரத்தைத் தொட்ட யாவரும் சொஸ்தமானார்கள்."],

    "Mark 7:1": ["மூதாதையர் பாரம்பரியம்", "சீஷர்கள் கைகழுவாமல் சாப்பிடுவதைக் குறித்துப் பரிசேயர்கள் இயேசுவிடம் வாக்குவாதம் செய்தார்கள்."],
    "Mark 7:6": ["மாயக்காரரே என்று கண்டித்தல்", "உதடுகளினால் என்னைக் கனம்பண்ணுகிறார்கள், இருதயமோ எனக்குத் தூரமாய் இருக்கிறது என்று அவர்களைக் கண்டித்தார்."],
    "Mark 7:9": ["பாரம்பரியம் vs கற்பனை", "உங்கள் பாரம்பரியத்தைக் கைக்கொள்ளும்படி தேவனுடைய கற்பனையைத் தள்ளிப்போடுகிறீர்கள் என்றார்."],
    "Mark 7:14": ["மனுஷனைத் தீட்டுப்படுத்துவது எது?", "வெளியிலிருந்து உள்ளே போகிறது மனுஷனைத் தீட்டுப்படுத்தாது, இருதயத்திலிருந்து புறப்படுகிறவைகளே மனுஷனைத் தீட்டுப்படுத்தும் என்று கற்பித்தார்."],
    "Mark 7:24": ["சீரோபெனிக்கியா ஸ்திரீயின் விசுவாசம்", "புறஜாதி ஸ்திரீயின் விடாமுயற்சியுள்ள விசுவாசத்தைக் கண்டு, அவளுடைய மகளைப் பிடித்திருந்த பிசாசைத் துரத்தினார்."],
    "Mark 7:31": ["செவிட்டு ஊமையன் குணமாதல்", "தேக்கப்போலி திசைகளில் செவிடும் ஊமையுமான ஒரு மனுஷனை 'எப்பத்தா' (திறக்கப்படு) என்று சொல்லி இயேசு குணமாக்கினார்."],
    "Mark 7:36": ["ஜனங்களின் ஆச்சரியம்", "அவர் எல்லாவற்றையும் நன்றாய்ச் செய்தார் என்று ஜனங்கள் அவரைப் போற்றினார்கள்."],

    "Mark 8:1": ["நாலாயிரம் பேருக்கு உணவளித்தல்", "மூன்று நாட்கள் தன்னுடனிருந்த திரளான ஜனங்களுக்கு ஏழு அப்பங்களைக் கொண்டு இயேசு உணவளித்தார்."],
    "Mark 8:10": ["அடையாளம் கேட்டல்", "பரிசேயர்கள் அவரிடம் வந்து வானத்திலிருந்து ஓர் அடையாளத்தைக் காட்டும்படி அவரைச் சோதித்தார்கள்."],
    "Mark 8:14": ["பரிசேயரின் புளித்த மாவு", "பரிசேயர் மற்றும் ஏரோதின் புளித்த மாவைக் (போதனை) குறித்து எச்சரிக்கையாய் இருக்கச் சொன்னார்."],
    "Mark 8:22": ["பெத்சாய்தா குருடன்", "பெத்சாய்தாவில் ஒரு குருடனை இரண்டு நிலைகளில் தொட்டு இயேசு முழுமையாகக் குணமாக்கினார்."],
    "Mark 8:27": ["பேதுருவின் அறிக்கை", "நீர் யார் என்று சீஷர்களிடம் கேட்டபோது, 'நீர் கிறிஸ்து' என்று பேதுரு அறிக்கை செய்தான்."],
    "Mark 8:31": ["மரணத்தை முன்னறிவித்தல்", "மனுஷகுமாரன் அநேக பாடுகள் பட்டு, கொல்லப்பட்டு, மூன்றாம் நாளில் உயிர்த்தெழுவார் என்று முதன்முறையாக அறிவித்தார்."],
    "Mark 8:34": ["சிலுவையைச் சுமத்தல்", "ஒருவன் என்னைப் பின்பற்றி வர விரும்பினால், அவன் தன்னைத்தான் வெறுத்து, தன் சிலுவையை எடுத்துக்கொண்டு என்னைப் பின்பற்றி வரக்கடவன்."],

    "Mark 9:1": ["தேவனுடைய ராஜ்யம்", "இங்கே நிற்கிறவர்களில் சிலர் தேவனுடைய ராஜ்யம் வல்லமையோடு வருவதைக் காண்பார்கள் என்றார்."],
    "Mark 9:2": ["மறுரூப மலை", "பேதுரு, யாக்கோபு, யோவான் ஆகியோருக்கு முன்பாக இயேசு மறுரூபமானார்; மோசே, எலியா அவரோடு பேசினார்கள்."],
    "Mark 9:9": ["இரகசியம் காத்தல்", "மனுஷகுமாரன் உயிர்த்தெழும் வரை இந்தத் தரிசனத்தை ஒருவருக்கும் சொல்ல வேண்டாம் என்று கட்டளையிட்டார்."],
    "Mark 9:14": ["ஊமையான ஆவி பிடித்த சிறுவன்", "சீஷர்களால் துரத்த முடியாத அசுத்த ஆவியை இயேசு துரத்தி ஒரு சிறுவனைக் குணமாக்கினார்."],
    "Mark 9:30": ["மரணத்தை மீண்டும் அறிவித்தல்", "தாம் காட்டிக்கொடுக்கப்பட்டுக் கொல்லப்படுவதைப் பற்றி இரண்டாம் முறையாகச் சீஷர்களுக்குக் கூறினார்."],
    "Mark 9:33": ["பெரியவன் யார்?", "உங்களில் எவன் பெரியவனாயிருக்க விரும்புகிறானோ, அவன் எல்லாருக்கும் ஊழியக்காரனாயிருக்கக்கடவன்."],
    "Mark 9:38": ["எங்களுக்கு விரோதமல்லாதவன்", "என் நாமத்தினாலே அற்புதங்களைச் செய்கிறவனைத் தடுக்க வேண்டாம்; நமக்கு விரோதமல்லாதவன் நமது பட்சத்திலிருக்கிறான் என்றார்."],
    "Mark 9:42": ["இடறல் குறித்த எச்சரிக்கை", "சிறு பிள்ளைகளுக்கு இடறல் உண்டாக்குவதைக் குறித்தும், பாவத்திற்கு ஏதுவான உறுப்புகளைத் தறித்துப் போடுவதைக் குறித்தும் எச்சரித்தார்."],
    "Mark 9:49": ["உப்புள்ளவர்களாயிருங்கள்", "உங்களிடத்தில் உப்புள்ளவர்களாயிருங்கள், ஒருவரோடொருவர் சமாதானமாயிருங்கள் என்றார்."],

    "Mark 10:1": ["விவாகரத்து குறித்த போதனை", "புருஷன் தன் மனைவியைத் தள்ளிவிடுவது குறித்துப் போதித்து, தேவன் இணைத்ததை மனுஷன் பிரிக்காதிருக்கக்கடவன் என்றார்."],
    "Mark 10:13": ["சிறு பிள்ளைகளை ஆசீர்வதித்தல்", "சிறு பிள்ளைகளைத் தடுத்த சீஷர்களைக் கடிந்துகொண்டு, பிள்ளைகளை அணைத்து அவர்களை ஆசீர்வதித்தார்."],
    "Mark 10:17": ["ஐசுவரியமுள்ள வாலிபன்", "நித்திய ஜீவனை அடைய என்ன செய்ய வேண்டும் என்று கேட்ட வாலிபனிடம், உன் ஆஸ்திகளை விற்றுத் தரித்திரருக்குக் கொடுத்து என்னைப் பின்பற்றி வா என்றார்."],
    "Mark 10:23": ["செல்வத்தின் ஆபத்து", "ஐசுவரியவான் தேவனுடைய ராஜ்யத்தில் பிரவேசிப்பது எவ்வளவு அரிது என்று விளக்கினார்."],
    "Mark 10:32": ["மரணத்தை மூன்றாம் முறை அறிவித்தல்", "எருசலேமுக்குப் போகும் வழியில் தாம் படப்போகும் பாடுகளைப் பற்றி மீண்டும் கூறினார்."],
    "Mark 10:35": ["யாக்கோபு, யோவான் வேண்டுதல்", "தங்களுக்கு முதன்மையான இடங்களைக் கேட்ட சீஷர்களிடம், தலைமைத்துவம் என்பது ஊழியம் செய்வதே என்று கற்பித்தார்."],
    "Mark 10:46": ["குருடன் பர்திமேயு", "எரிகோவுக்கு அருகே தாவீதின் குமாரனே எனக்கு இரங்கும் என்று கூப்பிட்ட பர்திமேயுவுக்கு இயேசு பார்வையளித்தார்."],

    "Mark 11:1": ["வெற்றிப் பயணம்", "இயேசு ஒரு கழுதைக்குட்டியின் மேல் ஏறி எருசலேமுக்குள் பிரவேசித்தார்; ஜனங்கள் 'ஓசன்னா' என்று ஆர்ப்பரித்து அவரை வரவேற்றார்கள்."],
    "Mark 11:12": ["அத்திமரத்தைச் சபித்தல்", "கனியில்லாத ஓர் அத்திமரத்தைக் கண்ட இயேசு, ஆவிக்குரிய கனி தருவதைக் குறித்துப் பாடமாக அதைச் சபித்தார்."],
    "Mark 11:15": ["தேவாலயத்தைச் சுத்திகரித்தல்", "தேவாலயம் ஜெப வீடு என்று கூறி, அங்கிருந்த வியாபாரிகளையும் காசு மாற்றுகிறவர்களையும் இயேசு வெளியே துரத்தினார்."],
    "Mark 11:20": ["அத்திமரம் உலர்ந்து போதல்", "இயேசு சபித்த அத்திமரம் வேரோடு உலர்ந்து போயிருப்பதைச் சீஷர்கள் கவனித்தார்கள்."],
    "Mark 11:22": ["விசுவாசம் மற்றும் ஜெபம்", "தேவன் மேல் விசுவாசமாயிருப்பதைக் குறித்தும், விசுவாசத்தோடு ஜெபிப்பதன் வல்லமையைக் குறித்தும் இயேசு போதித்தார்."],
    "Mark 11:27": ["அதிகாரத்தைக் குறித்துக் கேள்வி", "பிரதான ஆசாரியர்களும் மூப்பர்களும் இயேசுவிடம் வந்து, நீர் எந்த அதிகாரத்தினால் இவைகளைச் செய்கிறீர் என்று கேட்டார்கள்."],

    "Mark 12:1": ["பொல்லாத குத்தகைக்காரர் உவமை", "எஜமானின் ஊழியர்களையும் மகனையும் கொன்ற குத்தகைக்காரர்களைப் பற்றிய உவமை மூலம், தேவனுடைய தூதர்களும் குமாரனும் புறக்கணிக்கப்படுவதை இயேசு விளக்கினார்."],
    "Mark 12:13": ["ராயனுக்கு வரி செலுத்துதல்", "வரியைக் குறித்துச் சூழ்ச்சியாகக் கேட்கப்பட்ட கேள்விக்கு, 'ராயனுடையதை ராயனுக்கும், தேவனுடையதை தேவனுக்கும் செலுத்துங்கள்' என்று பதிலளித்தார்."],
    "Mark 12:18": ["உயிர்த்தெழுதல் குறித்த கேள்வி", "மறுமையில் திருமண உறவு எப்படிக் கணக்கிடப்படும் என்று கேட்ட சதுசேயர்களுக்கு, உயிர்த்தெழுதலுக்குப் பின் உள்ள வாழ்வின் உண்மையை விளக்கினார்."],
    "Mark 12:28": ["முக்கியமான கற்பனை", "தேவனிடத்தில் முழு இருதயத்தோடும் அன்புகூருவதும், பிறனைத் தன்னைப் போல நேசிப்பதுமே எல்லாவற்றிலும் பெரிய கற்பனை என்று போதித்தார்."],
    "Mark 12:35": ["கிறிஸ்து தாவீதின் ஆண்டவர்", "கிறிஸ்து எப்படி ஒரே நேரத்தில் தாவீதின் குமாரனாகவும், தாவீது 'ஆண்டவர்' என்று அழைப்பவராகவும் இருக்க முடியும் என்று இயேசு கேட்டார்."],
    "Mark 12:38": ["வேதபாரகர்களுக்கு எச்சரிக்கை", "வேதபாரகர்களின் பெருமையைக் குறித்தும், அவர்கள் செய்யும் வெளிப்பகட்டான செயல்களைக் குறித்தும் ஜனங்களை எச்சரித்தார்."],
    "Mark 12:41": ["ஏழை விதவையின் காணிக்கை", "ஒரு ஏழை விதவை போட்ட இரண்டு காசுகளைக் கவனித்த இயேசு, அவள் தன் வாழ்வாதாரம் அனைத்தையும் கொடுத்த தியாகத்தைப் பாராட்டினார்."],

    "Mark 13:1": ["தேவாலய அழிவை முன்னறிவித்தல்", "தேவாலயத்தை விட்டு வெளியே வரும்போது, இங்கே ஒரு கல்லின் மேல் ஒரு கல் இராதபடி எல்லாம் இடிக்கப்படும் என்று சீஷர்களிடம் கூறினார்."],
    "Mark 13:3": ["முடிவு காலத்தின் அடையாளங்கள்", "இவை எப்போது நடக்கும் என்று தனியாகக் கேட்ட சீஷர்களுக்கு, வரும் காலத்தின் அடையாளங்களை விவரித்தார்."],
    "Mark 13:5": ["வஞ்சிக்கப்படாதிருங்கள்", "அநேகர் என் நாமத்தைத் தரித்துக்கொண்டு வந்து வஞ்சிப்பார்கள், எச்சரிக்கையாய் இருங்கள் என்றார்."],
    "Mark 13:7": ["யுத்தங்களும் துன்பங்களும்", "யுத்தங்கள், பூமியதிர்ச்சிகள் மற்றும் பஞ்சங்கள் நேரிடும்; இவை வேதனைகளின் ஆரம்பம் என்றார்."],
    "Mark 13:9": ["விசுவாசிகளுக்குத் துன்புறுத்தல்", "என் நாமத்தினிமித்தம் நீங்கள் விசாரணைக்கு உட்படுத்தப்படுவீர்கள் மற்றும் துன்புறுத்தப்படுவீர்கள் என்று எச்சரித்தார்."],
    "Mark 13:14": ["பாழாக்கும் அருவருப்பு", "தீர்க்கதரிசனத்தில் சொல்லப்பட்ட பாழாக்கும் அருவருப்பு இருக்கக்கூடாத இடத்தில் நிற்பதைக் காணும்போது எச்சரிக்கையாய் இருக்கச் சொன்னார்."],
    "Mark 13:21": ["கள்ளக் கிறிஸ்துக்கள்", "கள்ளக் கிறிஸ்துக்களும் கள்ளத் தீர்க்கதரிசிகளும் எழும்பி ஜனங்களை வஞ்சிக்க முயற்சிப்பார்கள் என்று மீண்டும் எச்சரித்தார்."],
    "Mark 13:24": ["மனுஷகுமாரன் வருதல்", "வானத்தில் அடையாளங்கள் தோன்றும்; மனுஷகுமாரன் மிகுந்த வல்லமையோடும் மகிமையோடும் வருவதை யாவரும் காண்பார்கள்."],
    "Mark 13:28": ["அத்திமரப் பாடம்", "அத்திமரம் துளிர்ப்பது கோடைகாலம் வருவதைக் குறிப்பது போல, இந்த அடையாளங்கள் முடிவை அறிவிக்கும் என்றார்."],
    "Mark 13:32": ["நாளும் நாழிகையும் இரகசியம்", "அந்த நாள் எப்போது வரும் என்பது பிதா ஒருவருக்கு மட்டுமே தெரியும்; வேறு யாரும் அதை அறியார்."],
    "Mark 13:33": ["விழிப்புடன் இருங்கள்", "எந்த நேரத்தில் அவர் வருவார் என்று தெரியாததால், எப்போதும் விழிப்புடனும் ஆயத்தமுடனும் இருங்கள் என்று வலியுறுத்தினார்."],

    "Mark 14:1": ["இயேசுவைக் கொல்லச் சதி", "பிரதான ஆசாரியர்களும் வேதபாரகரும் இயேசுவைத் தந்திரமாகப் பிடித்துக் கொலை செய்ய வழி தேடினார்கள்."],
    "Mark 14:3": ["பெத்தானியாவில் அபிஷேகம்", "பெத்தானியாவில் ஒரு ஸ்திரீ விலையேறப்பெற்ற தைலத்தை இயேசுவின் தலையில் ஊற்றி, அவருடைய அடக்கத்திற்காக அவரை ஆயத்தம் செய்தாள்."],
    "Mark 14:10": ["யூதாஸின் துரோகம்", "யூதாஸ்காரியோத்து பிரதான ஆசாரியர்களிடம் சென்று, இயேசுவைக் காட்டிக்கொடுக்கச் சம்மதித்தான்."],
    "Mark 14:12": ["பஸ்கா ஆயத்தம்", "பஸ்கா போஜனம் பண்ணுவதற்கான ஏற்பாடுகளைச் செய்யும்படி இயேசு சீஷர்களுக்குக் கட்டளையிட்டார்."],
    "Mark 14:17": ["காட்டிக்கொடுப்பதை முன்னறிவித்தல்", "பந்தியில் அமர்ந்திருக்கும்போது, உங்களில் ஒருவன் என்னைக் காட்டிக்கொடுப்பான் என்று இயேசு சொன்னார்."],
    "Mark 14:22": ["திருவிருந்து", "அப்பத்தையும் திராட்சரசத்தையும் தமது சரீரம் மற்றும் இரத்தத்தின் அடையாளமாக இயேசு கொடுத்துத் திருவிருந்தை நியமித்தார்."],
    "Mark 14:27": ["பேதுரு மறுதலிப்பதை முன்னறிவித்தல்", "நீங்கள் எல்லாரும் இடறலடைவீர்கள் என்றும், சேவல் கூவுவதற்கு முன் பேதுரு தன்னை மூன்று முறை மறுதலிப்பான் என்றும் கூறினார்."],
    "Mark 14:32": ["கெத்செமனே ஜெபம்", "கைது செய்யப்படுவதற்கு முன், இயேசு கெத்செமனே தோட்டத்தில் மிகுந்த வேதனையுடன் பிதாவிடம் ஜெபித்தார்."],
    "Mark 14:43": ["இயேசு கைது செய்யப்படல்", "யூதாஸ் திரளான ஜனங்களுடன் வந்து, இயேசுவை முத்தமிட்டுக் காட்டிக்கொடுத்தார்; இயேசு கைது செய்யப்பட்டார்."],
    "Mark 14:53": ["ஆலோசனைக் சங்கத்தின் முன் இயேசு", "இயேசு பிரதான ஆசாரியனிடம் கொண்டு செல்லப்பட்டார்; அங்கே பொய்ச்சாட்சிகள் அவர் மேல் குற்றம் சுமத்தினார்கள்."],
    "Mark 14:66": ["பேதுரு மறுதலித்தல்", "பேதுரு முன்றில் உட்கார்ந்திருக்கையில், மூன்று முறை இயேசுவை அறியேன் என்று மறுதலித்தான்; உடனே சேவல் கூவியது."],

    "Mark 15:1": ["பிலாத்துவினிடம் இயேசு", "காலையிலேயே இயேசுவைக் கட்டி, தேசாதிபதியாகிய பிலாத்துவினிடம் கொண்டு போய் அவர் மேல் குற்றம் சுமத்தினார்கள்."],
    "Mark 15:6": ["பரபாஸ் விடுதலை", "ஒரு கைதியை விடுதலை செய்யும் வழக்கத்தின்படி, ஜனங்கள் இயேசுவுக்குப் பதிலாகப் பரபாஸை விடுதலை செய்யக் கேட்டார்கள்."],
    "Mark 15:16": ["சேவகர்கள் பரியாசம் செய்தல்", "ரோம சேவகர்கள் இயேசுவுக்கு முள்முடி சூட்டி, சிவப்பான அங்கியை உடுத்தி அவரைப் பரியாசம் செய்தார்கள்."],
    "Mark 15:21": ["சிலுவைப்பாதை", "சீரேனே ஊரானாகிய சீமோன் என்பவனை இயேசுவின் சிலுவையைச் சுமக்கக் கட்டாயப்படுத்தினார்கள்."],
    "Mark 15:24": ["சிலுவையில் அறையப்படுதல்", "இயேசு சிலுவையில் அறையப்பட்டார்; சேவகர்கள் அவருடைய வஸ்திரங்களைச் சீட்டுப் போட்டுப் பங்கிட்டுக் கொண்டார்கள்."],
    "Mark 15:33": ["இயேசுவின் மரணம்", "பூமியெங்கும் இருள் உண்டானது; இயேசு மகா சத்தமிட்டுக் கூப்பிட்டுத் தமது ஆவியை விட்டார்."],
    "Mark 15:38": ["தேவாலயத் திரை கிழிதல்", "தேவாலயத் திரை மேல்தொடங்கி கீழ்வரைக்கும் இரண்டாகக் கிழிந்தது."],
    "Mark 15:42": ["இயேசுவின் அடக்கம்", "அரிமத்தியா ஊரானாகிய யோசேப்பு பிலாத்துவினிடம் அனுமதி பெற்று, இயேசுவின் சரீரத்தைக் கல்லறையில் வைத்தார்."],

    "Mark 16:1": ["இயேசுவின் உயிர்த்தெழுதல்", "வாரத்தின் முதல் நாள் காலையில் மரியாளும் மற்ற ஸ்திரீகளும் கல்லறைக்குச் சென்றபோது, கல் புரட்டப்பட்டிருப்பதைக் கண்டார்கள்."],
    "Mark 16:5": ["தூதரின் செய்தி", "வெள்ளையங்கி தரித்த ஒரு வாலிபன், இயேசு உயிர்த்தெழுந்தார் என்ற செய்தியை அவர்களிடம் கூறி, சீஷர்களுக்கு அறிவிக்கச் சொன்னார்."],
    "Mark 16:9": ["மகதலேனா மரியாளுக்குக் காட்சி", "உயிர்த்தெழுந்த இயேசு முதலில் மகதலேனா மரியாளுக்குக் காட்சி அளித்தார்."],
    "Mark 16:12": ["இரு சீஷர்களுக்குக் காட்சி", "கிராமத்திற்குப் போய்க்கொண்டிருந்த இரண்டு சீஷர்களுக்கு இயேசு வேறொரு ரூபத்தில் காட்சி அளித்தார்."],
    "Mark 16:14": ["பதினொருவருக்குக் காட்சி", "பதினொரு சீஷர்களும் பந்தியில் இருக்கும்போது இயேசு தோன்றி, அவர்களுடைய அவிசுவாசத்தைக் கடிந்துகொண்டார்."],
    "Mark 16:15": ["பெரிய கட்டளை", "நீங்கள் உலகமெங்கும் போய், சர்வ சிருஷ்டிக்கும் சுவிசேஷத்தைப் பிரசங்கியுங்கள் என்று இயேசு கட்டளையிட்டார்."],
    "Mark 16:19": ["இயேசு பரமேறுதல்", "இயேசு அவர்களுடன் பேசி முடித்த பின்பு, பரலோகத்திற்கு எடுத்துக்கொள்ளப்பட்டு தேவனுடைய வலதுபாரிசத்தில் அமர்ந்தார்."],
    "Mark 16:20": ["சீஷர்களின் ஊழியம்", "சீஷர்கள் புறப்பட்டுப் போய் எங்கும் பிரசங்கம் பண்ணினார்கள்; கர்த்தர் அற்புத அடையாளங்களால் அந்த வசனத்தை உறுதிப்படுத்தினார்."],

    
    // Continue here...

    "Revelation 1:1": ["இயேசு கிறிஸ்துவின் வெளிப்படுத்துதல்", "சீக்கிரத்தில் சம்பவிக்க வேண்டியவைகளைத் தம்முடைய ஊழியக்காரருக்குக் காண்பிக்கும்படி, தேவன் இயேசு கிறிஸ்துவுக்கு ஒப்புவித்த வெளிப்படுத்துதல் இதுவே."],
    "Revelation 1:3": ["தீர்க்கதரிசனத்தை வாசிப்பவர்களுக்கான ஆசீர்வாதம்", "இந்தத் தீர்க்கதரிசன வசனங்களை வாசிக்கிறவனும், கேட்கிறவர்களும், இதில் எழுதியிருக்கிறவைகளைக் கைக்கொள்ளுகிறவர்களும் பாக்கியவான்கள்."],
    "Revelation 1:4": ["ஏழு சபைகளுக்கும் வாழ்த்து", "ஆசியாவிலுள்ள ஏழு சபைகளுக்கும் யோவான் எழுதுகிறதாவது: இருக்கிறவரும் இருந்தவரும் வருகிறவருமாயிருக்கிறவரிடத்திலிருந்து உங்களுக்குக் கிருபையும் சமாதானமும் உண்டாவதாக."],
    "Revelation 1:7": ["கிறிஸ்துவின் வருகை", "இதோ, மேகங்களுடனே வருகிறார்; கண்கள் யாவும் அவரைக் காணும், அவரைக்குத்தினவர்களும் அவரைக் காண்பார்கள்."],
    "Revelation 1:8": ["தேவன் ஆல்பாவும் ஓமெகாவும்", "இருக்கிறவரும் இருந்தவரும் வருகிறவருமாகிய சர்வவல்லமையுள்ள கர்த்தர்: நான் ஆல்பாவும் ஓமெகாவும், ஆதியும் அந்தமுமாயிருக்கிறேன் என்று உரைக்கிறார்."],
    "Revelation 1:9": ["பத்மு தீவில் யோவான்", "தேவவசனத்தினிமித்தமும் இயேசு கிறிஸ்துவைப்பற்றிய சாட்சியினிமித்தமும் நான் பத்மு என்னப்பட்ட தீவிலே இருந்தேன்."],
    "Revelation 1:10": ["எக்காள சத்தம் போன்ற சத்தம்", "கர்த்தருடைய நாளில் நான் ஆவிக்குள்ளானேன்; அப்பொழுது எனக்குப் பின்னாலே எக்காள சத்தம் போன்ற ஒரு பெரிய சத்தத்தைக் கேட்டேன்."],
    "Revelation 1:12": ["மனுஷகுமாரனின் தரிசனம்", "நான் திரும்பிப் பார்த்தபோது, ஏழு பொன் குத்துவிளக்குகளையும், அவற்றின் மத்தியிலே மனுஷகுமாரனுக்கொப்பானவரையும் கண்டேன்."],
    "Revelation 1:17": ["பயப்படாதே, நான் பிழைத்திருக்கிறவர்", "இயேசு என்னைப் பார்த்து: பயப்படாதே, நான் முந்தினவரும் பிந்தினவரும், உயிருள்ளவருமாயிருக்கிறேன் என்று கூறினார்."],
    "Revelation 1:19": ["தரிசனத்தை எழுதக் கட்டளை", "நீ கண்டவைகளையும், இருக்கிறவைகளையும், இவைகளுக்குப் பின்பு சம்பவிக்கப்போகிறவைகளையும் எழுது."],
    "Revelation 1:20": ["குத்துவிளக்குகளின் மர்மம்", "ஏழு நட்சத்திரங்கள் ஏழு சபைகளின் தூதர்களாம்; நீ கண்ட ஏழு குத்துவிளக்குகளும் ஏழு சபைகளாம்."],

    "Revelation 2:1": ["எபேசு சபைக்குச் செய்தி", "இயேசு அவர்களின் கடின உழைப்பையும் பொறுமையையும் பாராட்டுகிறார், ஆனால் அவர்கள் தங்கள் ஆதி அன்பை விட்டதாக எச்சரிக்கிறார்."],
    "Revelation 2:5": ["மனந்திரும்ப அழைப்பு", "நீ விழுந்த இடத்தைப் நினைத்து, மனந்திரும்பி, ஆதியில் செய்த கிரியைகளைச் செய்யக்கடவாய் என்று சபை பணிக்கப்படுகிறது."],
    "Revelation 2:7": ["ஜெயங்கொள்ளுகிறவர்களுக்கு வாக்குத்தத்தம்", "ஜெயங்கொள்ளுகிறவனெவனோ அவனுக்குத் தேவனுடைய பரதீசின் மத்தியிலிருக்கிற ஜீவவிருட்சத்தின் கனியைப் புசிக்கக் கொடுப்பேன்."],
    "Revelation 2:8": ["சிமிர்னா சபைக்குச் செய்தி", "உபத்திரவப்படும் விசுவாசிகளை இயேசு ஊக்கப்படுத்துகிறார், அவர்களின் வறுமையையும் துன்பத்தையும் தான் அறிவதாகக் கூறுகிறார்."],
    "Revelation 2:10": ["உபத்திரவத்தில் உண்மையாயிருத்தல்", "நீ மரணபரியந்தம் உண்மையாயிரு, அப்பொழுது ஜீவகிரீடத்தை உனக்குத் தருவேன்."],
    "Revelation 2:12": ["பெர்கமு சபைக்குச் செய்தி", "சாத்தானுடைய சிங்காசனம் இருக்கிற இடத்திலே குடியிருக்கிற சபைக்கு இயேசு உரையாற்றி, தவறான போதனைகளுக்கு எதிராக எச்சரிக்கிறார்."],
    "Revelation 2:14": ["சமரசத்திற்கு எதிரான எச்சரிக்கை", "பிலேயாமின் போதனையையும் நிக்கொலாயி மதஸ்தரின் போதனையையும் பின்பற்றி, ஜனங்களைப் பாவத்திற்குள் நடத்துகிறவர்கள் உன்னிடத்தில் உண்டு."],
    "Revelation 2:16": ["பெர்கமுவில் மனந்திரும்ப அழைப்பு", "மனந்திரும்பு, இல்லாவிடில் நான் சீக்கிரமாய் உன்னிடத்தில் வந்து, என் வாயின் பட்டயத்தால் அவர்களோடே யுத்தம் பண்ணுவேன்."],
    "Revelation 2:18": ["தியத்தீரா சபைக்குச் செய்தி", "அவர்களின் அன்பு, விசுவாசம் மற்றும் ஊழியத்தை இயேசு பாராட்டுகிறார், ஆனால் கள்ளத் தீர்க்கதரிசியின் செல்வாக்கைக் குறித்து எச்சரிக்கிறார்."],
    "Revelation 2:20": ["யேசபேலைக் குறித்த எச்சரிக்கை", "யேசபேல் என்னும் ஸ்திரீயானவள் என் ஊழியக்காரரைப் விபசாரம்பண்ணவும் விக்கிரகங்களுக்குப் படைத்தவைகளைப் புசிக்கவும் போதித்து அவர்களை மோசம்போக்குகிறாள்."],
    "Revelation 2:24": ["விசுவாசிகளுக்கு ஊக்கம்", "மற்றவர்களாகிய உங்களுக்கு நான் சொல்லுகிறதாவது: நான் வரும்வரைக்கும் உங்களிடத்திலிருப்பதைப் பிடித்துக்கொண்டிருங்கள்."],
    "Revelation 2:26": ["ஜெயங்கொள்ளுகிறவர்களுக்கு அதிகாரம்", "ஜெயங்கொண்டு என் கிரியைகளை முடிவுபரியந்தம் கைக்கொள்ளுகிறவனெவனோ அவனுக்கு ஜாதிகளின்மேல் அதிகாரம் கொடுப்பேன்."],
    "Revelation 2:28": ["விடிவெள்ளி நட்சத்திரம்", "ஜெயங்கொள்ளுகிறவனுக்கு விடிவெள்ளி நட்சத்திரத்தைக் கொடுப்பேன்."],
    "Revelation 2:29": ["ஆவி சொல்லுகிறதைக் கேட்க அழைப்பு", "ஆவியானவர் சபைகளுக்குச் சொல்லுகிறதைக் காதுள்ளவன் கேட்கக்கடவன்."],

    "Revelation 3:1": ["சர்தை சபைக்குச் செய்தி", "நீ உயிருள்ளவன் என்று பெயர்கொண்டிருந்தும் செத்தவனாயிருக்கிறாய் என்று சர்தை சபைக்கு இயேசு கூறுகிறார்."],
    "Revelation 3:2": ["விழித்திருக்க அழைப்பு", "நீ விழித்துக்கொண்டு, சாகப்போகிற மீதியானவைகளை ஸ்திரப்படுத்து; உன் கிரியைகள் என் தேவனுக்குமுன்பு நிறைவுள்ளவைகளாக நான் காணவில்லை."],
    "Revelation 3:3": ["மனந்திரும்ப எச்சரிக்கை", "நீ விழித்திராவிட்டால், திருடன் வருகிறவிதமாய் உன்னிடத்தில் வருவேன், நான் வரும் நேரத்தை நீ அறியமாட்டாய்."],
    "Revelation 3:4": ["சர்தையிலுள்ள உண்மையுள்ளவர்கள்", "தங்கள் அங்கிகளை அசுசிப்படுத்தாத சில பேர் சர்தையிலுண்டு; அவர்கள் பாத்திரவான்களானபடியால் வெள்ளை அங்கி தரித்து என்னோடேகூட நடப்பார்கள்."],
    "Revelation 3:7": ["பிலதெல்பியா சபைக்குச் செய்தி", "கொஞ்ச பெலனிருந்தும், என் வசனத்தைக் கைக்கொண்டு, என் நாமத்தை மறுதலியாத உண்மையுள்ள சபையோடு இயேசு பேசுகிறார்."],
    "Revelation 3:8": ["திறக்கப்பட்ட வாசல்", "இதோ, திறந்த வாசலை உனக்கு முன்பாக வைத்திருக்கிறேன், அதை ஒருவனும் பூட்டமாட்டான்."],
    "Revelation 3:10": ["பாதுகாப்பு வாக்குத்தத்தம்", "என் பொறுமையைக் குறித்துச் சொல்லிய வசனத்தை நீ கைக்கொண்டபடியினால், பூமியில் குடியிருக்கிறவர்களைச் சோதிக்கும்படி உலகமெங்கும் வரப்போகிற சோதனைக் காலத்திற்கு உன்னைத் தப்புவிப்பேன்."],
    "Revelation 3:11": ["உன்னிடத்திலிருப்பதைப் பிடித்துக்கொள்", "இதோ, சீக்கிரமாய் வருகிறேன்; ஒருவனும் உன் கிரீடத்தைப் பறித்துக்கொள்ளாதபடி உனக்குள்ளதைப் பிடித்துக்கொள்."],
    "Revelation 3:12": ["ஜெயங்கொள்ளுகிறவனுக்குப் பலன்", "ஜெயங்கொள்ளுகிறவனை என் தேவனுடைய ஆலயத்தில் தூணாக்குவேன், என் தேவனுடைய நாமத்தை அவன்மேல் எழுதுவேன்."],
    "Revelation 3:14": ["லவோதிக்கேயா சபைக்குச் செய்தி", "குளிருமின்றி அனலுமின்றி வெதுவெதுப்பாயிருக்கிற சபைக்கு இயேசு உரையாற்றுகிறார்."],
    "Revelation 3:16": ["வெதுவெதுப்பான விசுவாசத்திற்கு எச்சரிக்கை", "நீ குளிருமின்றி அனலுமின்றி வெதுவெதுப்பாயிருக்கிறபடியினால் உன்னை என் வாயினின்று வாந்திபண்ணிப்போடுவேன்."],
    "Revelation 3:17": ["உண்மையான ஆவிக்குரிய நிலை", "நீ ஐசுவரியவான் என்று சொல்லியும், நீ துர்ப்பாக்கியமுள்ளவனும், தரித்திரனும், குருடனும், நிர்வாணியுமாயிருக்கிறதை அறியாதிருக்கிறாய்."],
    "Revelation 3:19": ["மனந்திரும்ப அழைப்பு", "நான் நேசிக்கிறவர்களெவர்களோ அவர்களைக் கடிந்துகொண்டு சிட்சிக்கிறேன்; ஆகையால் நீ ஜாக்கிரதையாயிருந்து மனந்திரும்பு."],
    "Revelation 3:20": ["இயேசு வாசற்படியில் நிற்கிறார்", "இதோ, வாசற்படியிலே நின்று தட்டுகிறேன்; ஒருவன் என் சத்தத்தைக் கேட்டு, கதவைத் திறந்தால், அவனிடத்தில் நான் பிரவேசித்து, அவனோடே போஜனம் பண்ணுவேன்."],
    "Revelation 3:21": ["ஜெயங்கொள்ளுகிறவனுக்கு வாக்குத்தத்தம்", "நான் ஜெயங்கொண்டு என் பிதாவினுடைய சிங்காசனத்திலே அவரோடேகூட வீற்றிருக்கிறதுபோல, ஜெயங்கொள்ளுகிறவனும் என்னோடேகூட என் சிங்காசனத்தில் வீற்றிருக்கும்படி அருள்செய்வேன்."],
    "Revelation 3:22": ["ஆவி சொல்லுகிறதைக் கேள்", "ஆவியானவர் சபைகளுக்குச் சொல்லுகிறதைக் காதுள்ளவன் கேட்கக்கடவன்."],

    "Revelation 4:1": ["பரலோகத்தில் திறக்கப்பட்ட வாசல்", "பரலோகத்தில் ஒரு வாசல் திறக்கப்பட்டிருக்கக் கண்டேன்; அங்கே ஏறிவா, சம்பவிக்க வேண்டியவைகளை உனக்குக் காண்பிப்பேன் என்று ஒரு சத்தம் கேட்டது."],
    "Revelation 4:2": ["பரலோக சிங்காசனம்", "நான் ஆவிக்குள்ளானேன்; அப்பொழுது பரலோகத்திலே ஒரு சிங்காசனம் வைக்கப்பட்டிருந்தது, அந்தச் சிங்காசனத்தின்மேல் ஒருவர் வீற்றிருந்தார்."],
    "Revelation 4:4": ["இருபத்து நான்கு மூப்பர்கள்", "சிங்காசனத்தைச் சுற்றிலும் இருபத்து நான்கு சிங்காசனங்கள் இருந்தன; அவற்றின்மேல் வெள்ளை அங்கி தரித்து, பொன் கிரீடம் சூடிய இருபத்து நான்கு மூப்பர்கள் அமர்ந்திருந்தார்கள்."],
    "Revelation 4:6": ["நான்கு ஜீவன்கள்", "சிங்காசனத்தின் முன்பாகப் பளிங்குக்கொப்பான கண்ணாடி போன்ற கடல் இருந்தது; சிங்காசனத்தைச் சுற்றிலும் கண்களால் நிறைந்த நான்கு ஜீவன்கள் இருந்தன."],
    "Revelation 4:8": ["பரிசுத்தர், பரிசுத்தர், பரிசுத்தர்", "அந்த நான்கு ஜீவன்களும்: இருந்தவரும் இருக்கிறவரும் வருகிறவருமாகிய சர்வவல்லமையுள்ள தேவனாகிய கர்த்தர் பரிசுத்தர், பரிசுத்தர், பரிசுத்தர் என்று ஓயாமல் சொல்லிக்கொண்டிருந்தன."],
    "Revelation 4:9": ["சிங்காசனத்தைச் சுற்றியுள்ள ஆராதனை", "அந்த ஜீவன்கள் சிங்காசனத்தின்மேல் வீற்றிருக்கிறவருக்கு மகிமையையும் கனத்தையும் செலுத்தும்போது, மூப்பர்களும் அவரை ஆராதிப்பார்கள்."],
    "Revelation 4:10": ["மூப்பர்கள் தங்கள் கிரீடங்களை வைக்கின்றனர்", "இருபத்து நான்கு மூப்பர்களும் சிங்காசனத்தின்மேல் வீற்றிருக்கிறவருக்கு முன்பாக விழுந்து வணங்கி, தங்கள் கிரீடங்களைச் சிங்காசனத்திற்கு முன்பாக வைத்தார்கள்."],
    "Revelation 4:11": ["சகல மகிமைக்கும் பாத்திரராகிய தேவன்", "எங்கள் கர்த்தாவே, நீர் மகிமையையும் கனத்தையும் வல்லமையையும் பெற்றுக்கொள்ளுகிறதற்குப் பாத்திரராயிருக்கிறீர்; நீரே சகலத்தையும் படைத்தீர்."],

    "Revelation 5:1": ["தேவனுடைய கரத்திலிருந்த புஸ்தகம்", "சிங்காசனத்தின்மேல் வீற்றிருக்கிறவருடைய வலதுகரத்திலே ஏழு முத்திரைகளால் முத்திரிக்கப்பட்ட ஒரு புஸ்தகத்தைக் கண்டேன்."],
    "Revelation 5:2": ["பாத்திரமானவரைத் தேடுதல்", "புஸ்தகத்தைத் திறக்கவும் அதின் முத்திரைகளை உடைக்கவும் பாத்திரவான் யார் என்று ஒரு பலமுள்ள தூதன் மிகுந்த சத்தத்தோடே கூப்பிட்டான்."],
    "Revelation 5:4": ["முத்திரிக்கப்பட்ட புஸ்தகத்திற்காக யோவான் அழுதல்", "புஸ்தகத்தைத் திறக்கவும் வாசிக்கவும் ஒருவனும் பாத்திரவானாகக் காணப்படாததினால் நான் மிகவும் அழுதேன்."],
    "Revelation 5:5": ["யூதா கோத்திரத்துச் சிங்கம் பாத்திரமானவர்", "மூப்பர்களில் ஒருவன் என்னை நோக்கி: அழாதே, யூதா கோத்திரத்துச் சிங்கமும் தாவீதின் வேருமானவர் புஸ்தகத்தைத் திறக்க ஜெயங்கொண்டிருக்கிறார் என்றான்."],
    "Revelation 5:6": ["ஆட்டுக்குட்டியானவர் தோன்றுதல்", "அடிக்கப்பட்டிருந்தது போன்ற ஒரு ஆட்டுக்குட்டியானவர் சிங்காசனத்தின் மத்தியிலும் மூப்பர்களின் மத்தியிலும் நிற்கக் கண்டேன்."],
    "Revelation 5:7": ["ஆட்டுக்குட்டியானவர் புஸ்தகத்தை வாங்குகிறார்", "அந்த ஆட்டுக்குட்டியானவர் வந்து, சிங்காசனத்தின்மேல் வீற்றிருந்தவருடைய வலதுகரத்திலிருந்து புஸ்தகத்தை வாங்கினார்."],
    "Revelation 5:8": ["ஆட்டுக்குட்டியானவரை ஆராதித்தல்", "அவர் புஸ்தகத்தை வாங்கினபோது, நான்கு ஜீவன்களும் இருபத்து நான்கு மூப்பர்களும் ஆட்டுக்குட்டியானவருக்கு முன்பாக விழுந்து வணங்கினார்கள்."],
    "Revelation 5:9": ["மீட்பின் புதிய பாட்டு", "நீர் புஸ்தகத்தை வாங்கவும் அதின் முத்திரைகளை உடைக்கவும் பாத்திரராயிருக்கிறீர்; ஏனெனில் நீர் அடிக்கப்பட்டு, உம்முடைய இரத்தத்தினாலே எங்களை தேவனுக்கென்று மீட்டுக் கொண்டீர்."],
    "Revelation 5:11": ["கோடிக்கணக்கான தூதர்களின் துதி", "சிங்காசனத்தைச் சுற்றிலும் இருந்த அநேக தூதர்களின் சத்தத்தைக் கேட்டேன்; அவர்களுடைய இலக்கம் கோடாகோடியாயிருந்தது."],
    "Revelation 5:12": ["ஆட்டுக்குட்டியானவர் பாத்திரர்", "அடிக்கப்பட்ட ஆட்டுக்குட்டியானவர் வல்லமையையும் ஐசுவரியத்தையும் ஞானத்தையும் கனத்தையும் மகிமையையும் ஆசீர்வாதத்தையும் பெற்றுக்கொள்ளப் பாத்திரராயிருக்கிறார்."],
    "Revelation 5:13": ["சகல சிருஷ்டிகளும் ஆராதித்தல்", "வானத்திலும் பூமியிலுமுள்ள சகல சிருஷ்டிகளும் சிங்காசனத்தின்மேல் வீற்றிருக்கிறவருக்கும் ஆட்டுக்குட்டியானவருக்கும் துதி உண்டாவதாக என்று சொல்லக் கேட்டேன்."],
    "Revelation 5:14": ["நித்திய ஆராதனை", "அதற்கு நான்கு ஜீவன்களும் ஆமென் என்றன; மூப்பர்கள் விழுந்து, சதாகாலங்களிலும் உயிரோடிருக்கிறவரை ஆராதித்தார்கள்."],

    "Revelation 6:1": ["முதல் முத்திரை: வெள்ளைக் குதிரை", "ஆட்டுக்குட்டியானவர் முதல் முத்திரையை உடைக்கக் கண்டேன்; அப்பொழுது ஒரு வெள்ளைக் குதிரையைக் கண்டேன், அதன்மேல் ஏறியிருந்தவர் ஜெயிக்கிறவராய்ப் புறப்பட்டார்."],
    "Revelation 6:3": ["இரண்டாம் முத்திரை: சிவப்புக் குதிரை", "இரண்டாம் முத்திரையை உடைத்தபோது ஒரு சிவப்புக் குதிரை புறப்பட்டது; பூமியிலுள்ளவர்கள் ஒருவரையொருவர் கொலைசெய்யத்தக்கதாகச் சமாதானத்தை எடுத்துப்போட அதற்கு அதிகாரம் கொடுக்கப்பட்டது."],
    "Revelation 6:5": ["மூன்றாம் முத்திரை: கறுப்புக் குதிரை", "மூன்றாம் முத்திரையை உடைத்தபோது ஒரு கறுப்புக் குதிரையைக் கண்டேன்; அதன்மேல் ஏறியிருந்தவர் ஒரு தராசைத் தன் கையிலே பிடித்திருந்தார், இது பஞ்சத்தைக் குறிக்கிறது."],
    "Revelation 6:7": ["நான்காம் முத்திரை: மங்கின நிறமுள்ள குதிரை", "மங்கின நிறமுள்ள ஒரு குதிரையைக் கண்டேன்; அதன்மேல் ஏறியிருந்தவனுக்கு மரணம் என்று பெயர், அவன் பூமியின் கால்பங்கு அதிகாரத்தைப் பெற்றான்."],
    "Revelation 6:9": ["ஐந்தாம் முத்திரை: இரத்த சாட்சிகளின் கூக்குரல்", "தேவவசனத்தினிமித்தம் கொல்லப்பட்டவர்களுடைய ஆத்துமாக்கள் பலிபீடத்திற்குக் கீழிருந்து: 'எங்கள் இரத்தத்தைக் குறித்து எப்பொழுது நியாயத்தீர்ப்புச் செய்வீர்' என்று கூக்குரலிட்டன."],
    "Revelation 6:12": ["ஆறாம் முத்திரை: பிரபஞ்ச மாற்றங்கள்", "பெரிய பூமியதிர்ச்சி உண்டாயிற்று; சூரியன் கறுப்பானது, சந்திரன் இரத்தம்போலானது, வானத்தின் நட்சத்திரங்கள் பூமியிலே விழுந்தன."],
    "Revelation 6:15": ["தேவனுடைய கோபத்திற்குத் தப்ப ஓடுதல்", "பூமியின் ராஜாக்களும் தலைவர்களும் சிங்காசனத்தின்மேல் வீற்றிருக்கிறவருடைய கோபத்திற்குத் தங்களை மறைத்துக்கொள்ளும்படி மலைகளின் கன்மலைகளில் ஒளித்துக்கொண்டார்கள்."],
    "Revelation 6:17": ["கோபாக்கினையின் மகா நாள்", "தேவனுடைய கோபாக்கினையின் மகா நாள் வந்துவிட்டது, அதற்கு முன்பாக நிற்க யாரால் கூடும்?"],

    "Revelation 7:1": ["நான்கு தூதர்கள் காற்றைத் தடுத்தல்", "பூமியின் நான்கு திசைகளிலும் நான்கு தூதர்கள் நின்று, பூமியின்மேலாவது சமுத்திரத்தின்மேலாவது காற்று வீசாதபடி அதைப் பிடித்துக்கொண்டிருந்தார்கள்."],
    "Revelation 7:2": ["ஜீவனுள்ள தேவனுடைய முத்திரை", "வேறொரு தூதன் ஜீவனுள்ள தேவனுடைய முத்திரையைப் பிடித்துக்கொண்டு வானத்திலிருந்து இறங்கி வந்து, தேவனுடைய ஊழியக்காரரின் நெற்றியில் முத்திரையிடும் வரை பூமியைச் சேதப்படுத்த வேண்டாம் என்றான்."],
    "Revelation 7:4": ["முத்திரையிடப்பட்ட 1,44,000 பேர்", "இஸ்ரவேல் புத்திரருடைய சகல கோத்திரங்களிலும் முத்திரையிடப்பட்டவர்கள் ஒரு இலட்சத்து நாற்பத்து நாலாயிரம் பேர் என்று சொல்லக் கேட்டேன்."],
    "Revelation 7:9": ["வெள்ளை அங்கி தரித்த திரளான கூட்டம்", "சகல ஜாதிகளிலும் கோத்திரங்களிலும் பாஷைகளிலுமிருந்து வந்த திரளான கூட்டத்தைக் கண்டேன்; அவர்கள் வெள்ளை அங்கிகளைத் தரித்து, கைகளில் பேரீச்ச மட்டைகளைப் பிடித்து நின்றார்கள்."],
    "Revelation 7:13": ["வெள்ளை அங்கி தரித்தவர்கள் யார்?", "வெள்ளை அங்கிகளைத் தரித்திருக்கிற இவர்கள் யார் என்று மூப்பர்களில் ஒருவன் கேட்டான்; இவர்கள் மிகுந்த உபத்திரவத்திலிருந்து வந்தவர்கள் என்று விளக்கப்பட்டது."],
    "Revelation 7:15": ["சிங்காசனத்திற்கு முன்பாக ஊழியம்", "அவர்கள் தேவனுடைய சிங்காசனத்திற்கு முன்பாக இருந்து, இரவும் பகலும் அவருடைய ஆலயத்திலே அவரைச் சேவிக்கிறார்கள்."],
    "Revelation 7:16": ["பசியும் தாகமும் இனி இல்லை", "அவர்கள் இனி பசிப்பதும் இல்லை, தாகம் கொள்வதும் இல்லை; வெயிலாவது வெப்பமாவது அவர்கள்மேல் படாது."],
    "Revelation 7:17": ["ஆட்டுக்குட்டியானவர் மேய்க்கிறார்", "ஆட்டுக்குட்டியானவர் அவர்களை ஜீவத்தண்ணீருள்ள ஊற்றுகளண்டைக்கு நடத்துவார்; தேவன் அவர்கள் கண்ணீர் யாவையும் துடைப்பார்."],

    "Revelation 8:1": ["ஏழாம் முத்திரை", "ஆட்டுக்குட்டியானவர் ஏழாம் முத்திரையை உடைத்தபோது, பரலோகத்தில் அரைமணி நேரமளவு அமைதியுண்டாயிற்று."],
    "Revelation 8:2": ["ஏழு எக்காளங்களுடன் ஏழு தூதர்கள்", "தேவனுக்கு முன்பாக ஏழு தூதர்கள் நிற்கக் கண்டேன்; அவர்களுக்கு ஏழு எக்காளங்கள் கொடுக்கப்பட்டன."],
    "Revelation 8:3": ["பரிசுத்தவான்களின் ஜெபங்கள்", "வேறொரு தூதன் வந்து பொன் தூபகலசத்தைப் பிடித்து, பரிசுத்தவான்களுடைய ஜெபங்களோடு தூபத்தைச் சிங்காசனத்தின் முன்பாக இருக்கும் பொன் பலிபீடத்தின்மேல் செலுத்தினான்."],
    "Revelation 8:5": ["பூமியின்மேல் எறியப்பட்ட நெருப்பு", "தூதன் அந்தத் தூபகலசத்தைப் பலிபீடத்து நெருப்பினால் நிரப்பி பூமியின்மேல் எறிந்தான்; உடனே சத்தங்களும் இடிமுழக்கங்களும் பூமியதிர்ச்சியும் உண்டாயின."],
    "Revelation 8:6": ["எக்காளங்கள் ஊத ஆயத்தம்", "எக்காளங்களை உடைய ஏழு தூதர்களும் அவற்றை ஊதும்படி ஆயத்தமானார்கள்."],
    "Revelation 8:7": ["முதல் எக்காளம்", "முதல் தூதன் எக்காளம் ஊதினான்; இரத்தங்கலந்த கல்மழையும் நெருப்பும் உண்டாகி பூமியின்மேல் எறியப்பட்டது; மரங்களில் மூன்றிலொரு பங்கு வெந்துபோயின."],
    "Revelation 8:8": ["இரண்டாம் எக்காளம்", "இரண்டாம் தூதன் எக்காளம் ஊதினான்; எரிகிற பெரிய மலை போன்ற ஒன்று சமுத்திரத்தில் எறியப்பட்டது; சமுத்திரத்தில் மூன்றிலொரு பங்கு இரத்தமாயிற்று."],
    "Revelation 8:10": ["மூன்றாம் எக்காளம்", "மூன்றாம் தூதன் எக்காளம் ஊதினான்; 'எட்டி' (Wormwood) என்னும் பெயருள்ள பெரிய நட்சத்திரம் வானத்திலிருந்து விழுந்து, ஆறுகளில் மூன்றிலொரு பங்கை கசப்பாக்கியது."],
    "Revelation 8:12": ["நான்காம் எக்காளம்", "நான்காம் தூதன் எக்காளம் ஊதினான்; சூரியன், சந்திரன், நட்சத்திரங்களில் மூன்றிலொரு பங்கு அடிக்கப்பட்டது, அவற்றின் ஒளி இருளடைந்தது."],
    "Revelation 8:13": ["மூன்று ஆபத்துகள் (Woes)", "வானத்தின் மத்தியில் ஒரு கழுகு பறந்து: 'இனி எக்காளம் ஊதப்போகிற மற்ற மூன்று தூதர்களினால் பூமியில் குடியிருக்கிறவர்களுக்கு ஐயோ! ஐயோ! ஐயோ! (ஆபத்து)' என்று சொல்லக் கேட்டேன்."],

    "Revelation 9:1": ["ஐந்தாம் எக்காளம்: பாதாளக் குழி", "ஐந்தாம் தூதன் எக்காளம் ஊதினான்; வானத்திலிருந்து பூமியில் விழுந்த ஒரு நட்சத்திரத்தைக் கண்டேன்; பாதாளக் குழியின் திறவுகோல் அவனுக்குக் கொடுக்கப்பட்டது."],
    "Revelation 9:2": ["பாதாளத்திலிருந்து புகை", "அவன் பாதாளக் குழியைத் திறந்தான்; ஒரு பெரிய சூளையின் புகையைப்போலக் குழியிலிருந்து புகை எழும்பியது, சூரியனும் ஆகாயமும் இருளடைந்தன."],
    "Revelation 9:3": ["வெட்டுக்கிளிகளின் வருகை", "அந்தப் புகையிலிருந்து வெட்டுக்கிளிகள் பூமியின்மேல் புறப்பட்டன; அவைகளுக்குத் தேள்களின் வல்லமை போன்ற வல்லமை கொடுக்கப்பட்டது."],
    "Revelation 9:4": ["முத்திரையிடப்படாதவர்களுக்கு வேதனை", "பூமியின் புல்லைச் சேதப்படுத்தாமல், தங்கள் நெற்றியில் தேவனுடைய முத்திரையிடப்படாத மனுஷரை மாத்திரம் வேதனைப்படுத்த அவைகளுக்குக் கட்டளையிடப்பட்டது."],
    "Revelation 9:7": ["வெட்டுக்கிளி சேனையின் விவரிப்பு", "அந்த வெட்டுக்கிளிகள் யுத்தத்திற்கு ஆயத்தம் பண்ணப்பட்ட குதிரைகளுக்கு ஒப்பாயிருந்தன; அவைகளின் முகங்கள் மனுஷ முகங்களைப்போல இருந்தன."],
    "Revelation 9:11": ["வெட்டுக்கிளிகளின் ராஜா", "பாதாளத்தின் தூதன் அவைகளுக்கு ராஜா; அவனுக்கு எபிரெயு பாஷையிலே அபத்தோன் என்றும், கிரேக்க பாஷையிலே அப்பொல்லியோன் என்றும் பெயர்."],
    "Revelation 9:12": ["முதலாம் ஆபத்து கடந்தது", "முதலாம் ஆபத்து கடந்துபோயிற்று; இதோ, இன்னும் இரண்டு ஆபத்துகள் வருகின்றன."],
    "Revelation 9:13": ["ஆறாம் எக்காளம்", "ஆறாம் தூதன் எக்காளம் ஊதினான்; தேவனுக்கு முன்பாக இருந்த பொன் பலிபீடத்தின் நான்கு கொம்புகளிலிருந்து ஒரு சத்தம் பிறந்தது."],
    "Revelation 9:15": ["நான்கு தூதர்கள் அவிழ்த்துவிடப்படுதல்", "மனுஷரில் மூன்றிலொரு பங்கைக் கொல்லும்படி ஆயத்தமாக்கப்பட்டிருந்த நான்கு தூதர்களும் அவிழ்த்துவிடப்பட்டார்கள்."],
    "Revelation 9:16": ["பெரிய குதிரைச்சேனை", "குதிரைச்சேனைகளின் இலக்கம் இருபது கோடி என்று சொல்லக் கேட்டேன்; அவை அழிவைக் கொண்டுவந்தன."],
    "Revelation 9:20": ["மனந்திரும்பாத மனுஷர்கள்", "இந்த வாதைகளால் கொல்லப்படாத மற்ற மனுஷர்கள் தங்கள் கைகளின் கிரியைகளை விட்டு மனந்திரும்பாமல், பேய்களையும் விக்கிரகங்களையும் ஆராதிப்பதிலேயே நிலைத்திருந்தார்கள்."],

    "Revelation 10:1": ["பலமுள்ள தூதனும் சிறு புஸ்தகமும்", "பலமுள்ள வேறொரு தூதன் வானத்திலிருந்து இறங்கி வரக்கண்டேன்; அவன் கையிலே திறக்கப்பட்ட ஒரு சிறு புஸ்தகம் இருந்தது."],
    "Revelation 10:3": ["ஏழு இடிமுழக்கங்கள்", "அவன் சிங்கம் கர்ச்சிப்பதுபோல மகா சத்தமாய் ஆர்ப்பரித்தான்; அவன் ஆர்ப்பரித்தபோது ஏழு இடிமுழக்கங்கள் தங்கள் சத்தங்களை முழங்கின."],
    "Revelation 10:4": ["மறைபொருள் முத்திரையிடப்படுதல்", "அந்த ஏழு இடிமுழக்கங்கள் சொன்னவைகளை நான் எழுதப்போனேன்; ஆனால்: 'அவைகளை எழுதாமல் முத்திரை போடு' என்று வானத்திலிருந்து ஒரு சத்தம் கேட்டது."],
    "Revelation 10:5": ["தூதனின் ஆணை", "சமுத்திரத்தின்மேலும் பூமியின்மேலும் நின்ற தூதன் தன் கையை வானத்திற்கு நேராக உயர்த்தி, நித்தியமாய் உயிரோடிருக்கிறவர்மேல் ஆணையிட்டுக் கூறினான்."],
    "Revelation 10:6": ["இனி காலதாமதம் இல்லை", "இனி காலதாமதம் இருக்காது என்று அவன் அறிவித்தான்."],
    "Revelation 10:7": ["தேவ ரகசியம் நிறைவேறும்", "ஏழாம் தூதன் எக்காளம் ஊதப்போகிற நாட்களில், தேவன் தம்முடைய ஊழியக்காரராகிய தீர்க்கதரிசிகளுக்கு அறிவித்தபடி தேவ ரகசியம் நிறைவேறும்."],
    "Revelation 10:8": ["சிறு புஸ்தகத்தை வாங்க யோவானுக்குக் கட்டளை", "வானத்திலிருந்து கேட்ட சத்தம் என்னைத் தூதன் கையிலிருக்கும் அந்தச் சிறு புஸ்தகத்தை வாங்கும்படி பணித்தது."],
    "Revelation 10:9": ["சிறு புஸ்தகத்தைப் புசித்தல்", "நான் அதை வாங்கிப் புசித்தேன்; அது என் வாய்க்குத் தேனைப்போல இனிப்பாயிருந்தது, என் வயிற்றுக்கோ கசப்பாயிருந்தது."],
    "Revelation 10:11": ["மீண்டும் தீர்க்கதரிசனம் சொல்லக் கட்டளை", "நீ மறுபடியும் அநேக ஜனங்களையும் ஜாதிகளையும் பாஷைகளையும் ராஜாக்களையும் குறித்துத் தீர்க்கதரிசனம் சொல்லவேண்டும் என்று அவன் சொன்னான்."],

    "Revelation 11:1": ["தேவனுடைய ஆலயத்தை அளவிடுதல்", "ஒரு அளவுகோல் என்னிடம் கொடுக்கப்பட்டது; தேவனுடைய ஆலயத்தையும் பலிபீடத்தையும் அதில் தொழுகிறவர்களையும் அளக்கும்படி கட்டளையிடப்பட்டது."],
    "Revelation 11:2": ["புறம்பே இருக்கிற பிரகாரம்", "ஆலயத்திற்குப் புறம்பே இருக்கிற பிரகாரம் ஜாதிகளுக்குக் கொடுக்கப்பட்டிருப்பதால் அதை அளக்க வேண்டாம்; அவர்கள் பரிசுத்த நகரத்தை நாற்பத்திரண்டு மாதம் மிதிப்பார்கள்."],
    "Revelation 11:3": ["இரண்டு சாட்சிகள்", "என்னுடைய இரண்டு சாட்சிகளும் இரட்டுடுத்திக்கொண்டவர்களாய் ஆயிரத்து இருநூற்று அறுபது நாள் தீர்க்கதரிசனம் சொல்லும்படி அவர்களுக்கு அதிகாரம் கொடுப்பேன்."],
    "Revelation 11:5": ["சாட்சிகளின் வல்லமை", "அவர்களுக்குத் தீங்கு செய்ய நினைப்பவன் எவனோ அவன் அவர்களுடை வாயிலிருந்து புறப்படும் நெருப்பினால் அழிக்கப்படுவான்; அவர்கள் வாதைகளால் பூமியைச் சித்திரவதை செய்ய வல்லமை உடையவர்கள்."],
    "Revelation 11:7": ["மிருகம் சாட்சிகளைக் கொல்லுதல்", "அவர்கள் தங்கள் சாட்சியைச் சொல்லி முடித்தபோது, பாதாளத்திலிருந்து எழும்புகிற மிருகம் அவர்களோடு யுத்தம் பண்ணி அவர்களைக் கொலை செய்யும்."],
    "Revelation 11:8": ["மகா நகரத்தின் வீதிகளில் பிணங்கள்", "அவர்களுடைய பிணங்கள் எகிப்து என்றும் சோதோம் என்றும் அழைக்கப்படுகிற அந்த மகா நகரத்தின் வீதியிலே கிடக்கும்; அங்கேதான் நம்முடைய கர்த்தரும் சிலுவையில் அறையப்பட்டார்."],
    "Revelation 11:11": ["சாட்சிகள் உயிர் பெறுதல்", "மூன்றரை நாளைக்குப் பின்பு தேவனிடத்திலிருந்து ஜீவாத்துமா அவர்களுக்குள் பிரவேசித்தது; அவர்கள் காலூன்றி நின்றார்கள், அதைக் கண்டவர்களுக்கு மிகுந்த பயம் உண்டாயிற்று."],
    "Revelation 11:12": ["அவர்கள் பரலோகத்திற்கு ஏறுதல்", "அவர்கள் மேகத்தில் ஏறிப் பரலோகத்திற்குச் சென்றார்கள்; அவர்களுடைய பகைவர்கள் அதைக் கண்டார்கள்."],
    "Revelation 11:13": ["பெரிய பூமியதிர்ச்சி", "அந்நேரத்திலே பெரிய பூமியதிர்ச்சி உண்டாகி நகரத்தில் பத்தில் ஒரு பங்கு விழுந்தது; ஏழாயிரம் பேர் மடிந்தார்கள், மற்றவர்கள் பயந்து தேவனை மகிமைப்படுத்தினார்கள்."],
    "Revelation 11:15": ["ஏழாம் எக்காளம்", "ஏழாம் தூதன் எக்காளம் ஊதினான்; 'உலகத்தின் ராஜ்யங்கள் நம்முடைய கர்த்தருக்கும் அவருடைய கிறிஸ்துவுக்குமுரிய ராஜ்யங்களாயின' என்று பரலோகத்தில் மகா சத்தங்கள் உண்டாயின."],
    "Revelation 11:17": ["சர்வவல்லமையுள்ளவருக்குத் துதி", "இருக்கிறவரும் இருந்தவருமாகிய சர்வவல்லமையுள்ள கர்த்தாவே, நீர் உமது மகா வல்லமையைக் கொண்டு அரசாளுவதினால் உமக்கு ஸ்தோத்திரம் என்று மூப்பர்கள் ஆராதித்தார்கள்."],
    "Revelation 11:19": ["பரலோகத்தில் தேவாலயம் திறக்கப்படுதல்", "பரலோகத்திலே தேவனுடைய ஆலயம் திறக்கப்பட்டது; அவருடைய உடன்படிக்கைப் பெட்டி காணப்பட்டது; மின்னல்களும் இடிமுழக்கங்களும் பெரிய கல்மழையும் உண்டாயின."],

    "Revelation 12:1": ["ஸ்திரீயும் வலுசர்ப்பமும்", "வானத்திலே ஒரு பெரிய அடையாளம் காணப்பட்டது; ஒரு ஸ்திரீ சூரியனை அணிந்திருந்தாள், அவள் பாதங்களின் கீழே சந்திரனும், அவள் சிரசின்மேல் பன்னிரண்டு நட்சத்திரங்களுள்ள கிரீடமும் இருந்தன."],
    "Revelation 12:3": ["சிவப்பான மகா வலுசர்ப்பம்", "வானத்திலே வேறொரு அடையாளம் காணப்பட்டது; ஏழு தலைகளையும் பத்துக்கொம்புகளையும் உடைய சிவப்பான மகா வலுசர்ப்பம் அந்த ஸ்திரீயினுடைய பிள்ளையை விழுங்கும்படி ஆயத்தமாய் நின்றது."],
    "Revelation 12:5": ["ஆண் பிள்ளை", "சகல ஜாதிகளையும் இரும்புக்கோலால் ஆளும் ஆண் பிள்ளையை அவள் பெற்றாள்; அந்தப் பிள்ளை தேவனிடத்திற்கும் அவருடைய சிங்காசனத்திற்கும் எடுத்துக்கொள்ளப்பட்டது."],
    "Revelation 12:6": ["வனாந்தரத்திற்குத் தப்பியோடிய ஸ்திரீ", "அந்த ஸ்திரீ வனாந்தரத்திற்குத் தப்பியோடினாள்; அங்கே அவளைப் பராமரிக்கும்படி தேவன் ஒரு இடத்தைத் தந்து அவளைப் பாதுகாத்தார்."],
    "Revelation 12:7": ["பரலோகத்தில் யுத்தம்", "பரலோகத்திலே யுத்தமுண்டாயிற்று; மிகாவேலும் அவனைச் சேர்ந்த தூதர்களும் வலுசர்ப்பத்தோடே யுத்தம்பண்ணினார்கள்."],
    "Revelation 12:9": ["சாத்தான் பூமியில் தள்ளப்படுதல்", "உலகத்தையனைத்தையும் மோசம்போக்குகிற பிசாசு என்றும் சாத்தான் என்றும் சொல்லப்பட்ட பழைய பாம்பாகிய மகா வலுசர்ப்பம் பூமியிலே தள்ளப்பட்டது."],
    "Revelation 12:10": ["ஆட்டுக்குட்டியின் மூலம் வெற்றி", "பரலோகத்திலே ஒரு பெரிய சத்தம் உண்டாகி: 'இப்பொழுது இரட்சிப்பும் வல்லமையும் நமது தேவனுடைய ராஜ்யமும் உண்டாயிருக்கிறது; நம்முடைய சகோதரர்மேல் குற்றஞ்சாட்டுகிறவன் தள்ளப்பட்டுப்போனான்' என்று சொல்லக் கேட்டேன்."],
    "Revelation 12:13": ["ஸ்திரீயைத் துன்புறுத்தும் வலுசர்ப்பம்", "வலுசர்ப்பம் தான் பூமியிலே தள்ளப்பட்டதைக் கண்டு, அந்த ஆண் பிள்ளையைப் பெற்ற ஸ்திரீயைத் துன்பப்படுத்தியது."],
    "Revelation 12:14": ["வனாந்தரத்தில் பாதுகாப்பு", "அந்த ஸ்திரீ வலுசர்ப்பத்தின் முகத்திற்கு விலகி, வனாந்தரத்திலுள்ள தன் இடத்திற்குப் பறந்துபோகும்படி பெரிய கழுகின் இரண்டு சிறகுகள் அவளுக்குக் கொடுக்கப்பட்டன."],
    "Revelation 12:17": ["பரிசுத்தவான்களுக்கு எதிரான யுத்தம்", "வலுசர்ப்பம் ஸ்திரீயின்மேல் கோபங்கொண்டு, தேவனுடைய கற்பனைகளைக் கைக்கொள்ளுகிறவர்களும் இயேசு கிறிஸ்துவைப்பற்றிய சாட்சியை உடையவர்களுமாகிய அவளுடைய சந்ததியான மற்றவர்களோடே யுத்தம்பண்ணப்போயிற்று."],

    "Revelation 13:1": ["சமுத்திரத்திலிருந்து எழும்பிய மிருகம்", "சமுத்திரத்திலிருந்து ஒரு மிருகம் எழும்பி வரக் கண்டேன்; அதற்குப் பத்துக்கொம்புகளும் ஏழு தலைகளும் இருந்தன; வலுசர்ப்பம் அதற்குத் தன் வல்லமையையும் அதிககாரத்தையும் கொடுத்தது."],
    "Revelation 13:3": ["உலகத்தை வியக்கவைத்த மிருகம்", "அந்த மிருகத்தின் தலைகளில் ஒன்று சாகுமளவாய்க் காயப்பட்டிருந்தது; அந்தச் சாவுக்கேதுவான காயம் சொஸ்தமாக்கப்பட்டது, அப்பொழுது பூமியிலுள்ள யாவரும் ஆச்சரியப்பட்டு அந்த மிருகத்தைப் பின்பற்றினார்கள்."],
    "Revelation 13:4": ["மிருகத்தை ஆராதித்தல்", "வலுசர்ப்பத்திற்கும் மிருகத்திற்கும் மக்கள் ஆராதனை செய்தார்கள்; 'இந்த மிருகத்திற்கு ஒப்பானவர் யார்? இதனோடே யுத்தம்பண்ண யாரால் கூடும்?' என்று சொன்னார்கள்."],
    "Revelation 13:5": ["பெருமையானவைகளைப் பேசும் மிருகம்", "பெருமையானவைகளையும் தூஷணங்களையும் பேசும் வாய் அதற்குக் கொடுக்கப்பட்டது; நாற்பத்திரண்டு மாதம் கிரியை செய்ய அதற்குக் கட்டளை கொடுக்கப்பட்டது."],
    "Revelation 13:7": ["பரிசுத்தவான்களுடன் யுத்தம்", "பரிசுத்தவான்களோடே யுத்தம்பண்ணி அவர்களை ஜெயிக்க அதற்குக் கட்டளை கொடுக்கப்பட்டது; சகல ஜாதிகளின்மேலும் அதற்கு அதிகாரம் உண்டாயிற்று."],
    "Revelation 13:8": ["மிருகத்தை வணங்குபவர்கள்", "உலகத்தோற்ற முதல் அடிக்கப்பட்ட ஆட்டுக்குட்டியினுடைய ஜீவபுஸ்தகத்தில் பெயர்கள் எழுதப்படாத பூமியின் குடிகள் யாவரும் அதை வணங்குவார்கள்."],
    "Revelation 13:11": ["பூமியிலிருந்து எழும்பிய மிருகம்", "பூமியிலிருந்து வேறொரு மிருகம் எழும்பி வரக் கண்டேன்; அது ஆட்டுக்குட்டிக்கு ஒப்பான இரண்டு கொம்புகளையுடையதாயிருந்து, வலுசர்ப்பத்தைப்போலப் பேசியது."],
    "Revelation 13:13": ["பொய்யான அடையாளங்கள்", "அது வானத்திலிருந்து பூமியின்மேல் நெருப்பை இறக்கத்தக்கதாகப் பெரிய அடையாளங்களைச் செய்தது."],
    "Revelation 13:14": ["மிருகத்தின் உருவம்", "மிருகத்தின் முன்பாக அடையாளங்களைச் செய்யும்படி தனக்குக் கொடுக்கப்பட்ட அதிகாரத்தினால் பூமியின் குடிகளை மோசம்போக்கி, மிருகத்திற்கு ஒரு சொரூபம் (Image) பண்ணும்படி சொன்னது."],
    "Revelation 13:16": ["மிருகத்தின் முத்திரை", "சிறியோர் பெரியோர், ஐசுவரியவான்கள் தரித்திரர் யாவரும் தங்கள் வலதுகையிலாவது நெற்றியிலாவது ஒரு முத்திரையைப் பெறும்படி செய்தது."],
    "Revelation 13:17": ["வர்த்தகக் கட்டுப்பாடு", "மிருகத்தின் முத்திரையாவது அதின் நாமமாவது அதின் நாமத்தின் இலக்கமாவது இல்லாதவன் எவனும் கொள்ளவும் விற்கவும் கூடாதபடி செய்தது."],
    "Revelation 13:18": ["மிருகத்தின் இலக்கம்", "மிருகத்தின் இலக்கத்தைக் கணக்கிட ஞானம் வேண்டும்; அது மனுஷனுடைய இலக்கந்தான்; அதின் இலக்கம் அறுநூற்று அறுபத்தாறு (666)."],

    "Revelation 14:1": ["ஆட்டுக்குட்டியும் 1,44,000 பேரும்", "ஆட்டுக்குட்டியானவர் சீயோன் மலைமேல் நிற்கக் கண்டேன்; அவரோடேகூட அவருடைய பிதாவின் நாமம் தங்கள் நெற்றிகளில் எழுதப்பட்டிருந்த இலட்சத்து நாற்பத்து நாலாயிரம் பேர் இருந்தார்கள்."],
    "Revelation 14:2": ["பரலோகப் பாட்டு", "பெருவெள்ளத்து இரைச்சலைப்போலவும் பலத்த இடிமுழக்கத்தைப் போலவும் பரலோகத்திலிருந்து ஒரு சத்தம் உண்டாகக் கேட்டேன்; அவர்கள் சிங்காசனத்திற்கு முன்பாக ஒரு புதிய பாட்டைப் பாடினார்கள்."],
    "Revelation 14:6": ["முதல் தூதனின் செய்தி", "பூமியில் குடியிருக்கிற சகல ஜாதிகளுக்கும் கோத்திரங்களுக்கும் அறிவிக்கத்தக்கதாக நித்திய சுவிசேஷத்தைத் தூதன் ஒருவன் கொண்டுபோகக் கண்டேன்."],
    "Revelation 14:8": ["பாபிலோன் வீழ்ச்சி", "வேறொரு தூதன் பின்சென்று: 'மகா பாபிலோன் விழுந்தது! விழுந்தது! அது சகல ஜாதிகளுக்கும் தன் வேசித்தனமாகிய கோப மதுவைக் குடிக்கக் கொடுத்தது' என்றான்."],
    "Revelation 14:9": ["மிருகத்தை வணங்குவோருக்கு எச்சரிக்கை", "மூன்றாம் தூதன் அவர்களைப் பின்பற்றி வந்து: 'மிருகத்தையாவது அதின் சொரூபத்தையாவது வணங்கி, தன் நெற்றியிலாவது கயிலாவது அதின் முத்திரையைத் தரித்துக்கொள்ளுகிறவன் எவனோ, அவன் தேவனுடைய கோபாக்கினையாகிய மதுவைக் குடிப்பான்' என்றான்."],
    "Revelation 14:12": ["பரிசுத்தவான்களின் பொறுமை", "தேவனுடைய கற்பனைகளையும் இயேசுவின்மேலுள்ள விசுவாசத்தையும் காத்துக்கொள்ளுகிற பரிசுத்தவான்களுடைய பொறுமை இதிலே விளங்கும்."],
    "Revelation 14:13": ["கர்த்தருக்குள் மரிக்கிறவர்கள் பாக்கியவான்கள்", "இதுமுதல் கர்த்தருக்குள் மரிக்கிறவர்கள் பாக்கியவான்கள்; அவர்கள் தங்கள் பிரயாசங்களை விட்டு ஒழிந்து ஓய்ந்திருப்பார்கள், அவர்களுடைய கிரியைகள் அவர்களோடே கூடப்போகும்."],
    "Revelation 14:14": ["பூமியின் அறுவடை", "மேகத்தின்மேல் மனுஷகுமாரனுக்கொப்பானவர் ஒரு பொன் கிரீடத்தைச் சிரசில் தரித்து, கையில் கூர்மையான அரிவாளைப் பிடித்து அமர்ந்திருக்கக் கண்டேன்; பூமியின் பயிர் விளைந்திருந்தது."],
    "Revelation 14:17": ["திராட்சப்பழங்களைச் சேகரித்தல்", "பரலோகத்திலுள்ள ஆலயத்திலிருந்து வேறொரு தூதன் புறப்பட்டு வந்தான்; அவனும் ஒரு கூர்மையான அரிவாளைப் பிடித்திருந்தான்."],
    "Revelation 14:19": ["தேவனுடைய கோபாக்கினை என்னும் ஆலை", "தூதன் தன் அரிவாளைப் பூமியின்மேல் வீசி, பூமியின் திராட்சப்பழங்களை அறுத்து, தேவனுடைய கோபாக்கினை என்னும் மகா ஆலைக்குள்ளே போட்டான்."],

    "Revelation 15:1": ["ஏழு கடைசி வாதைகள்", "வானத்திலே பெரிதும் ஆச்சரியமுமான வேறொரு அடையாளத்தைக் கண்டேன்; ஏழு கடைசி வாதைகளை உடைய ஏழு தூதர்களே அவர்கள்; அவைகளால் தேவனுடைய கோபம் முடிகிறது."],
    "Revelation 15:2": ["கண்ணாடி போன்ற கடல்", "நெருப்பு கலந்த கண்ணாடி போன்ற ஒரு கடலையும், மிருகத்தை ஜெயித்து வந்தவர்கள் அந்தக் கடலருகே தேவனுடைய வீணைகளைப் பிடித்துக்கொண்டு நிற்பதையும் கண்டேன்."],
    "Revelation 15:3": ["மோசே மற்றும் ஆட்டுக்குட்டியின் பாட்டு", "அவர்கள் தேவனுடைய தாசனாகிய மோசேயின் பாட்டையும் ஆட்டுக்குட்டியானவருடைய பாட்டையும் பாடி: 'சர்வவல்லமையுள்ள தேவனாகிய கர்த்தாவே, உமது கிரியைகள் மகத்துவமும் ஆச்சரியமுமானவைகள்' என்றார்கள்."],
    "Revelation 15:5": ["பரலோக ஆலயம் திறக்கப்படுதல்", "சாட்சியின் கூடாரமாகிய ஆலயம் பரலோகத்திலே திறக்கப்பட்டது."],
    "Revelation 15:6": ["ஏழு தூதர்கள் வெளியே வருதல்", "ஏழு வாதைகளை உடைய ஏழு தூதர்கள் சுத்தமான பிரகாசமான வஸ்திரம் தரித்து, மார்புகளில் பொற்கச்சைகளைக் கட்டிக்கொண்டு ஆலயத்திலிருந்து புறப்பட்டார்கள்."],
    "Revelation 15:7": ["கோபகலசங்கள் கொடுக்கப்படுதல்", "நான்கு ஜீவன்களில் ஒன்று அந்த ஏழு தூதர்களுக்கும் தேவனுடைய கோபத்தால் நிறைந்த ஏழு பொற்கலசங்களைக் கொடுத்தது."],
    "Revelation 15:8": ["மகிமையால் நிறைந்த ஆலயம்", "தேவனுடைய மகிமையினாலும் அவருடைய வல்லமையினாலும் ஆலயம் புகையினால் நிறைந்தது; அந்த ஏழு தூதர்களுடைய ஏழு வாதைகளும் முடிந்து தீருமளவும் ஒருவனும் ஆலயத்திற்குள் பிரவேசிக்கக் கூடாதிருந்தது."],

    "Revelation 16:1": ["கோபகலசங்கள் ஊற்றப்படுதல்", "ஆலயத்திலிருந்து ஒரு மகா சத்தம் உண்டாகி, அந்த ஏழு தூதர்களை நோக்கி: 'நீங்கள் போய் தேவனுடைய கோபகலசங்களைப் பூமியின்மேல் ஊற்றுங்கள்' என்று சொல்லக் கேட்டேன்."],
    "Revelation 16:2": ["முதல் கலசம்: கொடிய புண்கள்", "முதல் தூதன் தன் கலசத்தைப் பூமியின்மேல் ஊற்றினான்; அப்பொழுது மிருகத்தின் முத்திரையைத் தரித்தவர்களுக்கும் அதின் சொரூபத்தை வணங்குகிறவர்களுக்கும் கொடிய புண்கள் உண்டாயின."],
    "Revelation 16:3": ["இரண்டாம் கலசம்: சமுத்திரம் இரத்தமாதல்", "இரண்டாம் தூதன் தன் கலசத்தைச் சமுத்திரத்திலே ஊற்றினான்; அது செத்தவனுடைய இரத்தத்தைப்போலாயிற்று, சமுத்திரத்திலுள்ள பிராணிகள் யாவும் மடிந்தன."],
    "Revelation 16:4": ["மூன்றாம் கலசம்: ஆறுகள் இரத்தமாதல்", "மூன்றாம் தூதன் தன் கலசத்தை ஆறுகளிலும் நீரூற்றுகளிலும் ஊற்றினான்; அவைகள் இரத்தமாயின."],
    "Revelation 16:8": ["நான்காம் கலசம்: சுட்டெரிக்கும் சூரியன்", "நான்காம் தூதன் தன் கலசத்தைச் சூரியன்மேல் ஊற்றினான்; மனுஷரை நெருப்பினால் சுட்டெரிக்க அதற்கு அதிகாரம் கொடுக்கப்பட்டது."],
    "Revelation 16:10": ["ஐந்தாம் கலசம்: மிருகத்தின் ராஜ்யத்தில் இருள்", "ஐந்தாம் தூதன் தன் கலசத்தை மிருகத்தின் சிங்காசனத்தின்மேல் ஊற்றினான்; அப்பொழுது அதின் ராஜ்யம் அந்தகாரப்பட்டது; மக்கள் தங்கள் வேதனையினால் தங்கள் நாக்குகளைக் கடித்தார்கள்."],
    "Revelation 16:12": ["ஆறாம் கலசம்: ஐபிராத்து நதி வற்றுதல்", "ஆறாம் தூதன் தன் கலசத்தை ஐபிராத்து என்னும் பெரிய நதியின்மேல் ஊற்றினான்; அப்பொழுது சூரியன் உதிக்கும் திசையிலிருந்து வரும் ராஜாக்களுக்கு வழி ஆயத்தமாகும்படி அந்த நதியின் தண்ணீர் வற்றிப்போயிற்று."],
    "Revelation 16:13": ["தவளைகளைப் போன்ற அசுத்த ஆவிகள்", "வலுசர்ப்பத்தின் வாயிலும் மிருகத்தின் வாயிலும் கள்ளத்தீர்க்கதரிசியின் வாயிலும் இருந்து தவளைகளுக்கு ஒப்பான மூன்று அசுத்த ஆவிகள் புறப்பட்டு வரக் கண்டேன்."],
    "Revelation 16:16": ["அர்மகெதோன்", "அப்பொழுது எபிரெய பாஷையிலே அர்மகெதோன் என்னப்பட்ட இடத்திலே ராஜாக்களைக் கூட்டினார்கள்."],
    "Revelation 16:17": ["ஏழாம் கலசம்: எல்லாம் முடிந்தது", "ஏழாம் தூதன் தன் கலசத்தை ஆகாயத்தில் ஊற்றினான்; அப்பொழுது சிங்காசனத்திலிருந்து: 'முடிந்தது' என்று ஒரு மகா சத்தம் உண்டாயிற்று."],
    "Revelation 16:18": ["பெரிய பூமியதிர்ச்சி", "மின்னல்களும் சத்தங்களும் இடிமுழக்கங்களும் உண்டாயின; பூமி உண்டாானது முதல் அதுவரை சம்பவித்திராத பெரிய பூமியதிர்ச்சி உண்டாயிற்று."],
    "Revelation 16:19": ["பாபிலோனுக்கு நியாயத்தீர்ப்பு", "அந்த மகா நகரம் மூன்று பங்காகப் பிரிக்கப்பட்டது; மகா பாபிலோன் தேவனுக்கு முன்பாக நினைப்பூட்டப்பட்டது, அவர் அவளுக்குத் தமது கோபாக்கினையாகிய மதுக் கலசத்தைக் கொடுத்தார்."],
    "Revelation 16:21": ["வானத்திலிருந்து கல்மழை", "தாலந்து எடையுள்ள பெரிய கல்மழை வானத்திலிருந்து மனுஷர்மேல் விழுந்தது; அந்த வாதை மிகவும் கொடியதாயிருந்ததினால் மனுஷர்கள் தேவனைத் தூஷித்தார்கள்."],

    "Revelation 17:1": ["மகா வேசியின் நியாயத்தீர்ப்பு", "ஏழு கலசங்களை உடைய ஏழு தூதர்களில் ஒருவன் என்னோடு பேசி: 'திரளான தண்ணீர்கள்மேல் உட்கார்ந்திருக்கிற மகா வேசிக்கு வரும் நியாயத்தீர்ப்பை உனக்குக் காண்பிப்பேன் வா' என்றான்."],
    "Revelation 17:3": ["சிவப்பு நிற மிருகத்தின்மேல் ஸ்திரீ", "ஆவிக்குள்ளான என்னை வனாந்தரத்திற்குக் கொண்டுபோனான்; அப்பொழுது தூஷண நாமங்களால் நிறைந்ததும் ஏழு தலைகளையும் பத்துக்கொம்புகளையும் உடையதுமான சிவப்பான மிருகத்தின்மேல் ஒரு ஸ்திரீ உட்கார்ந்திருக்கக் கண்டேன்."],
    "Revelation 17:4": ["ஸ்திரீயின் ஆடம்பரம்", "அந்த ஸ்திரீ இரத்தாம்பரமும் சிவப்பான வஸ்திரமும் தரித்து, பொன்னினாலும் இரத்தினங்களினாலும் முத்துக்களினாலும் சிங்காரிக்கப்பட்டிருந்தாள்; அவளுடைய கையிலிருந்த பொற்கலசம் அருவருப்புகளினால் நிறைந்திருந்தது."],
    "Revelation 17:5": ["மர்மமான மகா பாபிலோன்", "அவள் நெற்றியில்: 'மர்மம், மகா பாபிலோன், வேசிகளுக்கும் பூமியிலுள்ள அருவருப்புகளுக்கும் தாய்' என்கிற நாமம் எழுதப்பட்டிருந்தது."],
    "Revelation 17:6": ["பரிசுத்தவான்களின் இரத்தத்தினால் வெறித்தவள்", "அந்த ஸ்திரீ பரிசுத்தவான்களின் இரத்தத்தினாலும் இயேசுவினுடைய சாட்சிகளின் இரத்தத்தினாலும் வெறித்திருக்கக் கண்டேன்; அவளைக் கண்டு நான் மிகவும் ஆச்சரியப்பட்டேன்."],
    "Revelation 17:7": ["மர்மத்தின் விளக்கம்", "தூதன் என்னை நோக்கி: 'ஏன் ஆச்சரியப்படுகிறாய்? இந்த ஸ்திரீயினுடைய மர்மத்தையும் இவளைச் சுமக்கிற ஏழு தலைகளையும் பத்துக்கொம்புகளையுமுடைய மிருகத்தின் மர்மத்தையும் உனக்குச் சொல்லுகிறேன்' என்றான்."],
    "Revelation 17:9": ["ஏழு தலைகளின் பொருள்", "அந்த ஏழு தலைகளும் அந்த ஸ்திரீ உட்கார்ந்திருக்கிற ஏழு மலைகளாம்; அவைகள் ஏழு ராஜாக்களையும குறிக்கும்."],
    "Revelation 17:12": ["பத்துக் கொம்புகள்", "நீ கண்ட பத்துக் கொம்புகளும் இன்னும் ராஜ்யம் பெறாத பத்து ராஜாக்களாம்; இவர்கள் மிருகத்துடனே கூட ஒரு மணி நேரம் ராஜாக்களாக அதிகாரம் பெறுவார்கள்."],
    "Revelation 17:14": ["ஆட்டுக்குட்டியானவர் ஜெயிப்பார்", "இவர்கள் ஆட்டுக்குட்டியானவரோடே யுத்தம்பண்ணுவார்கள்; ஆட்டுக்குட்டியானவர் ராஜாதி ராஜாவும் கர்த்தாதி கர்த்தாவுமாயிருக்கிறபடியால் அவர்களை ஜெயிப்பார்."],
    "Revelation 17:16": ["ஸ்திரீயின் அழிவு", "மிருகத்தின்மேல் நீ கண்ட பத்துக் கொம்புகளும் அந்த வேசியைப் பகைத்து, அவளைப் பாழும் நிர்வாணமுமாக்கி, அவளுடைய மாம்சத்தைப் புசித்து, அவளை நெருப்பினால் சுட்டெரிப்பார்கள்."],
    "Revelation 17:18": ["ஸ்திரீ மகா நகரத்தைக் குறிக்கிறாள்", "நீ கண்ட அந்த ஸ்திரீ பூமியின் ராஜாக்களை அரசாளுக்கிற மகா நகரமேயாம்."],

    "Revelation 18:1": ["பாபிலோன் வீழ்ச்சி", "வானத்திலிருந்து இறங்கிவந்த வேறொரு தூதன்: 'மகா பாபிலோன் விழுந்தது! விழுந்தது!' என்று மகா சத்தமாய் அறிவிக்கக் கண்டேன்."],
    "Revelation 18:2": ["பேய்களின் குடியிருப்பான பாபிலோன்", "ஒரு காலத்தில் மகத்துவமாய் இருந்த அந்த நகரம் பேய்களுடைய குடியிருப்பும், அசுத்த ஆவிகளுடைய அடைக்கலமுமானது."],
    "Revelation 18:4": ["பாபிலோனை விட்டு வெளியே வர அழைப்பு", "என் ஜனங்களே, நீங்கள் அவளுடைய பாவங்களுக்கு உடன்படாமலும், அவளுக்கு வரும் வாதைகளில் அகப்படாமலும் இருக்கும்படி அவளைவிட்டு வெளியே வாருங்கள் என்று வானத்திலிருந்து ஒரு சத்தம் கேட்டது."],
    "Revelation 18:6": ["பாபிலோனின் நியாயத்தீர்ப்பு", "அவள் உங்களுக்குச் செய்தபடியே அவளுக்குச் செய்யுங்கள்; அவளுடைய கிரியைகளுக்குத்தக்கதாக அவளுக்கு இரட்டிப்பாகக் கொடுங்கள்."],
    "Revelation 18:9": ["பாபிலோனுக்காக ராஜாக்கள் புலம்புதல்", "அவளோடே விபசாரம்பண்ணிச் சுகபோகமாய் வாழ்ந்த பூமியின் ராஜாக்கள் அவளுடைய எரிப்பின் புகையைக் காணும்போது அவளுக்காக அழுது புலம்புவார்கள்."],
    "Revelation 18:11": ["வியாபாரிகள் துக்கப்படுதல்", "தங்கள் சரக்குகளை இனி ஒருவனும் கொள்ளாதபடியினால் பூமியின் வியாபாரிகள் அவளுக்காக அழுது துக்கப்படுவார்கள்."],
    "Revelation 18:17": ["திடீர் அழிவு", "ஒரே மணிநேரத்தில் இவ்வளவு ஐசுவரியமும் பாழாய்ப்போயிற்றே என்று மாலுமிகளும் வர்த்தகர்களும் தூரத்தில் நின்று அவளுடைய அழிவைக் கண்டு புலம்புவார்கள்."],
    "Revelation 18:20": ["பரலோகம் மகிழ்தல்", "பரலோகமே! பரிசுத்தவான்களே! அப்போஸ்தலர்களே! தீர்க்கதரிசிகளே! அவளைக் குறித்து மகிழுங்கள்; உங்களுக்காகத் தேவன் அவளை நியாயந்தீர்த்தார்."],
    "Revelation 18:21": ["பாபிலோன் எறியப்படுதல்", "பலமுள்ள ஒரு தூதன் ஒரு பெரிய ஏந்திரக்கல்லைப் போன்ற ஒரு கல்லை எடுத்துச் சமுத்திரத்திலே எறிந்து: 'இப்படியே பாபிலோன் மகா நகரம் பலமாய் எறியப்பட்டு, இனி ஒருபோதும் காணப்படாமல் போகும்' என்றான்."],
    "Revelation 18:23": ["செல்வாக்கு முடிவுக்கு வருதல்", "விளக்கின் வெளிச்சம் இனி உனக்குள் பிரகாசிப்பதில்லை; உன்னுடைய சூனியத்தினால் சகல ஜாதிகளும் மோசம்போனார்கள்."],
    "Revelation 18:24": ["இரத்தப்பழி", "தீர்க்கதரிசிகளுடையவும் பரிசுத்தவான்களுடையவும் பூமியில் கொல்லப்பட்ட அனைவருடையவும் இரத்தம் அவளிடத்தில் காணப்பட்டது."],

    "Revelation 19:1": ["பரலோகத்தில் துதி", "பரலோகத்திலுள்ள திரளான ஜனக்கூட்டம்: 'அல்லேலூயா, இரட்சிப்பும் மகிமையும் கனமும் வல்லமையும் நம்முடைய தேவனாகிய கர்த்தருக்கே உரியது' என்று சொல்லக் கேட்டேன்."],
    "Revelation 19:3": ["பாபிலோனின் புகை எழும்புகிறது", "மறுபடியும் அவர்கள்: 'அல்லேலூயா' என்றார்கள்; அவளுடைய எரிப்பின் புகை சதாகாலங்களிலும் எழும்புகிறது."],
    "Revelation 19:4": ["மூப்பர்கள் ஆராதித்தல்", "இருபத்து நான்கு மூப்பர்களும் நான்கு ஜீவன்களும் சிங்காசனத்தின்மேல் வீற்றிருக்கிற தேவனை வணங்கி: 'ஆமென், அல்லேலூயா' என்றார்கள்."],
    "Revelation 19:6": ["கர்த்தருடைய அரசாட்சி", "திரளான ஜனக்கூட்டத்தின் இரைச்சலைப்போல: 'சர்வவல்லமையுள்ள தேவனாகிய கர்த்தர் அரசாட்சி செய்கிறார், அல்லேலூயா' என்று சொல்லக் கேட்டேன்."],
    "Revelation 19:7": ["ஆட்டுக்குட்டியின் கல்யாணம்", "நாம் மகிழ்ந்து அவருக்கு மகிமை செலுத்தக்கடவோம்; ஆட்டுக்குட்டியானவருடைய கல்யாணம் வந்தது, அவருடைய மனைவி தன்னை ஆயத்தம் பண்ணினாள்."],
    "Revelation 19:9": ["அழைக்கப்பட்டவர்கள் பாக்கியவான்கள்", "ஆட்டுக்குட்டியானவருடைய கல்யாண விருந்துக்கு அழைக்கப்பட்டவர்கள் பாக்கியவான்கள் என்று எழுது என்று தூதன் சொன்னான்."],
    "Revelation 19:11": ["வெள்ளைக் குதிரைமேல் ஏறியவர்", "பரலோகம் திறந்திருக்கக் கண்டேன்; இதோ, ஒரு வெள்ளைக் குதிரை காணப்பட்டது, அதன்மேல் ஏறியிருந்தவர் 'உண்மையுள்ளவர்' என்றும் 'சத்தியமுள்ளவர்' என்றும் பெயருள்ளவர்."],
    "Revelation 19:13": ["தேவனுடைய வார்த்தை", "இரத்தத்தில் தோய்க்கப்பட்ட வஸ்திரத்தைத் தரித்திருந்தார்; அவருடைய நாமம் 'தேவனுடைய வார்த்தை' என்பது."],
    "Revelation 19:15": ["ராஜாதி ராஜா", "ஜாதிகளை வெட்டும்படி அவருடைய வாயிலிருந்து கூர்மையான பட்டயம் புறப்பட்டது; அவர் இரும்புக்கோலால் அவர்களை ஆளுவார்."],
    "Revelation 19:17": ["தேவனுடைய மகா விருந்து", "சூரியனில் நின்ற ஒரு தூதன் சகல பறவைகளையும் நோக்கி: 'நீங்கள் தேவனுடைய மகா விருந்துக்குக் கூடிவாருங்கள்' என்று கூப்பிட்டான்."],
    "Revelation 19:19": ["மிருகம் யுத்தம் பண்ணுதல்", "மிருகமும் பூமியின் ராஜாக்களும் குதிரைமேல் ஏறியிருந்தவரோடும் அவருடைய சேனைகளோடும் யுத்தம்பண்ணக் கூடிவந்திருக்கக் கண்டேன்."],
    "Revelation 19:20": ["மிருகமும் கள்ளத்தீர்க்கதரிசியும் தோற்கடிக்கப்படுதல்", "மிருகம் பிடிக்கப்பட்டது, அதின் முன்பாக அடையாளங்களைச் செய்த கள்ளத்தீர்க்கதரிசியும் பிடிக்கப்பட்டான்; இருவரும் கந்தகம் எரிகிற அக்கினிக் கடலிலே உயிருடன் தள்ளப்பட்டார்கள்."],
    "Revelation 19:21": ["பகைவர்கள் அழிதல்", "மற்றவர்கள் குதிரைமேல் ஏறியிருந்தவருடைய வாயிலிருந்து புறப்பட்ட பட்டயத்தால் கொல்லப்பட்டார்கள்; பறவைகள் யாவும் அவர்களுடைய மாம்சத்தினால் திருப்தியடைந்தன."],

    "Revelation 20:1": ["சாத்தான் ஆயிரம் வருஷம் கட்டப்படுதல்", "ஒரு தூதன் பாதாளத்தின் திறவுகோலையும் ஒரு பெரிய சங்கிலியையும் தன் கையிலே பிடித்துக்கொண்டு வானத்திலிருந்து இறங்கி வரக் கண்டேன்."],
    "Revelation 20:4": ["பரிசுத்தவான்களின் அரசாட்சி", "இயேசுவைப்பற்றிய சாட்சியினிமித்தம் சிரச்சேதம் பண்ணப்பட்டவர்களுடைய ஆத்துமாக்களைக் கண்டேன்; அவர்கள் உயிர்த்தெழுந்து கிறிஸ்துவுடனேகூட ஆயிரம் வருஷம் அரசாண்டார்கள்."],
    "Revelation 20:5": ["முதலாம் உயிர்த்தெழுதல்", "மரித்தோரில் மற்றவர்கள் அந்த ஆயிரம் வருஷம் முடியுமளவும் உயிரடையவில்லை; இதுவே முதலாம் உயிர்த்தெழுதல்."],
    "Revelation 20:7": ["சாத்தான் விடுதலையாதல்", "அந்த ஆயிரம் வருஷம் முடிந்தபின்பு சாத்தான் தன் சிறையிருப்பிலிருந்து விடுதலையாக்கப்படுவான்."],
    "Revelation 20:8": ["இறுதித் துரோகம்", "பூமியின் நான்கு திசைகளிலுமுள்ள ஜாதிகளை மோசம்போக்கவும், அவர்களை யுத்தத்திற்குக் கூட்டவும் அவன் புறப்படுவான்."],
    "Revelation 20:9": ["வானத்திலிருந்து இறங்கிய அக்கினி", "அவர்கள் பரிசுத்தவான்களுடைய பாளயத்தையும் பிரியமான நகரத்தையும் வளைத்துக்கொண்டார்கள்; அப்பொழுது வானத்திலிருந்து தேவனால் அக்கினி இறங்கி அவர்களைப் பட்சித்தது."],
    "Revelation 20:10": ["சாத்தான் அக்கினிக்கடலில் தள்ளப்படுதல்", "அவர்களை மோசம்போக்கின பிசாசானவன் மிருகமும் கள்ளத்தீர்க்கதரிசியும் இருக்கிற அக்கினியும் கந்தகமுமான கடலிலே தள்ளப்பட்டான்."],
    "Revelation 20:11": ["வெள்ளை சிங்காசனம்", "பெரிய வெள்ளைச் சிங்காசனத்தையும் அதின்மேல் வீற்றிருக்கிறவரையும் கண்டேன்; அவருக்கு முன்பாகப் பூமியும் வானமும் அகன்று போயின."],
    "Revelation 20:12": ["மரித்தோர் நியாயந்தீர்க்கப்படுதல்", "மரித்தோராகிய சிறியோரும் பெரியோரும் தேவனுக்கு முன்பாக நிற்கக் கண்டேன்; புஸ்தகங்கள் திறக்கப்பட்டன; ஒவ்வொருவரும் தங்கள் கிரியைகளின்படியே நியாயந்தீர்க்கப்பட்டார்கள்."],
    "Revelation 20:14": ["மரணமும் பாதாளமும் அழிக்கப்படுதல்", "மரணமும் பாதாளமும் அக்கினிக்கடலிலே தள்ளப்பட்டன; இது இரண்டாம் மரணம்."],
    "Revelation 20:15": ["ஜீவபுஸ்தகம்", "ஜீவபுஸ்தகத்திலே எழுதப்பட்டவனாகக் காணப்படாதவன் எவனோ அவன் அக்கினிக்கடலிலே தள்ளப்பட்டான்."],

    "Revelation 21:1": ["புதிய வானமும் புதிய பூமியும்", "புதிய வானத்தையும் புதிய பூமியையும் கண்டேன்; முந்தின வானமும் முந்தின பூமியும் ஒழிந்துபோயின; சமுத்திரமும் இல்லாமல் போயிற்று."],
    "Revelation 21:2": ["புதிய எருசலேம்", "புதிய எருசலேமாகிய பரிசுத்த நகரம் தன் புருஷனுக்காக அலங்கரிக்கப்பட்ட மணவாட்டியைப்போல ஆயத்தம் பண்ணப்பட்டு வானத்திலிருந்து இறங்கி வரக் கண்டேன்."],
    "Revelation 21:3": ["தேவன் மனுஷர்களுடனே வாசம்பண்ணுதல்", "இதோ, மனுஷர்களிடத்திலே தேவனுடைய வாசஸ்தலமிருக்கிறது, அவர்களோடே அவர் வாசம்பண்ணுவார்; அவர்கள் அவருடைய ஜனங்களாயிருப்பார்கள்."],
    "Revelation 21:4": ["மரணமும் துக்கமும் இனி இல்லை", "அவர்களுடைய கண்ணீர் யாவையும் தேவன் துடைப்பார்; இனி மரணமுமில்லை, துக்கமுமில்லை, அலறுதலுமில்லை, வருத்தமுமில்லை."],
    "Revelation 21:5": ["சகலமும் புதிதாகுதல்", "சிங்காசனத்தின்மேல் வீற்றிருந்தவர்: 'இதோ, நான் சகலத்தையும் புதிதாக்குகிறேன்' என்றார்."],
    "Revelation 21:6": ["ஆல்பாவும் ஓமெகாவும்", "முடிந்தது; நான் ஆல்பாவும் ஓமெகாவும், ஆதியும் அந்தமுமாயிருக்கிறேன்; தாகமாயிருக்கிறவனுக்கு ஜீவதண்ணீர் ஊற்றடியில் இலவசமாய்க் கொடுப்பேன்."],
    "Revelation 21:8": ["தீயோருக்கான நியாயத்தீர்ப்பு", "பயப்படுகிறவர்களும், அவிசுவாசிகளும், அருவருப்பானவர்களும்... இரண்டாம் மரணமாகிய அக்கினியும் கந்தகமும் எரிகிற கடலிலே பங்கடைவார்கள்."],
    "Revelation 21:9": ["மணவாட்டியாகிய புதிய எருசலேம்", "ஆட்டுக்குட்டியானவருடைய மனைவியாகிய மணவாட்டியை உனக்குக் காண்பிப்பேன் என்று ஒரு தூதன் என்னோடு பேசினான்."],
    "Revelation 21:11": ["நகரத்தின் மகிமை", "அது தேவனுடைய மகிமையைப் பெற்றிருந்தது; அதின் ஒளி மிகவும் விலையேறப்பெற்ற இரத்தினக்கல்லைப் போலிருந்தது."],
    "Revelation 21:15": ["பரிசுத்த நகரத்தை அளத்தல்", "நகரத்தையும் அதின் வாசல்களையும் அதின் மதிலையும் அளக்கிறதற்கு அந்தத் தூதன் தன் கையிலே ஒரு பொற்கோலைப் பிடித்திருந்தான்."],
    "Revelation 21:18": ["நகரத்தின் விலையேறப்பெற்ற அஸ்திபாரங்கள்", "நகரத்தின் மதில் வச்சிரக்கல்லால் கட்டப்பட்டிருந்தது; நகரம் தெளிந்த கண்ணாடிக்கு ஒப்பான சுத்தப் பொன்னாயிருந்தது."],
    "Revelation 21:22": ["நகரத்திற்குள் தேவாலயம் இல்லை", "சர்வவல்லமையுள்ள தேவனாகிய கர்த்தரும் ஆட்டுக்குட்டியானவருமே அதற்குத் தேவாலயம், ஆதலால் அதற்குள் தேவாலயத்தைக் காணவில்லை."],
    "Revelation 21:23": ["தேவ மகிமையே அதன் வெளிச்சம்", "நகரத்திற்கு வெளிச்சம் கொடுக்கச் சூரியனும் சந்திரனும் அதற்குத் தேவையில்லை; தேவனுடைய மகிமையே அதைப் பிரகாசிப்பித்தது."],
    "Revelation 21:27": ["மீட்கப்பட்டவர்கள் மாத்திரமே நுழைவார்கள்", "அருவருப்பானதையும் பொய்யையும் நடப்பிக்கிற எவனும் அதற்குள் பிரவேசிப்பதில்லை; ஆட்டுக்குட்டியின் ஜீவபுஸ்தகத்தில் எழுதப்பட்டவர்கள் மாத்திரமே பிரவேசிப்பார்கள்."],

    "Revelation 22:1": ["ஜீவத்தண்ணீர் நதி", "பளிங்குபோல் தெளிவான ஜீவத்தண்ணீருள்ள சுத்தமான நதி தேவனுடையவும் ஆட்டுக்குட்டியானவருடையவும் சிங்காசனத்திலிருந்து புறப்பட்டு வரக் காண்பித்தான்."],
    "Revelation 22:2": ["ஜீவவிருட்சம்", "நதியின் இருபுறத்திலும் ஜீவவிருட்சம் இருந்தது; அது மாதம் தோறும் தன் கனியைத் தந்தது, அந்த விருட்சத்தின் இலைகள் ஜாதிகளை ஆரோக்கியப்படுத்துகிறவைகளாயிருந்தன."],
    "Revelation 22:3": ["ஊழியக்காரர் முகம் தரிசித்தல்", "இனி ஒரு சாபமுமிருக்காது; தேவனுடையவும் ஆட்டுக்குட்டியானவருடையவும் சிங்காசனம் அதிலிருக்கும்; அவருடைய ஊழியக்காரர் அவரைச் சேவித்து, அவருடைய முகத்தைத் தரிசிப்பார்கள்."],
    "Revelation 22:5": ["நித்திய ஒளி", "அங்கே இனி இராக்காலமிராது; தேவனாகிய கர்த்தர் அவர்கள்மேல் பிரகாசிப்பார்; அவர்கள் சதாகாலங்களிலும் அரசாளுவார்கள்."],
    "Revelation 22:6": ["வார்த்தைகள் உண்மையுள்ளவை", "இந்த வசனங்கள் உண்மையுள்ளவைகளும் சத்தியமுள்ளவைகளுமாய் இருக்கின்றன என்று தூதன் என்னிடம் கூறினான்."],
    "Revelation 22:7": ["இயேசு சீக்கிரமாய் வருகிறார்", "இதோ, சீக்கிரமாய் வருகிறேன்; இந்தத் தீர்க்கதரிசன வசனங்களைக் கைக்கொள்ளுகிறவன் பாக்கியவான்."],
    "Revelation 22:10": ["காலம் சமீபமாயிருக்கிறது", "இந்தத் தீர்க்கதரிசன புஸ்தகத்தின் வசனங்களை முத்திரை போடாதே; காலம் சமீபமாயிருக்கிறது."],
    "Revelation 22:12": ["கிறிஸ்துவின் பலன்", "இதோ, சீக்கிரமாய் வருகிறேன்; அவனவனுடைய கிரியைகளின்படி அவனவனுக்கு நான் அளிக்கும் பலன் என்னோடேகூட வருகிறது."],
    "Revelation 22:13": ["ஆல்பாவும் ஓமெகாவும்", "நான் ஆல்பாவும் ஓமெகாவும், ஆதியும் அந்தமும், முந்தினவரும் பிந்தினவருமாயிருக்கிறேன்."],
    "Revelation 22:16": ["இயேசு விடிவெள்ளி நட்சத்திரம்", "இயேசுவாகிய நான் சபைகளில் இவைகளை உங்களுக்குச் சாட்சியாக அறிவிக்கும்படி என் தூதனை அனுப்பினேன்; நான் தாவீதின் வேரும் சந்ததியும், பிரகாசமுள்ள விடிவெள்ளி நட்சத்திரமுமாயிருக்கிறேன்."],
    "Revelation 22:17": ["வாருங்கள் என்னும் அழைப்பு", "ஆவியும் மணவாட்டியும்: 'வா' என்கிறார்கள்; தாகமாயிருக்கிறவன் வரக்கடவன்; விருப்பமுள்ளவன் ஜீவத்தண்ணீரை இலவசமாய் வாங்கிக்கொள்ளக்கடவன்."],
    "Revelation 22:18": ["தீர்க்கதரிசனத்தைக் குறித்த எச்சரிக்கை", "இந்தத் தீர்க்கதரிசன புஸ்தகத்திலுள்ள வசனங்களோடு ஒருவன் எதையாகிலும் கூட்டினால் தேவன் அவனுக்கு வாதைகளைக் கூட்டுவார்; எதையாகிலும் குறைத்தால் ஜீவபுஸ்தகத்திலிருந்து அவனுடைய பங்கைக் குறைப்பார்."],
    "Revelation 22:20": ["கிறிஸ்துவின் இறுதி வாக்குறுதி", "இவைகளைச் சாட்சியாக அறிவிக்கிறவர்: 'மெய்யாகவே நான் சீக்கிரமாய் வருகிறேன்' என்கிறார். ஆமென், கர்த்தராகிய இயேசுவே, வாரும்."],
    "Revelation 22:21": ["இறுதி ஆசீர்வாதம்", "நம்முடைய கர்த்தராகிய இயேசு கிறிஸ்துவின் கிருபை உங்கள் அனைவரோடும் இருப்பதாக. ஆமென்."],
};

